def _load_master_password():
    for env_name in ("YUCEPORTAL_MASTER_PASSWORD", "YA_RPA_MYSQL_PASSWORD"):
        value = os.getenv(env_name)
        if value is not None:
            return value
    try:
        return getpass.getpass("MySQL password: ")
    except (EOFError, KeyboardInterrupt):
        raise RuntimeError(
            "MySQL password is required. Set YUCEPORTAL_MASTER_PASSWORD or "
            "YA_RPA_MYSQL_PASSWORD, or run manage.py interactively."
        ) from None


def _get_mysql_setting(key, fallback):
    value = YA_RPA_MYSQL.get(key) if isinstance(YA_RPA_MYSQL, dict) else None
    if value is None:
        return fallback
    if key == "password" and isinstance(value, str):
        return value
    if isinstance(value, str) and value.strip():
        return value.strip()
    return fallback
 
