GRAPH_BASE = "https://graph.microsoft.com/v1.0"

def build_msal_app(cache=None):
    """Return a ConfidentialClientApplication (server-side app with client_secret)."""
    return msal.ConfidentialClientApplication(MS_CLIENT_ID, authority=MS_AUTHORITY, client_credential=MS_CLIENT_SECRET, token_cache=cache)

def get_user_row_by_username(username):
    cur = mysql.connection.cursor()
    cur.execute("SELECT * FROM users1 WHERE username=%s", (username,))
    return cur.fetchone()

def save_refresh_token(user_id, refresh_token):
    cur = mysql.connection.cursor()
    cur.execute("UPDATE users1 SET ms_refresh_token=%s WHERE ID=%s", (refresh_token, user_id))
    mysql.connection.commit()

def load_refresh_token(user_id):
    cur = mysql.connection.cursor()
    cur.execute("SELECT ms_refresh_token FROM users1 WHERE ID=%s", (user_id,))
    row = cur.fetchone()
    return row["ms_refresh_token"] if row and row["ms_refresh_token"] else None

@app.route("/ms-auth/start")
def ms_auth_start():
    if "username" not in session:
        return redirect(url_for("welcome_page"))

    auth_url = build_msal_app().get_authorization_request_url(
        scopes=MS_SCOPES,
        redirect_uri=MS_REDIRECT_URI,
        state=session["username"]
    )
    return redirect(auth_url)


@app.route("/ms-auth/redirect")
def ms_auth_redirect():
    error = request.args.get("error")
    if error:
        return f"Microsoft auth error: {error}", 400

    code = request.args.get("code")
    state = request.args.get("state")  # we set it to username
    if not code or not state:
        return "Missing code/state", 400

    app_msal = build_msal_app()
    result = app_msal.acquire_token_by_authorization_code(
        code=code,
        scopes=MS_SCOPES,
        redirect_uri=MS_REDIRECT_URI
    )

    if "error" in result:
        return f"Token error: {result.get('error_description')}", 400

    # Persist refresh_token
    user = get_user_row_by_username(state)
    if not user:
        return "User not found", 404

    refresh_token = result.get("refresh_token")
    if refresh_token:
        save_refresh_token(user["ID"], refresh_token)

    session["ms_access_token"] = result.get("access_token")
    session["ms_token_expires_at"] = int(dt.datetime.utcnow().timestamp()) + int(result.get("expires_in", 3600))

    return redirect(url_for("index", ms_connected="true"))

def ensure_graph_access_token():
    """Return a valid access token for Microsoft Graph, refreshing if needed."""
    now = int(dt.datetime.utcnow().timestamp())
    if session.get("ms_access_token") and now < session.get("ms_token_expires_at", 0) - 60:
        return session["ms_access_token"]

    user_id = session.get("ID")
    rt = load_refresh_token(user_id)
    if not rt:
        return None

    app_msal = build_msal_app()
    result = app_msal.acquire_token_by_refresh_token(rt, scopes=MS_SCOPES)
    if "error" in result:
        save_refresh_token(user_id, None)
        session.pop("ms_access_token", None)
        return None

    session["ms_access_token"] = result["access_token"]
    session["ms_token_expires_at"] = int(dt.datetime.utcnow().timestamp()) + int(result.get("expires_in", 3600))
    if "refresh_token" in result:
        save_refresh_token(user_id, result["refresh_token"])
    return session["ms_access_token"]

@app.route("/api/m365/meetings", methods=["GET"])
def api_m365_meetings():
    # Require user session (your app uses session["logged_in"])
    if "logged_in" not in session:
        return jsonify({"status": "error", "message": "not logged in"}), 403

    date_str = request.args.get("date")
    if not date_str:
        return jsonify({"status": "error", "message": "date param required (YYYY-MM-DD)"}), 400

    # Validate date
    try:
        year, month, day = map(int, date_str.split("-"))
        # Türkiye uses UTC+3 year-round; use local wall-clock day in Istanbul
        start_dt = f"{year:04d}-{month:02d}-{day:02d}T00:00:00+03:00"
        end_dt   = f"{year:04d}-{month:02d}-{day:02d}T23:59:59+03:00"
    except Exception:
        return jsonify({"status": "error", "message": "invalid date format (use YYYY-MM-DD)"}), 400

    # Get/refresh access token
    token = ensure_graph_access_token()
    if not token:
        # User hasn't connected Microsoft yet
        return jsonify({"status": "not_connected"}), 200

    headers = {
        "Authorization": f"Bearer {token}",
        # Ask Graph to return times in Istanbul zone for readability
        "Prefer": 'outlook.timezone="Europe/Istanbul"',
        "Accept": "application/json"
    }

    # calendarView expands recurrences across the window and returns instances
    url = f"{GRAPH_BASE}/me/calendarView"
    params = {
        "startDateTime": start_dt,
        "endDateTime": end_dt,
        "$orderby": "start/dateTime",
        "$top": 50  # page size; we’ll follow @odata.nextLink if present
    }

    meetings = []
    try:
        while True:
            resp = requests.get(url, headers=headers, params=params, timeout=20)
            if resp.status_code == 401:
                # Token likely expired; clear and try once
                session.pop("ms_access_token", None)
                token = ensure_graph_access_token()
                if not token:
                    return jsonify({"status": "not_connected"}), 200
                headers["Authorization"] = f"Bearer {token}"
                resp = requests.get(url, headers=headers, params=params, timeout=20)

            if not resp.ok:
                return jsonify({"status": "error", "message": resp.text}), 500

            data = resp.json()
            for ev in data.get("value", []):
                organizer = (ev.get("organizer") or {}).get("emailAddress", {}) or {}
                location  = (ev.get("location") or {}).get("displayName", "") or ""
                attendees = []
                for a in ev.get("attendees", []) or []:
                    email = (a.get("emailAddress") or {})
                    attendees.append({
                        "name": email.get("name", ""),
                        "email": email.get("address", ""),
                        "type": a.get("type", ""),  # required | optional | resource
                        "response": (a.get("status") or {}).get("response", ""),  # accepted/declined/tentative/none
                        "responseTime": (a.get("status") or {}).get("time", "")
                    })

                # Online meeting info (Teams, etc.)
                online = ev.get("isOnlineMeeting") is True or bool(ev.get("onlineMeeting"))
                join_url = (ev.get("onlineMeeting") or {}).get("joinUrl")

                meetings.append({
                    "id": ev.get("id"),
                    "subject": ev.get("subject") or "(No title)",
                    "start":  (ev.get("start") or {}).get("dateTime"),
                    "end":    (ev.get("end") or {}).get("dateTime"),
                    "allDay": bool(ev.get("isAllDay")),
                    "location": location,
                    "organizer": {
                        "name": organizer.get("name", ""),
                        "email": organizer.get("address", "")
                    },
                    "isOnlineMeeting": online,
                    "onlineMeetingProvider": ev.get("onlineMeetingProvider"),  # e.g., teamsForBusiness
                    "joinUrl": join_url,
                    "attendees": attendees,
                    "bodyPreview": ev.get("bodyPreview", ""),
                    "categories": ev.get("categories", [])
                })

            next_link = data.get("@odata.nextLink")
            if not next_link:
                break
            # For nextLink, pass absolute URL and clear params to avoid duplication
            url = next_link
            params = None

        return jsonify({"status": "ok", "date": date_str, "meetings": meetings})

    except requests.RequestException as e:
        return jsonify({"status": "error", "message": f"network error: {e}"}), 502
    except Exception as e:
        return jsonify({"status": "error", "message": f"server error: {e}"}), 500

