# Kullanıcı Giriş Decorator
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "logged_in" in session:
            return f(*args, **kwargs)

        next_url = request.full_path

        if next_url.endswith("?"):
            next_url = next_url[:-1]

        session["after_login_redirect"] = next_url

        return redirect(url_for("welcome_page"))

    return decorated_function

# Künye erişim yetki
def kunye_yetki(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if session.get("bolge360_kunye") == 1:
            return f(*args, **kwargs)
        else:
            return redirect(url_for("welcome_page"))
    return decorated_function

def username_required(f):
    @wraps(f)
    def decorated_function(username, *args, **kwargs):
        if "logged_in" not in session:
            return redirect(url_for("welcome_page"))
        if session.get("username") != username:
            return redirect(url_for("error_page"))
        return f(username, *args, **kwargs)
    return decorated_function

# Departman Kontrolü
def department_check(required_dept1, required_dept2=None):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            if session.get("departman") == required_dept1 or session.get("departman") == required_dept2:
                return f(*args, **kwargs)
            else:
                flash("Bu sayfayı görmek için yetkiniz yok", "danger")
                return redirect(url_for("index"))
        return decorated_function
    return decorator

@app.route('/get_reservation_number_and_office_status')
@login_required
def get_reservation_number_and_office_status():
    mysql_cursor = mysql.connection.cursor()

    office_q = """
        SELECT ofis_bayi
        FROM ofis_gunleri
        WHERE users1_id = %s AND selected_date = CURDATE();
    """
    mysql_cursor.execute(office_q, (session.get("ID"),))
    office_row = mysql_cursor.fetchone()

    if office_row:
        office_status = office_row["ofis_bayi"]
    else:
        office_status = None

    if office_status == "Ofis":
        office_status = "Ofisten Çalışma"
    elif office_status == "Bayi":
        office_status = "Bayi / Müşteri Ziyareti"
    elif office_status is None:
        office_status = "İzin"
    elif office_status == "Home":
        office_status = "Uzaktan Çalışma"

    charge_q = """
        SELECT *
        FROM sarj_istasyon_rezerve
        WHERE users1_id = %s
          AND rezerv_tarih = CURDATE()
          AND is_active=1;
    """
    mysql_cursor.execute(charge_q, (session.get("ID"),))
    charge_rows = mysql_cursor.fetchall() or []

    def normalize(v):
        import datetime
        if isinstance(v, (datetime.date, datetime.datetime)):
            return v.strftime("%Y-%m-%d %H:%M:%S") if isinstance(v, datetime.datetime) else v.strftime("%Y-%m-%d")
        return v

    charge_reservations = [
        {
            "ID": r.get("ID"),
            "username": r.get("username"),
            "name_surname": r.get("name_surname"),
            "plaka": r.get("plaka"),
            "istasyon_no": r.get("istasyon_no"),
            "rezerv_tarih": normalize(r.get("rezerv_tarih")),
            "rezerv_saat": r.get("rezerv_saat"),
            "is_active": int(r.get("is_active")) if r.get("is_active") is not None else None,
            "kullanilma_durumu": r.get("kullanilma_durumu"),
            "created_at": normalize(r.get("created_at")),
            "users1_id": r.get("users1_id"),
            "AC_DC": r.get("AC_DC"),
        }
        for r in charge_rows
    ]

    carwash_q = """
        SELECT plaka, rezerv_tarih
        FROM arac_yikama
        WHERE username = %s
          AND rezerv_tarih = CURDATE()
          AND (canceled_at IS NULL OR canceled_at = '0000-00-00 00:00:00');
    """
    mysql_cursor.execute(carwash_q, (session.get("username"),))
    carwash_rows = mysql_cursor.fetchall() or []

    carwash_reservations = [
        {
            "plaka": r.get("plaka"),
            "rezerv_tarih": normalize(r.get("rezerv_tarih")),
        }
        for r in carwash_rows
    ]

    mysql_cursor.close()

    conn = pyodbc.connect(YA_2El_AracSatis)
    mssql_cursor = conn.cursor()

    ms_sql_query = """
        SELECT [plaka], [rezerv_park_no]
        FROM [Yuce_Portal].[dbo].[YA_otopark]
        WHERE CAST(rezerv_tarih AS DATE) = CAST(GETDATE() AS DATE)
          AND [username] = ?
          AND [is_active] = 1;
    """
    nam_surnam = f"{session.get('name')} {session.get('surname')}"
    mssql_cursor.execute(ms_sql_query, (nam_surnam,))
    reservation_result = mssql_cursor.fetchone()

    reservation_number = reservation_result.rezerv_park_no if reservation_result else None

    mssql_cursor.close()
    conn.close()

    return jsonify({"office_status": office_status, "reservation_number": reservation_number, "charge_reservations": charge_reservations, "carwash_reservations": carwash_reservations})

