@app.route("/bayi_login_api", methods=["GET", "POST"])
def bayi_login_api():
    if request.method == "POST":
        data = request.get_json()
        username = data.get('mail')
        password_entered = data.get('password')

        cursor, conn = Connectdb_N_Return_cursorNconn(YA_2El_AracSatis)

        # JOIN bayii_users + Bayiiler, only active bayi (b.isActive = 1)
        query = """
            SELECT 
                u.id,                      -- 0
                u.email,                   -- 1
                u.[password],              -- 2
                u.[status],                -- 3
                u.namee,                   -- 4
                u.surnamee,                -- 5
                u.bayiisi_ID,              -- 6
                u.last_loginDate,          -- 7
                u.yetkiler,                -- 8
                u.garanti_imha_bayiisi_id, -- 9
                b.dealerName,              -- 10
                b.isActive,                -- 11
                b.YS_code,                 -- 12
                b.dealerName_Turkuaz       -- 13
            FROM YA_2El_AracSatis.dbo.bayii_users u
            INNER JOIN YA_2El_AracSatis.dbo.Bayiiler b
                ON u.bayiisi_ID = b.ID
            WHERE u.email = ?
              AND b.isActive = 1
        """
        cursor.execute(query, (username,))
        row = cursor.fetchone()

        # Check if user exists
        userExists = row is not None

        # row[3] = u.status, row[11] = b.isActive (already filtered to 1, but we can double-check)
        if userExists and row[3] == 1 and row[11] == 1:
            real_password_sha = row[2]

            if sha256_crypt.verify(password_entered, real_password_sha):
                # User is valid, set session
                session["logged_in"] = True
                session["email"] = row[1]
                session["name"] = row[4]
                session["surname"] = row[5]
                session["Bayiisi_ID"] = row[6]
                session["yetkiler"] = row[8]
                session["username"] = "Skoda"

                if row[9]:
                    session["garantiimha_bayiisi_id"] = row[9]

                # From Bayiiler
                session["bayi_adi"] = row[10]                 # dealerName
                session["YS_code"] = row[12]                  # NEW
                session["dealerName_Turkuaz"] = row[13]       # NEW

                session["ID"] = row[0]
                session["departman"] = "-"
                session["superuser"] = 0
                session["YA_user"] = False

                # Update last login date
                login_date = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                update_query = """
                    UPDATE [YA_2El_AracSatis].[dbo].[bayii_users]
                    SET last_loginDate = ?
                    WHERE email = ?
                """
                cursor.execute(update_query, (login_date, username))
                conn.commit()

                print(session)

                return jsonify({"status": "success", "message": "Başarıyla giriş yapıldı"}), 200
            else:
                # Invalid password
                return jsonify({"status": "error", "message": "Mail adresiniz veya Şifreniz hatalı"}), 400
        else:
            # Invalid email, inactive user, or bayi not active
            return jsonify({"status": "error", "message": "Girdiğiniz bilgiler hatalıdır.<br>Lütfen tekrar deneyiniz."}), 400

