@app.before_request
def check_session_timeout():
    if "login_timestamp" in session:
        login_timestamp = datetime.datetime.strptime(session["login_timestamp"], "%Y-%m-%d %H:%M:%S")
        current_time = datetime.datetime.now()
        time_difference = current_time - login_timestamp
        if time_difference >= timedelta(hours=14):
            # Session has expired; clear the session
            session.clear()

