            form.Yemek2.data = row.yemek2
            form.Yemek3.data = row.yemek3
            form.Yemek4.data = row.yemek4
            form.Yemek5.data = row.yemek5
            form.Yemek6.data = row.yemek6
            form.Not.data = row.notlar

