@app.route("/api/kafeterya_siparis_ekle", methods=["POST"])
@login_required
def api_kafeterya_siparis_ekle():
    from decimal import Decimal, ROUND_HALF_UP
    data = request.get_json(force=True)
    tarih = data.get("tarih")
    items = data.get("items", [])
    toplam_client = Decimal(str(data.get("tutar", 0)))

    # 🔹 SİPARİŞ NOTU BURADA ALINIYOR
    siparis_notu = (data.get("notlar") or "").strip()

    if not tarih or not items:
        return jsonify({"success": False, "message": "Eksik veri."}), 400

    kullanici_id = session.get("ID")
    kullanici_username = session.get("username")
    ad = session.get("name")
    soyad = session.get("surname")
    adsoyad = f"{ad} {soyad}".strip()
    if not kullanici_id:
        return jsonify({"success": False, "message": "Kullanıcı oturumu bulunamadı."}), 401

    toplam_server = Decimal("0")
    norm_items = []
    for it in items:
        qty = int(it.get("qty") or 0)
        price = Decimal(str(it.get("unit_price") or 0))
        name = (it.get("name") or "").strip()
        if not name or qty <= 0:
            continue
        toplam_server += price * qty
        norm_items.append({"id": it.get("id"), "name": name, "qty": qty, "unit_price": price})

    if not norm_items:
        return jsonify({"success": False, "message": "Sepet boş."}), 400

    conn = pyodbc.connect(YA_2El_AracSatis)
    try:
        conn.autocommit = False
        cur = conn.cursor()

        # 🔹 Notlar kolonu INSERT'e eklendi
        cur.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[Kafeterya_Siparis]
              ([KullaniciID], [KullaniciUsername], [AdSoyad],
               [SiparisTarih], [ToplamTutar], [ParaBirimi], [Durum], [Notlar], [CreatedBy])
            OUTPUT INSERTED.SiparisID
            VALUES (?, ?, ?, CONVERT(date, ?), ?, 'TRY', 'pending', ?, ?)
        """, (
            kullanici_id,
            kullanici_username,
            adsoyad,
            tarih,
            float(toplam_server),
            siparis_notu,        # 🔹 BURADA DB'YE GİDİYOR
            kullanici_username
        ))
        siparis_id = int(cur.fetchval())

        for it in norm_items:
            sira  = int(it.get("id") or 0) or None
            urun_adi = it["name"]
            adet  = it["qty"]
            birim_fiyat = float(it["unit_price"])
            cur.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[Kafeterya_SiparisKalemleri]
                  ([SiparisID], [MenuDate], [MenuItemSira], [MenuItemID],
                   [UrunAdi], [BirimFiyat], [Adet])
                VALUES (?, CONVERT(date, ?), ?, NULL, ?, ?, ?)
            """, (siparis_id, tarih, sira, urun_adi, birim_fiyat, adet))

        conn.commit()

        flash(f"Siparişiniz alındı. Sipariş No: #{siparis_id}", "success")

        return jsonify({
            "success": True,
            "siparis_id": siparis_id,
            "redirect": url_for("kafeterya_siparislerim")
        })
    except Exception as e:
        conn.rollback()
        return jsonify({"success": False, "message": str(e)})
    finally:
        conn.close()

@app.route("/kafeterya_siparislerim", methods=["GET", "POST"])
@login_required
def kafeterya_siparislerim():
    from datetime import datetime, date, time
    def is_cancellable_row(siparis_tarih: date, durum: str) -> bool:
        if (durum or "").lower() == "cancelled":
            return False
        now_local = datetime.now()
        today = now_local.date()

        if siparis_tarih > today:
            return True                      # future -> always cancellable
        if siparis_tarih < today:
            return False                     # past -> never cancellable
        # same day
        return now_local.time() < time(13, 0, 0)

    kullanici_id = session.get("ID")
    if not kullanici_id:
        flash("Kullanıcı oturumu bulunamadı.", "danger")
        return redirect(url_for("kafeterya_siparis_ver"))

    # --- POST: İPTAL ---
    if request.method == "POST":
        siparis_id = request.form.get("siparis_id", type=int)
        if not siparis_id:
            msg = "Geçersiz istek."
            if request.headers.get("X-Requested-With") == "XMLHttpRequest":
                return jsonify({"success": False, "message": msg}), 400
            flash(msg, "warning")
            return redirect(url_for("kafeterya_siparislerim"))

        conn = pyodbc.connect(YA_2El_AracSatis)
        cur = conn.cursor()
        try:
            # Sipariş sana mı ait, kural uygun mu?
            cur.execute("""
                SELECT CONVERT(date, SiparisTarih) AS Tarih, Durum
                FROM [Yuce_Portal].[dbo].[Kafeterya_Siparis]
                WHERE SiparisID = ? AND KullaniciID = ?
            """, siparis_id, kullanici_id)
            row = cur.fetchone()
            if not row:
                msg = "Sipariş bulunamadı."
                if request.headers.get("X-Requested-With") == "XMLHttpRequest":
                    return jsonify({"success": False, "message": msg}), 404
                flash(msg, "warning")
                return redirect(url_for("kafeterya_siparislerim"))

            sip_tarih = row.Tarih
            durum = row.Durum or "pending"

            if not is_cancellable_row(sip_tarih, durum):
                msg = "Bu sipariş için iptal edilemez (geçmiş gün) veya iptal süresi dolmuş (bugün 13:00 sonrası)."
                if request.headers.get("X-Requested-With") == "XMLHttpRequest":
                    return jsonify({"success": False, "message": msg}), 400
                flash(msg, "warning")
                return redirect(url_for("kafeterya_siparislerim"))

            cur.execute("""
                UPDATE [Yuce_Portal].[dbo].[Kafeterya_Siparis]
                SET Durum = 'cancelled'
                WHERE SiparisID = ? AND KullaniciID = ? AND Durum <> 'cancelled'
            """, siparis_id, kullanici_id)
            conn.commit()

            msg = f"Sipariş #{siparis_id} iptal edildi."
            if request.headers.get("X-Requested-With") == "XMLHttpRequest":
                return jsonify({"success": True, "message": msg})
            flash(msg, "success")
        except Exception as e:
            conn.rollback()
            if request.headers.get("X-Requested-With") == "XMLHttpRequest":
                return jsonify({"success": False, "message": str(e)}), 500
            flash(f"Hata: {e}", "danger")
        finally:
            cur.close()
            conn.close()

        return redirect(url_for("kafeterya_siparislerim"))

    show_all = request.args.get("show_all", "0") == "1"
    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    try:
        base_sql = f"""
            SELECT
                s.SiparisID,
                s.ToplamTutar,
                CONVERT(date, s.SiparisTarih) AS SiparisTarih,
                s.Durum,
                STRING_AGG(CONCAT(k.Adet, 'x ', k.UrunAdi), ', ') WITHIN GROUP (ORDER BY k.KalemID) AS UrunIsimleri
            FROM [Yuce_Portal].[dbo].[Kafeterya_Siparis] s
            JOIN [Yuce_Portal].[dbo].[Kafeterya_SiparisKalemleri] k
              ON k.SiparisID = s.SiparisID
            WHERE s.KullaniciID = ?
              {" " if show_all else "AND s.Durum <> 'cancelled' "}
            GROUP BY s.SiparisID, s.ToplamTutar, CONVERT(date, s.SiparisTarih), s.Durum
            ORDER BY SiparisTarih DESC, s.SiparisID DESC
        """
        cur.execute(base_sql, kullanici_id)
        rows = cur.fetchall()
    finally:
        cur.close()
        conn.close()

    today_d = datetime.now().date()
    siparisler = []
    for r in rows:
        sip_tarih = r.SiparisTarih
        durum = r.Durum or "pending"
        siparisler.append({
            "siparis_id": int(r.SiparisID),
            "tutar": float(r.ToplamTutar),
            "siparis_tarihi": sip_tarih.strftime("%d.%m.%Y"),
            "urun_ismi_listesi": r.UrunIsimleri or "",
            "durum": durum,
            "cancellable": is_cancellable_row(sip_tarih, durum),
            "is_past": sip_tarih < today_d,                 # sadece görsel silik için
            "is_cancelled": (durum.lower() == "cancelled")
        })

    if request.headers.get("X-Requested-With") == "XMLHttpRequest":
        return jsonify(siparisler)

    return render_template("kafeterya_siparislerim.html", siparisler=siparisler, show_all=show_all)

@app.route("/kafeterya_tum_siparisler", methods=["GET", "POST"])
@login_required
def kafeterya_tum_siparisler():
    from datetime import datetime, date, timedelta

    def get_cnx():
        return pyodbc.connect(YA_2El_AracSatis)

    # ---- İptal kuralı ----
    def cutoff_dt_for(order_date: date) -> datetime:
        # sipariş tarihinden 1 gün önce 13:00
        return datetime.combine(order_date - timedelta(days=1), datetime.min.time()).replace(
            hour=13, minute=0, second=0, microsecond=0
        )

    def is_cancellable(now_dt: datetime, order_date: date, is_cancelled: bool) -> bool:
        if is_cancelled:
            return False
        return now_dt < cutoff_dt_for(order_date)

    def is_past_cutoff(now_dt: datetime, order_date: date) -> bool:
        return now_dt > cutoff_dt_for(order_date)

    # ---- Veri erişimi ----
    def fetch_all_orders(include_cancelled: bool, only_date: date | None, current_username: str):
        """
        Template / AJAX için döner:
          {
            siparis_id, owner_username, owner_adsoyad,
            urun_ismi_listesi, tutar, para_birimi,
            siparis_tarihi (date), is_cancelled, is_past, cancellable,
            notlar
          }
        """
        cnx = get_cnx()
        cur = cnx.cursor()

        sql = """
            SELECT
                s.SiparisID,
                s.KullaniciUsername,
                s.AdSoyad,
                s.ToplamTutar,
                s.ParaBirimi,
                s.Durum,
                s.SiparisTarih,              -- datetime olarak kalsın
                CAST(s.SiparisTarih AS date) AS SiparisTarihiDateOnly,
                s.CreatedAt,
                s.Notlar                     -- 🔹 NOTLAR EKLENDİ
            FROM [Yuce_Portal].[dbo].[Kafeterya_Siparis] AS s
            WHERE 1=1
        """
        params = []

        if not include_cancelled:
            sql += " AND (s.Durum IS NULL OR s.Durum NOT IN ('cancelled','iptal','canceled'))"

        # ✅ Sağlam tarih filtresi: [gün başı, ertesi gün başı)
        if only_date is not None:
            start_dt = datetime.combine(only_date, datetime.min.time())
            end_dt = datetime.combine(only_date + timedelta(days=1), datetime.min.time())
            sql += " AND s.SiparisTarih >= ? AND s.SiparisTarih < ?"
            params.extend([start_dt, end_dt])

        sql += " ORDER BY s.SiparisTarih DESC, s.SiparisID DESC"

        cur.execute(sql, params)
        orders = cur.fetchall()

        if not orders:
            cur.close()
            cnx.close()
            return []

        order_ids = [r.SiparisID for r in orders]
        qmarks = ",".join("?" for _ in order_ids)

        # Kalemleri sırayla çek → Adet'i dahil et
        cur.execute(f"""
            SELECT k.SiparisID, k.UrunAdi, k.MenuItemSira, k.Adet
            FROM [Yuce_Portal].[dbo].[Kafeterya_SiparisKalemleri] AS k
            WHERE k.SiparisID IN ({qmarks})
            ORDER BY k.SiparisID, k.MenuItemSira
        """, order_ids)
        items = cur.fetchall()

        items_by_order = {}
        for it in items:
            adet = int(it.Adet or 1)
            label = f"{it.UrunAdi} x{adet}" if adet > 1 else it.UrunAdi
            items_by_order.setdefault(it.SiparisID, []).append(label)

        now_dt = datetime.now()
        out = []
        for r in orders:
            order_date_only = r.SiparisTarihiDateOnly  # date
            durum = (r.Durum or "").lower().strip()
            cancelled = durum in ("cancelled", "canceled", "iptal")

            user_can_cancel = (r.KullaniciUsername == current_username) and is_cancellable(
                now_dt, order_date_only, cancelled
            )

            out.append({
                "siparis_id": r.SiparisID,
                "owner_username": r.KullaniciUsername,
                "owner_adsoyad": r.AdSoyad,
                "urun_ismi_listesi": " + ".join(items_by_order.get(r.SiparisID, [])),
                "tutar": float(r.ToplamTutar or 0),
                "para_birimi": r.ParaBirimi or "TRY",
                "siparis_tarihi": order_date_only,
                "is_cancelled": cancelled,
                "is_past": is_past_cutoff(now_dt, order_date_only),
                "cancellable": user_can_cancel,
                "notlar": r.Notlar or ""      # 🔹 NOTLAR ARTIK DICT İÇİNDE
            })

        cur.close()
        cnx.close()
        return out

    def cancel_order_for_user(username: str, siparis_id: int) -> bool:
        """Sipariş, aynı kullanıcıya aitse ve cutoff geçmediyse iptal et."""
        cnx = get_cnx()
        cur = cnx.cursor()
        cur.execute("""
            SELECT SiparisID, KullaniciUsername, Durum, CAST(SiparisTarih AS date) AS SiparisTarihi
            FROM [Yuce_Portal].[dbo].[Kafeterya_Siparis]
            WHERE SiparisID = ?
        """, (siparis_id,))
        row = cur.fetchone()
        if not row:
            cur.close()
            cnx.close()
            return False
        if row.KullaniciUsername != username:
            cur.close()
            cnx.close()
            return False

        durum = (row.Durum or "").lower().strip()
        if durum in ("cancelled", "canceled", "iptal"):
            cur.close()
            cnx.close()
            return False

        if not is_cancellable(datetime.now(), row.SiparisTarihi, False):
            cur.close()
            cnx.close()
            return False

        cur.execute("""
            UPDATE [Yuce_Portal].[dbo].[Kafeterya_Siparis]
            SET Durum = 'cancelled'
            WHERE SiparisID = ? AND KullaniciUsername = ?
        """, (siparis_id, username))
        cnx.commit()
        cur.close()
        cnx.close()
        return True

    # ---------- controller ----------
    current_username = session.get("username")
    if not current_username:
        abort(401)

    # POST => iptal denemesi
    if request.method == "POST":
        try:
            siparis_id = int(request.form.get("siparis_id", "0"))
        except ValueError:
            siparis_id = 0
        ok = cancel_order_for_user(current_username, siparis_id)
        flash("Sipariş iptal edildi." if ok else "İptal işlemi yapılamadı.", "success" if ok else "warning")
        return redirect(url_for("kafeterya_tum_siparisler"))

    # GET => liste (filtrelerle)
    show_all = request.args.get("show_all", "0") == "1"
    only_date = None
    if request.args.get("date"):
        try:
            only_date = datetime.strptime(request.args["date"], "%Y-%m-%d").date()
        except ValueError:
            only_date = None

    siparisler = fetch_all_orders(include_cancelled=show_all, only_date=only_date, current_username=current_username)

    # AJAX -> tabloyu client'ta yeniden kurmak için JSON
    if request.headers.get("X-Requested-With") == "XMLHttpRequest":
        return jsonify([
            {
                "siparis_id": s["siparis_id"],
                "owner_username": s["owner_username"],
                "owner_adsoyad": s.get("owner_adsoyad"),
                "urun_ismi_listesi": s["urun_ismi_listesi"],
                "tutar": s["tutar"],
                "siparis_tarihi": s["siparis_tarihi"].strftime("%Y-%m-%d"),
                "is_cancelled": s["is_cancelled"],
                "is_past": s["is_past"],
                "cancellable": s["cancellable"],
                "notlar": s["notlar"],   # 🔹 JSON CEVABINDA DA VAR
            } for s in siparisler
        ])

    # Normal render
    return render_template("kafeterya_tum_siparisler.html", siparisler=siparisler, show_all=show_all)

@app.route("/user_profile_view/<string:username>", methods=["GET"])
@login_required
def userProfileView(username):
    cursor = mysql.connection.cursor()
    query = "SELECT * FROM users1 WHERE username = %s AND is_active = 1;"
    cursor.execute(query, (username,))
    user = cursor.fetchone()

    if not user:
        return "User not found", 404

    if user["dogum_ay"]:
        user["dogum_ay"] = month_number_to_name(int(user["dogum_ay"]))
    if user["Kidem_Tarihi"]:
        user["Kidem_Tarihi"] = user["Kidem_Tarihi"].strftime("%d.%m.%Y")
    if user["arac_plaka2"]:
        user["plaka"] += ", " + user["arac_plaka2"]

    today = datetime.datetime.now().date()
    query_ofis_bayi = """
        SELECT ofis_bayi 
        FROM ofis_gunleri 
        WHERE users1_id = %s AND selected_date = %s 
        ORDER BY selected_date DESC 
        LIMIT 1
    """
    cursor.execute(query_ofis_bayi, (user["ID"], today))
    ofis_bayi_result = cursor.fetchone()
    user["ofis_bayi_status"] = ofis_bayi_result["ofis_bayi"] if ofis_bayi_result else "Bilinmiyor"

    # Get other users in same department
    user_dept = user["departman"]
    query_same_dept = """
        SELECT *
        FROM users1 
        WHERE departman = %s AND username != %s AND is_active = 1
    """
    cursor.execute(query_same_dept, (user_dept, username))
    same_dept_users = cursor.fetchall()

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor2 = conn.cursor()
    query_rozet = f"""
        SELECT [id], [rozet], [aciklama], [image_path], [assigned_to] 
        FROM [Yuce_Portal].[dbo].[Rozetler] 
        WHERE assigned_to = '{username}'
    """
    cursor2.execute(query_rozet)
    rozetler = cursor2.fetchall()

    if session.get("username") != 'dogao' and session.get("username") != 'sevvalo':
        Write_Log_ToDB(session.get("username"), "GET", f"/user_profile_view/{username}", 0)

    return render_template("user_profile_view.html", user=user, rozetler=rozetler, same_dept_users=same_dept_users)

