@app.route('/api/assignee_stats/<string:username>', methods=['GET'])
@login_required
def get_assignee_stats(username):
    #Board ID 26 bizim ITSP !
    jira = JIRA(
        server="https://skoda-yuce-auto.atlassian.net/",
        basic_auth=("d.ozkutuk@skoda.com.tr", Jira_API_KEY)
    )

    #assignee_account_name = request.args.get('assignee')
    if username == 'dogao':
        assignee_account_name = "Doğa Özkütük"
    elif username == 'sevvalo':
        assignee_account_name = "Şevval İpek Özçelik"
    elif username == 'cemc':
        assignee_account_name = "Cem Çolak"
    elif username == 'berkeb':
        assignee_account_name = "Berke Başara"
    
    
    board_id = request.args.get('board_id', default=26, type=int)

    if not assignee_account_name:
        return jsonify({'error': 'Missing assignee parameter'}), 400

    jql_query = f"""
        sprint in closedSprints() AND project = ITSP 
        AND status = Done AND assignee = '{assignee_account_name}'
        ORDER BY created DESC
    """
    start_at = 0
    max_results = 100
    total_estimate_seconds = 0
    count = 0
    while True:
        issues = jira.search_issues(jql_query, startAt=start_at, maxResults=max_results)
        if not issues:
            break
        for issue in issues:
            estimate = issue.fields.timeoriginalestimate or 0
            total_estimate_seconds += estimate
            count += 1
        if len(issues) < max_results:
            break
        start_at += max_results

    total_hours = total_estimate_seconds / 3600
    return jsonify({'assignee': assignee_account_name, 'issue_count': count, 'total_hours': round(total_hours, 1)})

@app.route('/api/get_calendar_days', methods=['POST'])
@login_required
def get_calendar_days():
    #try:
    data = request.json
    username = data.get('username')

    if not username:
        return jsonify({'status': 'error', 'message': 'Username is required'}), 400

    cursor = mysql.connection.cursor()

    cursor.execute("SELECT ID FROM users1 WHERE username = %s", (username,))
    row = cursor.fetchone()

    if not row:
        return jsonify({'status': 'error', 'message': 'User not found'}), 404

    user_id = row["ID"]

    cursor.execute("""
        SELECT selected_date, ofis_bayi 
        FROM ofis_gunleri 
        WHERE users1_id = %s
    """, (user_id,))
    records = cursor.fetchall()
    cursor.close()

    result = {
        'ofis': [],
        'home': [],
        'bayi': []
    }

    for row in records:
        selected_date = row['selected_date']
        status = row['ofis_bayi']

        if hasattr(selected_date, 'strftime'):
            date_str = selected_date.strftime('%Y-%m-%d')
        else:
            date_str = str(selected_date)

        status_clean = status.strip().lower()
        if status_clean == 'ofis':
            result['ofis'].append(date_str)
        elif status_clean == 'home':
            result['home'].append(date_str)
        elif status_clean == 'bayi':
            result['bayi'].append(date_str)

    Write_Log_ToDB(session.get("username"), "POST", "/api/get_calendar_days", 0, f"Calendar days fetched for {username}")

    return jsonify({'status': 'success', 'data': result})

    #except Exception as e:
    #    print(f"Error: {e}")
    #    return jsonify({'status': 'error', 'message': 'Failed to retrieve calendar data'})

