@app.route('/dashboardapi/logs_today')
def logs_today():
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    # Total logs today
    total_logs_query = """
        SELECT COUNT(*) 
        FROM [Yuce_Portal].[dbo].[YP_users_log] 
        WHERE CAST(RequestedDateTime AS DATE) = CAST(GETDATE() AS DATE)
    """
    cursor.execute(total_logs_query)
    total_logs = cursor.fetchone()[0]

    # Distinct user logins today (POST to '/')
    login_count_query = """
        SELECT COUNT(DISTINCT Username) 
        FROM [Yuce_Portal].[dbo].[YP_users_log]
        WHERE RequestType = 'POST' 
          AND RequestLink = '/' 
          AND CAST(RequestedDateTime AS DATE) = CAST(GETDATE() AS DATE)
    """
    cursor.execute(login_count_query)
    login_count = cursor.fetchone()[0]

    return jsonify({
        'logsToday': total_logs,
        'loginCountToday': login_count
    })

@app.route('/dashboardapi/login_counts_by_date')
@login_required
def login_counts_by_date():
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    query = """
        SET DATEFIRST 7;
        SELECT 
            CAST(RequestedDateTime AS DATE) AS LoginDate,
            COUNT(DISTINCT Username) AS LoginCount
        FROM [Yuce_Portal].[dbo].[YP_users_log]
        WHERE 
            RequestType = 'POST' 
            AND RequestLink = '/'
            AND DATEPART(WEEKDAY, RequestedDateTime) BETWEEN 2 AND 6
        GROUP BY CAST(RequestedDateTime AS DATE)
        ORDER BY LoginDate ASC
    """

    cursor.execute(query)
    rows = cursor.fetchall()

    # Format the results as a list of dictionaries
    result = [
        {'date': row.LoginDate.strftime('%d-%m-%Y'), 'login_count': row.LoginCount}
        for row in rows
    ]

    return jsonify(result)

@app.route('/dashboardapi/islem_counts_by_date')
def islem_counts_by_date():
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    query = """
        SELECT 
            CAST(RequestedDateTime AS DATE) AS LogDate,
            COUNT(*) AS IslemCount
        FROM [Yuce_Portal].[dbo].[YP_users_log]
        WHERE DATENAME(WEEKDAY, RequestedDateTime) NOT IN ('Saturday', 'Sunday')
        GROUP BY CAST(RequestedDateTime AS DATE)
        ORDER BY LogDate ASC
    """

    cursor.execute(query)
    rows = cursor.fetchall()

    result = [
        {'date': row.LogDate.strftime('%d-%m-%Y'), 'islem_count': row.IslemCount}
        for row in rows
    ]

    return jsonify(result)

@app.route("/api/search/people", methods=["GET"])
@login_required
def api_search_people():
    q = (request.args.get("q") or "").strip()
    if len(q) < 2:
        return jsonify({"ok": True, "items": []})

    limit = request.args.get("limit", 12, type=int)
    limit = max(1, min(limit, 30))

    like = f"%{q}%"
    starts_like = f"{q}%"

    sql = """
        SELECT
            ID,
            username,
            name,
            surname,
            departman,
            email,
            plaka,
            kisa_kod
        FROM users1
        WHERE (is_active IS NULL OR is_active = 1)
          AND (
                username LIKE %s OR
                name LIKE %s OR
                surname LIKE %s OR
                CONCAT(name,' ',surname) LIKE %s OR
                departman LIKE %s OR
                email LIKE %s OR
                plaka LIKE %s OR
                CAST(kisa_kod AS CHAR) LIKE %s OR
                SOUNDEX(name) = SOUNDEX(%s) OR
                SOUNDEX(surname) = SOUNDEX(%s)
          )
        ORDER BY
            CASE
                WHEN username = %s THEN 0
                WHEN CONCAT(name,' ',surname) = %s THEN 1
                WHEN CAST(kisa_kod AS CHAR) = %s THEN 2
                WHEN username LIKE %s THEN 3
                WHEN CONCAT(name,' ',surname) LIKE %s THEN 4
                WHEN CAST(kisa_kod AS CHAR) LIKE %s THEN 5
                ELSE 6
            END,
            ID DESC
        LIMIT %s
    """

    params = (
        like, like, like, like, like, like, like, like,
        q, q,
        q, q, q, starts_like, like, starts_like,
        limit
    )

    try:
        myc = mysql.connection.cursor()
        myc.execute(sql, params)
        rows = myc.fetchall() or []

        items = []
        for r in rows:
            uname = (r.get("username") or "").strip()
            full = f"{(r.get('name') or '').strip()} {(r.get('surname') or '').strip()}".strip()

            items.append({
                "id": r.get("ID"),
                "username": uname,
                "name": full,
                "departman": r.get("departman"),
                "email": r.get("email"),
                "plaka": r.get("plaka"),
                "kisa_kod": r.get("kisa_kod"),
                "profile_url": f"/user_profile_view/{uname}" if uname else None,
                "photo_url": f"/static/users_card_photos/{uname}.jpg" if uname else None
            })

        return jsonify({"ok": True, "items": items})

    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

@app.route("/api/search/dealers", methods=["GET"])
@login_required
def api_search_dealers():
    q = (request.args.get("q") or "").strip()
    if len(q) < 2:
        return jsonify({"ok": True, "items": []})

    limit = request.args.get("limit", 12, type=int)
    limit = max(1, min(limit, 30))
    like = f"%{q.upper()}%"

    username = "USR_YUCE_DOGANO"
    userpwd = "qxBhjm0rUA"
    host = "10.113.197.4"
    port = 1521
    service_name = "DOTODWHDBP1"
    dsn = f"{username}/{userpwd}@{host}:{port}/{service_name}"

    try:
        oracle_conn = oracledb.connect(dsn)
        cur = oracle_conn.cursor()

        oracle_query = """
        SELECT *
        FROM (
            SELECT
                YS.FK_EDUCATION_FIRM_ID AS FIRM_ID,
                YS.FIRM_CODE,
                MAX(CASE WHEN DR.REGION_TYPE = 'S' THEN DRC.REGION_CHIEF_FULL_NAME END) AS SATIS_BOLGE,
                MAX(CASE WHEN DR.REGION_TYPE = 'L' THEN DRC.REGION_CHIEF_FULL_NAME END) AS SSH_BOLGE,
                CC.CITY_NAME AS CITY
            FROM YUCE_DM.TBL_DW_GEN_DIM_DEALER YS

            INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION DR
                ON YS.DEALER_ID = DR.FK_DEALER_ID
            AND DR.REGION_TYPE IN ('S','L')

            INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION_CHIEF DRC
                ON DRC.FK_REGION_DEALER_ID = DR.REGION_DEALER_ID

            INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM GEN_FIRM
                ON GEN_FIRM.EDUCATION_FIRM_ID = YS.FK_EDUCATION_FIRM_ID

            LEFT JOIN YUCE_DM.TBL_DW_GEN_DIM_CITY_COUNTY CC
                ON CC.CODE = YS.FK_CITY_CODE

            WHERE
                YS.STATUS_EXPLANATION = 'Yürürlükte'
                AND YS.FK_EDUCATION_FIRM_ID NOT IN (24992)
                AND YS.FIRM_CODE NOT IN ('YÜCE AUTO')
                AND (
                    UPPER(YS.FIRM_CODE) LIKE :p_like
                    OR UPPER(CC.CITY_NAME) LIKE :p_like
                )

            GROUP BY
                YS.FK_EDUCATION_FIRM_ID,
                YS.FIRM_CODE,
                CC.CITY_NAME

            ORDER BY
                YS.FIRM_CODE
        )
        WHERE ROWNUM <= :p_limit
        """

        cur.execute(oracle_query, {"p_like": like, "p_limit": limit})
        rows = cur.fetchall()

    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            cur.close()
            oracle_conn.close()
        except:
            pass

    # ---------- MSSQL: 2S / 3S / CITY STORE ----------
    conn_ba = pyodbc.connect(YA_2El_AracSatis)
    cursor_ba = conn_ba.cursor()
    cursor_ba.execute("""
        SELECT ys_code, S2, S3, City_Store
        FROM [YucePortal_Bolgesel].[dbo].[BayiBilgileri]
    """)
    bayi_rows = cursor_ba.fetchall()

    bayi_map = {
        str(r[0]).strip(): {
            "S2": bool(r[1]),
            "S3": bool(r[2]),
            "City_Store": bool(r[3])
        }
        for r in bayi_rows
    }

    items = []
    for r in rows:
        firm_id = str(r[0]).strip()
        firm_code = (r[1] or "").strip()

        flags = bayi_map.get(firm_id, {})
        badges = []
        if flags.get("S2"): badges.append("2S")
        if flags.get("S3"): badges.append("3S")
        if flags.get("City_Store"): badges.append("City Store")

        items.append({
            "firm_id": firm_id,
            "firm_code": firm_code,
            "city": r[4],
            "satis_bolge": r[2],
            "ssh_bolge": r[3],
            "badges": badges,
            "detail_url": f"/bayiler/{firm_id}"
        })

    return jsonify({"ok": True, "items": items})

def fetch_active_bayiler_from_mssql():
    connection = pyodbc.connect(YA_2El_AracSatis)
    cur = connection.cursor()

    sql = """
        SELECT [dealerName], [YS_code]
        FROM [YA_2El_AracSatis].[dbo].[Bayiiler]
        WHERE isActive = 1
        ORDER BY [dealerName]
    """
    cur.execute(sql)
    rows = cur.fetchall()

    cur.close()
    connection.close()

    out = []
    for r in rows:
        out.append({
            "dealerName": (r.dealerName or "").strip(),
            "YS_code": (str(r.YS_code).strip() if r.YS_code is not None else None)
        })
    return out

