@app.route("/haftalik_takvim", methods=["GET", "POST"])
@login_required
def haftalik_takvim():
    session_id = session.get('ID')
    user_name = session.get('username')
    departman = session.get("departman")

    import locale
    import datetime
    locale.setlocale(locale.LC_TIME, 'turkish')
    today = datetime.datetime.now()
    todayy = today.strftime("%d %B %Y")

    cursor = mysql.connection.cursor()

    cursor.execute("SELECT selected_date FROM ofis_gunleri WHERE users1_id = %s AND ofis_bayi = 'Ofis'", (session_id,))
    results = cursor.fetchall()

    cursor.execute("SELECT selected_date FROM ofis_gunleri WHERE users1_id = %s AND ofis_bayi = 'Bayi'", (session_id,))
    results_bayi = cursor.fetchall()

    cursor.execute("SELECT selected_date FROM ofis_gunleri WHERE users1_id = %s AND ofis_bayi = 'Home'", (session_id,))
    results_home = cursor.fetchall()

    # Office day counts (overall, department, bayi, home)
    cursor.execute("""
        SELECT selected_date, COUNT(users1_id) as user_count 
        FROM ofis_gunleri 
        WHERE ofis_bayi = 'Ofis'
        GROUP BY selected_date
    """)
    people_counts = cursor.fetchall()

    cursor.execute("""
        SELECT selected_date, COUNT(users1_id) as user_count 
        FROM ofis_gunleri 
        WHERE ofis_bayi = 'Ofis' AND Department = %s
        GROUP BY selected_date
    """, (departman,))
    people_counts_dept = cursor.fetchall()

    cursor.execute("""
        SELECT selected_date, COUNT(users1_id) as user_count 
        FROM ofis_gunleri 
        WHERE ofis_bayi = 'Bayi'
        GROUP BY selected_date
    """)
    people_counts_bayi = cursor.fetchall()

    cursor.execute("""
        SELECT selected_date, COUNT(users1_id) as user_count 
        FROM ofis_gunleri 
        WHERE ofis_bayi = 'Home'
        GROUP BY selected_date
    """)
    people_counts_home = cursor.fetchall()

    cursor.close()

    def fmt(date_obj):
        return f"{date_obj.year}-{date_obj.month}-{date_obj.day}"

    # Convert fetched data into dicts (key = "YYYY-M-D", value = count)
    people_count_by_date = {fmt(row['selected_date']): row['user_count'] for row in people_counts}
    people_counts_dept_dict = {fmt(row['selected_date']): row['user_count'] for row in people_counts_dept}
    people_counts_bayi_dict = {fmt(row['selected_date']): row['user_count'] for row in people_counts_bayi}
    people_counts_home_dict = {fmt(row['selected_date']): row['user_count'] for row in people_counts_home}

    saved_dates = [fmt(row['selected_date']) for row in results]
    saved_dates_bayi = [fmt(row['selected_date']) for row in results_bayi]
    saved_dates_home = [fmt(row['selected_date']) for row in results_home]

    user_name_surname = session.get('name') + " " + session.get('surname')
    try:
        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()
        cursor.execute("""
            SELECT rezerv_tarih FROM [Yuce_Portal].[dbo].[YA_otopark]
            WHERE username = ? AND is_active = 1
            ORDER BY created_at DESC
        """, (user_name_surname,))
        parking_rows = cursor.fetchall()
        cursor.close()
    except Exception as exc:
        print("Could not fetch parking reservations:", exc)
        parking_rows = []
        try:
            cursor.close()
        except:
            pass

    parking_dates = [fmt(row[0]) for row in parking_rows if row[0]]

    cursor = mysql.connection.cursor()
    cursor.execute("""
        SELECT rezerv_tarih
        FROM sarj_istasyon_rezerve
        WHERE users1_id = %s AND is_active = 1
        ORDER BY rezerv_tarih DESC
    """, (session.get("ID"),))
    charging_rows = cursor.fetchall()
    cursor.close()

    charging_dates = [fmt(row['rezerv_tarih']) for row in charging_rows if row['rezerv_tarih']]

    cursor = mysql.connection.cursor()
    cursor.execute("""
        SELECT rezerv_tarih
        FROM arac_yikama
        WHERE username = %s
        AND canceled_by IS NULL
        AND canceled_at IS NULL
        GROUP BY rezerv_tarih
        ORDER BY rezerv_tarih DESC
    """, (session.get("username"),))
    yikama_rows = cursor.fetchall()
    cursor.close()

    yikama_dates = [fmt(row['rezerv_tarih']) for row in yikama_rows if row['rezerv_tarih']]


    cursor = mysql.connection.cursor()
    cursor.execute("""
        SELECT selected_date
        FROM ofis_gunleri
        WHERE users1_id = %s AND NOTLAR IS NOT NULL AND NOTLAR <> ''
        GROUP BY selected_date
    """, (session_id,))
    note_rows = cursor.fetchall()
    cursor.close()

    def fmt(date_obj):
        return f"{date_obj.year}-{date_obj.month}-{date_obj.day}"

    note_dates = [fmt(r['selected_date']) for r in note_rows]

    cursor = mysql.connection.cursor()
    cursor.execute("""
        SELECT
            DATE_FORMAT(tarih, '%%Y-%%m-%%d') AS dt,
            COUNT(*) AS cnt
        FROM misafirler
        WHERE kimin_misafiri_username = %s
        GROUP BY DATE_FORMAT(tarih, '%%Y-%%m-%%d')
    """, (session.get("username"),))
    visitor_rows = cursor.fetchall() or []
    cursor.close()

    # JS tarafındaki key formatın: "YYYY-M-D" (zero-pad yok) → ona çeviriyoruz
    visitor_counts = {}
    for r in visitor_rows:
        dt = (r.get("dt") or "").strip()  # "2026-01-09"
        if not dt:
            continue
        y, m, d = dt.split("-")
        key = f"{int(y)}-{int(m)}-{int(d)}"  # "2026-1-9"
        visitor_counts[key] = int(r.get("cnt") or 0)

    return render_template("haftalik_takvim.html", saved_dates=saved_dates, saved_dates_bayi=saved_dates_bayi, saved_dates_home=saved_dates_home, people_count_by_date=people_count_by_date,
        people_counts_dept=people_counts_dept_dict, people_counts_bayi=people_counts_bayi_dict, people_counts_home=people_counts_home_dict, todayy=todayy,
        parking_dates=parking_dates, charging_dates=charging_dates, yikama_dates=yikama_dates, note_dates=note_dates, visitor_counts=visitor_counts)

@app.route('/ofis_gunleri/submit', methods=['POST'])
@login_required
def save_dates():
    try:
        data = request.json or {}
        session_id = session.get('ID')
        selected_dates = data.get('selected_dates') or []
        departman = session.get('departman')

        cursor = mysql.connection.cursor()

        for date in selected_dates:
            cursor.execute("""
                SELECT id FROM ofis_gunleri
                WHERE users1_id=%s AND selected_date=%s
                LIMIT 1
            """, (session_id, date))
            row = cursor.fetchone()

            if row:
                # ✅ Ofis'e çevriliyorsa: Bayi ve Bayi_kodu temizle
                cursor.execute("""
                    UPDATE ofis_gunleri
                    SET ofis_bayi='Ofis',
                        Bayi=NULL,
                        Bayi_kodu=NULL
                    WHERE id=%s
                """, (row['id'],))
            else:
                cursor.execute("""
                    INSERT INTO ofis_gunleri (users1_id, selected_date, ofis_bayi, Department)
                    VALUES (%s, %s, 'Ofis', %s)
                """, (session_id, date, departman))

        mysql.connection.commit()

        cursor.execute("""
            SELECT selected_date
            FROM ofis_gunleri
            WHERE users1_id=%s AND ofis_bayi='Ofis'
        """, (session_id,))
        updated_dates = cursor.fetchall()

        cursor.close()

        return jsonify({
            'status': 'success',
            'message': 'Dates saved successfully',
            'updated_dates': updated_dates
        })

    except Exception as e:
        print("Error:", e)
        return jsonify({'status': 'error', 'message': 'Failed to save dates'}), 500

