@app.route('/return/whoat/offce/or/bayi', methods=['POST'])
@login_required
def return_who_at_officeOrBayi():
    try:
        data = request.json or {}
        selected_date = data.get('selected_date')  # expected 'YYYY-MM-DD'
        if not selected_date:
            return jsonify({'status': 'error', 'message': 'selected_date is required (YYYY-MM-DD)'}), 400

        dpt = session.get("departman")
        user_id = session.get("ID")
        username = session.get("username")
        nam_surnam = f"{session.get('name')} {session.get('surname')}"

        # ---- MySQL part ------------------------------------------------------
        cursor = mysql.connection.cursor()

        # 1) Explicit selections: Ofis / Bayi / Home (for the selected date)
        explicit_sql = """
            SELECT
                u.username, u.name, u.surname, u.email, u.departman,
                o.selected_date, o.ofis_bayi,
                o.Bayi, o.Bayi_kodu
            FROM ofis_gunleri o
            INNER JOIN users1 u ON o.users1_id = u.ID
            WHERE o.selected_date = %s AND u.is_active = 1
            ORDER BY
                CASE WHEN u.departman = %s THEN 0 ELSE 1 END,
                u.username
        """
        cursor.execute(explicit_sql, (selected_date, dpt))
        results = cursor.fetchall() or []

        # ✅ NEW: Bayi olanlara parantezli bayi ismi alanı ekle
        # (DictCursor ise dict, değilse tuple olabilir)
        if results and isinstance(results[0], dict):
            for r in results:
                bayi_adi = (r.get("Bayi") or "").strip()
                if (r.get("ofis_bayi") == "Bayi") and bayi_adi:
                    r["bayi_name"] = bayi_adi               # "ALTUR"
                    r["bayi_paren"] = f"({bayi_adi})"       # "(ALTUR)"
                else:
                    r["bayi_name"] = None
                    r["bayi_paren"] = None

        # 2) "İzin" = users with NO row in ofis_gunleri for that date (and active)
        izin_sql = """
            SELECT
                u.username,
                u.name,
                u.surname,
                u.email,
                u.departman
            FROM users1 u
            WHERE u.is_active = 1
            AND u.departman <> 'Yönetim Kurulu'
            AND u.ID NOT IN (
                SELECT users1_id
                FROM ofis_gunleri
                WHERE selected_date = %s
                AND ofis_bayi IN ('Ofis','Bayi','Home')
            )
            ORDER BY
                CASE WHEN u.departman = %s THEN 0 ELSE 1 END,
                u.username
        """
        cursor.execute(izin_sql, (selected_date, dpt))
        izin_users = cursor.fetchall() or []

        # ---- Your personal status & reservations (for selected_date) ---------
        office_q = """
            SELECT ofis_bayi, Bayi, Bayi_kodu
            FROM ofis_gunleri
            WHERE users1_id = %s AND selected_date = %s
            ORDER BY FIELD(ofis_bayi,'Ofis','Bayi','Home','Note') ASC
            LIMIT 1
        """
        cursor.execute(office_q, (user_id, selected_date))
        office_row = cursor.fetchone()

        if office_row:
            if isinstance(office_row, dict):
                office_status_raw = office_row.get("ofis_bayi")
                my_bayi = office_row.get("Bayi")
                my_bayi_kodu = office_row.get("Bayi_kodu")
            else:
                office_status_raw = office_row[0]
                my_bayi = office_row[1] if len(office_row) > 1 else None
                my_bayi_kodu = office_row[2] if len(office_row) > 2 else None
        else:
            office_status_raw = None
            my_bayi = None
            my_bayi_kodu = None

        office_status_map = {
            "Ofis": "Ofisten Çalışma",
            "Bayi": "Bayi / Müşteri Ziyareti",
            "Home": "Uzaktan Çalışma",
            None:   "İzin"
        }
        office_status = office_status_map.get(office_status_raw, office_status_raw)

        # Charging reservations (for the selected date)
        charge_q = """
            SELECT *
            FROM sarj_istasyon_rezerve
            WHERE users1_id = %s
              AND rezerv_tarih = %s
              AND is_active = 1
        """
        cursor.execute(charge_q, (user_id, selected_date))
        charge_rows = cursor.fetchall() or []

        # Car wash reservations (for the selected date)
        carwash_q = """
            SELECT plaka, rezerv_tarih
            FROM arac_yikama
            WHERE username = %s
              AND rezerv_tarih = %s
              AND (canceled_at IS NULL OR canceled_at = '0000-00-00 00:00:00')
        """
        cursor.execute(carwash_q, (username, selected_date))
        carwash_rows = cursor.fetchall() or []

        def normalize(v):
            import datetime
            if isinstance(v, (datetime.date, datetime.datetime)):
                return v.strftime("%Y-%m-%d %H:%M:%S") if isinstance(v, datetime.datetime) else v.strftime("%Y-%m-%d")
            return v

        def getv(row, key, idx=None):
            if isinstance(row, dict):
                return row.get(key)
            if idx is not None and isinstance(row, (list, tuple)):
                return row[idx]
            return None

        charge_reservations = []
        for r in charge_rows:
            charge_reservations.append({
                "ID": getv(r, "ID"),
                "username": getv(r, "username"),
                "name_surname": getv(r, "name_surname"),
                "plaka": getv(r, "plaka"),
                "istasyon_no": getv(r, "istasyon_no"),
                "rezerv_tarih": normalize(getv(r, "rezerv_tarih")),
                "rezerv_saat": getv(r, "rezerv_saat"),
                "is_active": int(getv(r, "is_active")) if getv(r, "is_active") is not None else None,
                "kullanilma_durumu": getv(r, "kullanilma_durumu"),
                "created_at": normalize(getv(r, "created_at")),
                "users1_id": getv(r, "users1_id"),
                "AC_DC": getv(r, "AC_DC"),
            })

        carwash_reservations = []
        for r in carwash_rows:
            carwash_reservations.append({
                "plaka": getv(r, "plaka", 0),
                "rezerv_tarih": normalize(getv(r, "rezerv_tarih", 1)),
            })

        cursor.close()

        # ---- MSSQL part: parking reservation for selected_date ---------------
        import pyodbc
        conn = pyodbc.connect(YA_2El_AracSatis)
        mssql_cursor = conn.cursor()

        ms_sql_query = """
            SELECT [plaka], [rezerv_park_no]
            FROM [Yuce_Portal].[dbo].[YA_otopark]
            WHERE CAST(rezerv_tarih AS DATE) = CAST(? AS DATE)
              AND [username] = ?
              AND [is_active] = 1
        """
        mssql_cursor.execute(ms_sql_query, (selected_date, nam_surnam))
        reservation_result = mssql_cursor.fetchone()
        reservation_number = reservation_result.rezerv_park_no if reservation_result else None

        mssql_cursor.close()
        conn.close()

        Write_Log_ToDB(session.get("username"), "GET", "/return/whoat/offce/or/bayi", 0, f"{selected_date} is viewed")

        return jsonify({
            'status': 'success',
            'users': results,
            'izin_users': izin_users,
            'me': {
                'office_status': office_status,
                'reservation_number': reservation_number,
                'charge_reservations': charge_reservations,
                'carwash_reservations': carwash_reservations,
                'bayi': my_bayi,
                'bayi_kodu': my_bayi_kodu
            }
        })

    except Exception as e:
        print(f"Error: {e}")
        return jsonify({'status': 'error', 'message': 'Failed to retrieve attendance data'}), 500
    
@app.route('/api/daynote/save', methods=['POST'])
@login_required
def save_daynote():
    data = request.get_json(force=True)
    date_str   = data.get('date')
    note_text  = (data.get('text') or '').strip()
    user_id    = session.get('ID')
    departman  = session.get('departman')

    cur = mysql.connection.cursor()
    # o gün için kullanıcı satırı var mı? (Ofis/Bayi/Home/Note fark etmez)
    cur.execute("""
        SELECT id FROM ofis_gunleri
        WHERE users1_id=%s AND selected_date=%s
        ORDER BY FIELD(ofis_bayi,'Ofis','Bayi','Home','Note') ASC
        LIMIT 1
    """, (user_id, date_str))
    row = cur.fetchone()

    if row:
        cur.execute("UPDATE ofis_gunleri SET NOTLAR=%s WHERE id=%s", (note_text, row['id']))
    else:
        # yalnızca not için satır aç (sayım sorgularını etkilemez)
        cur.execute("""
            INSERT INTO ofis_gunleri (users1_id, selected_date, ofis_bayi, Department, NOTLAR)
            VALUES (%s, %s, 'Note', %s, %s)
        """, (user_id, date_str, departman, note_text))

    mysql.connection.commit()
    cur.close()
    return jsonify({'status': 'ok'})

