@app.route('/haftalik_takvim_misafir_ekle', methods=['POST'])
@login_required
def haftalik_takvim_misafir_ekle():
    data = request.json or {}

    session_id = session.get('ID')
    created_by_username = (session.get('username') or '').strip()
    created_by_fullname = (session.get('name_surname') or session.get('fullname') or '').strip()

    # Frontend'den gelebilecek alternatif key'ler
    tarih = (data.get('tarih') or data.get('date') or '').strip()
    isim = (data.get('isim') or data.get('name') or '').strip()

    kimin_username = (data.get('kimin_misafiri_username') or '').strip()
    kimin_fullname = (data.get('kimin_misafiri_name_surname') or data.get('kimin_misafiri') or '').strip()

    giris = (data.get('tahmini_giris_saati') or data.get('start') or '').strip()
    cikis = (data.get('tahmini_cikis_saati') or data.get('end') or '').strip()

    otopark = 1 if data.get('otopark') or data.get('park') else 0
    sarj    = 1 if data.get('sarj') or data.get('charge') else 0
    yemek   = 1 if data.get('yemek') or data.get('food') else 0
    ikram   = 1 if data.get('ikram') or data.get('snack') else 0

    aciklama = (data.get('aciklama') or '').strip()

    # Basit validasyon
    if not tarih:
        return jsonify({'status': 'error', 'message': 'tarih boş olamaz'}), 400
    if not isim:
        return jsonify({'status': 'error', 'message': 'isim boş olamaz'}), 400

    rec_id = (data.get('id') or '').strip()

    cursor = mysql.connection.cursor()

    if rec_id:
        # UPDATE
        sql = """
            UPDATE misafirler
            SET
                tarih=%s,
                isim=%s,
                kimin_misafiri_username=%s,
                kimin_misafiri_name_surname=%s,
                giris_saati=%s,
                cikis_saati=%s,
                otopark=%s,
                sarj=%s,
                yemek=%s,
                ikram=%s,
                aciklama=%s,
                updated_at=NOW()
            WHERE id=%s
        """
        cursor.execute(sql, (
            tarih, isim,
            kimin_username, kimin_fullname,
            giris, cikis,
            otopark, sarj, yemek, ikram,
            aciklama,
            rec_id
        ))
    else:
        # INSERT
        sql = """
            INSERT INTO misafirler
            (tarih, isim,
                kimin_misafiri_username, kimin_misafiri_name_surname,
                giris_saati, cikis_saati,
                otopark, sarj, yemek, ikram,
                aciklama,
                created_by_id, created_by_username, created_by_fullname,
                created_at, updated_at)
            VALUES
            (%s, %s,
                %s, %s,
                %s, %s,
                %s, %s, %s, %s,
                %s,
                %s, %s, %s,
                NOW(), NOW())
        """
        cursor.execute(sql, (
            tarih, isim,
            kimin_username, kimin_fullname,
            giris, cikis,
            otopark, sarj, yemek, ikram,
            aciklama,
            session_id, created_by_username, created_by_fullname
        ))

    mysql.connection.commit()
    cursor.close()

    return jsonify({'status': 'success', 'message': 'Misafir kaydedildi'})

@app.route("/api/visitors/delete", methods=["POST"])
@login_required
def api_visitors_delete():
    try:
        data = request.json or {}
        rec_id = str(data.get("id") or "").strip()
        if not rec_id:
            return jsonify({"ok": False, "error": "id boş olamaz"}), 400

        session_username = (session.get("username") or "").strip()
        if not session_username:
            return jsonify({"ok": False, "error": "session username yok"}), 400

        # ✅ sadece kendi misafirini silebilsin
        sql = """
            DELETE FROM misafirler
            WHERE id = %s
              AND kimin_misafiri_username = %s
        """

        cur = mysql.connection.cursor()
        cur.execute(sql, (rec_id, session_username))
        mysql.connection.commit()
        affected = cur.rowcount
        cur.close()

        if affected == 0:
            # id yok veya başka birinin misafiri
            return jsonify({"ok": False, "error": "Kayıt bulunamadı veya yetkiniz yok"}), 404

        return jsonify({"ok": True, "message": "Misafir silindi", "id": rec_id})

    except Exception as e:
        print("Error:", e)
        return jsonify({"ok": False, "error": str(e)}), 500

@app.route("/api/visitors/get", methods=["GET"])
@login_required
def api_visitors_get():
    date_key = (request.args.get("date") or "").strip()

    y, m, d = date_key.split("-")
    date_key = f"{int(y):04d}-{int(m):02d}-{int(d):02d}"

    session_username = session.get("username")

    print(date_key)

    sql = """
        SELECT
            id,
            DATE_FORMAT(tarih, '%%Y-%%m-%%d') AS tarih,
            isim,
            kimin_misafiri_username,
            kimin_misafiri_name_surname,
            TIME_FORMAT(giris_saati, '%%H:%%i') AS giris_saati,
            TIME_FORMAT(cikis_saati, '%%H:%%i') AS cikis_saati,
            otopark, sarj, yemek, ikram,
            aciklama
        FROM misafirler
        WHERE tarih = %s
        AND kimin_misafiri_username = %s
        ORDER BY id DESC
    """

    cur = mysql.connection.cursor()
    cur.execute(sql, (date_key, session_username))
    rows = cur.fetchall() or []
    cur.close()

    visitors = []
    for r in rows:
        visitors.append({
            "id": r.get("id"),
            "date": r.get("tarih"),
            "name": r.get("isim"),
            "host_username": r.get("kimin_misafiri_username"),
            "kimin_misafiri": r.get("kimin_misafiri_name_surname"),
            "start": r.get("giris_saati") or "",
            "end": r.get("cikis_saati") or "",
            "park": 1 if r.get("otopark") else 0,
            "charge": 1 if r.get("sarj") else 0,
            "food": 1 if r.get("yemek") else 0,
            "snack": 1 if r.get("ikram") else 0,
            "aciklama": r.get("aciklama") or ""
        })

    return jsonify({"ok": True, "visitors": visitors, "count": len(visitors)})

@app.route("/yuce_portal_log_kaydi", methods=["GET", "POST"])
@department_check("Bilgi Teknolojileri")
def portal_log_kaydi():
    page = int(request.args.get('page', 1))
    per_page = 100
    offset = (page - 1) * per_page

    username_filter = request.args.get('username', '').strip()
    requestedlink_filter = request.args.get('requestedlink', '').strip()
    date_from_filter = request.args.get('date_from', '').strip()
    date_to_filter = request.args.get('date_to', '').strip()

    exclude_username1 = request.args.get('exclude_username1', '').strip()
    exclude_username2 = request.args.get('exclude_username2', '').strip()
    exclude_username3 = request.args.get('exclude_username3', '').strip()

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    filters = []
    if username_filter:
        filters.append(f"[Username] LIKE '%{username_filter}%'")
    if requestedlink_filter:
        filters.append(f"[RequestLink] LIKE '%{requestedlink_filter}%'")
    if date_from_filter:
        filters.append(f"[RequestedDateTime] >= '{date_from_filter}'")
    if date_to_filter:
        filters.append(f"[RequestedDateTime] <= '{date_to_filter}'")
    if exclude_username1:
        filters.append(f"[Username] NOT LIKE '{exclude_username1}'")
    if exclude_username2:
        filters.append(f"[Username] NOT LIKE '{exclude_username2}'")
    if exclude_username3:
        filters.append(f"[Username] NOT LIKE '{exclude_username3}'")

    where_clause = " AND ".join(filters)
    if where_clause:
        where_clause = "WHERE " + where_clause

    total_query = f"SELECT COUNT(*) FROM [Yuce_Portal].[dbo].[YP_users_log] {where_clause}"
    cursor.execute(total_query)
    total_records = cursor.fetchone()[0]

    query = f"""
    WITH PaginatedLogs AS (
        SELECT [Username], [RequestType], [RequestLink], 
               FORMAT([RequestedDateTime], 'yyyy-MM-dd HH:mm:ss') AS RequestedDateTime,
               [ReturnCode], [details],
               ROW_NUMBER() OVER (ORDER BY RequestedDateTime DESC) AS RowNum
        FROM [Yuce_Portal].[dbo].[YP_users_log]
        {where_clause}
    )
    SELECT [Username], [RequestType], [RequestLink], [RequestedDateTime], [ReturnCode], [details]
    FROM PaginatedLogs
    WHERE RowNum BETWEEN {offset + 1} AND {offset + per_page}
    ORDER BY RowNum;
    """
    cursor.execute(query)
    logs = cursor.fetchall()

    log_list = [
        {
            "Username": row[0],
            "RequestType": row[1],
            "RequestLink": row[2],
            "RequestedDateTime": row[3],
            "ReturnCode": row[4],
            "Details": row[5],
        }
        for row in logs
    ]

    connection.close()

    total_pages = (total_records + per_page - 1) // per_page
    visible_pages = range(max(1, page - 2), min(total_pages + 1, page + 3))

    Write_Log_ToDB(session.get("username"), "GET", "/yuce_portal_log_kaydi", 0)
    return render_template("yuceportal_log_kaydi.html", logs=log_list, current_page=page, total_pages=total_pages, visible_pages=visible_pages, username=username_filter, requestedlink=requestedlink_filter, date_from=date_from_filter, date_to=date_to_filter, exclude_username1=exclude_username1, exclude_username2=exclude_username2, exclude_username3=exclude_username3)

@app.route("/api/yuce_portal_log_kaydi/new")
@login_required
@department_check("Bilgi Teknolojileri")
def check_new_logs():
    last_datetime_str = request.args.get("last_datetime")
    if not last_datetime_str:
        return jsonify([])

    try:
        last_datetime = datetime.datetime.strptime(last_datetime_str, "%Y-%m-%d %H:%M:%S")
    except ValueError:
        return jsonify([])

    username_filter = request.args.get('username', '').strip()
    requestedlink_filter = request.args.get('requestedlink', '').strip()
    date_from_filter = request.args.get('date_from', '').strip()
    date_to_filter = request.args.get('date_to', '').strip()
    exclude_username1 = request.args.get('exclude_username1', '').strip()
    exclude_username2 = request.args.get('exclude_username2', '').strip()
    exclude_username3 = request.args.get('exclude_username3', '').strip()

    filters = ["[RequestedDateTime] > ?"]
    params = [last_datetime]

    if username_filter:
        filters.append("[Username] LIKE ?")
        params.append(f"%{username_filter}%")
    if requestedlink_filter:
        filters.append("[RequestLink] LIKE ?")
        params.append(f"%{requestedlink_filter}%")
    if date_from_filter:
        filters.append("[RequestedDateTime] >= ?")
        params.append(date_from_filter)
    if date_to_filter:
        filters.append("[RequestedDateTime] <= ?")
        params.append(date_to_filter)
    if exclude_username1:
        filters.append("[Username] NOT LIKE ?")
        params.append(exclude_username1)
    if exclude_username2:
        filters.append("[Username] NOT LIKE ?")
        params.append(exclude_username2)
    if exclude_username3:
        filters.append("[Username] NOT LIKE ?")
        params.append(exclude_username3)

    where_clause = " AND ".join(filters)

    query = f"""
        SELECT TOP 20 [Username], [RequestType], [RequestLink], 
                     [RequestedDateTime], [ReturnCode], [details]
        FROM [Yuce_Portal].[dbo].[YP_users_log]
        WHERE {where_clause}
        ORDER BY [RequestedDateTime] DESC
    """

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    cursor.execute(query, params)
    logs = cursor.fetchall()
    connection.close()

    log_list = [
        {
            "Username": row[0],
            "RequestType": row[1],
            "RequestLink": row[2],
            "RequestedDateTime": row[3].strftime("%Y-%m-%d %H:%M:%S"),
            "ReturnCode": row[4],
            "Details": row[5],
        }
        for row in logs
    ]

    return jsonify(log_list)

