def send_notification(username, message, a_tag, image_path=None, subject=None, send_mail=True):
    cursor = mysql.connection.cursor()
    query = "SELECT ID, email, name, surname FROM users1 WHERE username = '{}'".format(username)
    cursor.execute(query)

    data = cursor.fetchone()
    user_id, receiver_email, name, surname = data["ID"], data["email"], data["name"], data["surname"]
    fullname = name + " " + surname

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()
    cursor.execute("""
        INSERT INTO [Yuce_Portal].[dbo].[notifications] 
        (user_id, user_username, message, a_tag, image_path, is_read, is_active, created_at)
        VALUES (?, ?, ?, ?, ?, 0, 1, GETDATE())
    """, (user_id, username, message, a_tag, image_path))
    conn.commit()

    content = message
    if subject == None:
        subject = "YücePortal'da Yeni Bir Bildiriminiz Var"
        message = f"""
            Sayın {fullname},<br>
            {message}<br>
            İyi çalışmalar.
        """
    
    if send_mail:
        send_email(content, subject, receiver_email, cc_email=None, sender_email='yuceportal@skoda.com.tr',login=None,password=None)

