    if not story_id:
        return jsonify({'viewers': []}), 400
    try:
        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()
        query = f"""
            SELECT [username], [view_datetime]
            FROM [Yuce_Portal].[dbo].[Story_viewsLog]
            WHERE [story_id] = {story_id}
            ORDER BY view_datetime DESC
        """
        cursor.execute(query)
        rows = cursor.fetchall()
        viewers = []
        for row in rows:
            viewers.append({
                "username": row.username,
                "view_datetime": row.view_datetime.strftime("%d.%m.%Y %H:%M")
            })
        return jsonify({'viewers': viewers})
    except Exception as e:
        print("Error fetching viewers:", e)
        return jsonify({'viewers': []}), 500
    finally:
        cursor.close()
        connection.close()

