@app.route("/profile&settings_UPDATE_PHOTO", methods=["POST"])
@login_required
def profileSettings_UPD_PHOTO():
    """
    Accept any valid image format (png, jpeg, etc.) and 
    always save as <username>.jpg, scaled and compressed.
    """
    if 'file' not in request.files:
        return jsonify({"error": "No file part"}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400

    # --- 1) Try to open file as an image ---
    try:
        img = Image.open(file.stream)
    except UnidentifiedImageError:
        return jsonify({"error": "Invalid or unsupported image file."}), 400
    except Exception as e:
        return jsonify({"error": f"Error opening image: {str(e)}"}), 500

    # --- 2) Convert to RGB for JPEG ---
    img = img.convert("RGB")

    max_dim = 1000  # you can change this to whatever you need
    img.thumbnail((max_dim, max_dim)) 

    # --- 4) Save as JPEG, specifying quality to control size ---
    save_filename = f"{session['username']}.jpg"
    save_path = os.path.join(
        r"C:\Users\yuceappadmin\Documents\GitHub\RPA-Projects\static\users_card_photos",
        save_filename
    )
    try:
        img.save(save_path, "JPEG", optimize=True, quality=80)
    except Exception as e:
        Write_Log_ToDB(session.get("username"), "POST", "/profile&settings_UPDATE_PHOTO", 0, details=f"Failed. {e}")
        return jsonify({"error": f"Error saving file: {str(e)}"}), 500
    
    
    Write_Log_ToDB(session.get("username"), "POST", "/profile&settings_UPDATE_PHOTO", 0, details="User changed their profile picture.")

    return jsonify({"message": "File uploaded successfully", "file_path": save_path}), 200

