@app.route("/planlama_pcl_pdf", methods = ["GET", "POST"])
@department_check("Bilgi Teknolojileri", "Ürün ve Planlama")
@login_required
def PclPdfJob():
    from pcl_pdf_excel_funcs import read_column_to_list
    from pcl_pdf_funcs import pdf_folder_job, search_and_copy_files, count_files_in_folder

    form = PclPdfForm(request.form)

    if request.method == "POST":
        file1 = form.file1.data
        dosya_adi = form.dosya_adi.data
        file1 = request.files['file1']

        if file1:  # Check if a file was uploaded
            filename = secure_filename(file1.filename)
            file1.save(os.path.join('templates', 'Excel_attachment', filename))
            try:
                values_to_be_searched = read_column_to_list(r"templates\Excel_attachment" + r"\ ".replace(" ","") + filename)
            except:
                flash("Excel Dosyasını okurken bir hata oluştu.", "danger")
                return redirect(url_for("index"))
            
            values = []
            for value in values_to_be_searched:
                values.append(str(value))
            
            faulty_input_list = [] # The list of input values that are not "FaturaNo" or "ŞasiNo"
            correct_inputs_list = [] # Inputs that have 8 or 17 length, correct format

            for value in values:
                if len(value) == 8 or len(value) == 17:
                    correct_inputs_list.append(value)
                else:
                    faulty_input_list.append(value)

            correct_inputs_length = len(correct_inputs_list)
            faulty_inputs_length = len(faulty_input_list)
            total_inputs_length = len(correct_inputs_list) + len(faulty_input_list)
            
            pdf_folder_job()
            ortak_alan_path = r"Y:\YUCE AUTO GENEL\RPA"
            new_folder_path = os.path.join(ortak_alan_path, dosya_adi)

            pdfs_not_found_aslist = []

            # Create the new folder
            os.makedirs(new_folder_path)
            end_file = ortak_alan_path + r"\ ".replace(" ","") + dosya_adi
            for substr in correct_inputs_list:
                file_not_found = search_and_copy_files(r"C:\-+-Users\-+-yuceappadmin\Desktop\-+-pdfs".replace("-+-",""), end_file, substr)
                if file_not_found != None:
                    pdfs_not_found_aslist.append(file_not_found)
            
            amount_of_found_invoices = count_files_in_folder(ortak_alan_path + r"\ ".replace(" ","") + dosya_adi)

            cursor = mysql.connection.cursor()
            if len(pdfs_not_found_aslist) >= 1:
                pdfs_not_found_asstring = ",".join(pdfs_not_found_aslist)
                query_for_invoicesNotfound = f"INSERT INTO invoices_notfound (invoices, inserted_date, username) VALUES ('{pdfs_not_found_asstring}', NOW(), '{session.get('username')}');"
                cursor.execute('delete from invoices_notfound')
                cursor.execute(query_for_invoicesNotfound)
            elif len(pdfs_not_found_aslist) == 0:
                cursor.execute('delete from invoices_notfound')
            mysql.connection.commit()
            cursor.close()

            message1 = "Toplam {} tane fatura için program başarıyla çalıştı".format(total_inputs_length)
            flash(message1, "success")

            message2 = "Girdiğiniz excelde {} tane satırda hata var.".format(faulty_inputs_length)
            flash(message2, "warning")
            message3 = f"{amount_of_found_invoices} adet fatura bulundu. \n Bu yoldan erişebilirsiniz : {dosya_adi}"
            
            Write_Log_ToDB(session.get('username'), "POST", "/planlama_pcl_pdf", 0, f"User ran the program for file: {filename}")
            flash(message3, "success")
            
            return redirect(url_for("PclPdfJob", confetti="true"))
        
        else:
            flash("Hata oluştu", "danger")
            return redirect(url_for("PclPdfJob"))
        
    elif request.method == "GET":
        cursor = mysql.connection.cursor()
        cursor.execute("SELECT * FROM invoices_notfound")
        result = cursor.fetchone()
        
        if result != None:
            pdfsnotfound = result['invoices']
        else:
            pdfsnotfound = 'Bulunamayan fatura yoktur.'

        Write_Log_ToDB(session.get('username'), "GET", "/planlama_pcl_pdf", 0)
        return render_template("planlama_pcl_pdf.html", form=form, pdfsnotfound=pdfsnotfound)
    else:
        return redirect(url_for("index"))

# Eksik PCL Listesi Excel
@app.route('/download_missing_pdfs_excel', methods=['GET'])
@login_required
@department_check("Bilgi Teknolojileri", "Ürün ve Planlama")
def download_missing_pdfs_excel():
    connection = mysql.connection
    cursor = connection.cursor()
    cursor.execute("SELECT * FROM invoices_notfound")
    result = cursor.fetchone()

    if result is None or not result['invoices']:
        return redirect(url_for("PclPdfJob"))

    pdfs_not_found = result['invoices'].split(",")
    df = pd.DataFrame(pdfs_not_found, columns=["Eksik Fatura Numaraları"])

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        df.to_excel(writer, index=False, sheet_name="Eksik_PCL_Listesi")

        workbook = writer.book
        worksheet = workbook["Eksik_PCL_Listesi"]

        from openpyxl.styles import PatternFill, Font, Alignment

        header_fill = PatternFill(start_color="0E3A2F", end_color="0E3A2F", fill_type="solid")
        header_font = Font(color="78FAAE", bold=True)
        center_alignment = Alignment(horizontal="center", vertical="center")

        for cell in worksheet[1]:  # First row is the header
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = center_alignment

        for row in worksheet.iter_rows():
            for cell in row:
                if cell.value == "None":
                    cell.value = ""
                cell.alignment = center_alignment

        worksheet.column_dimensions['A'].width = 30

        worksheet["A1"] = "Eksik Fatura Numaraları"

    output.seek(0)

    return send_file(output, as_attachment=True, download_name="Eksik_Fatura_Listesi.xlsx", mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")

@app.route("/tse_raporlu_araclar", methods=["GET", "POST"])
@login_required
def gemi_araclar():
    from openpyxl import load_workbook
    from openpyxl.styles import PatternFill, Font, Alignment, Border, Side
    if request.method == "GET":
        return render_template("gemi_araclar.html")

    if "chassis_file" not in request.files:
        flash("Dosya seçilmedi.", "warning")
        return render_template("gemi_araclar.html")

    f = request.files["chassis_file"]
    if not f or f.filename == "":
        flash("Dosya seçilmedi.", "warning")
        return render_template("gemi_araclar.html")

    filename = secure_filename(f.filename)

    try:
        df_in = pd.read_excel(f, engine="openpyxl", header=None)
    except Exception as e:
        flash(f"Excel okunamadı: {e}", "danger")
        return render_template("gemi_araclar.html")

    if df_in.shape[1] < 1:
        flash("Excel'de en az 1 sütun olmalı (A sütunu Şasi No).", "danger")
        return render_template("gemi_araclar.html")

    chassis_series = df_in.iloc[:, 0].astype(str).str.strip()

    chassis_clean = chassis_series[
        chassis_series.notna()
        & (chassis_series != "")
        & (chassis_series.str.lower() != "nan")
        & (chassis_series.str.lower() != "none")
    ]

    chassis_list = chassis_clean.unique().tolist()

    if not chassis_list:
        flash("A sütununda Şasi No bulunamadı.", "warning")
        return render_template("gemi_araclar.html")

    def chunked(lst, size=900):
        for i in range(0, len(lst), size):
            yield lst[i : i + size]

    mapping = {}

    try:
        with oracledb.connect(dsn) as connection:
            with connection.cursor() as cursor:
                base_sql = """
                    SELECT CHASSIS, TOP_MODEL_DEFINITION, COUNTRY_MODEL_DEFINITION
                    FROM yuce_dm.TBL_DW_VEH_RPT_VEHICLE_STATUS_UP_TO_DATE
                    WHERE CHASSIS IN ({})
                """

                for chunk in chunked(chassis_list, 900):
                    binds = ", ".join([f":{i+1}" for i in range(len(chunk))])
                    sql = base_sql.format(binds)
                    cursor.execute(sql, chunk)

                    for ch, top_model, country_model in cursor.fetchall():
                        if ch is not None:
                            mapping[str(ch).strip()] = (top_model, country_model)

    except Exception as e:
        flash(f"Oracle sorgusu başarısız: {e}", "danger")
        return render_template("gemi_araclar.html")

    df_out = pd.DataFrame({
        "Şasi No": chassis_series,
        "Üst Model": chassis_series.map(lambda x: mapping.get(str(x).strip(), (None, None))[0]),
        "Model": chassis_series.map(lambda x: mapping.get(str(x).strip(), (None, None))[1]),
    })

    today_str = datetime.datetime.now().strftime("%d.%m.%Y")
    out_name = f"TSE Raporu Çıkan Araçlar - {today_str}.xlsx"
    out_path = os.path.join(tempfile.gettempdir(), out_name)

    try:
        df_out.to_excel(out_path, index=False, engine="openpyxl")

        wb = load_workbook(out_path)
        ws = wb.active

        ws.sheet_view.showGridLines = False

        ws.column_dimensions["A"].width = 30
        ws.column_dimensions["B"].width = 20
        ws.column_dimensions["C"].width = 60

        header_fill = PatternFill("solid", fgColor="0E3A2F")
        header_font = Font(color="78FAAE", bold=True)
        header_alignment = Alignment(horizontal="center", vertical="center")

        even_fill = PatternFill("solid", fgColor="FFFFFF")
        odd_fill = PatternFill("solid", fgColor="F1F2F2")

        thin = Side(style="thin", color="000000")
        border = Border(left=thin, right=thin, top=thin, bottom=thin)

        max_row = ws.max_row
        max_col = ws.max_column

        for r in range(1, max_row + 1):
            ws.row_dimensions[r].height = 30

        for c in range(1, max_col + 1):
            cell = ws.cell(row=1, column=c)
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = header_alignment
            cell.border = border

        data_alignment = Alignment(vertical="center")
        for r in range(2, max_row + 1):
            fill = even_fill if ((r - 2) % 2 == 0) else odd_fill
            for c in range(1, max_col + 1):
                cell = ws.cell(row=r, column=c)
                cell.fill = fill
                cell.border = border
                cell.alignment = data_alignment

        wb.save(out_path)

    except Exception as e:
        flash(f"Excel yazılamadı: {e}", "danger")
        return render_template("gemi_araclar.html")

    ship_names = request.form.getlist("ship_name[]")
    ship_qtys  = request.form.getlist("ship_qty[]")

    ships = []
    for name, qty in zip(ship_names, ship_qtys):
        name = (name or "").strip()
        qty_str = (qty or "").strip()

        if not name or not qty_str:
            continue

        try:
            qty_int = int(qty_str)
        except ValueError:
            continue

        if qty_int <= 0:
            continue

        ships.append((name, qty_int))

    merged = {}
    for name, qty in ships:
        merged[name] = merged.get(name, 0) + qty
    ships = list(merged.items())

    total_count = len(df_out)

    model_counts = (
        df_out["Üst Model"]
        .dropna()
        .value_counts()
        .sort_index()
    )

    model_lines = "<br>".join([f"{model}: {count}" for model, count in model_counts.items()])

    if ships:
        ship_sentence = ", ".join([f"{name} gemisindeki <b>{qty}</b>" for name, qty in ships])
    else:
        ship_sentence = total_count

    content = f"""
    Merhaba,<br><br>
    {ship_sentence} aracın TSE raporları çıkmıştır.<br><br>
    {model_lines}<br><br>
    Bilgilerinize sunarız.<br>
    İyi çalışmalar.
    """.strip()

    sender = request.form.get("email")
    pwd = request.form.get("password")
    subject = "TSE Raporu Çıkan Araçlar"
    #receiver_email = ["SkodaFilo@skoda.com.tr", "SkodaSatis@skoda.com.tr"]
    #cc_email = ["SkodaStratejikPlanlama@skoda.com.tr", "SkodaUrunvePlanlama@skoda.com.tr", "u.demirezen@skoda.com.tr", "m.topcu@skoda.com.tr"]
    receiver_email = ["s.ozcelik@skoda.com.tr"]
    cc_email = None
    
    try:
        send_email_2(sender_email=sender, mail_password=pwd, subject=subject, content=content, receiver_email=receiver_email, cc_email=cc_email, bcc_email=None, attachment=out_path)
    except Exception as e:
        flash(f"E-posta gönderilemedi: {e}", "danger")
        return render_template("gemi_araclar.html")

    flash("Dosya işlendi ve e-posta gönderildi.", "success")
    return render_template("gemi_araclar.html")

