# UI'de başlangıçta gösterilecek modeller
PREDEFINED_MODELS = [
    ("Fabia", 1),
    ("Scala", 1),
    ("Kamiq", 1),
    ("Elroq", 1),
    ("Octavia", 2),
    ("Karoq", 2),
    ("Superb", 2),
    ("Kodiaq", 2),
    ("Enyaq", 2),
    ("Enyaq Coupe", 2),
]

# Form alan isimleri -> Türkçe ay isimleri
MONTH_FIELD_KEYS = [
    "ocak", "subat", "mart", "nisan", "mayis", "haziran",
    "temmuz", "agustos", "eylul", "ekim", "kasim", "aralik"
]

def _parse_float_from_form(field_name: str, default: float) -> float:
    raw = request.form.get(field_name, "").strip()
    if not raw:
        return default
    raw = raw.replace(",", ".")
    try:
        return float(raw)
    except ValueError:
        return default

@app.route("/ys_bonus", methods=["GET", "POST"])
@login_required
def ys_bonus():
    flash("YS bonus özelliği projeden kaldırıldı.", "warning")
    return redirect(url_for("index"))
    form = YSBonusForm(request.form)

    # ----------------- GET: Sayfa ilk açıldığında -----------------
    if request.method == "GET":
        # BonusScoringConfig'ten teorik max'ları alacağız
        cfg = BonusScoringConfig.default()
        base_max_g1 = cfg.base_max_grup1   # Grup1 için (Fabia-Scala-Kamiq-Elroq)
        base_max_g2 = cfg.base_max_grup2   # Grup2 için (Octavia-Karoq-Superb-Kodiaq-Enyaq...)

        # Var olan FieldList entry'lerini temizle
        while len(form.model_oranlari) > 0:
            form.model_oranlari.pop_entry()

        # Ön tanımlı modelleri ekle ve ay tavanlarını doldur
        for model_name, grup_no in PREDEFINED_MODELS:
            subform = form.model_oranlari.append_entry()
            subform.model.data = model_name
            subform.grup.data = str(grup_no)

            # Grup bazlı teorik maksimum
            base_max = base_max_g1 if grup_no == 1 else base_max_g2

            for field_key, month_name in zip(MONTH_FIELD_KEYS, MONTHS):
                # İlk açılışta tüm aylar için teorik max yazıyoruz.
                # (istersen burada bazı model+ay kombinasyonlarını özel değerlerle override edebiliriz)
                getattr(subform, field_key).data = base_max

        # Katsayı kartları için default değerleri template’e gönder
        katsayi_defaults = {
            # Alış – Grup 1 (30'luk)
            "alis_g1_80": 0.0,
            "alis_g1_80_89": 0.25,
            "alis_g1_90_99": 0.5,
            "alis_g1_100": 1.0,

            # Alış – Grup 2 (45'lik)
            "alis_g2_80": 0.0,
            "alis_g2_80_89": 0.5,
            "alis_g2_90_99": 1.0,
            "alis_g2_100": 1.5,

            # Satış – Grup 1
            "satis_g1_80": 0.0,
            "satis_g1_80_89": 0.5,
            "satis_g1_90_99": 1.0,
            "satis_g1_100": 1.5,

            # Satış – Grup 2
            "satis_g2_80": 0.0,
            "satis_g2_80_89": 1.0,
            "satis_g2_90_99": 2.0,
            "satis_g2_100": 2.5,

            # CEM
            "cem_470": 0.0,
            "cem_470_479": 0.25,
            "cem_480": 0.5,
        }

        return render_template("ys_bonus.html", form=form, katsayi_defaults=katsayi_defaults)

    # ----------------- POST: Hesaplama -----------------
    # 1) Dosyaları al
    alis_file_fs = request.files.get("alis_hedef")
    satis_file_fs = request.files.get("satis_hedef")
    cem_file_fs = request.files.get("cem_gerceklesen")
    rapor_025_fs = request.files.get("rapor_025")

    if not all([alis_file_fs, satis_file_fs, cem_file_fs, rapor_025_fs]):
        flash("Lütfen tüm excel dosyalarını yükleyin.", "danger")
        return render_template("ys_bonus.html", form=form)

    # Geçici klasöre kaydet
    temp_dir = tempfile.mkdtemp(prefix="ys_bonus_")

    def save_upload(fs_obj, filename):
        path = os.path.join(temp_dir, filename)
        fs_obj.save(path)
        return path

    vehicle_path = save_upload(rapor_025_fs, "vehicle.xlsx")
    alis_path = save_upload(alis_file_fs, "alis.xlsx")
    satis_path = save_upload(satis_file_fs, "satis.xlsx")
    cem_path = save_upload(cem_file_fs, "cem.xlsx")

    # 2) Model + Ay tavanlarını formdan topla
    model_month_caps = {}

    for subform in form.model_oranlari:
        raw_model = (subform.model.data or "").strip()
        if not raw_model:
            continue

        # Engine'deki ile aynı normalize + key çıkarma
        cleaned_model = clean_model_text(raw_model)
        model_key = detect_model_key(cleaned_model) or cleaned_model

        for field_key, month_name in zip(MONTH_FIELD_KEYS, MONTHS):
            val = getattr(subform, field_key).data
            if val in (None, ""):
                continue
            try:
                cap_val = float(val)
            except (TypeError, ValueError):
                continue
            model_month_caps[(model_key, month_name)] = cap_val

    # 3) Katsayı kartlarını config'e çevir
    alis_30_levels = (
        _parse_float_from_form("alis_g1_80", 0.0),
        _parse_float_from_form("alis_g1_80_89", 0.25),
        _parse_float_from_form("alis_g1_90_99", 0.5),
        _parse_float_from_form("alis_g1_100", 1.0),
    )

    alis_45_levels = (
        _parse_float_from_form("alis_g2_80", 0.0),
        _parse_float_from_form("alis_g2_80_89", 0.5),
        _parse_float_from_form("alis_g2_90_99", 1.0),
        _parse_float_from_form("alis_g2_100", 1.5),
    )

    satis_30_levels = (
        _parse_float_from_form("satis_g1_80", 0.0),
        _parse_float_from_form("satis_g1_80_89", 0.5),
        _parse_float_from_form("satis_g1_90_99", 1.0),
        _parse_float_from_form("satis_g1_100", 1.5),
    )

    satis_45_levels = (
        _parse_float_from_form("satis_g2_80", 0.0),
        _parse_float_from_form("satis_g2_80_89", 1.0),
        _parse_float_from_form("satis_g2_90_99", 2.0),
        _parse_float_from_form("satis_g2_100", 2.5),
    )

    cem_levels = (
        _parse_float_from_form("cem_470", 0.0),
        _parse_float_from_form("cem_470_479", 0.25),
        _parse_float_from_form("cem_480", 0.5),
    )

    scoring_config = BonusScoringConfig(
        alis_30_levels=alis_30_levels,
        alis_45_levels=alis_45_levels,
        satis_30_levels=satis_30_levels,
        satis_45_levels=satis_45_levels,
        cem_levels=cem_levels,
    )

    # 4) İstersen formdan ay filtresi okuruz; şimdilik tüm aylar
    selected_month = None

    # 5) Engine pipeline'ını çalıştır (dikkat: yeni imza!)
    final_df, summary_df, output_bytes, output_filename = run_ys_bonus_pipeline(
        vehicle_file=vehicle_path,
        alis_file=alis_path,
        satis_file=satis_path,
        cem_file=cem_path,
        model_month_caps=model_month_caps,
        scoring_config=scoring_config,
        selected_month=selected_month,
    )

    # 6) RAM'deki Excel'i kullanıcıya indir
    return send_file(
        output_bytes,
        as_attachment=True,
        download_name=output_filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    )

def parse_decimal(val):
    """Formdan gelen string'i DECIMAL'a çevir (boşsa None). Virgül/nokta uyumlu."""
    if val is None:
        return None
    val = str(val).strip()
    if val == "":
        return None
    try:
        val = val.replace(",", ".")
        return Decimal(val)
    except Exception:
        return None

@app.route("/ys_bonus2/excel/<excel_key>", methods=["GET"])
@login_required
def ys_bonus2_excel_download(excel_key):
    flash("YS bonus özelliği projeden kaldırıldı.", "warning")
    return redirect(url_for("index"))
    from werkzeug.security import safe_join
    upload_folder = current_app.config.get("YS_BONUS_UPLOAD_FOLDER", os.path.join(current_app.root_path, "uploads", "ys_bonus"))

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()
    cursor.execute("""
        SELECT Id, AracRaporuFileName, AlisExcelFileName, SatisExcelFileName, CemExcelFileName
        FROM [Yuce_Portal].[dbo].[YS_Bonus_Excel_Config]
        ORDER BY Id DESC
    """)
    excel_rows = cursor.fetchall()
    conn.close()

    excel_cfg = {"arac": None, "alis": None, "satis": None, "cem": None}

    for r in excel_rows:
        if not excel_cfg["arac"] and r[1]: excel_cfg["arac"] = r[1]
        if not excel_cfg["alis"] and r[2]: excel_cfg["alis"] = r[2]
        if not excel_cfg["satis"] and r[3]: excel_cfg["satis"] = r[3]
        if not excel_cfg["cem"]  and r[4]: excel_cfg["cem"]  = r[4]
        if all(excel_cfg.values()):
            break

    if excel_key not in excel_cfg:
        abort(404)

    filename = excel_cfg.get(excel_key)
    if not filename:
        abort(404)

    filename = secure_filename(filename)

    full_path = safe_join(upload_folder, filename)
    if not full_path or not os.path.isfile(full_path):
        abort(404)

    return send_from_directory(upload_folder, filename, as_attachment=True)

@app.route("/ys_bonus2", methods=["GET", "POST"])
@login_required
def ys_bonus2():
    flash("YS bonus özelliği projeden kaldırıldı.", "warning")
    return redirect(url_for("index"))
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    # ---------------------------
    # ORTAK: DB'DEN MEVCUT VERİLERİ OKU (GET & POST ORTAK)
    # ---------------------------

    # 1) Excel Config – tüm satırlara bak, her kolon için en son dolu değeri bul
    cursor.execute("""
        SELECT Id, AracRaporuFileName, AlisExcelFileName, SatisExcelFileName, CemExcelFileName
        FROM [Yuce_Portal].[dbo].[YS_Bonus_Excel_Config]
        ORDER BY Id DESC
    """)
    excel_rows = cursor.fetchall()

    excel_cfg = {
        "id": excel_rows[0][0] if excel_rows else None,
        "arac": None,
        "alis": None,
        "satis": None,
        "cem": None,
    }

    for r in excel_rows:
        # r: (Id, Arac, Alis, Satis, Cem)
        if not excel_cfg["arac"] and r[1]:
            excel_cfg["arac"] = r[1]
        if not excel_cfg["alis"] and r[2]:
            excel_cfg["alis"] = r[2]
        if not excel_cfg["satis"] and r[3]:
            excel_cfg["satis"] = r[3]
        if not excel_cfg["cem"] and r[4]:
            excel_cfg["cem"] = r[4]

        if all(v is not None for k, v in excel_cfg.items() if k != "id"):
            break

    # 2) Grup Maks (son kayıt yoksa default 3.0/4.5)
    cursor.execute("""
        SELECT TOP 1 Id, Grup1Maks, Grup2Maks
        FROM [Yuce_Portal].[dbo].[YS_Bonus_GrupMaks]
        ORDER BY Id DESC
    """)
    grup_row = cursor.fetchone()
    grup_cfg = {
        "id": grup_row[0] if grup_row else None,
        "grup1": float(grup_row[1]) if grup_row and grup_row[1] is not None else 3.0,
        "grup2": float(grup_row[2]) if grup_row and grup_row[2] is not None else 4.5,
    }

    # 3) Model + Ay Maks (tüm satırlar)
    cursor.execute("""
        SELECT Id, Model, Grup,
               Ocak, Subat, Mart, Nisan, Mayis, Haziran,
               Temmuz, Agustos, Eylul, Ekim, Kasim, Aralik
        FROM [Yuce_Portal].[dbo].[YS_Bonus_ModelMaks]
        ORDER BY Model ASC
    """)
    model_rows = cursor.fetchall()
    model_cfg = []
    for r in model_rows:
        model_cfg.append({
            "id": r[0],
            "model": r[1],
            "grup": r[2],
            "ocak": r[3], "subat": r[4], "mart": r[5], "nisan": r[6],
            "mayis": r[7], "haziran": r[8], "temmuz": r[9], "agustos": r[10],
            "eylul": r[11], "ekim": r[12], "kasim": r[13], "aralik": r[14],
        })

    # 4) Hard Zero İndirim (tek satır - en son kayıt)
    cursor.execute("""
        SELECT TOP 1 Id,
               TestAraci, GeciciArac, AracDegisim, YSSahibi,
               SkodaDOCalisan, YACalisan, YACalisanYakini, SkodaDOCalisanYakini
        FROM [Yuce_Portal].[dbo].[YS_Bonus_HardZeroIndirim]
        ORDER BY Id DESC
    """)
    hz = cursor.fetchone()
    hard_zero_cfg = {
        "id": hz[0] if hz else None,
        "TestAraci": bool(hz[1]) if hz else False,
        "GeciciArac": bool(hz[2]) if hz else False,
        "AracDegisim": bool(hz[3]) if hz else False,
        "YSSahibi": bool(hz[4]) if hz else False,
        "SkodaDOCalisan": bool(hz[5]) if hz else False,
        "YACalisan": bool(hz[6]) if hz else False,
        "YACalisanYakini": bool(hz[7]) if hz else False,
        "SkodaDOCalisanYakini": bool(hz[8]) if hz else False,
    }

    # 5) Mikro Filo Kuralları (tüm satırlar)
    cursor.execute("""
        SELECT Id, MinOranPct, MaxOranPct, EkKesintiPuan
        FROM [Yuce_Portal].[dbo].[YS_Bonus_MikroFiloKural]
        ORDER BY MinOranPct ASC
    """)
    mf_rows = cursor.fetchall()
    mikrofilo_cfg = []
    for r in mf_rows:
        mikrofilo_cfg.append({
            "id": r[0],
            "min": r[1],
            "max": r[2],
            "kesinti": r[3],
        })

    # 6) Özel Cap Kuralları (aktif satırlar)
    cursor.execute("""
        SELECT Id, Ay, ModelIcerik, MaksBonusYuzde, IsActive
        FROM [Yuce_Portal].[dbo].[YS_Bonus_OzelCapKural]
        WHERE IsActive = 1
        ORDER BY Ay ASC, ModelIcerik ASC
    """)
    oc_rows = cursor.fetchall()
    ozel_cfg = []
    for r in oc_rows:
        ozel_cfg.append({
            "id": r[0],
            "ay": r[1],
            "icerik": r[2],
            "max": r[3],
            "active": bool(r[4]),
        })

    # 7) İndirim Kesinti Kuralları (tablodan)
    cursor.execute("""
        SELECT Id, IndirimTipi,
            Ocak, Subat, Mart, Nisan, Mayis, Haziran,
            Temmuz, Agustos, Eylul, Ekim, Kasim, Aralik
        FROM [Yuce_Portal].[dbo].[YS_Bonus_IndirimKesinti]
        ORDER BY IndirimTipi ASC
    """)
    ind_rows = cursor.fetchall()
    indirim_cfg = []
    for r in ind_rows:
        indirim_cfg.append({
            "id": r[0],
            "tip": r[1],
            "ocak": r[2],
            "subat": r[3],
            "mart": r[4],
            "nisan": r[5],
            "mayis": r[6],
            "haziran": r[7],
            "temmuz": r[8],
            "agustos": r[9],
            "eylul": r[10],
            "ekim": r[11],
            "kasim": r[12],
            "aralik": r[13],
        })

    # ---------------------------
    # POST — KAYDET / KAYDET+HESAPLA
    # ---------------------------
    if request.method == "POST":
        action = request.form.get("action")  # "save_only" veya "save_and_run"

        # 1) Excel dosyalarını kaydet + DB'ye isimlerini yaz
        upload_folder = current_app.config.get(
            "YS_BONUS_UPLOAD_FOLDER",
            os.path.join(current_app.root_path, "uploads", "ys_bonus")
        )
        os.makedirs(upload_folder, exist_ok=True)

        # Mevcut isimleri baz al; yeni dosya gelmezse bunlar kalacak
        arac_name = excel_cfg["arac"]
        alis_name = excel_cfg["alis"]
        satis_name = excel_cfg["satis"]
        cem_name = excel_cfg["cem"]

        f_arac = request.files.get("arac_raporu")
        f_alis = request.files.get("alis_excel")
        f_satis = request.files.get("satis_excel")
        f_cem = request.files.get("cem_excel")

        if f_arac and f_arac.filename:
            filename = secure_filename(f_arac.filename)
            save_path = os.path.join(upload_folder, filename)
            f_arac.save(save_path)
            arac_name = filename

        if f_alis and f_alis.filename:
            filename = secure_filename(f_alis.filename)
            save_path = os.path.join(upload_folder, filename)
            f_alis.save(save_path)
            alis_name = filename

        if f_satis and f_satis.filename:
            filename = secure_filename(f_satis.filename)
            save_path = os.path.join(upload_folder, filename)
            f_satis.save(save_path)
            satis_name = filename

        if f_cem and f_cem.filename:
            filename = secure_filename(f_cem.filename)
            save_path = os.path.join(upload_folder, filename)
            f_cem.save(save_path)
            cem_name = filename

        cursor.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[YS_Bonus_Excel_Config]
            (AracRaporuFileName, AlisExcelFileName, SatisExcelFileName, CemExcelFileName)
            VALUES (?, ?, ?, ?)
        """, (arac_name, alis_name, satis_name, cem_name))

        # 2) Grup Maks satırı ekle
        g1_raw = request.form.get("grup1_maks")
        g2_raw = request.form.get("grup2_maks")
        g1 = parse_decimal(g1_raw) or Decimal(str(grup_cfg["grup1"]))
        g2 = parse_decimal(g2_raw) or Decimal(str(grup_cfg["grup2"]))

        cursor.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[YS_Bonus_GrupMaks] (Grup1Maks, Grup2Maks)
            VALUES (?, ?)
        """, (g1, g2))

        # 3) Mevcut model satırlarını güncelle / sil
        cursor.execute("SELECT Id FROM [Yuce_Portal].[dbo].[YS_Bonus_ModelMaks]")
        existing_ids = [row[0] for row in cursor.fetchall()]
        delete_model_ids = set(request.form.getlist("delete_model_ids"))

        for mid in existing_ids:
            if str(mid) in delete_model_ids:
                cursor.execute(
                    "DELETE FROM [Yuce_Portal].[dbo].[YS_Bonus_ModelMaks] WHERE Id = ?",
                    (mid,)
                )
                continue

            prefix = f"model_{mid}_"
            model_name = request.form.get(prefix + "model")
            if model_name is None:
                continue

            model_name = model_name.strip()
            grup_val = request.form.get(prefix + "grup")

            ocak = parse_decimal(request.form.get(prefix + "ocak"))
            subat = parse_decimal(request.form.get(prefix + "subat"))
            mart = parse_decimal(request.form.get(prefix + "mart"))
            nisan = parse_decimal(request.form.get(prefix + "nisan"))
            mayis = parse_decimal(request.form.get(prefix + "mayis"))
            haziran = parse_decimal(request.form.get(prefix + "haziran"))
            temmuz = parse_decimal(request.form.get(prefix + "temmuz"))
            agustos = parse_decimal(request.form.get(prefix + "agustos"))
            eylul = parse_decimal(request.form.get(prefix + "eylul"))
            ekim = parse_decimal(request.form.get(prefix + "ekim"))
            kasim = parse_decimal(request.form.get(prefix + "kasim"))
            aralik = parse_decimal(request.form.get(prefix + "aralik"))

            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[YS_Bonus_ModelMaks]
                SET Model = ?, Grup = ?,
                    Ocak = ?, Subat = ?, Mart = ?, Nisan = ?, Mayis = ?, Haziran = ?,
                    Temmuz = ?, Agustos = ?, Eylul = ?, Ekim = ?, Kasim = ?, Aralik = ?
                WHERE Id = ?
            """, (
                model_name, grup_val,
                ocak, subat, mart, nisan, mayis, haziran,
                temmuz, agustos, eylul, ekim, kasim, aralik,
                mid
            ))

        # 4) Yeni model satırları
        new_models = request.form.getlist("model_new_model[]")
        new_groups = request.form.getlist("model_new_grup[]")
        new_ocak = request.form.getlist("model_new_ocak[]")
        new_subat = request.form.getlist("model_new_subat[]")
        new_mart = request.form.getlist("model_new_mart[]")
        new_nisan = request.form.getlist("model_new_nisan[]")
        new_mayis = request.form.getlist("model_new_mayis[]")
        new_haziran = request.form.getlist("model_new_haziran[]")
        new_temmuz = request.form.getlist("model_new_temmuz[]")
        new_agustos = request.form.getlist("model_new_agustos[]")
        new_eylul = request.form.getlist("model_new_eylul[]")
        new_ekim = request.form.getlist("model_new_ekim[]")
        new_kasim = request.form.getlist("model_new_kasim[]")
        new_aralik = request.form.getlist("model_new_aralik[]")

        def safe_get(lst, i):
            return lst[i] if i < len(lst) else None

        for idx, model_name in enumerate(new_models):
            model_name = (model_name or "").strip()
            if not model_name:
                continue

            grup_val = safe_get(new_groups, idx)

            ocak = parse_decimal(safe_get(new_ocak, idx))
            subat = parse_decimal(safe_get(new_subat, idx))
            mart = parse_decimal(safe_get(new_mart, idx))
            nisan = parse_decimal(safe_get(new_nisan, idx))
            mayis = parse_decimal(safe_get(new_mayis, idx))
            haziran = parse_decimal(safe_get(new_haziran, idx))
            temmuz = parse_decimal(safe_get(new_temmuz, idx))
            agustos = parse_decimal(safe_get(new_agustos, idx))
            eylul = parse_decimal(safe_get(new_eylul, idx))
            ekim = parse_decimal(safe_get(new_ekim, idx))
            kasim = parse_decimal(safe_get(new_kasim, idx))
            aralik = parse_decimal(safe_get(new_aralik, idx))

            cursor.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YS_Bonus_ModelMaks]
                (Model, Grup, Ocak, Subat, Mart, Nisan, Mayis, Haziran,
                 Temmuz, Agustos, Eylul, Ekim, Kasim, Aralik)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """, (
                model_name, grup_val,
                ocak, subat, mart, nisan, mayis, haziran,
                temmuz, agustos, eylul, ekim, kasim, aralik
            ))

        # 5) Hard Zero indirimler
        hz_fields = [
            ("TestAraci", "hz_TestAraci"),
            ("GeciciArac", "hz_GeciciArac"),
            ("AracDegisim", "hz_AracDegisim"),
            ("YSSahibi", "hz_YSSahibi"),
            ("SkodaDOCalisan", "hz_SkodaDOCalisan"),
            ("YACalisan", "hz_YACalisan"),
            ("YACalisanYakini", "hz_YACalisanYakini"),
            ("SkodaDOCalisanYakini", "hz_SkodaDOCalisanYakini"),
        ]
        hz_values = []
        for db_col, form_name in hz_fields:
            val = request.form.get(form_name)
            hz_values.append(1 if val in ("1", "on", "true", "True") else 0)

        cursor.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[YS_Bonus_HardZeroIndirim]
            (TestAraci, GeciciArac, AracDegisim, YSSahibi,
             SkodaDOCalisan, YACalisan, YACalisanYakini, SkodaDOCalisanYakini)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        """, hz_values)

        # 6) Mikro Filo kuralları
        cursor.execute("SELECT Id FROM [Yuce_Portal].[dbo].[YS_Bonus_MikroFiloKural]")
        mf_ids = [row[0] for row in cursor.fetchall()]
        delete_mf_ids = set(request.form.getlist("delete_mf_ids"))

        for mfid in mf_ids:
            if str(mfid) in delete_mf_ids:
                cursor.execute(
                    "DELETE FROM [Yuce_Portal].[dbo].[YS_Bonus_MikroFiloKural] WHERE Id = ?",
                    (mfid,)
                )
                continue

            prefix = f"mf_{mfid}_"
            min_val = parse_decimal(request.form.get(prefix + "min"))
            max_val = parse_decimal(request.form.get(prefix + "max"))
            ek_kesinti = parse_decimal(request.form.get(prefix + "kesinti"))

            if min_val is None and max_val is None and ek_kesinti is None:
                continue

            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[YS_Bonus_MikroFiloKural]
                SET MinOranPct = ?, MaxOranPct = ?, EkKesintiPuan = ?
                WHERE Id = ?
            """, (min_val, max_val, ek_kesinti, mfid))

        new_mf_min = parse_decimal(request.form.get("mf_new_min"))
        new_mf_max = parse_decimal(request.form.get("mf_new_max"))
        new_mf_kesinti = parse_decimal(request.form.get("mf_new_kesinti"))
        if new_mf_min is not None and new_mf_max is not None and new_mf_kesinti is not None:
            cursor.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YS_Bonus_MikroFiloKural] (MinOranPct, MaxOranPct, EkKesintiPuan)
                VALUES (?, ?, ?)
            """, (new_mf_min, new_mf_max, new_mf_kesinti))

        # 7) Özel Cap Kuralları
        cursor.execute("SELECT Id FROM [Yuce_Portal].[dbo].[YS_Bonus_OzelCapKural] WHERE IsActive = 1")
        oc_ids = [row[0] for row in cursor.fetchall()]
        delete_ozel_ids = set(request.form.getlist("delete_ozel_ids"))

        for ocid in oc_ids:
            if str(ocid) in delete_ozel_ids:
                cursor.execute(
                    "DELETE FROM [Yuce_Portal].[dbo].[YS_Bonus_OzelCapKural] WHERE Id = ?",
                    (ocid,)
                )
                continue

            prefix = f"ozel_{ocid}_"
            ay = request.form.get(prefix + "ay")
            icerik = request.form.get(prefix + "icerik")
            max_val = parse_decimal(request.form.get(prefix + "max"))
            active_flag = 1 if request.form.get(prefix + "active") in ("1", "on", "true", "True") else 0

            if not ay or not icerik or max_val is None:
                continue

            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[YS_Bonus_OzelCapKural]
                SET Ay = ?, ModelIcerik = ?, MaksBonusYuzde = ?, IsActive = ?
                WHERE Id = ?
            """, (ay, icerik, max_val, active_flag, ocid))

        new_ozel_ay = request.form.get("ozel_new_ay")
        new_ozel_icerik = request.form.get("ozel_new_icerik")
        new_ozel_max = parse_decimal(request.form.get("ozel_new_max"))
        new_ozel_active = 1 if request.form.get("ozel_new_active") else 0
        if new_ozel_ay and new_ozel_icerik and new_ozel_max is not None:
            cursor.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YS_Bonus_OzelCapKural] (Ay, ModelIcerik, MaksBonusYuzde, IsActive)
                VALUES (?, ?, ?, ?)
            """, (new_ozel_ay, new_ozel_icerik, new_ozel_max, new_ozel_active))

        # 8) İndirim Kesinti Kuralları
        cursor.execute("SELECT Id FROM [Yuce_Portal].[dbo].[YS_Bonus_IndirimKesinti]")
        ind_ids = [row[0] for row in cursor.fetchall()]
        delete_indirim_ids = set(request.form.getlist("delete_indirim_ids"))

        for iid in ind_ids:
            if str(iid) in delete_indirim_ids:
                cursor.execute(
                    "DELETE FROM [Yuce_Portal].[dbo].[YS_Bonus_IndirimKesinti] WHERE Id = ?",
                    (iid,)
                )
                continue

            prefix = f"indirim_{iid}_"
            tip = request.form.get(prefix + "tip")
            if tip is None:
                continue

            ocak = parse_decimal(request.form.get(prefix + "ocak"))
            subat = parse_decimal(request.form.get(prefix + "subat"))
            mart = parse_decimal(request.form.get(prefix + "mart"))
            nisan = parse_decimal(request.form.get(prefix + "nisan"))
            mayis = parse_decimal(request.form.get(prefix + "mayis"))
            haziran = parse_decimal(request.form.get(prefix + "haziran"))
            temmuz = parse_decimal(request.form.get(prefix + "temmuz"))
            agustos = parse_decimal(request.form.get(prefix + "agustos"))
            eylul = parse_decimal(request.form.get(prefix + "eylul"))
            ekim = parse_decimal(request.form.get(prefix + "ekim"))
            kasim = parse_decimal(request.form.get(prefix + "kasim"))
            aralik = parse_decimal(request.form.get(prefix + "aralik"))

            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[YS_Bonus_IndirimKesinti]
                SET IndirimTipi = ?,
                    Ocak = ?, Subat = ?, Mart = ?, Nisan = ?, Mayis = ?, Haziran = ?,
                    Temmuz = ?, Agustos = ?, Eylul = ?, Ekim = ?, Kasim = ?, Aralik = ?
                WHERE Id = ?
            """, (
                tip,
                ocak, subat, mart, nisan, mayis, haziran,
                temmuz, agustos, eylul, ekim, kasim, aralik,
                iid
            ))

        new_tip = request.form.get("indirim_new_tip")
        if new_tip:
            new_ocak = parse_decimal(request.form.get("indirim_new_ocak"))
            new_subat = parse_decimal(request.form.get("indirim_new_subat"))
            new_mart = parse_decimal(request.form.get("indirim_new_mart"))
            new_nisan = parse_decimal(request.form.get("indirim_new_nisan"))
            new_mayis = parse_decimal(request.form.get("indirim_new_mayis"))
            new_haziran = parse_decimal(request.form.get("indirim_new_haziran"))
            new_tem = parse_decimal(request.form.get("indirim_new_temmuz"))
            new_agu = parse_decimal(request.form.get("indirim_new_agustos"))
            new_eyl = parse_decimal(request.form.get("indirim_new_eylul"))
            new_eki = parse_decimal(request.form.get("indirim_new_ekim"))
            new_kas = parse_decimal(request.form.get("indirim_new_kasim"))
            new_arl = parse_decimal(request.form.get("indirim_new_aralik"))

            cursor.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YS_Bonus_IndirimKesinti]
                (
                    IndirimTipi,
                    Ocak, Subat, Mart, Nisan, Mayis, Haziran,
                    Temmuz, Agustos, Eylul, Ekim, Kasim, Aralik
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """, (
                new_tip,
                new_ocak, new_subat, new_mart, new_nisan, new_mayis, new_haziran,
                new_tem, new_agu, new_eyl, new_eki, new_kas, new_arl
            ))

        conn.commit()

        if action == "save_and_run":
            try:
                output_file = run_bonus_with_db_config(
                    selected_month=None,
                    yil=None,
                    conn_str=YA_2El_AracSatis
                )
                flash(f"Ayarlar kaydedildi ve bonus hesaplama tamamlandı. Çıktı dosyası: {output_file}", "success")
            except Exception as e:
                flash(f"Ayarlar kaydedildi fakat bonus hesaplama sırasında hata oluştu: {e}", "danger")
        else:
            flash("Ayarlar kaydedildi.", "success")

        conn.close()
        return redirect(url_for("ys_bonus2"))

    # GET
    conn.close()
    return render_template(
        "ys_bonus2.html",
        excel_cfg=excel_cfg,
        grup_cfg=grup_cfg,
        model_cfg=model_cfg,
        hard_zero_cfg=hard_zero_cfg,
        mikrofilo_cfg=mikrofilo_cfg,
        ozel_cfg=ozel_cfg,
        indirim_cfg=indirim_cfg
    )

@app.route("/ys_bonus2/download_latest")
@login_required
def download_latest_ys_bonus():
    flash("YS bonus özelliği projeden kaldırıldı.", "warning")
    return redirect(url_for("index"))
    file_path = os.path.join(os.getcwd(), "YücePortal_Bonus_Hesabı_Tüm_Aylar.xlsx")

    if not os.path.isfile(file_path):
        flash("Bonus dosya bulunamadı.", "warning")
