@app.route("/hedef", methods=["GET", "POST", "DELETE", "PUT"])
@login_required
def hedef():
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()
    now = datetime.datetime.now()
    message = ""

    user_id = session.get("ID")
    user_name = session.get("username")
    user_namesurname = session.get("name") + " " + session.get("surname")

    # === Yardımcı güvenli dönüştürme fonksiyonları ===
    def safe_int(val):
        try:
            if val is None or str(val).strip() == "":
                return None
            return int(val)
        except Exception:
            return None

    def safe_float(val):
        try:
            if val is None or str(val).strip() == "":
                return None
            return float(str(val).replace(",", "."))
        except Exception:
            return None


    # == Toplamları hem model bazlı hem ay bazlı olarak HedefToplam tablosuna yazan fonksiyon ==
    def sync_hedef_toplamlari(conn):
        cursor = conn.cursor()

        # 1) AYLIK Kurgu Hedefleri
        cursor.execute("""
            SELECT satis_turu, yil, model, ay, SUM(kurgu_hedefi)
            FROM [Yuce_PortalTest].[dbo].[AylikKurguHedefi]
            WHERE is_deleted = 0
            GROUP BY satis_turu, yil, model, ay
        """)
        aylik_rows = cursor.fetchall()

        for r in aylik_rows:
            satis_turu, yil, model, ay, toplam = r

            # HedefToplam'a upsert
            cursor.execute("""
                MERGE [Yuce_PortalTest].[dbo].[HedefToplam] AS t
                USING (SELECT ? AS tip, ? AS satis_turu, ? AS yil, 'model' AS boyut,
                            ? AS model, NULL AS ay, ? AS toplam) AS s
                ON (t.tip=s.tip AND t.satis_turu=s.satis_turu AND t.yil=s.yil
                    AND t.boyut='model' AND t.model=s.model)
                WHEN MATCHED THEN
                    UPDATE SET toplam=s.toplam, update_date=SYSDATETIME()
                WHEN NOT MATCHED THEN
                    INSERT (tip,satis_turu,yil,boyut,model,ay,toplam)
                    VALUES (s.tip,s.satis_turu,s.yil,'model',s.model,NULL,s.toplam);
            """, ('aylik', satis_turu, yil, model, toplam))

        # 2) YS Hedefleri
        cursor.execute("""
            SELECT satis_turu, yil, model, ay, SUM(yillik_hedef)
            FROM [Yuce_PortalTest].[dbo].[YillikHedefiYS]
            WHERE is_deleted = 0
            GROUP BY satis_turu, yil, model, ay
        """)
        ys_rows = cursor.fetchall()

        for r in ys_rows:
            satis_turu, yil, model, ay, toplam = r
            cursor.execute("""
                MERGE [Yuce_PortalTest].[dbo].[HedefToplam] AS t
                USING (SELECT ? AS tip, ? AS satis_turu, ? AS yil, 'model' AS boyut,
                            ? AS model, NULL AS ay, ? AS toplam) AS s
                ON (t.tip=s.tip AND t.satis_turu=s.satis_turu AND t.yil=s.yil
                    AND t.boyut='model' AND t.model=s.model)
                WHEN MATCHED THEN
                    UPDATE SET toplam=s.toplam, update_date=SYSDATETIME()
                WHEN NOT MATCHED THEN
                    INSERT (tip,satis_turu,yil,boyut,model,ay,toplam)
                    VALUES (s.tip,s.satis_turu,s.yil,'model',s.model,NULL,s.toplam);
            """, ('ys', satis_turu, yil, model, toplam))

        # 3) DS Hedefleri
        cursor.execute("""
            SELECT satis_turu, yil, model, ay, SUM(yillik_hedef)
            FROM [Yuce_PortalTest].[dbo].[YillikHedefiDS]
            WHERE is_deleted = 0
            GROUP BY satis_turu, yil, model, ay
        """)
        ds_rows = cursor.fetchall()

        for r in ds_rows:
            satis_turu, yil, model, ay, toplam = r
            cursor.execute("""
                MERGE [Yuce_PortalTest].[dbo].[HedefToplam] AS t
                USING (SELECT ? AS tip, ? AS satis_turu, ? AS yil, 'model' AS boyut,
                            ? AS model, NULL AS ay, ? AS toplam) AS s
                ON (t.tip=s.tip AND t.satis_turu=s.satis_turu AND t.yil=s.yil
                    AND t.boyut='model' AND t.model=s.model)
                WHEN MATCHED THEN
                    UPDATE SET toplam=s.toplam, update_date=SYSDATETIME()
                WHEN NOT MATCHED THEN
                    INSERT (tip,satis_turu,yil,boyut,model,ay,toplam)
                    VALUES (s.tip,s.satis_turu,s.yil,'model',s.model,NULL,s.toplam);
            """, ('ds', satis_turu, yil, model, toplam))

        
        # =====================================================
        # 4) AY BAZLI TOPLAM — Aylık Kurgu Hedefi
        # =====================================================
        cursor.execute("""
            SELECT satis_turu, yil, ay, SUM(kurgu_hedefi)
            FROM [Yuce_PortalTest].[dbo].[AylikKurguHedefi]
            WHERE is_deleted = 0
            GROUP BY satis_turu, yil, ay
        """)
        aylik_ay_rows = cursor.fetchall()

        for r in aylik_ay_rows:
            satis_turu, yil, ay, toplam = r
            cursor.execute("""
                MERGE [Yuce_PortalTest].[dbo].[HedefToplam] AS t
                USING (SELECT 'aylik' AS tip, ? AS satis_turu, ? AS yil, 'ay' AS boyut,
                              NULL AS model, ? AS ay, ? AS toplam) AS s
                ON (t.tip=s.tip AND t.satis_turu=s.satis_turu AND t.yil=s.yil
                    AND t.boyut='ay' AND t.ay=s.ay)
                WHEN MATCHED THEN
                    UPDATE SET toplam=s.toplam, update_date=SYSDATETIME()
                WHEN NOT MATCHED THEN
                    INSERT (tip,satis_turu,yil,boyut,model,ay,toplam)
                    VALUES ('aylik',?, ?, 'ay', NULL, ?, ?);
            """, (satis_turu, yil, ay, toplam, satis_turu, yil, ay, toplam))

        # =====================================================
        # 5) AY BAZLI TOPLAM — YS Hedefi
        # =====================================================
        cursor.execute("""
            SELECT satis_turu, yil, ay, SUM(yillik_hedef)
            FROM [Yuce_PortalTest].[dbo].[YillikHedefiYS]
            WHERE is_deleted = 0
            GROUP BY satis_turu, yil, ay
        """)
        ys_ay_rows = cursor.fetchall()

        for r in ys_ay_rows:
            satis_turu, yil, ay, toplam = r
            cursor.execute("""
                MERGE [Yuce_PortalTest].[dbo].[HedefToplam] AS t
                USING (SELECT 'ys' AS tip, ? AS satis_turu, ? AS yil, 'ay' AS boyut,
                              NULL AS model, ? AS ay, ? AS toplam) AS s
                ON (t.tip=s.tip AND t.satis_turu=s.satis_turu AND t.yil=s.yil
                    AND t.boyut='ay' AND t.ay=s.ay)
                WHEN MATCHED THEN
                    UPDATE SET toplam=s.toplam, update_date=SYSDATETIME()
                WHEN NOT MATCHED THEN
                    INSERT (tip,satis_turu,yil,boyut,model,ay,toplam)
                    VALUES ('ys',?, ?, 'ay', NULL, ?, ?);
            """, (satis_turu, yil, ay, toplam, satis_turu, yil, ay, toplam))

        # =====================================================
        # 6) AY BAZLI TOPLAM — DS Hedefi
        # =====================================================
        cursor.execute("""
            SELECT satis_turu, yil, ay, SUM(yillik_hedef)
            FROM [Yuce_PortalTest].[dbo].[YillikHedefiDS]
            WHERE is_deleted = 0
            GROUP BY satis_turu, yil, ay
        """)
        ds_ay_rows = cursor.fetchall()

        for r in ds_ay_rows:
            satis_turu, yil, ay, toplam = r
            cursor.execute("""
                MERGE [Yuce_PortalTest].[dbo].[HedefToplam] AS t
                USING (SELECT 'ds' AS tip, ? AS satis_turu, ? AS yil, 'ay' AS boyut,
                              NULL AS model, ? AS ay, ? AS toplam) AS s
                ON (t.tip=s.tip AND t.satis_turu=s.satis_turu AND t.yil=s.yil
                    AND t.boyut='ay' AND t.ay=s.ay)
                WHEN MATCHED THEN
                    UPDATE SET toplam=s.toplam, update_date=SYSDATETIME()
                WHEN NOT MATCHED THEN
                    INSERT (tip,satis_turu,yil,boyut,model,ay,toplam)
                    VALUES ('ds',?, ?, 'ay', NULL, ?, ?);
            """, (satis_turu, yil, ay, toplam, satis_turu, yil, ay, toplam))


        conn.commit()
        cursor.close()




