@app.route("/ssh_hedef/excel_current", methods=["GET"])
@login_required
def ssh_hedef_excel_current_download():
    from openpyxl import load_workbook
    template_path = os.path.join(app.root_path, "static", "ssh_hedef_excel", "ssh_hedef_excel.xlsx")
    if not os.path.exists(template_path):
        return jsonify({"ok": False, "error": "Şablon Excel bulunamadı"}), 404

    wb = load_workbook(template_path)

    # Yıl: query param varsa onu al, yoksa şablondaki A1
    year_q = request.args.get("year")
    if year_q:
        try:
            yil = int(str(year_q).strip())
        except:
            return jsonify({"ok": False, "error": "year parametresi geçersiz"}), 400
    else:
        # şablonun ilk sheet A1 yıl bilgisi içeriyor (ör: 2026)
        first_ws = wb[wb.sheetnames[0]]
        try:
            yil = int(first_ws["A1"].value)
        except:
            yil = 2026  # fallback

    # Sheet -> HedefTuru mapping
    sheet_map = {
        "is_emri": 1,        # isemri
        "parca_satis": 2,    # parca
        "aksesuar_satis": 3  # aksesuar
    }

    # Ay kolonları (C=Ocak ... N=Aralık)
    month_to_col = {m: (2 + m) for m in range(1, 13)}  # 1->3(C), 12->14(N)

    # DB’den verileri çek
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()
    try:
        cursor.execute("""
            SELECT YS_code, HedefTuru, Ay, Deger
            FROM dbo.ServisHedef
            WHERE Yil = ?
        """, yil)

        # (ys_code, hedef_turu, ay) -> deger
        data_map = {}
        for r in cursor.fetchall():
            ys = str(r.YS_code).strip() if r.YS_code is not None else ""
            tur = int(r.HedefTuru)
            ay = int(r.Ay)
            deger = None if r.Deger is None else int(r.Deger)
            if ys and 1 <= ay <= 12 and tur in (1, 2, 3):
                data_map[(ys, tur, ay)] = deger
    finally:
        try: cursor.close()
        except: pass
        try: conn.close()
        except: pass

    # Şablonu doldur
    for sheet_name, tur in sheet_map.items():
        if sheet_name not in wb.sheetnames:
            continue

        ws = wb[sheet_name]

        # Yıl hücresini güncelle (A1)
        ws["A1"].value = yil

        # Satır 2’den itibaren: A=DealerName, B=YS Kodu
        for row in range(2, ws.max_row + 1):
            ys_val = ws.cell(row=row, column=2).value  # B sütunu
            if ys_val is None or str(ys_val).strip() == "":
                # Şablonun altı boşsa kır (istersen continue yapabilirsin)
                continue

            ys_code = str(ys_val).strip()

            # Ocak..Aralık (C..N)
            for ay in range(1, 13):
                col = month_to_col[ay]
                v = data_map.get((ys_code, tur, ay), None)

                # İstersen boş kalsın: None
                ws.cell(row=row, column=col).value = v

    # Memory’e yazıp indir
    out = io.BytesIO()
    wb.save(out)
    out.seek(0)

    filename = f"ssh_hedef_onayli_{yil}.xlsx"
    return send_file(
        out,
        as_attachment=True,
        download_name=filename,
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
    )

SHEETS_TO_TUR = {
    "is_emri": "isemri",
    "parca_satis": "parca",
    "aksesuar_satis": "aksesuar",
}

MONTHS_TR = ["Ocak","Şubat","Mart","Nisan","Mayıs","Haziran","Temmuz","Ağustos","Eylül","Ekim","Kasım","Aralık"]

def _parse_excel_int(v):
    if v is None:
        return None
    if isinstance(v, (int, float)):
        return int(v)
    s = str(v).replace(" ", "").strip()
    if s == "":
        return None
    try:
        return int(float(s))
    except:
        return None

@app.route("/ssh_hedef/excel_upload", methods=["POST"])
@login_required
def ssh_hedef_excel_upload():
    from openpyxl import load_workbook
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()
    username = session["username"]

    try:
        f = request.files.get("file")
        if not f or f.filename == "":
            return jsonify({"ok": False, "error": "Dosya seçilmedi (file)"}), 400

        filename = secure_filename(f.filename.lower())
        if not filename.endswith(".xlsx"):
            return jsonify({"ok": False, "error": "Sadece .xlsx kabul edilir"}), 400

        # Excel'i memory'den oku
        data = f.read()
        if not data:
            return jsonify({"ok": False, "error": "Dosya boş"}), 400

        wb = load_workbook(io.BytesIO(data), data_only=True)

        # Bayi eşleştirme: YS_code -> DealerID
        cursor.execute("""
            SELECT ID, YS_code
            FROM dbo.Bayiiler
            WHERE isActive = 1
        """)
        ys_to_dealer = {}
        for r in cursor.fetchall():
            ys = str(r.YS_code).strip() if r.YS_code is not None else ""
            if ys:
                ys_to_dealer[ys] = int(r.ID)

        items = []
        errors = []
        total_cells_read = 0
        total_cells_used = 0

        for sheet_name, tur_str in SHEETS_TO_TUR.items():
            if sheet_name not in wb.sheetnames:
                errors.append(f"Sheet bulunamadı: {sheet_name}")
                continue

            ws = wb[sheet_name]

            # A1: yıl
            yil = _parse_excel_int(ws["A1"].value)
            if not yil or yil < 2000:
                errors.append(f"{sheet_name}: A1 yıl hatalı/boş")
                continue

            # Header satırı: B1 = "YS Kodu", C1..N1 aylar
            # Satır 2'den itibaren veri
            for row in range(2, ws.max_row + 1):
                dealer_name = ws.cell(row=row, column=1).value  # A
                ys_code_val = ws.cell(row=row, column=2).value  # B
                ys_code = "" if ys_code_val is None else str(ys_code_val).strip()

                if not ys_code:
                    # YS yoksa satırı geç
                    continue

                dealer_id = ys_to_dealer.get(ys_code)
                if not dealer_id:
                    errors.append(f"{sheet_name}: YS_code eşleşmedi: {ys_code} (satır {row}, bayi={dealer_name})")
                    continue

                # C..N = Ocak..Aralık (12 ay)
                for i, month_name in enumerate(MONTHS_TR, start=1):
                    col = 2 + i  # C=3
                    cell_val = ws.cell(row=row, column=col).value
                    total_cells_read += 1

                    v = _parse_excel_int(cell_val)
                    if v is None:
                        # boş => skip (değişiklik yok)
                        continue

                    ay = i
                    total_cells_used += 1
                    items.append({
                        "dealer_id": dealer_id,
                        "ys_code": ys_code,
                        "tur": tur_str,
                        "yil": yil,
                        "ay": ay,
                        "value": int(v)
                    })

        if not items:
            return jsonify({
                "ok": False,
                "error": "Excel içinde gönderilecek (dolu) hücre bulunamadı",
                "errors": errors
            }), 400

        # Change request oluştur
        cursor.execute("""
            INSERT INTO dbo.ServisHedefChangeRequest
            (Status, CreatedAt, CreatedBy, ApproverUser, ReviewNote)
            OUTPUT INSERTED.RequestID
            VALUES (0, SYSDATETIME(), ?, 'sevvalo', ?)
        """, username, f"Excel upload: {filename}")
        req_id = int(cursor.fetchone()[0])

        detail_sql = """
            INSERT INTO dbo.ServisHedefChangeDetail
            (RequestID, DealerID, YS_code, HedefTuru, Yil, Ay, CurrentDeger, ProposedDeger, CreatedAt, CreatedBy)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, SYSDATETIME(), ?)
        """

        inserted = 0
        skipped_same = 0

        # upsert değil; detay tablosuna yazıyoruz.
        # CurrentDeger'ı ServisHedef'ten çekiyoruz (senin POST mantığın gibi)
        for it in items:
            dealer_id = int(it["dealer_id"])
            ys_code = it["ys_code"]
            tur = _tur_to_int(it["tur"])
            yil = int(it["yil"])
            ay = int(it["ay"])
            val = int(it["value"])

            cursor.execute("""
                SELECT Deger
                FROM dbo.ServisHedef
                WHERE DealerID=? AND HedefTuru=? AND Yil=? AND Ay=?
            """, dealer_id, tur, yil, ay)
            row = cursor.fetchone()
            current_val = int(row[0]) if row and row[0] is not None else None

            # İstersen burada "aynıysa yazma" filtresi yapabilirsin:
            if current_val is not None and int(current_val) == int(val):
                skipped_same += 1
                continue

            try:
                cursor.execute(detail_sql, req_id, dealer_id, ys_code, tur, yil, ay, current_val, val, username)
                inserted += 1
            except pyodbc.IntegrityError:
                # aynı request içinde aynı hücre tekrar geldiyse skip
                pass

        if inserted == 0:
            conn.rollback()
            return jsonify({
                "ok": False,
                "error": "Tüm dolu hücreler mevcut değerle aynı (değişiklik yok). Request açılmadı.",
                "skipped_same": skipped_same,
                "errors": errors
            }), 400

        conn.commit()
        return jsonify({
            "ok": True,
            "request_id": req_id,
            "inserted_cells": inserted,
            "skipped_same": skipped_same,
            "total_cells_read": total_cells_read,
            "total_cells_used": total_cells_used,
            "errors": errors
        })

    except Exception as e:
        try:
            conn.rollback()
        except:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500

    finally:
        try: cursor.close()
        except: pass
        try: conn.close()
        except: pass

@app.route("/genel_hedef", methods=["GET", "POST"])
@login_required
def genel_hedef():
    form = GenelHedefForm(request.form)

    if request.method == "POST":
        if form.validate():
            hedef_konusu = form.hedef_konusu.data.strip()
            departman = form.Departman.data
            hedef = form.Hedef.data  # DecimalField -> Decimal

            conn = pyodbc.connect(YA_2El_AracSatis)
            cur = conn.cursor()
            cur.execute("""
                INSERT INTO dbo.GenelHedefler (hedef_konusu, departman, hedef, aktif_pasif, updated_at, updated_by)
                VALUES (?, ?, ?, 1, SYSDATETIME(), ?)
            """, (hedef_konusu, departman, float(hedef), getattr(request, "remote_user", None) or "system"))
            conn.commit()
            conn.close()

            flash("Genel hedef eklendi.", "success")
            return redirect(url_for("genel_hedef"))
        else:
            flash("Form hatalı. Lütfen alanları kontrol edin.", "danger")

    # TABLO VERİSİ (GET)
    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    cur.execute("""
        SELECT id, hedef_konusu, departman, hedef, aktif_pasif, aciklama
        FROM dbo.GenelHedefler
        ORDER BY id DESC
    """)
    rows = cur.fetchall()
    conn.close()

    # rows: pyodbc.Row -> template'de indexleyeceğiz
    return render_template("genel_hedefler.html", form=form, hedefler=rows)

@app.route("/update_genel_hedef", methods=["POST"])
@login_required
def update_genel_hedef():
    data = request.get_json(force=True)  # [{id, hedef_konusu, departman, hedef, aktif_pasif, aciklama}, ...]

    if not isinstance(data, list):
        return jsonify({"ok": False, "message": "Invalid payload"}), 400

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()

    username = getattr(request, "remote_user", None) or "system"

    for item in data:
        try:
            rid = int(item.get("id"))
            hedef_konusu = (item.get("hedef_konusu") or "").strip()
            departman = (item.get("departman") or "").strip()
            hedef = item.get("hedef")
            aktif_pasif = 1 if item.get("aktif_pasif") in (1, True, "1", "true") else 0
            aciklama = item.get("aciklama")

            # hedef numeric'e çevrim (boş gelirse DB'deki kalsın istemiyorsan burada kontrol ekleriz)
            hedef_val = None
            if hedef is not None and str(hedef).strip() != "":
                hedef_val = Decimal(str(hedef))

            cur.execute("""
                UPDATE dbo.GenelHedefler
                SET
                    hedef_konusu = ?,
                    departman    = ?,
                    hedef        = ?,
                    aktif_pasif  = ?,
                    aciklama     = ?,
                    updated_at   = SYSDATETIME(),
                    updated_by   = ?
                WHERE id = ?
            """, (hedef_konusu, departman, float(hedef_val) if hedef_val is not None else 0.0, aktif_pasif, aciklama, username, rid))

        except Exception as e:
            conn.rollback()
            conn.close()
            return jsonify({"ok": False, "message": f"Row update failed: {e}"}), 400

    conn.commit()
    conn.close()
    return jsonify({"ok": True})

