@app.route('/api/otomotiv_haberleri/aktif_pasif', methods=['POST'])
@login_required
def update_is_active():
    payload = request.get_json(force=True)

    if not isinstance(payload, list):
        return jsonify({"status": "error", "msg": "Payload must be a list"}), 400

    rows_to_update = []
    for item in payload:
        try:
            pk = int(item["id"])
        except (KeyError, ValueError, TypeError):
            continue

        active_flag = 1 if item.get("is_active") else 0
        rows_to_update.append((active_flag, pk))

    if not rows_to_update:
        return jsonify({"status": "error", "msg": "No valid rows"}), 400

    try:
        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()

        cursor.executemany(
            """
            UPDATE [Yuce_Portal].[dbo].[Otomotiv_Haberleri]
            SET is_active = ?
            WHERE ID = ?
            """,
            rows_to_update)
        conn.commit()
        cursor.close()
        return jsonify({"status": "ok", "updated": len(rows_to_update)}), 200

    except Exception as e:
        if conn:
            conn.rollback()
        return jsonify({"status": "error", "msg": str(e)}), 500

    finally:
        if conn:
            conn.close()

