@app.route("/jato_excel_toDB_func")
@login_required
def run_jato_upd():
    from jato_excel_toDB import Jato_excel_toDB, find_excel_files

    ortak_path = r"Y:\YUCE AUTO GENEL\Urun_Jato_Guncelleme"

    jato_excels = find_excel_files(r"Y:\YUCE AUTO GENEL\Urun_Jato_Guncelleme")

    if len(jato_excels) == 0:
        flash(r'"Y:\YUCE AUTO GENEL\Urun_Jato_Guncelleme" Dosyasında Jato exceli bulunamadı.', "danger")
        return render_template("jato_excel_toDB.html")
    else:
        excel_tot_paths = []
        for jato_excel in jato_excels:
            excel_tot_paths.append(ortak_path + r"\ ".replace(" ","") + jato_excel)
        
