@app.route("/pdf_comparison", methods = ["GET", "POST"])
@login_required
def pdf_comparison():
    if not PDF_COMPARISON_AVAILABLE:
        flash("PDF karşılaştırma özelliği projeden kaldırıldı.", "warning")
        return redirect(url_for("index"))
    form = pdf_comparison_Form(request.form)
    hide_pdf_form = False
    show_comparison_area = False
    if request.method == "GET":
        Write_Log_ToDB(session.get('username'), "GET", "/pdf_comparison", 0)
        return render_template("pdf_comparison.html", form=form, show_comparison_area=show_comparison_area)
    elif request.method == "POST":
        file1 = form.file1.data
        file2 = form.file2.data
        file1 = request.files['file1']
        file2 =  request.files['file2']

        if file1:  # Check if a file was uploaded
            file1name = secure_filename(file1.filename)
            file1.save(os.path.join('pdf_comparison', 'pdfs_fromUsers', file1name))
        else:
            Write_Log_ToDB(session.get('username'), "POST", "/pdf_comparison", 0, "Error: File1 empty.")
            flash("Her iki PDF ayrı ayrı yüklenmelidir.", "danger")
            return redirect(url_for("pdf_comparison"))
        if file2:  # Check if a file was uploaded
            file2name = secure_filename(file2.filename)
            file2.save(os.path.join('pdf_comparison', 'pdfs_fromUsers', file2name))
        else:
            Write_Log_ToDB(session.get('username'), "POST", "/pdf_comparison", 0, "Error: File2 empty.")
            flash("Her iki PDF ayrı ayrı yüklenmelidir.", "danger")
            return redirect(url_for("pdf_comparison"))
        
        if file1name == file2name:
            Write_Log_ToDB(session.get('username'), "POST", "/pdf_comparison", 0, "Error: File1 and File2 are the same.")
            flash("Yüklenen 2 dosyanın isimleri farklı olmalıdır!", "danger")
            return redirect(url_for("pdf_comparison"))
        
        pdf1 = r"C:\Users\yuceappadmin\Documents\GitHub\RPA-Projects\pdf_comparison\pdfs_fromUsers" + r"\{}".format(file1name)
        pdf2 = r"C:\Users\yuceappadmin\Documents\GitHub\RPA-Projects\pdf_comparison\pdfs_fromUsers" + r"\{}".format(file2name)
        
        similarity_percentage, different_words_count, coloured_text1, coloured_text2 = pdf_comparison_complete(pdf1, pdf2)

        hide_pdf_form = True
        show_comparison_area = True

        os.remove(pdf1)
        os.remove(pdf2)

        similarity_percentage = round(similarity_percentage, 2)

        Write_Log_ToDB(session.get('username'), "POST", "/pdf_comparison", 0, "Success")
        flash("PDF karşılaştırma işlemi başarıyla gerçekleşti.", "success")
        return render_template("pdf_comparison.html", form=form, similarity_percentage=similarity_percentage, different_words_count=different_words_count, coloured_text1=coloured_text1, coloured_text2=coloured_text2, confetti="true", hide_pdf_form=hide_pdf_form, show_comparison_area=show_comparison_area)

