    if request.method == "GET":
        query_to_request_userdata = """
            SELECT TOP (1000) 
                u.[namee],
                u.[surnamee],
                FORMAT(u.[last_loginDate], 'dd.MM.yyyy') AS last_loginDate,
                d.[dealerName],
                DATEDIFF(day, u.[last_loginDate], GETDATE()) AS days_since_last_login
            FROM [Garanti_Imha].[dbo].[users] u
            JOIN [Garanti_Imha].[dbo].[Dealers] d
            ON u.[bayiisi_ID] = d.[ID]
            WHERE u.[bayiisi_ID] != 100 
            AND u.[bayiisi_ID] != 50
            ORDER BY u.[last_loginDate] DESC;
        """
        connection = pypyodbc.connect(Garanti_imha_DB)
        cursor = connection.cursor()
        cursor.execute(query_to_request_userdata)
        users_result = cursor.fetchall()  # Fetch all results into a list
        cursor.close()
        connection.close()
        Write_Log_ToDB(session.get('username'), "GET", "/garanti_imha_kullanici_detay_raporu_cekme", 0)
        return render_template("garanti_imha_raporcekme.html", users_result=users_result, form=form)
    
