@app.route("/2.El_Arac_ekrani", methods=["GET"])
@login_required
def Ikinci_El_Arac():
    form = bayii_user_teklif_verme_Form(request.form)
    Bayiisi_ID = session["Bayiisi_ID"]
    
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    
    # Query to get all cars, check if the user has already placed a bid, and get the Gonderildi status
    query = f"""
    SELECT cars.*, 
        FORMAT(cars.[deadline], 'dd.MM.yyyy') AS deadline,
        ISNULL(t.BidAmount, 0) AS BidAmount,
        ISNULL(t.Gonderildi, 0) AS Gonderildi,
        t.Aciklama,
        photos.[path_photo_1],
        photos.[path_photo_2],
        photos.[path_photo_3],
        photos.[path_photo_4],
        photos.[path_photo_5],
        photos.[path_AracTeklifForm],
        ISNULL(log.[TeklifVerClicked], 0) AS TeklifVerClicked,
        t.dealerID
    FROM [YA_2El_AracSatis].[dbo].[Araclar] cars
    LEFT JOIN (
        SELECT AracID, Teklif AS BidAmount, Gonderildi, Aciklama, ID, dealerID
        FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler]
        WHERE dealerID = {Bayiisi_ID}
    ) t ON cars.id = t.AracID
    LEFT JOIN [YA_2El_AracSatis].[dbo].[Arac_Photos] photos
        ON cars.[Arac_Plaka] = photos.[Plaka]
    LEFT JOIN [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] log
        ON t.ID = log.[Teklif_ID]
    WHERE cars.active_onsale = 1
    AND (',' + cars.onsale_dealers + ',') LIKE '%,{Bayiisi_ID},%';
        """
    cursor.execute(query)
    results = cursor.fetchall()
    cursor.close()
    connection.close()
    
    abc = []
    results_tobe_sent = []
    for result in results:
        #print(result[12])
        result[6] = format_with_period(result[6])
        result[7] = format_with_period(result[7])
        if result[26] == None or result[26] == Bayiisi_ID:
            if result[17] != 1:
                results_tobe_sent.append(result)
                abc.append(result[17])
        locale.setlocale(locale.LC_TIME, "en_US.UTF-8")
        result[12] = result[12].strftime("%b %d, %Y %H:%M:%S")
    
    if len(results_tobe_sent) != 0:
        existance = True
    elif len(results_tobe_sent) == 0:
        existance = False
    
    if 0 in abc:
        btn_mustbe_enabled = 1
    else:
        btn_mustbe_enabled = 0

    Write_Log_ToDB(session.get('email'), "GET", "/2.El_Arac_ekrani", 0)

    return render_template("Arac_2El_Ekrani.html", results=results_tobe_sent, form=form, existance=existance, btn_mustbe_enabled=btn_mustbe_enabled)

@app.route("/bayi_2.elAraclar_sonuclar", methods=["GET"])
@login_required
def ihalesi_Tamamlanmis_Araclar():
    Bayiisi_ID = session["Bayiisi_ID"]
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    query = f"""
    SELECT TOP (1000) [id]
        ,[Arac_Plaka]
        ,[Model_Yil]
        ,[Yil]
        ,[Renk]
        ,[KM]
        ,[Fiyat]
    FROM [YA_2El_AracSatis].[dbo].[Araclar]
    WHERE active_onsale > 3
    """
    cursor.execute(query)
    results = cursor.fetchall()

    for result in results:
        result[6] =  format_with_period(result[6]) + " TL"
    

    query2 = f"""
    SELECT 
        t.[ID] AS TeklifID,
        t.[dealerID],
        t.[AracID],
        t.[Teklif],
        t.[Bidding_Date],
        t.[Gonderildi],
        a.[Arac_Plaka],
        a.[Model_Yil],
        a.[Yil],
        a.[Renk],
        a.[KM],
        a.[Fiyat]
    FROM 
        [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler] t
    INNER JOIN 
        [YA_2El_AracSatis].[dbo].[Araclar] a
    ON 
        t.[AracID] = a.[id]
    WHERE 
        t.[dealerID] = {Bayiisi_ID};
    """
    cursor.execute(query2)
    current_bayi_offers = cursor.fetchall()
    cursor.close()
    connection.close()
    current_bayi_offers_asdict = {}
    for offer in current_bayi_offers:
        current_bayi_offers_asdict[offer[6]] = format_with_period(offer[3]) + " TL"
    
    Write_Log_ToDB(session.get('email'), "GET", "/bayi_2.elAraclar_sonuclar", 0)

    return render_template('ihalesi_tamamlanmis_araclar_bayiview.html', results=results, current_bayi_offers_asdict=current_bayi_offers_asdict)

@app.route('/send_bids_fromBayii', methods=['POST'])
@login_required
def handle_api_request():
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data received"}), 400
    
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    
    for entry in data:
        textbox_id = entry['id']
        value = entry['value'] if entry['value'] else 0
        bayiisi_id = entry['bayiisi_id']
        aciklama = entry['aciklama']
        bidderID = entry['bidderID']
        called_btn = entry['buttonType']
        isChecked = entry['isChecked']

        dealer_id = session.get('Bayiisi_ID')

        # Check if a bid already exists for this user and car
        check_query = f"""
            SELECT COUNT(*) 
            FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler] 
            WHERE [dealerID] = {bayiisi_id} AND [AracID] = {textbox_id};
        """

        cursor.execute(check_query)
        bid_exists = cursor.fetchone()[0]
        
        if bid_exists != 0:
            # Update existing bid
            update_query = f"""
                UPDATE [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler]
                SET [Teklif] = ?, [Bidding_Date] = GETDATE(), [Aciklama] = '{aciklama}'
                WHERE [dealerID] = ? AND [AracID] = ? AND [Gonderildi] != 1;
            """
            cursor.execute(update_query, (value, bayiisi_id, textbox_id))
        else:
            # Insert new bid
            if aciklama == '-':
                aciklama = None
            insert_query = f"""
                INSERT INTO [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler] 
                ([dealerID], [AracID], [Teklif], [Bidding_Date], [Gonderildi], [Aciklama], [bidder_ID])
                VALUES ({bayiisi_id}, {textbox_id}, {value}, GETDATE(), 0, '{aciklama}', {bidderID});
            """
            cursor.execute(insert_query)
        
        
        query_for_id = f"SELECT ID FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler] WHERE dealerID={bayiisi_id} AND AracID={textbox_id} and bidder_ID={bidderID}"
        cursor.execute(query_for_id)
        teklif_id = cursor.fetchone()

        select_price_query = f"SELECT [Fiyat] FROM [YA_2El_AracSatis].[dbo].[Araclar] WHERE id={textbox_id};"
        cursor.execute(select_price_query)
        price_of_car = cursor.fetchone()[0]
        # Updates the price of the car in "[YA_2El_AracSatis].[dbo].[Araclar]" if the price entered is above the price of the car ([Fiyat] column)
        if called_btn == "Gonder":
            if value != None:
                if price_of_car == None:
                    price_of_car = 0
                value = int(value)
                if value > price_of_car:
                    update_priceofcar_query = f"UPDATE [YA_2El_AracSatis].[dbo].[Araclar] SET [Fiyat] = {value} WHERE id = {textbox_id};"
                    cursor.execute(update_priceofcar_query)
            check_query = f"SELECT * FROM [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] WHERE Teklif_ID={teklif_id[0]};"
            cursor.execute(check_query)
            check_res = cursor.fetchone()
            if check_res == None:
                if isChecked == True:
                    teklifver_query = f"INSERT INTO [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] ([TeklifVerClicked], [Teklif_ID], [dealerID]) VALUES (1, {teklif_id[0]}, {dealer_id});"
                if isChecked == False:
                    teklifver_query = f"INSERT INTO [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] ([TeklifVerClicked], [Teklif_ID], [dealerID]) VALUES (0, {teklif_id[0]}, {dealer_id});"
            else:
                if isChecked == True:
                    teklifver_query = f"UPDATE [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] SET TeklifVerClicked=1 WHERE Teklif_ID = {teklif_id[0]} AND [dealerID]={dealer_id}"
                if isChecked == False:
                    teklifver_query = f"UPDATE [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] SET TeklifVerClicked=0 WHERE Teklif_ID = {teklif_id[0]} AND [dealerID]={dealer_id}"
            
            cursor.execute(teklifver_query)
        elif called_btn == "Kaydet":
            if value != None:
                check_query = f"SELECT * FROM [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] WHERE Teklif_ID={teklif_id[0]}  AND dealerID={dealer_id};"
                cursor.execute(check_query)
                check_res = cursor.fetchone()
                if check_res == None:
                    if isChecked == True:
                        teklifver_query = f"INSERT INTO [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] ([TeklifVerClicked], [Teklif_ID], [dealerID]) VALUES (1, {teklif_id[0]}, {dealer_id});"
                    if isChecked == False:
                        teklifver_query = f"INSERT INTO [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] ([TeklifVerClicked], [Teklif_ID], [dealerID]) VALUES (0, {teklif_id[0]}, {dealer_id});"
                else:
                    if isChecked == True:
                        teklifver_query = f"UPDATE [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] SET TeklifVerClicked=1 WHERE Teklif_ID = {teklif_id[0]} AND [dealerID]={dealer_id}"
                    if isChecked == False:
                        teklifver_query = f"UPDATE [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] SET TeklifVerClicked=0 WHERE Teklif_ID = {teklif_id[0]} AND [dealerID]={dealer_id}"

                cursor.execute(teklifver_query)
            else:
                pass
    
    connection.commit()
    connection.close()

    Write_Log_ToDB(session.get('email'), "POST", "/send_bids_fromBayii", 0, f"DealerID: {dealer_id} took an action")

    return jsonify({"message": "Data processed successfully"}), 200
    
@app.route('/get_user_bids', methods=['GET'])
@login_required
def get_user_bids():
    bayiisi_id = session.get("Bayiisi_ID")
    
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    
    # Query to get the bids made by the user
    query = f"""
        SELECT [AracID], [Teklif]
        FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler]
        WHERE [dealerID] = ?;
    """
    cursor.execute(query, bayiisi_id)
    results = cursor.fetchall()
    
    bids = {str(row.AracID): row.Teklif for row in results}
    
    cursor.close()
    connection.close()
    
    return jsonify(bids), 200

