@app.route('/download_teklifler_excel', methods=['GET'])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def download_teklifler_excel():
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    # 1) Query for all offers, sorted by PartyID, Arac_Plaka, dealerName
    query = """
        SELECT 
            a.[PartyID],
            a.[Yil],
            a.[Model_Yil],
            a.[Arac_Plaka],
            a.[Renk],
            a.[KM],
            t.[Teklif],
            b.[dealerName],
            t.[Bidding_Date]
        FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler] t
        INNER JOIN [YA_2El_AracSatis].[dbo].[Araclar] a
            ON t.[AracID] = a.[id]
        INNER JOIN [YA_2El_AracSatis].[dbo].[Bayiiler] b
            ON t.[dealerID] = b.[ID]
        WHERE a.[active_onsale] <> 1
        ORDER BY a.[PartyID], a.[Arac_Plaka], b.[dealerName];
    """
    cursor.execute(query)
    offers = cursor.fetchall()
    offers = [list(row) for row in offers]
    columns = [column[0] for column in cursor.description]
    offers_df = pd.DataFrame(offers, columns=columns)

    # 2) Query for best offers, sorted similarly
    best_offers_query = """
        WITH HighestOffers AS (
            SELECT 
                [AracID], 
                MAX([Teklif]) AS Highest_Offer
            FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler]
            WHERE [Teklif] > 0
            GROUP BY [AracID]
        )
        SELECT 
            a.[PartyID],
            a.[Yil],
            a.[Model_Yil],
            a.[Arac_Plaka],
            a.[Renk],
            a.[KM],
            t.[Teklif],
            b.[dealerName],
            t.[Bidding_Date]
        FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler] t
        INNER JOIN HighestOffers ho 
            ON t.[AracID] = ho.[AracID] 
           AND t.[Teklif] = ho.Highest_Offer
        INNER JOIN [YA_2El_AracSatis].[dbo].[Araclar] a
            ON t.[AracID] = a.[id]
        INNER JOIN [YA_2El_AracSatis].[dbo].[Bayiiler] b
            ON t.[dealerID] = b.[ID]
        WHERE a.[active_onsale] <> 1
        ORDER BY a.[PartyID], a.[Arac_Plaka], b.[dealerName];
    """
    cursor.execute(best_offers_query)
    best_offers = cursor.fetchall()
    best_offers = [list(row) for row in best_offers]
    best_offer_columns = [column[0] for column in cursor.description]    
    best_offers_df = pd.DataFrame(best_offers, columns=best_offer_columns)

    # 3) Query for YA offers
    ya_offers_query = """
        SELECT
            a.[PartyID],
            a.[Yil],
            a.[Model_Yil],
            a.[Arac_Plaka],
            a.[Renk],
            a.[KM],
            t.[username],
            t.[Gonderme_Tarihi]
        FROM [YA_2El_AracSatis].[dbo].[Araclar] AS a
        INNER JOIN [YA_2El_AracSatis].[dbo].[YA_users_Teklifler] AS t
            ON t.[car_id] = a.[id]
        WHERE t.[ilgileniyor] = 1
        ORDER BY t.[Gonderme_Tarihi] DESC, a.[PartyID] ASC, a.[Arac_Plaka];
    """
    cursor.execute(ya_offers_query)
    ya_offers = cursor.fetchall()
    ya_offers = [list(row) for row in ya_offers]
    ya_offer_columns = [column[0] for column in cursor.description]    
    ya_offers_df = pd.DataFrame(ya_offers, columns=ya_offer_columns)

    # Combine the DataFrames (not strictly needed, but included per your original code)
    combined_df = pd.concat([offers_df, best_offers_df, ya_offers_df]) 

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        # Write to two separate sheets
        offers_df.to_excel(writer, index=False, sheet_name='Tüm Teklifler')
        best_offers_df.to_excel(writer, index=False, sheet_name='En Yüksek Teklifler')
        ya_offers_df.to_excel(writer, index=False, sheet_name='Yüce Auto Personel Teklifleri')

        workbook = writer.book
        offers_sheet = workbook['Tüm Teklifler']
        best_offers_sheet = workbook['En Yüksek Teklifler']
        ya_offers_sheet = workbook['Yüce Auto Personel Teklifleri']

        import openpyxl
        from openpyxl.styles import PatternFill, Font, Alignment, Border, Side

        offers_sheet.sheet_view.showGridLines = False
        best_offers_sheet.sheet_view.showGridLines = False
        ya_offers_sheet.sheet_view.showGridLines = False

        header_fill = PatternFill(start_color="0E3A2F", end_color="0E3A2F", fill_type="solid")
        header_font = Font(color="78FAAE", bold=True)
        center_alignment = Alignment(horizontal="center", vertical="center")

        # Format the header rows in both sheets
        for cell in offers_sheet[1]:
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = center_alignment

        for cell in best_offers_sheet[1]:
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = center_alignment

        for cell in ya_offers_sheet[1]:
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = center_alignment

        # Replace "None" with empty and center align all cells
        for row in offers_sheet.iter_rows():
            for cell in row:
                if cell.value == "None":
                    cell.value = ""
                cell.alignment = center_alignment

        for row in best_offers_sheet.iter_rows():
            for cell in row:
                if cell.value == "None":
                    cell.value = ""
                cell.alignment = center_alignment

        for row in ya_offers_sheet.iter_rows():
            for cell in row:
                if cell.value == "None":
                    cell.value = ""
                cell.alignment = center_alignment

        # Column widths
        offers_sheet.column_dimensions['A'].width = 10
        offers_sheet.column_dimensions['B'].width = 10
        offers_sheet.column_dimensions['C'].width = 50
        offers_sheet.column_dimensions['D'].width = 15
        offers_sheet.column_dimensions['E'].width = 30
        offers_sheet.column_dimensions['F'].width = 10
        offers_sheet.column_dimensions['G'].width = 15
        offers_sheet.column_dimensions['H'].width = 40
        offers_sheet.column_dimensions['I'].width = 20

        best_offers_sheet.column_dimensions['A'].width = 10
        best_offers_sheet.column_dimensions['B'].width = 10
        best_offers_sheet.column_dimensions['C'].width = 50
        best_offers_sheet.column_dimensions['D'].width = 15
        best_offers_sheet.column_dimensions['E'].width = 30
        best_offers_sheet.column_dimensions['F'].width = 10
        best_offers_sheet.column_dimensions['G'].width = 15
        best_offers_sheet.column_dimensions['H'].width = 40
        best_offers_sheet.column_dimensions['I'].width = 20

        ya_offers_sheet.column_dimensions['A'].width = 10
        ya_offers_sheet.column_dimensions['B'].width = 10
        ya_offers_sheet.column_dimensions['C'].width = 50
        ya_offers_sheet.column_dimensions['D'].width = 15
        ya_offers_sheet.column_dimensions['E'].width = 30
        ya_offers_sheet.column_dimensions['F'].width = 10
        ya_offers_sheet.column_dimensions['G'].width = 40
        ya_offers_sheet.column_dimensions['H'].width = 20

        # Rename headers
        offers_sheet['A1'] = "Süreç No"
        best_offers_sheet['A1'] = "Süreç No"
        ya_offers_sheet['A1'] = "Süreç No"

        offers_sheet['B1'] = "Model Yılı"
        best_offers_sheet['B1'] = "Model Yılı"
        ya_offers_sheet['B1'] = "Model Yılı"

        offers_sheet['C1'] = "Model"
        best_offers_sheet['C1'] = "Model"
        ya_offers_sheet['C1'] = "Model"

        offers_sheet['D1'] = "Plaka No"
        best_offers_sheet['D1'] = "Plaka No"
        ya_offers_sheet['D1'] = "Plaka No"

        offers_sheet['E1'] = "Renk"
        best_offers_sheet['E1'] = "Renk"
        ya_offers_sheet['E1'] = "Renk"

        offers_sheet['F1'] = "KM"
        best_offers_sheet['F1'] = "KM"
        ya_offers_sheet['F1'] = "KM"

        offers_sheet['G1'] = "Teklif"
        best_offers_sheet['G1'] = "Teklif"
        ya_offers_sheet['G1'] = "Kişi"

        offers_sheet['H1'] = "Bayi Adı"
        best_offers_sheet['H1'] = "Bayi Adı"
        ya_offers_sheet['H1'] = "Teklif Tarihi"

        offers_sheet['I1'] = "Teklif Tarihi"
        best_offers_sheet['I1'] = "Teklif Tarihi"

        # --- (3) ALTERNATING ROW COLORS FOR GROUPS OF Arac_Plaka ---
        color1 = PatternFill(start_color="E3E5E6", end_color="E3E5E6", fill_type="solid")
        color2 = PatternFill(start_color="FFFFFF", end_color="FFFFFF", fill_type="solid")

        def alternate_plaka_colors(sheet):
            """ Toggles fill color each time Arac_Plaka changes. 
                We assume Plaka is in column 4 => D 
                (A=1, B=2, C=3, D=4, etc.)
            """
            prev_plaka = None
            current_fill = color2  # so first new plaka will switch to color1

            # Start from row 2 because row 1 is header
            for row_idx in range(2, sheet.max_row + 1):
                plaka = sheet.cell(row=row_idx, column=4).value  # D column
                if plaka != prev_plaka:
                    # new group => flip fill
                    current_fill = color1 if current_fill == color2 else color2
                    prev_plaka = plaka

                # Apply current_fill to all cells in this row
                for cell in sheet[row_idx]:
                    cell.fill = current_fill

        # Apply row coloring to each sheet
        alternate_plaka_colors(offers_sheet)
        alternate_plaka_colors(best_offers_sheet)
        alternate_plaka_colors(ya_offers_sheet)

    # Move the cursor to the beginning of the file
    output.seek(0)

    Write_Log_ToDB(session.get('username'), "GET", "/download_teklifler_excel", 0, 
                   "User downloaded the excel file for the offers.")

    return send_file(
        output,
        as_attachment=True,
        download_name='YücePortal_2ElAracTeklifler.xlsx',
        mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    )

@app.route('/api/close_cars_to_bayi', methods=['POST'])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def close_cars_to_bayi():
    data = request.json  
    selected_cars = data.get('selected_cars', [])

    if not selected_cars:
        return jsonify({'success': False, 'message': 'No cars selected.'})

    try:
        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        # Check if all selected cars have active_onsale = 1
        check_query = "SELECT [Arac_Plaka], [active_onsale] FROM [YA_2El_AracSatis].[dbo].[Araclar] WHERE [id] IN ({})".format(','.join(['?'] * len(selected_cars)))
        cursor.execute(check_query, *selected_cars)
        results = cursor.fetchall()

        # Check if any car does not have active_onsale = 1
        invalid_cars = [row[0] for row in results if row[1] != 1]
        
        if invalid_cars:
            return jsonify({
                'success': False, 
                'message': 'Some cars do not have active_onsale = 1. Operation aborted.',
                'invalid_cars': invalid_cars  # Include the list of invalid cars in the response
            })

        # If all cars have active_onsale = 1, proceed with the update
        for car in selected_cars:
            update_query = "UPDATE [YA_2El_AracSatis].[dbo].[Araclar] SET [active_onsale] = 2 WHERE [id] = ?"
            cursor.execute(update_query, car)

        connection.commit()
        cursor.close()
        connection.close()

        Write_Log_ToDB(session.get('username'), "POST", "/api/close_cars_to_bayi", 0)

        return jsonify({'success': True, 'message': 'All selected cars updated successfully.'})
    
    except Exception as e:
        print(f"Error: {e}")
        return jsonify({'success': False, 'message': 'An error occurred.'})

