@app.route("/YuceAutoUser/SurecTamamlanmisAraclar", methods = ["GET", "POST"])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def YuceAutoUser_SurecTamamlanmisAraclar():
    page = request.args.get('page', 1, type=int)  # Get the current page from the query string, default to 1
    per_page = 50  # Number of records per page
    offset = (page - 1) * per_page

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    # Count total records
    count_query = "SELECT COUNT(*) FROM [YA_2El_AracSatis].[dbo].[Araclar] WHERE active_onsale=4"
    cursor.execute(count_query)
    total_cars = cursor.fetchone()[0]

    # Get records for the current page
    query = f"""
        SELECT [id], [onsale_dealers], [Arac_Plaka], [Model_Yil], [Yil], [Renk], [KM], [Fiyat], 
               [Servis_Gecmisi], [Eksper_Raporu], [creation_date], [active_onsale], [deadline], [PartyID]
        FROM [YA_2El_AracSatis].[dbo].[Araclar] 
        WHERE active_onsale=4
        ORDER BY PartyID DESC
        OFFSET {offset} ROWS FETCH NEXT {per_page} ROWS ONLY
    """
    cursor.execute(query)
    results = cursor.fetchall()

    # Format data for display
    for result in results:
        result[6] = format_with_period(result[6])
        result[7] = format_with_period(result[7])
        result[10] = result[10].strftime('%d.%m.%Y')
    
    # Calculate total pages
    total_pages = (total_cars + per_page - 1) // per_page  # Round up

    # views per party ID
    query_views = """
        WITH LatestDates AS
        (
            SELECT 
                PartyID
                ,MAX(creation_date) AS latest_creation_date
                ,MAX(deadline)      AS latest_deadline
                ,MAX(YA_deadline)   AS latest_YA_deadline
            FROM [YA_2El_AracSatis].[dbo].[Araclar]
            GROUP BY PartyID
        )
        SELECT
            d.PartyID
            -- Visitors to '/2.El_Arac_ekrani' between [latest_creation_date, latest_deadline]
            ,(
            SELECT COUNT(DISTINCT l.Username)
            FROM [Yuce_Portal].[dbo].[YP_users_log] l
            WHERE l.RequestLink = '/2.El_Arac_ekrani'
                AND l.RequestedDateTime BETWEEN d.latest_creation_date AND d.latest_deadline
            ) AS UniqueVisitorCount_2El_Arac_ekrani

            -- Visitors to '/Arac_2El_Ekrani_YA_Personel' between [deadline, YA_deadline]
            ,(
            SELECT COUNT(DISTINCT l.Username)
            FROM [Yuce_Portal].[dbo].[YP_users_log] l
            WHERE l.RequestLink = '/Arac_2El_Ekrani_YA_Personel'
                AND l.RequestedDateTime BETWEEN d.latest_deadline AND d.latest_YA_deadline
            ) AS UniqueVisitorCount_Arac_2El_Ekrani_YA_Personel
        FROM LatestDates d
        WHERE d.PartyID > 10
        ORDER BY d.PartyID;

        """

    cursor.execute(query_views)
    views = cursor.fetchall()

    cursor.close()
    connection.close()

    Write_Log_ToDB(session.get('username'), "GET", "/YuceAutoUser/SurecTamamlanmisAraclar", 0)

    return render_template("SurecTamamlanmisAraclar.html", results=results, page=page, total_pages=total_pages, views=views)

@app.route("/YuceAutoUser/SurecTamamlanmisAraclar/teklifler_bayii/<int:id>", methods = ["POST"])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def Arac2El_return_teklifler_bayii(id):
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    teklifler_query = f"""
    SELECT 
        t.ID AS Teklif_ID,
        t.dealerID,
        t.AracID,
        t.Teklif,
        t.Bidding_Date,
        t.Gonderildi,
        t.Aciklama,
        t.bidder_ID,
        log.TeklifVerClicked,
        log.dealerID AS LogDealerID,
        b.dealerName
    FROM [YA_2El_AracSatis].[dbo].[YA_2El_Arac_Teklifler] t
    JOIN [YA_2El_AracSatis].[dbo].[Arac_Teklifler_log] log
        ON t.ID = log.Teklif_ID
    JOIN [YA_2El_AracSatis].[dbo].[Bayiiler] b
        ON t.dealerID = b.ID
	WHERE t.AracID={id}
	ORDER BY t.Teklif DESC;
    """
    cursor.execute(teklifler_query)
    teklifler_from_bayii = cursor.fetchall()

    column_names = [desc[0] for desc in cursor.description]
    teklif_list = []
    teklifli_bayi_idler = []
    for teklif in teklifler_from_bayii:
        teklif_dict = dict(zip(column_names, teklif))
        teklif_dict['Bidding_Date'] = teklif_dict['Bidding_Date'].strftime("%d.%m.%Y %H:%M")
        if teklif_dict['TeklifVerClicked'] == 1:
            teklif_dict['TeklifVerClicked'] = "Evet"
        else:
            teklif_dict['TeklifVerClicked'] = "Hayır"

        #Teklif veren bayilerin ID'lerinin tutulduğu liste
        teklifli_bayi_idler.append(teklif_dict["LogDealerID"])
        teklif_list.append(teklif_dict)
    
    non_teklifed_query = f"""
    SELECT 
        b.ID AS Dealer_ID,
        b.dealerName
    FROM [YA_2El_AracSatis].[dbo].[Araclar] a
    JOIN [YA_2El_AracSatis].[dbo].[Bayiiler] b
        ON b.ID IN (SELECT value FROM STRING_SPLIT(a.onsale_dealers, ',')) WHERE a.id={id}
    """
    cursor.execute(non_teklifed_query)
    non_teklifed_result = cursor.fetchall()

    for nonteklif in non_teklifed_result:
        if nonteklif[0] not in teklifli_bayi_idler:
            dict_toappend = {'dealerName' : nonteklif[1] }
            teklif_list.append(dict_toappend)
    
    cursor.close()
    connection.close()
    
    return jsonify(teklif_list), 200

@app.route("/YuceAutoUser/SurecTamamlanmisAraclar/teklifler_YuceAuto/<int:id>", methods = ["POST"])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def Arac2El_return_teklifler_YuceAuto(id):
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    teklifler_query = f"""
    SELECT 
        A.id,
        A.Fiyat,
        Y.ID AS Teklif_ID,
        Y.username,
        Y.ilgileniyor,
        Y.Gonderme_Tarihi,
        Y.Aciklama,
        Y.Gonderildi
    FROM [YA_2El_AracSatis].[dbo].[Araclar] A
    INNER JOIN [YA_2El_AracSatis].[dbo].[YA_users_Teklifler] Y
        ON A.id = Y.car_id
        WHERE A.id = {id};
    """
    cursor.execute(teklifler_query)
    teklifler_from_ya = cursor.fetchall()

    column_names = [desc[0] for desc in cursor.description]
    teklif_list = []
    for teklif in teklifler_from_ya:
        teklif_dict = dict(zip(column_names, teklif))
        teklif_dict['Gonderme_Tarihi'] = teklif_dict['Gonderme_Tarihi'].strftime("%d.%m.%Y %H:%M")
        try:
            teklif_dict['Fiyat'] = teklif_dict['Fiyat'] + YA_price_increment
        except:
            pass
        if teklif_dict['ilgileniyor'] == 1:
            teklif_dict['ilgileniyor'] = "Evet"
        else:
            teklif_dict['ilgileniyor'] = "Hayır"
        teklif_list.append(teklif_dict)

    Write_Log_ToDB(session.get('username'), "POST", f"/YuceAutoUser/SurecTamamlanmisAraclar/teklifler_YuceAuto/{id}", 0, "User viewed Araç Details.")
    
    return jsonify(teklif_list), 200

