@app.route("/YuceAutoUser/Update_Mail_info", methods = ["GET", "POST"])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def update_mail_info():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No data provided'}), 400

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    mail_subject = None
    mail_body = None

    inserter = session.get("name") + " " + session.get("surname")

    for item in data:
        field_id = item.get('id')
        value = item.get('value')
        try:
            if '-to' in field_id:
                bayi_id = field_id.split('-to')[0]
                cursor.execute("""
                    UPDATE [YA_2El_AracSatis].[dbo].[Bayiiler]
                    SET [To] = ?
                    WHERE [ID] = ?;
                """, value, bayi_id)
            elif '-cc' in field_id:
                bayi_id = field_id.split('-cc')[0]
                cursor.execute("""
                    UPDATE [YA_2El_AracSatis].[dbo].[Bayiiler]
                    SET [Cc] = ?
                    WHERE [ID] = ?;
                """, value, bayi_id)
        except:
                try:
                    mail_subject = item.get('mailSubject')
                except:pass
                try:
                    mail_body = item.get('mailBody')
                except:pass
    cursor.execute("""
        UPDATE [YA_2El_AracSatis].[dbo].[Mail_Content]
        SET [Email_Subject] = ?, 
            [Email_Content] = ?, 
            [last_updated] = GETDATE(),
            [LastMan_Changed] = ?
        WHERE [id] = 1;  -- Update this condition as per your actual requirement
    """, mail_subject, mail_body, inserter)

    conn.commit()
    cursor.close()
    conn.close()

    return jsonify({'success': True, 'message': 'Mail information and content updated successfully'}), 200

# Ay isimlerinin numara olarak çevirilmesi
def month_name_to_number(month_name):
    months = {
        'Ocak': 1,
        'Şubat': 2,
        'Mart': 3,
        'Nisan': 4,
        'Mayıs': 5,
        'Haziran': 6,
        'Temmuz': 7,
        'Ağustos': 8,
        'Eylül': 9,
        'Ekim': 10,
        'Kasım': 11,
        'Aralık': 12
    }
    # Convert month name to number
    return months.get(month_name)

def month_number_to_name(month_number):
    months = {
        1: 'Ocak',
        2: 'Şubat',
        3: 'Mart',
        4: 'Nisan',
        5: 'Mayıs',
        6: 'Haziran',
        7: 'Temmuz',
        8: 'Ağustos',
        9: 'Eylül',
        10: 'Ekim',
        11: 'Kasım',
        12: 'Aralık'
    }
    # Convert month number to name
    return months.get(month_number, "Invalid Month")

