@app.route("/ys_faaliyet_raporu", methods = ["GET", "POST"])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def ys_faaliyet_raporu():
    form = ys_faaliyet_raporu_Form(request.form)

    if request.method == "GET":
        connection = oracledb.connect(dsn)
        cursor = connection.cursor()
        query = f"""
        SELECT
            YS.FIRM_CODE,
            MAX(CASE WHEN DR.REGION_TYPE = 'S' THEN DRC.REGION_CHIEF_FULL_NAME END) AS "Satış Bölge Yöneticisi",
            MAX(CASE WHEN DR.REGION_TYPE = 'L' THEN DRC.REGION_CHIEF_FULL_NAME END) AS "SSH Bölge Yöneticisi"
        FROM
            YUCE_DM.TBL_DW_GEN_DIM_DEALER YS
            INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION DR
                ON YS.DEALER_ID = DR.FK_DEALER_ID
            AND DR.REGION_TYPE IN ('S','L')
            INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION_CHIEF DRC
                ON DRC.FK_REGION_DEALER_ID = DR.REGION_DEALER_ID
            INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM GEN_FIRM
                ON GEN_FIRM.EDUCATION_FIRM_ID = YS.FK_EDUCATION_FIRM_ID
            LEFT JOIN YUCE_DM.TBL_DW_GEN_DIM_CITY_COUNTY CC
                ON CC.CODE = YS.FK_CITY_CODE
        WHERE
            YS.STATUS_EXPLANATION = 'Yürürlükte'
            AND YS.FIRM_CODE NOT IN ('YÜCE AUTO')
        GROUP BY
            YS.FK_EDUCATION_FIRM_ID, YS.FIRM_CODE, CC.CITY_NAME
        ORDER BY
            YS.FIRM_CODE ASC
        """
        cursor.execute(query)

        results = [tuple(row) for row in cursor.fetchall()]
        cursor.close()
        connection.close()

        Write_Log_ToDB(session.get('username'), "GET", "/ys_faaliyet_raporu", 0)

        return render_template("ys_faaliyet_raporu.html", form=form, results=results)
    
    if request.method == "POST":
        gorusme_tarihi = form.gorusme_tarihi.data
        bayi_adi = form.bayi_adi.data
        aday_adi = form.aday_adi.data
        cinsiyet = form.cinsiyet.data
        satis_servis = form.satis_servis.data
        aday_durumu = form.aday_durumu.data
        sinav_sayisal = form.sinav_sayisal.data
        sinav_sozel = form.sinav_sozel.data
        pozisyon_adi = form.pozisyon_adi.data
        aksiyon = form.aksiyon.data
        bolgeci = form.bolgeci.data
        ik_bolgeci = form.ik_bolgeci.data
        ise_baslama_tarihi = form.ise_baslama_tarihi.data
        isten_cikis_tarihi = form.isten_cikis_tarihi.data
        notlar = form.notlar.data
        cv = form.cv.data
        gorusme_baglam = form.gorusme_baglam.data

        cv_file = request.files.get("cv")

        if cv_file and cv_file.filename:
            moment = datetime.datetime.now().strftime("%Y-%m-%d %H-%M-%S")
            cv_name = f"{bayi_adi}_{moment}.{cv_file.filename.rsplit('.', 1)[-1]}"

            cv_file.save(f"C:/Users/yuceappadmin/Documents/GitHub/RPA-Projects/static/ys_faaliyet_cv/{cv_name}")
            cv_url = f"/static/ys_faaliyet_cv/{cv_name}"
        else:
            cv_url = None
        

        # Additions after change
        sinav_envanter = form.sinav_envanter.data
        aday_durumu_diger = form.aday_durumu_diger.data

        created_at = datetime.datetime.now()
        updated_at = datetime.datetime.now()

        created_by_name = session.get("name")
        created_by_surname = session.get("surname")
        created_by = created_by_name + " " + created_by_surname

        values = (
            gorusme_tarihi.strftime('%Y-%m-%d') if gorusme_tarihi else None,
            bayi_adi if bayi_adi else None,
            (" ".join([word.capitalize().replace("i·","i".replace("İ·","İ")) for word in aday_adi.split()])).replace("·","") if aday_adi else None,
            cinsiyet if cinsiyet else None,
            satis_servis if satis_servis else None,
            aday_durumu if aday_durumu else None,
            sinav_sayisal if sinav_sayisal is not None else None,
            sinav_sozel if sinav_sozel is not None else None,
            pozisyon_adi if pozisyon_adi else None,
            aksiyon if aksiyon else None,
            bolgeci if bolgeci else None,
            ik_bolgeci if ik_bolgeci else None,
            ise_baslama_tarihi.strftime('%Y-%m-%d') if ise_baslama_tarihi else None,
            isten_cikis_tarihi.strftime('%Y-%m-%d') if isten_cikis_tarihi else None,
            notlar if notlar else None,
            created_at.strftime('%Y-%m-%d %H:%M:%S'),
            updated_at.strftime('%Y-%m-%d %H:%M:%S'),
            created_by,
            sinav_envanter if sinav_envanter is not None else None,
            aday_durumu_diger if aday_durumu_diger is not None else None,
            cv_url,
            gorusme_baglam,
        )

        query = """
            INSERT INTO [Yuce_Portal].[dbo].[YS_Faaliyet_Raporu]
            ([gorusme_tarihi], [bayi], [aday_ismi], [cinsiyet], [satis_or_servis], [aday_durumu],
            [sayisal_sonuc], [sozel_sonuc], [pozisyon_adi], [terfi_iseAlim_rotasyon], [bolgeci],
            [ik_bolgeci], [start_date], [end_date], [notlar], [created_at], [updated_at], [Created_By], [envanter_sonuc], [DigerSebep], [CV], [gorusme_baglam])
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """


        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()
        cursor.execute(query, values)
        connection.commit()

        cursor.close()
        connection.close()

        Write_Log_ToDB(session.get('username'), "POST", "/ys_faaliyet_raporu", 0, f"{aday_adi} candidate has been inserted.")

        flash("Doldurduğunuz form başarıyla kaydedildi.", "success")
        return redirect(url_for("ys_faaliyet_raporu", confetti="true"))

