@app.route('/filter_adaylar', methods=['GET'])
def filter_adaylar():
    search_term = request.args.get('query', '').lower()  # Get the search query
    bayi_filter = request.args.get('bayi', '').lower()  # Optional bayi filter

    query = """
        SELECT [id], [gorusme_tarihi], [bayi], [aday_ismi], [cinsiyet], 
               [satis_or_servis], [aday_durumu], [sayisal_sonuc], [sozel_sonuc], 
               [pozisyon_adi], [terfi_iseAlim_rotasyon], [bolgeci], [ik_bolgeci], 
               [start_date], [end_date], [notlar], [envanter_sonuc], [notify_date], 
               [DigerSebep], [CV]
        FROM [Yuce_Portal].[dbo].[YS_Faaliyet_Raporu]
        WHERE [aday_ismi] COLLATE SQL_Latin1_General_CP1_CI_AI LIKE ?
    """

    params = [f"%{search_term}%"]

    if bayi_filter:
        query += " AND [bayi] COLLATE SQL_Latin1_General_CP1_CI_AI = ?"
        params.append(bayi_filter)

    query += " ORDER BY gorusme_tarihi DESC;"
    
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    cursor.execute(query, params)
    results = cursor.fetchall()

    for result in results:
        result[1] = result[1].strftime("%d.%m.%Y")
        if result[13] is not None:
            result[13] = result[13].strftime("%d.%m.%Y")
        if result[14] is not None:
            result[14] = result[14].strftime("%d.%m.%Y")
        if result[15] and len(result[15]) >= 60:
            result[15] = result[15][:58] + "..."
        if result[17] is not None:
            result[17] = result[17].strftime("%d.%m.%Y")
        for i in range(len(result)):
            result[i] = result[i] or "-"

    # Convert results into a list of dictionaries
    filtered_data = [
        {
            "id": row[0],
            "gorusme_tarihi": row[1],
            "bayi": row[2],
            "aday_ismi": row[3],
            "cinsiyet": row[4],
            "satis_or_servis": row[5],
            "aday_durumu": row[6],
            "sayisal_sonuc": row[7],
            "sozel_sonuc": row[8],
            "pozisyon_adi": row[9],
            "terfi_iseAlim_rotasyon": row[10],
            "bolgeci": row[11],
            "ik_bolgeci": row[12],
            "start_date": row[13],
            "end_date": row[14],
            "notlar": row[15],
            "envanter_sonuc": row[16],
            "notify_date": row[17],
            "DigerSebep": row[18],
            "cv": row[19],
        }
        for row in results
    ]

    return jsonify(filtered_data)

