    pozisyon_adi = form_data.get('pozisyon_adi')
    terfi_iseAlim_rotasyon = form_data.get('aksiyon')
    aday_durumu = form_data.get('aday_durumu')
    sinav_sayisal = form_data.get('sinav_sayisal')
    sinav_sozel = form_data.get('sinav_sozel')
    sinav_envanter = form_data.get('sinav_envanter')
    ise_baslama_tarihi = form_data.get('ise_baslama_tarihi')
    isten_cikis_tarihi = form_data.get('isten_cikis_tarihi')
