    updated_by_surname = session.get("surname")
    updated_by = f"{updated_by_name} {updated_by_surname}"
    updated_at = datetime.datetime.now()
    aday_durumu_diger = form_data.get('aday_durumu_diger')
    gorusme_tarihi = form_data.get('gorusme_tarihi')
    ik_bolgeci = form_data.get('ik_bolgeci')
    gorusme_baglam = form_data.get('gorusme_baglam')

    print(gorusme_baglam)

    try:
         gorusme_tarihi = datetime.datetime.strptime(gorusme_tarihi, '%Y-%m-%d') if gorusme_tarihi else None
    except ValueError:
        gorusme_tarihi = None

    try:
        ise_baslama_tarihi = datetime.datetime.strptime(ise_baslama_tarihi, '%Y-%m-%d') if ise_baslama_tarihi else None
    except ValueError:
        ise_baslama_tarihi = None

    try:
        isten_cikis_tarihi = datetime.datetime.strptime(isten_cikis_tarihi, '%Y-%m-%d') if isten_cikis_tarihi else None
    except ValueError:
        isten_cikis_tarihi = None

    try:
        bildirme_tarihi = datetime.datetime.strptime(bildirme_tarihi, '%Y-%m-%d') if bildirme_tarihi else None
    except ValueError:
        bildirme_tarihi = None

    # Handle possible invalid int conversions
    try:
        float(sinav_sayisal)
    except (ValueError, TypeError):
        sinav_sayisal = None
    try:
        float(sinav_sozel)
    except (ValueError, TypeError):
        sinav_sozel = None
    try:
        float(sinav_envanter)
    except (ValueError, TypeError):
        sinav_envanter = None

    if aday_durumu != 'Diğer':
        aday_durumu_diger = ''

    values = (
        aday_ismi if aday_ismi else None,
        bayi if bayi else None,
        cinsiyet if cinsiyet else None,
        satis_or_servis if satis_or_servis else None,
        pozisyon_adi if pozisyon_adi else None,
        terfi_iseAlim_rotasyon if terfi_iseAlim_rotasyon else None,
        aday_durumu if aday_durumu else None,
        sinav_sayisal if sinav_sayisal is not None else None,
        sinav_sozel if sinav_sozel is not None else None,
        ise_baslama_tarihi.strftime('%Y-%m-%d') if ise_baslama_tarihi else None,
        isten_cikis_tarihi.strftime('%Y-%m-%d') if isten_cikis_tarihi else None,
        notlar if notlar else None,
        updated_at.strftime('%Y-%m-%d %H:%M:%S'),
        updated_by,
        sinav_envanter if sinav_envanter is not None else None,
        bildirme_tarihi.strftime('%Y-%m-%d') if bildirme_tarihi else None,
        aday_durumu_diger if aday_durumu_diger else None,
        ik_bolgeci if ik_bolgeci else None,
        gorusme_tarihi if gorusme_tarihi else None,
        gorusme_baglam,
        id  # Add `id` as the last value for the WHERE clause
    )

    query = """
        UPDATE [Yuce_Portal].[dbo].[YS_Faaliyet_Raporu]
        SET aday_ismi = ?,
            bayi = ?,
            cinsiyet = ?,
            satis_or_servis = ?,
            pozisyon_adi = ?,
            terfi_iseAlim_rotasyon = ?,

            aday_durumu = ?,
            sayisal_sonuc = ?,
            sozel_sonuc = ?,
            start_date = ?,
            end_date = ?,
            notlar = ?,
            updated_at = ?,
            updated_by = ?,
            envanter_sonuc = ?,
            notify_date = ?,
            DigerSebep = ?,
            ik_bolgeci = ?,
            gorusme_tarihi = ?,
            gorusme_baglam = ?
        WHERE id = ?
    """
    
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    cursor.execute(query, values)
    connection.commit()
    cursor.close()
    connection.close()

    Write_Log_ToDB(session.get('username'), "POST", f"/ys_faaliyet_update_AdayInfo/{id}", 0, f"{id} person has been editted by {session.get('username')}.")

    flash("Aday bilgileri başarıyla güncellendi", "success")
    return jsonify({"message": "Aday bilgileri başarıyla güncellendi"}), 200

