@app.route('/download_adaylar_excel', methods=['GET'])
@login_required
@department_check("Bilgi Teknolojileri", "İnsan Kaynakları")
def download_adaylar_excel():
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    query = """
            SELECT
                [gorusme_tarihi]
                ,[aday_ismi]
                ,[bayi]
                ,[cinsiyet]
                ,[satis_or_servis]
                ,[pozisyon_adi]
                ,[terfi_iseAlim_rotasyon]
                ,[ik_bolgeci]
                ,[sayisal_sonuc]
                ,[sozel_sonuc]
                ,[envanter_sonuc]
                ,[aday_durumu]
                ,[DigerSebep]
                ,[start_date]
                ,[end_date]
                ,[notify_date]
                ,[notlar]
            FROM [Yuce_Portal].[dbo].[YS_Faaliyet_Raporu] ORDER BY gorusme_tarihi DESC;
        """
    cursor.execute(query)
    offers = cursor.fetchall()
    offers = [list(row) for row in offers]
    columns = [column[0] for column in cursor.description]
    offers_df = pd.DataFrame(offers, columns=columns)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        offers_df.to_excel(writer, index=False, sheet_name='Adaylar')

        workbook = writer.book
        offers_sheet = workbook['Adaylar']

        import openpyxl
        from openpyxl.styles import PatternFill, Font, Alignment

        header_fill = PatternFill(start_color="0E3A2F", end_color="0E3A2F", fill_type="solid")
        header_font = Font(color="78FAAE", bold=True)
        center_alignment = Alignment(horizontal="center", vertical="center")

        for cell in offers_sheet[1]:
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = center_alignment

        for row in offers_sheet.iter_rows():
            for cell in row:
                if cell.value == "None":
                    cell.value = ""
                cell.alignment = center_alignment

        #offers_sheet.delete_cols(17) # Deletes active_onsale col


        offers_sheet.column_dimensions['A'].width = 20
        offers_sheet.column_dimensions['B'].width = 30
        offers_sheet.column_dimensions['C'].width = 30
        offers_sheet.column_dimensions['D'].width = 10
        offers_sheet.column_dimensions['E'].width = 15
        offers_sheet.column_dimensions['F'].width = 25
        offers_sheet.column_dimensions['G'].width = 15
        offers_sheet.column_dimensions['H'].width = 15
        offers_sheet.column_dimensions['I'].width = 10
        offers_sheet.column_dimensions['J'].width = 10
        offers_sheet.column_dimensions['K'].width = 10
        offers_sheet.column_dimensions['L'].width = 15
        offers_sheet.column_dimensions['M'].width = 15
        offers_sheet.column_dimensions['N'].width = 20
        offers_sheet.column_dimensions['O'].width = 20
        offers_sheet.column_dimensions['P'].width = 20
        offers_sheet.column_dimensions['Q'].width = 60

        offers_sheet['A1'] = "Görüşme Tarihi"
        offers_sheet['B1'] = "Aday İsmi"
        offers_sheet['C1'] = "Bayi"
        offers_sheet['D1'] = "Cinsiyet"
        offers_sheet['E1'] = "Satış/Servis"
        offers_sheet['F1'] = "Pozisyon Adı"
        offers_sheet['G1'] = "Terfi/İşAlım/Rot"
        offers_sheet['H1'] = "İK Bölgeci"
        offers_sheet['I1'] = "Sayısal"
        offers_sheet['J1'] = "Sözel"
        offers_sheet['K1'] = "Envanter"
        offers_sheet['L1'] = "Aday Durumu"
        offers_sheet['M1'] = "Diğer Sebep"
        offers_sheet['N1'] = "İşe Giriş Tarihi"
        offers_sheet['O1'] = "İşten Çıkış Tarihi"
        offers_sheet['P1'] = "Bayi Bilgilendirme Tarihi"
        offers_sheet['Q1'] = "Notlar"

    # Move the cursor to the beginning of the file
    output.seek(0)

    return send_file(output, as_attachment=True, download_name='YücePortal_YS_Faaliyet_Adaylar.xlsx', mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')

