@app.route('/fiktif_araclar_mailing_filo', methods=['GET'])
@login_required
@department_check("Bilgi Teknolojileri", "Satış")
def fiktif_araclar_mailing_filo():
    form = filo_fiktif_bayi_mailing_Form(request.form)
    btn_locked = fiktif_araclar_emailing_lock_filo.locked()
    fiktifteki_araclar = _get_fiktif_araclar_filo()

    if request.method == "GET":
        form.mail_konu.data = fiktif_araclar_mail_subject_filo
        form.mail_body.data = fiktif_araclar_mail_body_filo

        username = session.get('username')
        safe_username = str(username).replace("\n", "\\n").replace("\r", "\\r").replace(";", "")

        bayii_aslist = []
        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        fiktifteki_araclar = list(fiktifteki_araclar)
        for c in range(len(fiktifteki_araclar)):
            try:
                cursor.execute("""
                    INSERT INTO [Yuce_Portal].[dbo].[Fiktif_Araclar_Log]
                    (siparis_no, Model_Tanimi, Renk, Trim_, Bayi_Adi, status_stok, username, request_datetime, request_type)
                    VALUES (?, ?, ?, ?, ?, ?, ?, GETDATE(), ?)
                """, (
                    fiktifteki_araclar[c][0],
                    fiktifteki_araclar[c][1],
                    fiktifteki_araclar[c][3],
                    fiktifteki_araclar[c][4],
                    fiktifteki_araclar[c][2],
                    fiktifteki_araclar[c][5],
                    safe_username,
                    'GET'
                ))
            except Exception as e:
                print("INSERT log error:", e)

            fiktifteki_araclar[c] = list(fiktifteki_araclar[c])
            if fiktifteki_araclar[c][2].count("-") > 1:
                parts = fiktifteki_araclar[c][2].split("-")
                remaining_part = parts[0] + parts[1]
                fiktifteki_araclar[c][2] = remaining_part
                bayi_kodu = "-".join(parts[2:]).strip()
            else:
                fiktifteki_araclar[c][2], bayi_kodu = [part.strip() for part in fiktifteki_araclar[c][2].split("-", 1)]

            if bayi_kodu.startswith("0"):
                bayi_kodu = bayi_kodu[1:]

            fiktifteki_araclar[c].append(bayi_kodu)

            if fiktifteki_araclar[c][2] not in bayii_aslist:
                bayii_aslist.append(fiktifteki_araclar[c][2])

        connection.commit()
        connection.close()
        

        Write_Log_ToDB(safe_username, "GET", "/fiktif_araclar_mailing_filo", 0, f"{safe_username} viewed the Page.")

        if btn_locked:
            flash("Şuan mail gönderimi yapılıyor.", "warning")

        return render_template(
            "fiktif_araclar_mailing_filo.html",
            form=form,
            fiktifteki_araclar=fiktifteki_araclar,
            bayii_aslist=bayii_aslist,
            btn_locked=btn_locked
        )

