@app.route("/GeciciAracTahsis/AracTanimlama", methods=["GET"])
@login_required
def Gecici_Arac_Tahsis_Arac_Tanimlama():
    Arac_veriler = _get_gecici_arac_tahsis_araclar()

    for index, arac_veri in enumerate(Arac_veriler):
        arac_veri = list(arac_veri)
        if isinstance(arac_veri[2], datetime.datetime):
            parsed_date = arac_veri[2]
        else:
            parsed_date = datetime.datetime.strptime(arac_veri[2], "%a, %d %b %Y %H:%M:%S %Z")
        
        arac_veri[2] = parsed_date.strftime("%d.%m.%Y")
        Arac_veriler[index] = tuple(arac_veri)

    form = GeciciAracTahsis_AracTanimlama_Form(request.form)

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()
    query = """
    SELECT TOP (10000) [ID]
        ,[PlakaNo]
        ,[SasiNo]
        ,[Model]
        ,[TrafikCikisTarihi]
        ,[Renk]
        ,[KM]
        ,[YA_AlisTarihi]
        ,[YA_AracSatilmaTarihi]
    FROM [Yuce_Portal].[dbo].[Gecici_Arac_Tahsis]
    ORDER BY [YA_AlisTarihi] DESC
    """
    cursor.execute(query)
    cars = cursor.fetchall()
    for car in cars:
        car[4] = car[4].strftime('%d.%m.%Y')
        car[6] = format_with_period(car[6])
        car[7] = car[7].strftime('%d.%m.%Y')
        if car[8]:
            if car[8] ==  datetime.date(1900, 1, 1):
                car[8] = None

    if request.method == "GET":
        Write_Log_ToDB(session.get('username'), "GET", "/GeciciAracTahsis/AracTanimlama", 0)
        return render_template("GeciciAracTahsis_AracTanimlama.html", form=form, Arac_veriler=Arac_veriler, cars=cars)

@app.route("/GeciciAracTahsis/AracTanimlama/POSTreq", methods=["POST"])
@login_required
def Gecici_Arac_Tahsis_AracTanimlama_POST():
    data = request.json

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    def sum_keys_with_prefix(data, prefix):
        """Sum all values for keys starting with a given prefix."""
        total = 0
        for key in data:
            if key.startswith(prefix):
                value = data[key]
                if isinstance(value, str):
                    value = value.replace('.', '').replace(',', '.')
                try:
                    total += float(value)
                except:
                    pass
        return total

    def keys_with_prefix_to_csv(data, prefix):
        """
        Collect all values for keys starting with a given prefix and return them as a CSV string.
        """
        values = []
        for key in data:
            if key.startswith(prefix):
                value = data[key]
                if isinstance(value, str):
                    value = value.replace('.', '').replace(',', '.')
                values.append(str(value))
        return ','.join(values)

    # Mutiple inputs are converted to csv below
    kasko_csv = keys_with_prefix_to_csv(data, 'kasko')
    trafik_sigortasi_csv = keys_with_prefix_to_csv(data, 'trafik_sigortasi')
    bakim_ve_onarim_csv = keys_with_prefix_to_csv(data, 'bakim_ve_onarim')

    # Multiple inputs are summed below
    total_kasko = sum_keys_with_prefix(data, 'kasko')
    total_trafik_sigortasi = sum_keys_with_prefix(data, 'trafik_sigortasi')
    total_bakim_ve_onarim = sum_keys_with_prefix(data, 'bakim_ve_onarim')

    arac_geri_alim_bedeli = sum_keys_with_prefix(data, 'arac_geri_alim_bedeli')
    ikinci_el_satis_bedeli = sum_keys_with_prefix(data, 'ikinci_el_satis_bedeli')
    arac_maliyet_toplam = sum_keys_with_prefix(data, 'arac_maliyet_toplam')

    # Extract the plaka_no from the request data
    plaka_no = data.get('plaka_no', 'N/A')

    # 1. Check if plaka_no already exists
    check_query = """
        SELECT 1 
        FROM [Yuce_Portal].[dbo].[Gecici_Arac_Tahsis]
        WHERE [PlakaNo] = ?
    """
    cursor.execute(check_query, (plaka_no,))
    existing_record = cursor.fetchone()

    # If record exists, return early with a message
    if existing_record:
        cursor.close()
        conn.close()
        return jsonify({
            "status": "error",
            "message": f"Plaka '{plaka_no}' için daha önce kayıt açılmış."
        })

    # Otherwise, continue and insert the new data
    insert_query = """
        INSERT INTO [Yuce_Portal].[dbo].[Gecici_Arac_Tahsis] 
            ([PlakaNo], [SasiNo], [Model], [TrafikCikisTarihi], [Renk], [KM], [YA_AlisTarihi], [YA_AracSatilmaTarihi], [AracGeriAlimBedeli], [TrafikSigortasi], [Kasko], [BakimVeOnarim], [IkinciElSatisBedeli], [AracMaliyetToplam], [FonlamaMaliyeti], [IkameAracKullanimGunSayisi], [KarZarar], [created_by], [last_updated_by], [created_date], [TrafikSigortasi_csv], [Kasko_csv], [BakimVeOnarim_csv]) 
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, GETDATE(), ?, ?, ?);
    """

    kar_zarar = data.get('kar_zarar', 0)
    kar_zarar = float(kar_zarar.replace(".","").replace(",",".") if isinstance(kar_zarar, str) else kar_zarar)

    values = (
        plaka_no,
        data.get('sasi_no', 'N/A'),
        data.get('model', 'N/A'),
        datetime.datetime.strptime(data.get('trafikCikis_Tarihi', ''), '%d.%m.%Y').strftime('%Y-%m-%d') if data.get('trafikCikis_Tarihi') else None,
        data.get('renk', 'N/A'),
        int(data.get('km', 0).replace(".","") if isinstance(data.get('km', 0), str) else data.get('km', 0)),
        data.get('YA_AlisTarihi', None),
        data.get('YA_AracSatilmaTarihi', None),
        arac_geri_alim_bedeli,
        total_trafik_sigortasi,
        total_kasko,
        total_bakim_ve_onarim,
        ikinci_el_satis_bedeli,
        arac_maliyet_toplam,
        data.get('fonlama_maliyeti', 0),
        data.get('ikame_arac_kullanim_gun_sayisi', 0),
        kar_zarar,
        session.get('username', 'default_user'),
        session.get('username', 'default_user'),
        trafik_sigortasi_csv,
        kasko_csv,
        bakim_ve_onarim_csv
    )

    cursor.execute(insert_query, values)
    conn.commit()

    message = "Data inserted successfully!"
    status = "success"

    cursor.close()
    conn.close()

    # Return response to frontend
    return jsonify({"status": status, "message": message})

