@app.route("/GeciciAracTahsis/FonlamaOrani", methods=["GET", "POST"])
@login_required
def Gecici_Arac_Tahsis_Fonlama_Orani():
    form = GeciciAracTahsis_FonlamaOrani_Form(request.form)
    if request.method == "GET":
        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()

        query = "SELECT TOP (1000) [ID], [Ay], [Yil], [Oran], [CreatedBy], [CreatedDate] FROM [Yuce_Portal].[dbo].[Gecici_Arac_Tahsis_Fonlama] ORDER BY Yil DESC, CAST(Ay AS INT) DESC;"
        cursor.execute(query)
        results = cursor.fetchall()

        for result in results:
            result[1] = month_number_to_name(int(result[1]))

        Write_Log_ToDB(session.get('username'), "GET", "/GeciciAracTahsis/FonlamaOrani", 0)
        return render_template("Gecici_Arac_Tahsis_FonlamaOrani.html", form=form, results=results)
    elif request.method == "POST":
        ay = form.ay.data
        yil = form.yil.data
        fonlama_orani = form.fonlama_orani.data.replace(",", ".")
        ay_int = month_name_to_number(ay)

        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()

        check_query = "SELECT COUNT(*) FROM [Yuce_Portal].[dbo].[Gecici_Arac_Tahsis_Fonlama] WHERE [Ay] = ? AND [Yil] = ?"
        cursor.execute(check_query, (ay_int, yil))
        result = cursor.fetchone()

        if result[0] > 0:
            flash(f"{ay} {yil} için fonlama oranı zaten kayıtlıdır.", "warning")
        else:
            insert_query = """
                INSERT INTO [Yuce_Portal].[dbo].[Gecici_Arac_Tahsis_Fonlama] 
                    ([Ay], [Yil], [Oran], [CreatedBy], [CreatedDate])
                VALUES (?, ?, ?, ?, GETDATE());
            """
            cursor.execute(insert_query, (ay_int, yil, fonlama_orani, session.get('username', 'default_user')))
            conn.commit()
            flash(f"{ay} {yil} için fonlama oranı kaydedilmiştir.", "success")
            Write_Log_ToDB(session.get('username'), "POST", "/GeciciAracTahsis/FonlamaOrani", 0, f"{ay} {yil} için fonlama oranı kaydedilmiştir.")

        cursor.close()
        conn.close()
        return redirect(url_for("Gecici_Arac_Tahsis_Fonlama_Orani"))

