@app.route("/dashboard_yetkilendirme", methods=["GET", "POST"])
@login_required
def Dashboard_Yetkilendirme():
    form = Dashboard_Yetkilendirme_Form(request.form)
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    if request.method == "GET":
        query = """
        SELECT 
            dy.[id] AS DashboardID,
            dy.[bayi_id_from_2ElSatis],
            dy.[ys_user_mail],
            dy.[Satis],
            dy.[Servis],
            dy.[is_active],
            b.[ID] AS BayiiID,
            b.[dealerName],
            b.[isActive] AS BayiiIsActive,
            dy.[Aciklama]
        FROM [Yuce_Portal].[dbo].[DashboardYetkilendirme] dy
        INNER JOIN [YA_2El_AracSatis].[dbo].[Bayiiler] b
            ON dy.[bayi_id_from_2ElSatis] = b.[ID]
        """
        cursor.execute(query)
        users = cursor.fetchall()

        cursor.close()
        connection.close()
        Write_Log_ToDB(session.get('username'), "GET", "/dashboard_yetkilendirme", 0)
        return render_template("dashboard_yetkilendirme.html", form=form, users=users)
    
    elif request.method == "POST":
        bayi_adi = form.bayi_adi.data
        user_email = form.user_email.data
        satis = int(form.satis.data)
        servis = int(form.servis.data)
        aktif_pasif = int(form.aktif_pasif.data)
        username = session.get('username')

        query_to_find_bayiID = f"""
        SELECT TOP (1) [ID], [dealerName], [isActive], [To], [Cc], [Ys_code], [dealerName_Turkuaz]
        FROM [YA_2El_AracSatis].[dbo].[Bayiiler]
        WHERE dealerName = '{bayi_adi}'
        """
        cursor.execute(query_to_find_bayiID)
        result = cursor.fetchone()
        bayi_id = result[0]  # bayiID from 2ElAracSatis
        bayi_code = result[5]
        bayi_turkuaz_adi = result[6]

        query = f"""
        INSERT INTO [Yuce_Portal].[dbo].[DashboardYetkilendirme] 
            (bayi_id_from_2ElSatis, firm_id, ys_user_mail, Satis, Servis, is_active, Created_by, Last_Updated_by, creation_datetime, last_Updated_datetime, Turkuaz_bayi_adi)
        VALUES 
            ({bayi_id}, {bayi_code}, '{user_email}', {satis}, {servis}, {aktif_pasif}, 
            '{username}', '{username}', GETDATE(), GETDATE(), '{bayi_turkuaz_adi}')
        """
        cursor.execute(query)

        connection.commit()
        cursor.close()
        connection.close()

        Write_Log_ToDB(session.get('username'), "GET", "/dashboard_yetkilendirme", 0, f"{user_email} için kayıt oluşturuldu.")
        flash(f"{user_email} için başarıyla kullanıcı oluşturuldu.", "success")
        return redirect(url_for("Dashboard_Yetkilendirme"))
    
@app.route("/update_dashboard_yetkilendirme", methods=["POST"])
@login_required
def update_Dashboard_Yetkilendirme():
    data = request.json or []

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    current_user_email = session.get('username')

    update_sql = """
        UPDATE [Yuce_Portal].[dbo].[DashboardYetkilendirme]
        SET 
            [is_active] = ?,
            [Aciklama] = ?,
            [last_Updated_by] = ?,
            [last_Updated_datetime] = GETDATE()
        WHERE [id] = ?
    """

    for record in data:
        row_id = int(record.get('id'))
        aktif_pasif = int(record.get('aktif_pasif', 0))
        aciklama = record.get('aciklama')  # may be None or string

        cursor.execute(update_sql, (aktif_pasif, aciklama, current_user_email, row_id))

    connection.commit()
    cursor.close()
    connection.close()

    Write_Log_ToDB(session.get('username'), "POST", "/update_dashboard_yetkilendirme", 0, "Changes (aktif_pasif + aciklama)")
    return jsonify({'message': 'Update successful!'})

