@app.route("/get_user_info")
@login_required
def get_user_info():
    username = request.args.get("username")

    if not username:
        return jsonify({"error": "No username provided"}), 400

    if session.get("username") == username:
        return jsonify({
                "name": session.get("name" + " " + "surname"),
                "title": session.get("title"),
                "department": session.get("departman")
            })
    elif session.get("name") + " " + session.get("surname") == username:
        return jsonify({
                "name": session.get("name" + " " + "surname"),
                "title": session.get("title"),
                "department": session.get("departman")
            })

    cursor = mysql.connection.cursor()

    query1 = "SELECT * FROM users1 WHERE username = %s"
    cursor.execute(query1, (username,))
    user = cursor.fetchone()

    if not user:
        query2 = "SELECT * FROM users1 WHERE CONCAT(name, ' ', surname) = %s"
        cursor.execute(query2, (username,))
        user = cursor.fetchone()

    if user:
        return jsonify({
            "name": user["name"] + " " + user["surname"],
            "title": user["title"],
            "department": user["departman"]
        })
    
    elif not user and username=="satin_alma_degerlendirme_sorumlu":
        return jsonify({
                "name": "Satın Alma Sorumlusu",
                "title": "",
                "department": "İnsan Kaynakları"
            })
    elif not user and username=="satin_alma_finans_sorumlu":
        return jsonify({
                "name": "Finansal Raporlama, Bütçe ve İç Kontrol Birim Yöneticisi",
                "title": "",
                "department": "Stratejik Planlama ve Mali İşler"
            })
    else:
        return jsonify({"error": "User not found"}), 404

@app.route("/organizasyon_data", methods=["GET"])
@login_required
def organizasyon_data():
    if session['YA_user'] == True:
        class Person:
            def __init__(self, username, name, mail, department, title, phone_number, manager, pager, ise_baslangic_tarihi, ofis_status):
                self.username = username
                self.name = name
                self.mail = mail
                self.department = department
                self.title = title
                self.phone_number = phone_number
                self.manager = manager
                self.pager = pager
                self.ise_baslangic_tarihi = ise_baslangic_tarihi
                self.ofis_status = ofis_status or "Bilinmiyor"

            def to_dict(self):
                return {
                    'username': self.username,
                    'name': self.name,
                    'mail': self.mail,
                    'department': self.department,
                    'title': self.title,
                    'phone_number': self.phone_number,
                    'manager': self.manager,
                    'phone_code': self.pager,
                    'ise_baslangic_tarihi': self.ise_baslangic_tarihi,
                    'ofis_status': self.ofis_status
                }

        # Step 1: Load attendance data
        cursor = mysql.connection.cursor()
        today_str = date.today().strftime('%Y-%m-%d')
        cursor.execute("SELECT users1_id, ofis_bayi FROM ofis_gunleri WHERE selected_date = %s", (today_str,))
        attendance_data = cursor.fetchall()
        user_status_map = {row["users1_id"]: row["ofis_bayi"] for row in attendance_data}

        # Load users1 table
        cursor.execute("SELECT ID, username FROM users1")
        user_id_map = {row["username"]: row["ID"] for row in cursor.fetchall()}

        # Step 2: Connect to LDAP
        server = Server('10.0.0.5', port=389, get_info=ALL)
        conn = Connection(server, user=f'yuceauto\\{session["username"]}', password=session["pw"], authentication=NTLM)

        # Initialize lists
        yonetim_aslist, yonetim_primary_aslist, yonetim_secondary_aslist = [], [], []
        icdenetim_aslist = []
        maliVeIdari_aslist, musterideneyimi_aslist, planlama_aslist = [], [], []
        satis_aslist, urun_aslist = [], []
        pazarlama_aslist, ssh_aslist, bayigelistirme_aslist = [], [], []
        ik_aslist, it_aslist, yeniis_modelleri_aslist = [], [], []
        filo_satis_aslist = []
        population_skoda = 0

        if conn.bind():
            search_base = 'DC=YUCEAUTO,DC=com,DC=tr'
            search_filter = '(objectClass=user)'
            attributes = ['sAMAccountName', 'cn', 'department', 'title', 'mail', 'userAccountControl', 'mobile', 'manager', 'pager', 'extensionAttribute1']
            conn.search(search_base, search_filter, search_scope=SUBTREE, attributes=attributes)

            for entry in conn.entries:
                username = entry.sAMAccountName.value.lower()
                name = entry.cn.value
                mail = entry.mail.value
                department = entry.department.value
                title = entry.title.value
                phone_number = entry.mobile.value or "-"
                user_account_control = entry.userAccountControl.value
                manager_dn = entry.manager.value
                phone_code = entry.pager.value
                ise_baslangic_tarihi = entry.extensionAttribute1.value

                manager_full_name = manager_dn.split(',')[0].replace('CN=', '').strip() if manager_dn else "Unknown"
                phone_code = " / " + phone_code if phone_code else ""
                user_id = user_id_map.get(username)
                ofis_status = user_status_map.get(user_id)

                user_is_disabled = bool(user_account_control & 0x0002)

                if title and not user_is_disabled:
                    population_skoda += 1
                    person = Person(username, name, mail, department, title, phone_number, manager_full_name, phone_code, ise_baslangic_tarihi, ofis_status)

                    if person.department == "Yönetim" or person.department == "Yönetim Kurulu":
                        if "müdür" in person.title.lower() and "müdür yard" not in person.title.lower() and "müdür asist" not in person.title.lower():
                            yonetim_aslist.insert(0, person)
                        else:
                            yonetim_aslist.append(person)
                        if "genel müdür" in person.title.lower() or "iç denetim" in person.title.lower() or "i̇ç denetim" in person.title.lower():
                            yonetim_secondary_aslist.append(person)
                        else:
                            yonetim_primary_aslist.append(person)
                    elif person.department == "İç Denetim Birimi":
                        icdenetim_aslist.append(person)
                    elif person.department == "Stratejik Planlama ve Mali İşler":
                        maliVeIdari_aslist.append(person)
                    elif person.department == "Dijital Dönüşüm ve Müşteri Deneyim Yönetimi":
                        musterideneyimi_aslist.append(person)
                    elif person.department == "Stratejik Planlama ve Mali İşler":
                        maliVeIdari_aslist.append(person)
                    elif person.department == "Satış":
                        satis_aslist.append(person)
                    elif person.department == "Ürün ve Planlama":
                        urun_aslist.append(person)
                    elif person.department == "Pazarlama":
                        pazarlama_aslist.append(person)
                    elif person.department == "Satış Sonrası Hizmetler":
                        ssh_aslist.append(person)
                    elif person.department == "Bayi Geliştirme":
                        bayigelistirme_aslist.append(person)
                    elif person.department == "İnsan Kaynakları":
                        ik_aslist.append(person)
                    elif person.department == "Bilgi Teknolojileri":
                        it_aslist.append(person)
                    elif person.department == "Yeni İş Modelleri":
                        yeniis_modelleri_aslist.append(person)

        def to_dict_list(lst): return [p.to_dict() for p in lst]

        def parse_date(date_str):
            try:
                return datetime.datetime.strptime(date_str, "%d.%m.%Y")
            except Exception:
                return datetime.datetime.max

        def reorder_yonetim(aslist):
            # Move Yönetim Kurulu Başkanı to top
            for person in aslist:
                if person.title.strip() == "Yönetim Kurulu Başkanı":
                    aslist.remove(person)
                    aslist.insert(0, person)
                    break

            # Move Yönetim Kurulu Üyesi right after
            for person in aslist:
                if person.title.strip() == "Yönetim Kurulu Üyesi":
                    aslist.remove(person)
                    aslist.insert(1, person)
                    break

            # Swap Ali Yüce & Cem Baykal (assumes they're at 1 & 2)
            if len(aslist) > 2:
                aslist[1], aslist[2] = aslist[2], aslist[1]

            return aslist

        def reorder_yonetim_primary(aslist):
            priority_order = [
                "AHMET YÜCE",
                "ALİ YÜCE",
                "Cem Baykal",
                "ALİ BİLALOĞLU",
                "GÜR ÇAĞDAŞ",
                "Gülasfi Felek",
                "ZAFER BAŞAR"
            ]

            prioritized = []
            remaining = aslist.copy()

            for name in priority_order:
                for person in aslist:
                    if person.name.strip() == name:
                        prioritized.append(person)
                        if person in remaining:
                            remaining.remove(person)
                        break

            # Add the rest without disturbing their order
            prioritized.extend(remaining)
            return prioritized

        def bring_order_todept(dept_aslist):
            title_order = {
                "Genel Müdür": 0,
                "Müdür": 1,
                "Birim Yöneticisi": 2,
                "Yönetici": 3,
                "Yetkili": 4,
                "Uzmanı": 5,
                "Uzman Yardımcısı": 6,
                "Stajyer": 7,
                "İş Analisti": 3,
                "Veri Bilimci": 3,
                "Hukuk Müşaviri": 3,
                "Mimar": 3,
                "Müşteri Deneyimi Tasarımcısı": 3
            }

            def get_title_rank(title):
                for keyword, rank in title_order.items():
                    if keyword.lower() in title.lower():
                        return rank
                return 99  # fallback rank for unknown titles

            sorted_list = sorted(
                dept_aslist,
                key=lambda x: (
                    get_title_rank(x.title),
                    parse_date(x.ise_baslangic_tarihi or "")
                )
            )
            return sorted_list

        icdenetim_aslist = bring_order_todept(icdenetim_aslist)
        maliVeIdari_aslist = bring_order_todept(maliVeIdari_aslist)
        musterideneyimi_aslist = bring_order_todept(musterideneyimi_aslist)
        #planlama_aslist = bring_order_todept(planlama_aslist)
        satis_aslist = bring_order_todept(satis_aslist)
        urun_aslist = bring_order_todept(urun_aslist)
        pazarlama_aslist = bring_order_todept(pazarlama_aslist)
        ssh_aslist = bring_order_todept(ssh_aslist)
        bayigelistirme_aslist = bring_order_todept(bayigelistirme_aslist)
        ik_aslist = bring_order_todept(ik_aslist)
        it_aslist = bring_order_todept(it_aslist)
        yeniis_modelleri_aslist = bring_order_todept(yeniis_modelleri_aslist)

        yonetim_aslist = reorder_yonetim_primary(yonetim_aslist)
        yonetim_primary_aslist = reorder_yonetim_primary(yonetim_primary_aslist)
        yonetim_primary_aslist = reorder_yonetim_primary(yonetim_primary_aslist)
        yonetim_secondary_aslist = reorder_yonetim_primary(yonetim_secondary_aslist)

        Write_Log_ToDB(session.get('username'), "GET", "/organizasyon_data", 0)

        return render_template("organizasyon_data.html",
            yonetim_aslist=to_dict_list(yonetim_aslist),
            yonetim_primary_aslist=to_dict_list(yonetim_primary_aslist),
            yonetim_secondary_aslist=to_dict_list(yonetim_secondary_aslist),
            icdenetim_aslist=to_dict_list(icdenetim_aslist),
            maliVeIdari_aslist=to_dict_list(maliVeIdari_aslist),
            musterideneyimi_aslist=to_dict_list(musterideneyimi_aslist),
            planlama_aslist=to_dict_list(planlama_aslist),
            satis_aslist=to_dict_list(satis_aslist),
            filo_satis_aslist=to_dict_list(filo_satis_aslist),
            urun_aslist=to_dict_list(urun_aslist),
            pazarlama_aslist=to_dict_list(pazarlama_aslist),
            ssh_aslist=to_dict_list(ssh_aslist),
            bayigelistirme_aslist=to_dict_list(bayigelistirme_aslist),
            ik_aslist=to_dict_list(ik_aslist),
            it_aslist=to_dict_list(it_aslist),
            yeniis_modelleri_aslist=to_dict_list(yeniis_modelleri_aslist),
            population_skoda=population_skoda
        )

@app.route("/soru_veya_oneri", methods=["GET", "POST"])
@login_required
def soru_veya_oneri():
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    form = Soru_veya_Oneri_Form(request.form)

    if request.method == "POST":
        modul = form.modul.data
        soru_oneri = form.soru_oneri.data
        created_by = session.get("username")
        created_by_name = session.get("name") + " " + session.get("surname")
        created_at = datetime.datetime.now()
        herkes_gorsun = form.onerimi_herkes_gorsun.data

        insert_query = """
            INSERT INTO [Yuce_Portal].[dbo].[Soru_ve_Oneriler] (Modul, Soru_Oneri, CreatedBy, CreatedBy_nam_surnam, CreatedAt, herkes_gorsun)
            VALUES (?, ?, ?, ?, ?, ?)
        """
        cursor.execute(insert_query, modul, soru_oneri, created_by, created_by_name, created_at, herkes_gorsun)
        conn.commit()

        import random

        messages = [
            "Öneriniz güvenli ellerde!",
            "Mesajınız bizde, değerlendirme sürecinde 🌱",
            "İletiniz alındı, teşekkür ederiz!",
            "Görüşleriniz bizim için altın değerinde ✨",
            "Bize ulaştınız, şimdi sıra bizde!",
            "Düşünceniz kaydedildi, güzel şeyler yolda!",
            "Paylaştığınız için teşekkürler 💬",
            "Fikriniz sisteme başarıyla işlendi 🤝",
            "Siz yazdınız, biz dikkatle okuyacağız!"
        ]

        send_email("YücePortal'da yeni bir talep ya da öneri oluşturuldu.", "Yeni Öneri/Talep Geldi", ["dogao@skoda.com.tr", "s.ozcelik@skoda.com.tr"], cc_email=None, sender_email=yuceportal_mail, login=None,password=None)

        flash(random.choice(messages), "success")
        return redirect("/soru_veya_oneri")

    cursor.execute("""
        SELECT o.*, 
            (SELECT COUNT(*) 
                FROM [Yuce_Portal].[dbo].[Soru_Oneri_Likes] 
                WHERE SoruOneriID = o.ID) AS like_count,
            CASE 
                WHEN EXISTS (
                    SELECT 1 FROM [Yuce_Portal].[dbo].[Soru_Oneri_Likes] 
                    WHERE SoruOneriID = o.ID AND LikedBy = ?
                ) THEN 1 ELSE 0
            END AS liked_by_user
        FROM [Yuce_Portal].[dbo].[Soru_ve_Oneriler] o
        WHERE CreatedBy = ? OR herkes_gorsun = 1
        ORDER BY CreatedAt DESC
    """, session.get("username"), session.get("username"))
    rows = cursor.fetchall()

    Write_Log_ToDB(session.get('username'), "GET", "/soru_veya_oneri", 0)
    return render_template("soru_veya_oneri.html", form=form, rows=rows)

@app.route("/like_soru_oneri", methods=["POST"])
@login_required
def like_soru_oneri():
    data = request.get_json()
    soru_id = data.get("id")
    username = session.get("username")

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    # Check if already liked
    cursor.execute("""
        SELECT 1 FROM [Yuce_Portal].[dbo].[Soru_Oneri_Likes]
        WHERE SoruOneriID = ? AND LikedBy = ?
    """, soru_id, username)

    already_liked = cursor.fetchone()

    if already_liked:
        cursor.execute("""
            DELETE FROM [Yuce_Portal].[dbo].[Soru_Oneri_Likes]
            WHERE SoruOneriID = ? AND LikedBy = ?
        """, soru_id, username)
        conn.commit()
        return jsonify(success=True, action="unliked")
    else:
        cursor.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[Soru_Oneri_Likes] (SoruOneriID, LikedBy)
            VALUES (?, ?)
        """, soru_id, username)
        conn.commit()
        return jsonify(success=True, action="liked")

