@app.route('/download_organization_excel', methods=['POST'])
@login_required
def download_organization_excel():
    Write_Log_ToDB(session.get('username'), "POST", "/download_organization_excel", 0, "User tried to download the Excel.")
    if session.get('YA_user') == True:
        data = request.get_json()
        combined_data = []
        for key, value in data.items():
            if isinstance(value, list) and all(isinstance(item, dict) for item in value):
                combined_data.extend(value)
            else:
                print(f"Skipping {key}: data format is not a list of dictionaries")
        df = pd.DataFrame(combined_data)
        column_order = ["department", "name", "title", "username", "mail", "phone_number", "phone_code"]
        column_names = {
            "department": "Departman",
            "name": "İsim",
            "title": "Ünvan",
            "username": "Kullanıcı Adı",
            "mail": "Mail Adresi",
            "phone_number": "Telefon Numarası",
            "phone_code": "Kısa Kodu",
        }
        df["phone_code"] = df["phone_code"].str.replace(" / ", "")
        df["phone_number"] = df["phone_number"].str.replace("-", "")
        df = df[column_order].rename(columns=column_names)
        output = io.BytesIO()
        with pd.ExcelWriter(output, engine='openpyxl') as writer:
            df.to_excel(writer, sheet_name="Yüce Auto Personel Listesi", index=False)

            workbook = writer.book
            sheet = workbook['Yüce Auto Personel Listesi']

            import openpyxl
            from openpyxl.styles import PatternFill, Font, Alignment, Border, Side

            sheet.sheet_view.showGridLines = False

            header_fill = PatternFill(start_color="0E3A2F", end_color="0E3A2F", fill_type="solid")
            header_font = Font(color="78FAAE", bold=True)
            center_alignment = Alignment(horizontal="center", vertical="center")

            for cell in sheet[1]:
                cell.fill = header_fill
                cell.font = header_font
                cell.alignment = center_alignment

            for row in sheet.iter_rows():
                for cell in row:
                    if cell.value == "None":
                        cell.value = ""

            sheet.column_dimensions['A'].width = 43
            sheet.column_dimensions['B'].width = 30
            sheet.column_dimensions['C'].width = 50
            sheet.column_dimensions['D'].width = 13
            sheet.column_dimensions['E'].width = 29
            sheet.column_dimensions['F'].width = 17
            sheet.column_dimensions['G'].width = 10

            gray_fill = PatternFill(start_color="E3E5E6", end_color="E3E5E6", fill_type="solid")
            white_fill = PatternFill(start_color="FFFFFF", end_color="FFFFFF", fill_type="solid")

            previous_department = None
            current_fill = gray_fill
            start_row = 2

            for row_idx, row in enumerate(sheet.iter_rows(min_row=2, max_col=sheet.max_column, max_row=sheet.max_row), start=2):
                department_cell = row[0]
                current_department = department_cell.value

                if current_department != previous_department and previous_department is not None:
                    for col in range(1, sheet.max_column + 1):
                        sheet.cell(row=start_row, column=col).border = Border(top=Side(style="thin"))
                        sheet.cell(row=row_idx - 1, column=col).border = Border(bottom=Side(style="thin"))
                    start_row = row_idx
                    current_fill = gray_fill if current_fill == white_fill else white_fill

                for cell in row:
                    cell.fill = current_fill
                    if cell.value == "None":
                        cell.value = ""

                previous_department = current_department

            for col in range(1, sheet.max_column + 1):
                sheet.cell(row=start_row, column=col).border = Border(top=Side(style="thin"))
                sheet.cell(row=sheet.max_row, column=col).border = Border(bottom=Side(style="thin"))
            sheet.cell(row=start_row, column=1).border = Border(left=Side(style="thin"))
            sheet.cell(row=sheet.max_row, column=sheet.max_column).border = Border(right=Side(style="thin"))

        output.seek(0)
        Write_Log_ToDB(session.get('username'), "POST", "/download_organization_excel", 0, "User successfully downloaded the Excel.")
        return send_file(output, as_attachment=True, download_name="Personel Listesi.xlsx", mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
    else:
        return "Unauthorized", 403

# -------------------------------------------------
# THUMB EXTRACTOR
# -------------------------------------------------
IMG_RE = re.compile(r'<img[^>]+src=["\']([^"\']+)["\']', re.IGNORECASE)
VID_RE = re.compile(
    r'<video[^>]+src=["\']([^"\']+)["\']|<source[^>]+src=["\']([^"\']+)["\']',
    re.IGNORECASE
)

def extract_thumb_from_content(html: str):
    if not html:
        return (None, None)

    m = IMG_RE.search(html)
    if m:
        src = m.group(1)
        # base64 ise thumb üretme (db şişmesin, thumb kırılmasın)
        if src.startswith("data:image"):
            return (None, None)
        return (src, "image")

    m2 = VID_RE.search(html)
    if m2:
        src = m2.group(1) or m2.group(2)
        return (src, "video")

    return (None, None)


# -------------------------------------------------
# UPLOAD CONFIG (TEK KAYNAK)
# -------------------------------------------------
IMAGE_SUBDIR = "posts"          # static/posts/...
VIDEO_SUBDIR = "posts_videos"   # static/posts_videos/...

ALLOWED_IMG_EXT = {"png", "jpg", "jpeg", "webp", "gif"}
ALLOWED_VIDEO_EXT = {"mp4", "webm", "ogg"}

def _ext_ok(filename: str, allowed: set) -> bool:
    if not filename or "." not in filename:
        return False
    ext = filename.rsplit(".", 1)[1].lower()
    return ext in allowed

def _save_to_static(subdir: str, file_storage):
    """
    Dosyayı: <app.static_folder>/<subdir>/ altına kaydeder.
    Dönüş: /static/<subdir>/<filename>
    """
    static_root = current_app.static_folder  # absolute path
    upload_dir = os.path.join(static_root, subdir)
    os.makedirs(upload_dir, exist_ok=True)

    original = file_storage.filename or "file"
    ext = original.rsplit(".", 1)[1].lower()

    base = secure_filename(original.rsplit(".", 1)[0])[:60] or "file"
    moment = datetime.datetime.now().strftime("%Y-%m-%d_%H-%M-%S")
    uniq = uuid4().hex[:8]
    filename = f"{base}_{moment}_{uniq}.{ext}"

    abs_path = os.path.join(upload_dir, filename)
    file_storage.save(abs_path)

    # Windows backslash fix
    rel = f"{subdir}/{filename}".replace("\\", "/")
    return url_for("static", filename=rel)


