@app.route("/update_posts", methods=["POST"])
@login_required
def update_posts():
    data = request.get_json() or {}

    # ✅ Hem tek obje hem liste desteği
    records = data if isinstance(data, list) else [data]

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    update_sql = """
        UPDATE [Yuce_Portal].[dbo].[posts]
        SET active = ?, pinned = ?, YA_users = ?, YS_users = ?
        WHERE id = ?
    """

    try:
        for rec in records:
            post_id = rec.get("id")
            if not post_id:
                continue

            # ✅ frontend “active” da gönderebilir, eski hali “aktif_pasif” da
            active_val = rec.get("active", rec.get("aktif_pasif", None))

            # ✅ sadece gelen alanları güncellemek istiyoruz
            # bunun için önce mevcut değerleri çekelim (tek satır)
            cursor.execute("""
                SELECT active, pinned, YA_users, YS_users
                FROM [Yuce_Portal].[dbo].[posts]
                WHERE id = ?
            """, (post_id,))
            row = cursor.fetchone()
            if not row:
                continue

            cur_active, cur_pinned, cur_ya, cur_ys = row

            new_active = cur_active if active_val is None else int(active_val)
            new_pinned = cur_pinned if rec.get("pinned") is None else int(rec.get("pinned"))
            new_ya     = cur_ya     if rec.get("YA_users") is None else int(rec.get("YA_users"))
            new_ys     = cur_ys     if rec.get("YS_users") is None else int(rec.get("YS_users"))

            cursor.execute(update_sql, new_active, new_pinned, new_ya, new_ys, post_id)

        conn.commit()

    except Exception as e:
        conn.rollback()
        return jsonify({"message": "Update failed", "error": str(e)}), 500
    finally:
        cursor.close()
        conn.close()

    return jsonify({"message": "Update successful!"})


