OTAL_SPOTS = 43
COMPANY_SPOTS = list(range(36, 44))
GENERAL_SPOTS = list(range(10, 36))

def get_base_today():
    """
    Rezervasyon pencere gününü 08:00'de değiştirir.
    00:00-07:59 arası 'dün' kabul edilir.
    """
    now = datetime.datetime.now()
    base = now - datetime.timedelta(hours=8)
    return base.date()

def get_max_day_for_user():
    base_today = get_base_today()
    if session.get("ID") in (106, 102):
        return base_today + datetime.timedelta(days=15)
    return base_today + datetime.timedelta(days=7)

def format_tr_date(d: datetime.date) -> str:
    return d.strftime("%d.%m.%Y")
 
