@app.route("/download_otopark_raporu/<string:tarih>", methods=["GET"])
@login_required
def download_otopark_raporu(tarih):
    #today_date = datetime.datetime.today().strftime("%Y-%m-%d")
    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    query = """
        SELECT [rezerv_park_no], [plaka], [username], [Geldi], [guvenlik_aciklama]
        FROM [Yuce_Portal].[dbo].[YA_otopark] 
        WHERE rezerv_tarih = ?
        AND is_active = 1
        ORDER BY [rezerv_park_no]
    """
    cursor.execute(query, (tarih,))
    reservations = cursor.fetchall()
    reservations = [
        [row[0], row[1], row[2], "Evet" if row[3] == 1 else "Hayır", row[4] if row[4] else ""]
        for row in reservations
    ]
    columns = ["Yer", "Plaka", "İsim", "Geldi/Gelmedi", "Açıklama"]  # Rename columns to match output
    reservations_df = pd.DataFrame(reservations, columns=columns)

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        reservations_df.to_excel(writer, index=False, sheet_name='Rezervasyonlar')

        workbook = writer.book
        sheet = workbook['Rezervasyonlar']

        import openpyxl
        from openpyxl.styles import PatternFill, Font, Alignment, Border, Side

        # Create header with the date
        formatted_tarih = datetime.datetime.strptime(tarih, "%Y-%m-%d").strftime("%d.%m.%Y")
        date_row = sheet.row_dimensions[1]  # First row
        sheet.insert_rows(1)  # Insert a new row at the top
        sheet.merge_cells('A1:E1')  # Merge cells A1 to E1
        date_cell = sheet.cell(row=1, column=1)
        date_cell.value = f"Rapor Tarihi: {formatted_tarih}"  # Add the date information
        date_cell.font = Font(bold=True)
        date_cell.alignment = Alignment(horizontal="center", vertical="center")

        header_fill = PatternFill(start_color="0E3A2F", end_color="0E3A2F", fill_type="solid")
        header_font = Font(color="78FAAE", bold=True)
        center_alignment = Alignment(horizontal="center", vertical="center")

        thin_border = Border(
            left=Side(style='thin'),
            right=Side(style='thin'),
            top=Side(style='thin'),
            bottom=Side(style='thin')
        )

        # **Apply styles to all headers (including "Durum" and "Açıklama")**
        for cell in sheet[1]:
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = center_alignment
            cell.border = thin_border

        # **Center-align all cells & replace "None" with empty string**
        for row in sheet.iter_rows():
            for cell in row:
                if cell.value == "None":
                    cell.value = ""
                cell.alignment = center_alignment
                cell.border = thin_border

        # **Adjust column widths**
        column_widths = {'A': 10, 'B': 20, 'C': 30, 'D': 15, 'E': 50}
        for col, width in column_widths.items():
            sheet.column_dimensions[col].width = width

    output.seek(0)

    Write_Log_ToDB(session.get('username'), "GET", "/download_otopark_raporu", 0, "User downloaded the Excel.")
    return send_file(output, as_attachment=True, download_name='Otopark Raporu.xlsx', mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')

@app.route("/get_available_spots", methods=["POST"])
@login_required
def get_available_spots():
    """
    Returns available spots for the selected_date.
    - Applies 08:00 cutoff window for 'today' and max_day.
    - Blocks user if they have NO-SHOW in last 3 days (is_active=1 & Geldi=0/NULL).
    - Company car logic:
        * if 36-43 has any availability => return ONLY 36-43
        * else => return 10-43
      Non-company => return 10-35
    Response:
      - If blocked: {"blocked": true, "message": "...", "wait_until": "YYYY-MM-DD", "no_show_date": "YYYY-MM-DD"}
      - Else:      {"blocked": false, "available": [..]}
    """
    import datetime

    selected_date = request.form.get("selected_date")
    if not selected_date:
        return jsonify({"blocked": True, "message": "Tarih seçilmedi."}), 400

    # ---- 08:00 cutoff logic ----
    now = datetime.datetime.now()
    base_today = (now - datetime.timedelta(hours=8)).date()  # 00:00-07:59 => yesterday
    if session.get("ID") in (106, 102):
        max_day = base_today + datetime.timedelta(days=15)
    else:
        max_day = base_today + datetime.timedelta(days=7)

    try:
        d = datetime.datetime.strptime(selected_date, "%Y-%m-%d").date()
    except ValueError:
        return jsonify({"blocked": True, "message": "Tarih formatı hatalı."}), 400

    if d < base_today:
        return jsonify({"blocked": True, "message": "Geçmiş günler için rezervasyon yapılamaz."}), 200
    if d > max_day:
        return jsonify({"blocked": True, "message": "Bu kadar uzak tarihe rezervasyon yapılamaz. (Max 7 gün sonrasına)"}), 200

    username_full = f"{session.get('name')} {session.get('surname')}"
    cutoff_date = base_today - datetime.timedelta(days=3)

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    # ---- 1) NO-SHOW BLOCK (last 3 days) ----
    cursor.execute("""
        SELECT TOP 1 rezerv_tarih
        FROM [Yuce_Portal].[dbo].[YA_otopark]
        WHERE username = ?
          AND is_active = 1
          AND (Geldi = 0 OR Geldi IS NULL)
          AND rezerv_tarih >= ?
        ORDER BY rezerv_tarih DESC
    """, (username_full, cutoff_date))

    ns = cursor.fetchone()
    if ns:
        ns_date = ns[0]  # date
        wait_until = ns_date + datetime.timedelta(days=3)
        cursor.close()
        connection.close()

        msg = (f"Üzgünüz, şu {ns_date.strftime('%d.%m.%Y')}'te rezervasyon yapıp gelmediğiniz için "
               f"tekrar rezervasyon yapmak için {wait_until.strftime('%d.%m.%Y')} beklemelisiniz.")

        return jsonify({
            "blocked": True,
            "code": "NO_SHOW_BLOCK",
            "no_show_date": ns_date.strftime("%Y-%m-%d"),
            "wait_until": wait_until.strftime("%Y-%m-%d"),
            "message": msg
        }), 200

    # ---- 2) Get reserved spots for that day ----
    cursor.execute("""
        SELECT rezerv_park_no
        FROM [Yuce_Portal].[dbo].[YA_otopark]
        WHERE rezerv_tarih = ? AND is_active = 1
    """, (selected_date,))
    reserved_spots = [row[0] for row in cursor.fetchall()]

    is_company_car = (session.get('arac_marka') == "Skoda (Şirket Aracı)")

    # ---- 3) Compute available spots with your business rules ----
    # keep your exclusions
    excluded = {3, 4}

    if is_company_car:
        company_spots = list(range(36, 44))  # 36-43
        available_company = [s for s in company_spots if s not in reserved_spots and s not in excluded]

        if available_company:
            available_spots = available_company  # ONLY company area
        else:
            all_spots = list(range(10, 44))     # fallback to all
            available_spots = [s for s in all_spots if s not in reserved_spots and s not in excluded]
    else:
        all_spots = list(range(10, 36))         # 10-35
        available_spots = [s for s in all_spots if s not in reserved_spots and s not in excluded]

    cursor.close()
    connection.close()

    return jsonify({"blocked": False, "available": available_spots}), 200

