@app.route("/get_reservations", methods=["POST"])
@login_required
def get_reservations():
    import json

    selected_date = request.form.get("selected_date")

    if not selected_date:
        return json.dumps({"error": "No date provided"}), 400

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    query = f"""
        SELECT [username], [plaka], [rezerv_park_no], FORMAT([rezerv_tarih], 'dd.MM.yyyy') AS rezerv_tarih
        FROM [Yuce_Portal].[dbo].[YA_otopark]
        WHERE rezerv_tarih = '{selected_date}'
          AND is_active = 1
        ORDER BY [rezerv_park_no]
    """
    cursor.execute(query)
    results = cursor.fetchall()

    cursor.close()
    connection.close()

    # 4) Convert results to JSON
    reservations = [
        {"username": row[0], "plaka": row[1], "park_no": row[2], "rezerv_tarih": row[3]}
        for row in results
    ]

    return json.dumps(reservations)

@app.route("/otopark_rezerv_data", methods=["GET"])
@login_required
def Otopark_Rezerve_Listesi():

    from datetime import datetime, time
    form = Otopark_Iptal_Form(request.form)

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()
    username = session.get('name') + " " + session.get('surname')

    query = f"""
        SELECT 
            [id], 
            [username], 
            [plaka], 
            FORMAT([rezerv_tarih], 'dd.MM.yyyy') AS rezerv_tarih, 
            [rezerv_park_no], 
            FORMAT([created_at], 'dd.MM.yyyy HH.mm') AS created_at, 
            [is_active]
        FROM [Yuce_Portal].[dbo].[YA_otopark]
        WHERE username = '{username}'
        ORDER BY CAST([rezerv_tarih] AS date) DESC
    """

    cursor.execute(query)
    results = cursor.fetchall()

    now = datetime.now()
    today = now.date()
    cutoff_time = datetime.combine(today, time(8, 0))  # ✅ Corrected

    for result in results:
        result_date = datetime.strptime(result[3], "%d.%m.%Y")
        rezerv_date_only = result_date.date()

        if rezerv_date_only < today or (rezerv_date_only == today and now >= cutoff_time):
            # Too late to cancel
            if result[6] != 0:
                result[6] = 2  # Mark as non-cancellable (disabled button etc.)

    Write_Log_ToDB(session.get('username'), "GET", "/otopark_rezerv_data", 0)

    return render_template("otopark_rezerv_data.html", results=results, form=form)

@app.route("/delete_reservation", methods=["POST"])
@login_required
def delete_reservation():
    import json

    reservation_id = request.form.get("reservation_id")
    aciklama = request.form.get("aciklama")

    if not reservation_id:
        return json.dumps({"success": False, "error": "No reservation ID provided"}), 400

    connection = pyodbc.connect(YA_2El_AracSatis)
    cursor = connection.cursor()

    cursor.execute("""
        SELECT rezerv_tarih, rezerv_park_no
        FROM [Yuce_Portal].[dbo].[YA_otopark]
        WHERE id = ?
    """, (reservation_id,))
    row = cursor.fetchone()

    if not row:
        return json.dumps({"success": False, "error": "Rezervasyon bulunamadı."}), 404

    rezerv_date, rezerv_spot = row

    cursor.execute("""
        UPDATE [Yuce_Portal].[dbo].[YA_otopark]
        SET is_active = 0,
            aciklama = ?,
            canceled_at = GETDATE(),
            Geldi = 0
        WHERE id = ?
    """, (aciklama, reservation_id))

    if rezerv_spot < 36:
        cursor.execute("""
            SELECT username, nam_surnam, email
            FROM [Yuce_Portal].[dbo].[YA_otopark_bekleme_list]
            WHERE requested_date = ?
            ORDER BY created_at
        """, (rezerv_date,))
        waiting_users = cursor.fetchall()

        for username_waiting, full_name, email in waiting_users:
            send_email(
                content=f"Merhaba {full_name},<br><br>"
                        f"{rezerv_date.strftime('%d.%m.%Y')} tarihi için otoparkta yer açıldı. "
                        f"<a href='https://yuceportal.skoda.com.tr/YA_otopark_rezerve'>Hemen rezerve etmek için tıklayın</a>.",
                subject="Otoparkta Yer Açıldı!",
                receiver_email=email,
                sender_email="yuceportal@skoda.com.tr"
            )
            try:
                token = find_device_token(username_waiting)
                send_push_notification(token=token, title="Otoparkta Yer Açıldı!", message=f"{rezerv_date.strftime('%d.%m.%Y')} tarihi için otoparkta yer açıldı.")
            except:
                pass
            
    connection.commit()
    cursor.close()
    connection.close()

    Write_Log_ToDB(session.get('username'), "POST", "/delete_reservation", 0, f"{reservation_id} is deleted (is_active=0).")

    return json.dumps({"success": True}), 200

@app.route("/YA_sarj_rezerve", methods=["GET", "POST"])
@login_required
def sarj_rezerve():
    ac_form = AC_Sarj_Rezerv_Form(request.form)
    dc_form = DC_Sarj_Rezerv_Form(request.form)

    plaka1 = session.get("plaka")
    plaka2 = session.get("plaka2")
    
    plakalar = []
    if plaka1:
        plakalar.append(plaka1)
    if plaka2:
        plakalar.append(plaka2)

    if plakalar:
        ac_form.plaka.choices = [(plaka, plaka) for plaka in plakalar]
        dc_form.plaka.choices = [(plaka, plaka) for plaka in plakalar]
    else:
        ac_form.plaka.choices = [("", "No Plate Available")]
        dc_form.plaka.choices = [("", "No Plate Available")]
    
    cursor = mysql.connection.cursor()
    username = session.get('username')

    if request.method == "GET":
        query = f"""
        SELECT
            rezerv_tarih,
            istasyon_no,
            rezerv_saat,
            plaka
        FROM sarj_istasyon_rezerve
        WHERE username = '{username}'
        AND rezerv_tarih >= CURDATE()
        AND is_active = 1
        ORDER BY rezerv_tarih ASC;
        """
        cursor.execute(query)
        raw_results = cursor.fetchall()

        turkish_months = [
            "", "Ocak", "Şubat", "Mart", "Nisan", "Mayıs", "Haziran",
            "Temmuz", "Ağustos", "Eylül", "Ekim", "Kasım", "Aralık"
        ]
        turkish_weekdays = [
            "Pazartesi", "Salı", "Çarşamba", "Perşembe",
            "Cuma", "Cumartesi", "Pazar"
        ]

        fw_dates_rezerve = []
        for row in raw_results:
            dt = row["rezerv_tarih"]
            day = dt.day
            month = turkish_months[dt.month]
            year = dt.year
            weekday = turkish_weekdays[dt.weekday()]
            formatted_date = f"{day} {month} {weekday} ({year})"

            fw_dates_rezerve.append({
                "plaka": row["plaka"],
                "istasyon_no": row["istasyon_no"],
                "rezerv_saat": row["rezerv_saat"],
                "rezerv_tarih": formatted_date,
                "rezerv_tarih_raw": dt.strftime("%Y-%m-%d")
            })

        today_str = datetime.datetime.now().strftime('%Y-%m-%d')
        future_str = (datetime.datetime.now() + timedelta(days=7)).strftime('%Y-%m-%d')

        Write_Log_ToDB(session.get('username'), "GET", "/arac_sarj_rezerve", 0)

        return render_template("arac_sarj_rezerve.html", ac_form=ac_form, dc_form=dc_form, fw_dates_rezerve=fw_dates_rezerve, min_Date=today_str, max_Date=future_str)

    if request.method == "POST":
        form_type = request.form.get("form_type")

        if form_type == "DC":
            form = dc_form
        elif form_type == "AC":
            form = ac_form
        else:
            flash("Form tipi belirlenemedi.", "danger")
            return redirect(url_for("sarj_rezerve"))

        plaka = form.plaka.data
        istasyon = form.istasyon.data
        tarih = form.tarih.data
        saat = form.saat.data
        username = session.get("username")
        name_surname = f"{session.get('name')} {session.get('surname')}"
        users1_id = session.get("ID")

        if not plaka:
            flash("Plaka seçilmedi.", "danger")
            return redirect(url_for("sarj_rezerve"))

        check_query = """
            SELECT COUNT(*) AS cnt
            FROM sarj_istasyon_rezerve
            WHERE rezerv_tarih = %s
            AND rezerv_saat = %s
            AND istasyon_no = %s
            AND is_active = 1
        """
        cursor.execute(check_query, (tarih, saat, istasyon))
        spot_count = cursor.fetchone()["cnt"]

        if spot_count > 0:
            flash("Bu saat için bu istasyon zaten rezerve edilmiş.", "danger")
            return redirect(url_for("sarj_rezerve"))

        insert_query = """
            INSERT INTO sarj_istasyon_rezerve
                (username, name_surname, plaka, istasyon_no, rezerv_tarih, rezerv_saat, is_active, kullanilma_durumu, users1_id, AC_DC)
            VALUES
                (%s, %s, %s, %s, %s, %s, 1, 1, %s, %s)
        """
        cursor.execute(insert_query, (username, name_surname, plaka, istasyon, tarih, saat, users1_id, form_type))
        mysql.connection.commit()

        Write_Log_ToDB(username, "POST", "/arac_sarj_rezerve", 0, f"{istasyon} numaralı yer için şarj rezervasyonu yaptı")
        flash(f"{tarih} tarihinde saat {saat} için {istasyon} numaralı istasyona rezervasyonunuz yapıldı.", "success")

        return redirect(url_for("sarj_rezerve"))

