@app.route("/get_available_istasyon", methods=["GET"])
@login_required
def get_available_istasyon():
    tarih = request.args.get("tarih")
    saat = request.args.get("saat")
    stype = request.args.get("type")  # "AC" or "DC"

    if not tarih or not saat or stype not in {"AC", "DC"}:
        return jsonify({"available": [], "reserved": []})

    cursor = mysql.connection.cursor()

    query = """
        SELECT istasyon_no,
               username,
               name_surname AS fullname
        FROM   sarj_istasyon_rezerve
        WHERE  rezerv_tarih = %s
          AND  rezerv_saat  = %s
          AND  is_active    = 1
    """
    cursor.execute(query, (tarih, saat))
    rows = cursor.fetchall()

    AC_SPOTS = {"5 (Ücretli)", "6 (Ücretli)", "7", "8", "9"}
    DC_SPOTS = {"2", "3", "4", "Giriş 1", "Giriş 2"}

    all_spots = AC_SPOTS if stype == "AC" else DC_SPOTS

    reserved = {str(row["istasyon_no"]) for row in rows if str(row["istasyon_no"]) in all_spots}
    available = sorted(all_spots - reserved)

    filtered_rows = [row for row in rows if str(row["istasyon_no"]) in all_spots]

    return jsonify({"available": available, "reserved": filtered_rows})

# --- simple config (edit if needed)
AC_SPOTS = {"5 (Ücretli)", "6 (Ücretli)", "7", "8", "9"}
DC_SPOTS = {"2", "3", "4", "Giriş 1", "Giriş 2"}

# --- for date+type+period, list available stations (and show who reserved)
@app.route("/api/charging/available", methods=["GET"])
@login_required
def api_charging_available():
    date_str = request.args.get("date")
    stype = (request.args.get("type") or "").upper()
    period = request.args.get("period")

    if not date_str or stype not in {"AC", "DC"} or not period:
        return jsonify({"available": [], "reserved": [], "message": "date, type, period required"}), 400

    # same window logic as parking
    today = datetime.datetime.now().date()
    max_day = today + datetime.timedelta(days=15 if session.get("ID") == 106 else 7)
    try:
        d = datetime.datetime.strptime(date_str, "%Y-%m-%d").date()
    except ValueError:
        return jsonify({"available": [], "reserved": [], "message": "invalid date format"}), 400
    if d < today:
        return jsonify({"available": [], "reserved": [], "allowed": False, "reason": "Geçmiş günler için yapılamaz."}), 200
    if d > max_day:
        return jsonify({"available": [], "reserved": [], "allowed": False, "reason": "Bu kadar uzak tarihe yapılamaz. (Max 7 gün sonrasına)"}), 200

    all_spots = AC_SPOTS if stype == "AC" else DC_SPOTS

    cursor = mysql.connection.cursor()
    cursor.execute("""
        SELECT istasyon_no, username, name_surname AS fullname
        FROM sarj_istasyon_rezerve
        WHERE rezerv_tarih = %s AND rezerv_saat = %s AND is_active = 1
    """, (date_str, period))
    rows = cursor.fetchall()

    reserved_set = {str(r["istasyon_no"]) for r in rows if str(r["istasyon_no"]) in all_spots}
    available = sorted(all_spots - reserved_set, key=lambda s: (len(s), s))
    reserved = [r for r in rows if str(r["istasyon_no"]) in all_spots]

    return jsonify({"allowed": True, "available": available, "reserved": reserved}), 200

# --- reserve date+type+period+station+plate
@app.route("/api/charging/reserve", methods=["POST"])
@login_required
def api_charging_reserve():
    payload  = request.get_json(silent=True) or {}
    date_str = payload.get("date")
    stype    = (payload.get("type") or "").upper()
    period   = payload.get("period")
    station  = str(payload.get("station") or "").strip()
    plate    = (payload.get("plate") or "").strip()

    if not date_str or stype not in {"AC", "DC"} or not period or not station or not plate:
        return jsonify({"status": "error", "message": "date, type, period, station, plate are required"}), 400

    # window logic (same as parking)
    today = datetime.datetime.now().date()
    max_day = today + datetime.timedelta(days=15 if session.get("ID") == 106 else 7)
    try:
        d = datetime.datetime.strptime(date_str, "%Y-%m-%d").date()
    except ValueError:
        return jsonify({"status": "error", "message": "invalid date format"}), 400
    if d < today or d > max_day:
        return jsonify({"status": "error", "message": "date out of allowed window"}), 400

    # basic validations
    all_spots = AC_SPOTS if stype == "AC" else DC_SPOTS
    if station not in all_spots:
        return jsonify({"status": "error", "message": "Geçersiz istasyon"}), 400

    plaka1 = session.get("plaka")
    plaka2 = session.get("plaka2")
    plates_allowed = {p for p in (plaka1, plaka2) if p}
    if plate not in plates_allowed:
        return jsonify({"status": "error", "message": "Bu plaka için yetkiniz yok"}), 403

    cursor = mysql.connection.cursor()
    username = session.get("username")
    name_surname = f"{session.get('name')} {session.get('surname')}".strip()
    users1_id = session.get("ID")

    # is station taken?
    cursor.execute("""
        SELECT COUNT(*) AS cnt
        FROM sarj_istasyon_rezerve
        WHERE rezerv_tarih = %s AND rezerv_saat = %s AND istasyon_no = %s AND is_active = 1
    """, (date_str, period, station))
    if cursor.fetchone()["cnt"] > 0:
        return jsonify({"status": "error", "code": "SPOT_TAKEN"}), 409

    # Optional: block multiple active bookings by same user at same date+period
    cursor.execute("""
        SELECT COUNT(*) AS cnt
        FROM sarj_istasyon_rezerve
        WHERE username = %s AND rezerv_tarih = %s AND rezerv_saat = %s AND is_active = 1
    """, (username, date_str, period))
    if cursor.fetchone()["cnt"] > 0:
        return jsonify({"status": "error", "code": "ALREADY_RESERVED"},), 409

    # insert reservation
    cursor.execute("""
        INSERT INTO sarj_istasyon_rezerve
            (username, name_surname, plaka, istasyon_no, rezerv_tarih, rezerv_saat,
             is_active, kullanilma_durumu, users1_id, AC_DC)
        VALUES (%s, %s, %s, %s, %s, %s, 1, 1, %s, %s)
    """, (username, name_surname, plate, station, date_str, period, users1_id, stype))
    mysql.connection.commit()

    Write_Log_ToDB(username, "POST", "/api/charging/reserve", 0,
                   f"{date_str} {period} için {stype} {station} rezerve edildi.")
    return jsonify({"status": "ok", "date": date_str, "period": period, "station": station, "type": stype}), 200

@app.route("/api/arac_yikama/reserve", methods=["POST"])
@login_required
def api_arac_yikama_reserve():
    payload  = request.get_json(silent=True) or {}
    date_str = (payload.get("date") or "").strip()
    plate    = (payload.get("plate") or "").strip()

    today   = datetime.datetime.now().date()
    max_day = today + datetime.timedelta(days=15 if session.get("ID") == 106 else 7)

    try:
        d = datetime.datetime.strptime(date_str, "%Y-%m-%d").date()
    except ValueError:
        return jsonify({"status": "error", "message": "invalid date format"}), 400

    # Date window check
    if d < today or d > max_day:
        return jsonify({"status": "error", "message": "date out of allowed window"}), 400

    # Plate authorization
    plaka1 = session.get("plaka")
    plaka2 = session.get("plaka2")
    plates_allowed = {p for p in (plaka1, plaka2) if p}
    if plate not in plates_allowed:
        return jsonify({"status": "error", "message": "Bu plaka için yetkiniz yok"}), 403

    cursor = mysql.connection.cursor()
    username = session.get("username")
    name_surname = f"{session.get('name')} {session.get('surname')}".strip()

    cursor.execute("""
        SELECT id
        FROM arac_yikama
        WHERE username = %s
        AND rezerv_tarih = %s
        AND canceled_at IS NULL
        LIMIT 1
    """, (username, d))
    already = cursor.fetchone()
    if already:
        return jsonify({
            "status":"error",
            "code":"already_reserved",
            "message":"Aynı gün için bir yıkama randevunuz zaten var."
        }), 409

    # aylık kota: sadece aktif rezervasyonları say
    cursor.execute("""
        SELECT COUNT(*) AS cnt
        FROM arac_yikama
        WHERE username = %s
        AND YEAR(rezerv_tarih) = %s
        AND MONTH(rezerv_tarih) = %s
        AND canceled_at IS NULL
    """, (username, d.year, d.month))
    row = cursor.fetchone()
    count_this_month = int(row['cnt'] if isinstance(row, dict) else row[0])

    if count_this_month >= 4:
        return jsonify({
            "status":"error",
            "code":"monthly_quota_exceeded",
            "message":"Aylık yıkama limitini aştınız, sonraki aya kadar yıkama talebinde bulunamazsınız"
        }), 403
    try:
        cursor.execute("""
            INSERT INTO arac_yikama
                (username, name_surname, plaka, rezerv_tarih)
            VALUES (%s, %s, %s, %s)
        """, (username, name_surname, plate, d))
        mysql.connection.commit()
    except Exception as e:
        mysql.connection.rollback()
        if getattr(e, "args", [None])[0] == 1062:
            return jsonify({
                "status": "error",
                "code": "already_reserved",
                "message": "Aynı gün için bir yıkama randevunuz zaten var."
            }), 409
        raise

    Write_Log_ToDB(username, "POST", "/api/arac_yikama/reserve", 0, f"{date_str} için {plate} plakalı araca araç yıkama rezerve edildi.")
    return jsonify({"status": "ok", "date": date_str, "plate": plate}), 200

@app.post("/api/arac_yikama/cancel")
@login_required
def cancel_arac_yikama():
    from datetime import datetime, date, time
    payload = request.get_json() or {}
    date_str = payload.get("date")
    if not date_str:
        return jsonify(status="error", message="Tarih zorunlu"), 400

    try:
        y, m, d = map(int, date_str.split("-"))
        target_day = date(y, m, d)
    except Exception:
        return jsonify(status="error", message="Geçersiz tarih"), 400

    now = datetime.now()
    allow_cancel = (target_day > now.date()) or (target_day == now.date() and now.time() < time(9, 0))
    if not allow_cancel:
        return jsonify(status="error", message="İptal süresi geçti (aynı gün 09:00’a kadar)."), 400

    cur = mysql.connection.cursor()
    cur.execute("""
        UPDATE arac_yikama
        SET canceled_by = %s,
            canceled_at = NOW()
        WHERE username = %s
          AND rezerv_tarih = %s
          AND canceled_by IS NULL
          AND canceled_at IS NULL
        LIMIT 1
    """, (session.get("username"), session.get("username"), target_day))
    mysql.connection.commit()
    updated = cur.rowcount
    cur.close()

    if updated == 0:
        return jsonify(status="error", message="Aktif rezervasyon bulunamadı."), 404

    return jsonify(status="ok")

