@app.route("/satin_alma_sorumlusu_talep_degerlendirme", methods=["GET"])
@login_required
def SatinAlma_Sorumlusu_Talep_Degerlendirme():
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    form = SatinAlma_TeklifForm(request.form)

    try:
        cursor.execute("""
        SELECT 
            [ID],
            [TalepNo],
            [TalepDept],
            CONVERT(varchar(10), TalepTarihi, 104) AS TalepTarihi,
            [FinalTotal],
            [created_by],
            [created_by_nam_surn],
            [is_active],
            [created_at],
            [Talep_Asama],
            [TalepEdenDepartman],
            [Aciklama],
            ISNULL([YansitmaFatura], 0) AS YansitmaFatura,
            [onaylar]
        FROM [Yuce_Portal].[dbo].[SatinAlmaTalep]
        WHERE 
            is_active = 1
            AND JSON_VALUE(onaylar, '$.satin_alma_degerlendirme_sorumlu') = '0'
        ORDER BY created_at DESC;
        """)
        columns = [column[0] for column in cursor.description]
        talepler = [dict(zip(columns, row)) for row in cursor.fetchall()]

        for t in talepler:
            t['FinalTotalFormatted'] = format_final_total(t.get('FinalTotal'))
            # normalize (bazı ortamlarda bit True/False gibi gelebiliyor)
            t['YansitmaFatura'] = 1 if str(t.get('YansitmaFatura', 0)) in ("1", "True", "true") else 0

    except Exception as e:
        flash(f'Hata oluştu: {str(e)}', 'danger')
        talepler = []

    finally:
        cursor.close()
        conn.close()

    Write_Log_ToDB(session.get('username'), "GET", "/satin_alma_sorumlusu_talep_degerlendirme", 0)
    return render_template("satin_alma_sorumlu_talep_degerlendirme.html", talepler=talepler, form=form)

