@app.route('/update_onay', methods=['POST'])
@login_required
def update_onay():
    data = request.get_json()
    ID = data.get('ID')
    onay_value = data.get('onay')
    selected_reason = data.get('selected_reason')
    talep_no = data.get('talep_no')
    teklif_sayisi = data.get('teklif_sayisi')

    try:
        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()

        # 1) Check current approval status of Kalem
        cursor.execute("""
            SELECT onay
            FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
            WHERE ID = ?
        """, (ID,))
        row = cursor.fetchone()

        if not row:
            return jsonify({'success': False, 'message': 'Kalem bulunamadı.'})
        if row[0] != 0:
            return jsonify({'success': False, 'message': 'Zaten işlenmiş.'})

        # 2) Update the kalem onay status
        cursor.execute("""
            UPDATE [Yuce_Portal].[dbo].[SatinAlmaKalem]
            SET onay = ?,
                OnayTipi = ?
            WHERE ID = ?;
        """, (onay_value, selected_reason, ID))

        # 3) Insert approval log
        cursor.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[SatinAlmaOnayLog]
            (TalepNo, KalemID, TeklifSayisi, SecilenDurum, ApprovedBy)
            VALUES (?, ?, ?, ?, ?)
        """, (talep_no, ID, teklif_sayisi, selected_reason, session.get("username")))

        # 4) Check category of the Talep + onaylar json
        cursor.execute("""
            SELECT TalepDept, onaylar
            FROM [Yuce_Portal].[dbo].[SatinAlmaTalep]
            WHERE TalepNo = ?
        """, (talep_no,))
        row = cursor.fetchone()

        if row:
            talep_dept, onaylar_json = row

            try:
                onaylar_dict = json.loads(onaylar_json or '{}')
            except Exception:
                onaylar_dict = {}

            # kategoriye göre eklenecek yönetici
            manager_to_insert = None
            if talep_dept == "Bilgi Teknolojileri (IT)":
                manager_to_insert = "kamilb"
            elif talep_dept == "Pazarlama":
                manager_to_insert = "burcub"

            # ✅ Finans adımı yansıtma talebinde "zaferb", normalde "satin_alma_finans_sorumlu"
            # Onaylar JSON'unda hangisi varsa onu anchor alacağız.
            # (yansıtma seçildiyse zaten zaferb olması lazım)
            finance_anchor_key = None
            if "zaferb" in onaylar_dict:
                finance_anchor_key = "zaferb"
            elif "satin_alma_finans_sorumlu" in onaylar_dict:
                finance_anchor_key = "satin_alma_finans_sorumlu"

            if manager_to_insert and manager_to_insert not in onaylar_dict:
                new_onaylar = {}
                inserted = False

                if finance_anchor_key:
                    for k, v in onaylar_dict.items():
                        if k == finance_anchor_key and not inserted:
                            new_onaylar[manager_to_insert] = 0
                            inserted = True
                        new_onaylar[k] = v
                else:
                    # anchor yoksa (beklenmez), sona ekle
                    new_onaylar = dict(onaylar_dict)
                    new_onaylar[manager_to_insert] = 0
                    inserted = True

                cursor.execute("""
                    UPDATE [Yuce_Portal].[dbo].[SatinAlmaTalep]
                    SET onaylar = ?
                    WHERE TalepNo = ?
                """, (json.dumps(new_onaylar, ensure_ascii=False), talep_no))

        conn.commit()
        Write_Log_ToDB(session.get('username'), "POST", "/update_onay", 0, f"Talep No: {talep_no}")
        return jsonify({'success': True})

    except Exception as e:
        return jsonify({'success': False, 'message': str(e)})

    finally:
        cursor.close()
        conn.close()

@app.route('/finalize_talep_onay/<int:talep_no>', methods=['POST'])
@login_required
def finalize_talep_onay(talep_no):
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    try:
        # 1) Any pending kalem?
        cursor.execute("""
            SELECT COUNT(*)
            FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
            WHERE TalepNo = ? AND onay = 0
        """, talep_no)
        pending_count = cursor.fetchone()[0]
        if pending_count > 0:
            return jsonify(success=False, message="Henüz tüm kalemler onaylanmadı veya reddedilmedi.")

        # 2) Approved / Rejected counts
        cursor.execute("""
            SELECT 
                SUM(CASE WHEN onay = 1 THEN 1 ELSE 0 END) AS approved_count,
                SUM(CASE WHEN onay = -1 THEN 1 ELSE 0 END) AS rejected_count
            FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
            WHERE TalepNo = ?
        """, talep_no)
        result = cursor.fetchone()
        approved_count = result[0] or 0
        rejected_count = result[1] or 0

        # 3) Current step outcome
        if approved_count > 0:
            satin_alma_value = 1
            talep_asama_value = 'Satın Alma Birimi Onayladı'
        else:
            satin_alma_value = -1
            talep_asama_value = 'Satın Alma Birimi Reddetti'

        # 4) FinalTotal per currency (approved only)
        cursor.execute("""
            SELECT ParaBirimi, SUM(UrunToplamFiyat)
            FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
            WHERE TalepNo = ? AND onay = 1
            GROUP BY ParaBirimi
        """, talep_no)
        sum_results = cursor.fetchall()

        final_total_dict = {}
        for para_birimi, toplam_fiyat in sum_results:
            if toplam_fiyat is not None:
                final_total_dict[para_birimi] = float(round(toplam_fiyat, 2))
        final_total_json = json.dumps(final_total_dict, ensure_ascii=False) if final_total_dict else "{}"

        # 5) TL_aprox from FinalTotal
        doviz = _get_exchange_rates()
        if doviz is None:
            return jsonify(success=False, message="Döviz kurları alınamadı. Lütfen tekrar deneyin.")

        dolar_kur = doviz.get("Dolar", 0)
        euro_kur = doviz.get("Euro", 0)

        tl_aprox = 0.0
        if "TL" in final_total_dict:
            tl_aprox = final_total_dict["TL"]
        if "Dolar" in final_total_dict:
            tl_aprox += final_total_dict["Dolar"] * dolar_kur
        if "Euro" in final_total_dict:
            tl_aprox += final_total_dict["Euro"] * euro_kur

        # 6) Base update on SatinAlmaTalep
        cursor.execute("""
            UPDATE [Yuce_Portal].[dbo].[SatinAlmaTalep]
            SET 
                FinalTotal = ?,
                onaylar = JSON_MODIFY(onaylar, '$.satin_alma_degerlendirme_sorumlu', ?),
                Talep_Asama = ?,
                TL_aprox = ?
            WHERE TalepNo = ?
        """, final_total_json, satin_alma_value, talep_asama_value, tl_aprox, talep_no)

        # 7) ACIL CHECK — override chain; choose next approver by TL_aprox
        cursor.execute("""
            SELECT CASE 
                     WHEN EXISTS (
                       SELECT 1
                       FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
                       WHERE TalepNo = ? AND OnayTipi = 'Acil'
                     ) THEN 1 ELSE 0
                   END
        """, talep_no)
        is_acil = (cursor.fetchone()[0] == 1)

        if is_acil:
            # Decide approver by TL_aprox threshold
            NEXT_APPROVER = "ulaso" if tl_aprox < 200000 else "zaferb"

            # Rebuild onaylar: keep current step result, set ONLY the chosen approver as next
            new_chain = {
                "satin_alma_degerlendirme_sorumlu": satin_alma_value
            }
            if satin_alma_value == 1:
                new_chain[NEXT_APPROVER] = 0

            new_chain_json = json.dumps(new_chain, ensure_ascii=False)

            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[SatinAlmaTalep]
                SET onaylar = ?
                WHERE TalepNo = ?
            """, new_chain_json, talep_no)

        conn.commit()

        # 8) Notifications — first pending approver (if any)
        cursor.execute("""
            SELECT onaylar 
            FROM [Yuce_Portal].[dbo].[SatinAlmaTalep]
            WHERE TalepNo = ?
        """, talep_no)
        row = cursor.fetchone()
        if row and row[0]:
            try:
                onaylar_dict = json.loads(row[0])
                for username, status in onaylar_dict.items():
                    if status == 0 and username != "satin_alma_degerlendirme_sorumlu":
                        message = f"{talep_no} numaralı satın alma talebi onayınızı beklemektedir. Lütfen kontrol ediniz."
                        a_tag = f"/satin_alma_onay"
                        send_notification(username, message, a_tag)
                        break
            except Exception as notify_err:
                print("Notification error:", str(notify_err))

        Write_Log_ToDB(session.get('username'), "POST", f"/finalize_talep_onay/{talep_no}", 0, f"Talep No: {talep_no} finalized.")
        return jsonify(success=True)

    except Exception as e:
        conn.rollback()
        return jsonify(success=False, error=str(e))

    finally:
        cursor.close()
        conn.close()

@app.route('/satin_alma_teklifler/<int:kalem_id>')
@login_required
def satin_alma_teklifler(kalem_id):
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    cursor.execute("""
        SELECT 
            t.TeklifID,
            t.UrunBirimFiyat,
            t.ParaBirimi,
            t.UrunToplamFiyat,
            t.UrunTedarikci,
            t.TeklifPdf_path,
            FORMAT(t.CreatedAt, 'dd.MM.yyyy HH:mm') AS CreatedAt,
            t.Adet,
            t.selected_teklif,
            log.SecilenDurum
        FROM [Yuce_Portal].[dbo].[SatinAlmaTeklif] t
        INNER JOIN [Yuce_Portal].[dbo].[SatinAlmaKalem] k ON t.KalemID = k.ID
        LEFT JOIN (
            SELECT TalepNo, SecilenDurum
            FROM (
                SELECT TalepNo, SecilenDurum,
                       ROW_NUMBER() OVER (PARTITION BY TalepNo ORDER BY ApprovedAt DESC) AS rn
                FROM [Yuce_Portal].[dbo].[SatinAlmaOnayLog]
            ) AS sub
            WHERE rn = 1
        ) log ON k.TalepNo = log.TalepNo
        WHERE t.KalemID = ?
        ORDER BY t.CreatedAt DESC
    """, kalem_id)

    offers = []
    for teklif_id, ubf, pb, utp, utd, pdf_path, created, Adet, selected_teklif, secilen_durum in cursor.fetchall():
        filename = os.path.basename(pdf_path) if pdf_path else None
        public_pdf_url = url_for('display_teklif_pdf', filename=filename) if filename else None

        offers.append({
            'id': teklif_id,
            'urun_birim_fiyat': float(ubf),
            'para_birimi':       pb,
            'urun_toplam_fiyat': float(utp),
            'urun_tedarikci':    utd,
            'teklif_pdf_path':   public_pdf_url,
            'created_at':        str(created),
            'miktar':            Adet,
            'selected_teklif':   selected_teklif,
            'secilen_durum':     secilen_durum
        })

    return jsonify(offers)

@app.route('/satin_alma_teklif_ekle', methods=['POST'])
@login_required
def satin_alma_teklif_ekle():
    kalem_id           = request.form.get('kalem_id')
    miktar             = request.form.get('Miktar')
    urun_birim_fiyat   = request.form.get('urun_birim_fiyat')
    para_birimi        = request.form.get('para_birimi')
    urun_toplam_fiyat  = request.form.get('urun_toplam_fiyat')
    urun_tedarikci     = request.form.get('urun_tedarikci')
    pdf_file           = request.files.get('teklif_pdf')

    try:
        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()

        # Check if this is the first teklif for the kalem
        cursor.execute("""
            SELECT COUNT(*) FROM [Yuce_Portal].[dbo].[SatinAlmaTeklif]
            WHERE KalemID = ?
        """, (kalem_id,))
        teklif_count = cursor.fetchone()[0]

        auto_select = 1 if teklif_count == 0 else 0

        if auto_select == 1:
            # Update Kalem with teklif values
            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[SatinAlmaKalem]
                SET UrunBirimFiyat = ?, ParaBirimi = ?, UrunToplamFiyat = ?
                WHERE ID = ?
            """, urun_birim_fiyat, para_birimi, urun_toplam_fiyat, kalem_id)

            # Get TalepNo for this kalem
            cursor.execute("""
                SELECT TalepNo FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
                WHERE ID = ?
            """, (kalem_id,))
            talep_row = cursor.fetchone()

            if talep_row:
                talep_no = talep_row[0]

                # Recalculate total by currency
                cursor.execute("""
                    SELECT ParaBirimi, SUM(UrunToplamFiyat)
                    FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
                    WHERE TalepNo = ?
                    GROUP BY ParaBirimi
                """, (talep_no,))

                from collections import defaultdict
                import json

                currency_totals = defaultdict(float)
                for currency, amount in cursor.fetchall():
                    currency = currency.strip().capitalize()
                    currency_totals[currency] += float(amount or 0)

                final_total_json = json.dumps(currency_totals)

                # Update Talep with FinalTotal
                cursor.execute("""
                    UPDATE [Yuce_Portal].[dbo].[SatinAlmaTalep]
                    SET FinalTotal = ?
                    WHERE TalepNo = ?
                """, (final_total_json, talep_no))

        # Insert teklif into the table
        cursor.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[SatinAlmaTeklif]
               (KalemID, UrunBirimFiyat, ParaBirimi, UrunToplamFiyat,
                UrunTedarikci, CreatedAt, CreatedBy, Adet, selected_teklif)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?);
            SELECT CAST(SCOPE_IDENTITY() AS INT);
        """,
            kalem_id,
            urun_birim_fiyat,
            para_birimi,
            urun_toplam_fiyat,
            urun_tedarikci,
            datetime.datetime.now(),
            session.get('username'),
            miktar,
            auto_select
        )
        cursor.nextset()
        teklif_id = cursor.fetchone()[0]

        # Save PDF if uploaded
        if pdf_file and pdf_file.filename:
            save_dir = r"C:\Users\yuceappadmin\Documents\GitHub\RPA-Projects\static\SatinAlma_Teklifler_PDF"
            os.makedirs(save_dir, exist_ok=True)
            timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            filename = f"{teklif_id}_{timestamp}.pdf"
            full_path = os.path.join(save_dir, filename)
            pdf_file.save(full_path)

            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[SatinAlmaTeklif]
                SET TeklifPdf_path = ?
                WHERE TeklifID = ?
            """, full_path, teklif_id)

        conn.commit()

    except Exception as e:
        app.logger.exception("Teklif eklerken hata")
        flash("Teklif kaydedilirken bir hata oluştu.", "danger")
    else:
        flash("Teklif başarıyla kaydedildi.", "success")
    finally:
        cursor.close()
        conn.close()

    Write_Log_ToDB(session.get('username'), "POST", "/satin_alma_teklif_ekle", 0, f"{kalem_id} için teklif kaydetti.")
    return redirect(url_for('SatinAlma_Sorumlusu_Talep_Degerlendirme'))

@app.route('/satin_alma_teklif_sec', methods=['POST'])
@login_required
def satin_alma_teklif_sec():
    kalem_id = request.form.get('kalem_id')
    selected_teklif_id = request.form.get('selected_teklif')
    satin_almaci_aciklama = request.form.get('satin_alma_sorumlu_aciklama')

    if satin_almaci_aciklama is None:
        satin_almaci_aciklama = "-"

    if kalem_id and selected_teklif_id:
        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()

        try:
            # 1. Set selected_teklif = 1 for the chosen teklif
            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[SatinAlmaTeklif]
                SET selected_teklif = 1
                WHERE TeklifID = ?
            """, (selected_teklif_id,))

            # 2. Set selected_teklif = 0 for all other teklifler
            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[SatinAlmaTeklif]
                SET selected_teklif = 0
                WHERE KalemID = ? AND TeklifID != ?
            """, (kalem_id, selected_teklif_id))

            # 3. Get data from selected teklif
            cursor.execute("""
                SELECT Adet, UrunBirimFiyat, ParaBirimi, UrunToplamFiyat, TeklifPdf_path
                FROM [Yuce_Portal].[dbo].[SatinAlmaTeklif]
                WHERE TeklifID = ?
            """, (selected_teklif_id,))
            teklif_data = cursor.fetchone()

            if teklif_data:
                miktar, birim_fiyat, para_birimi, toplam_fiyat, teklif_path = teklif_data
                if teklif_path != None:
                    teklif_path = teklif_path.replace(r"C:\Users\yuceappadmin\Documents\GitHub\RPA-Projects","")
                    teklif_path = teklif_path.replace(r"\s".replace("s",""),"/")

                # 4. Update the SatinAlmaKalem with teklif data and teklif_path
                cursor.execute("""
                    UPDATE [Yuce_Portal].[dbo].[SatinAlmaKalem]
                    SET 
                        TalepEdilenMiktar = ?,
                        UrunBirimFiyat = ?,
                        ParaBirimi = ?,
                        UrunToplamFiyat = ?,
                        satin_alma_sorumlu_aciklama = ?,
                        teklif_path = ?
                    WHERE ID = ?
                """, (miktar, birim_fiyat, para_birimi, toplam_fiyat, satin_almaci_aciklama, teklif_path, kalem_id))


                # 5. Get TalepNo for this Kalem
                cursor.execute("""
                    SELECT TalepNo
                    FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
                    WHERE ID = ?
                """, (kalem_id,))
                talep_result = cursor.fetchone()

                if talep_result:
                    talep_no = talep_result[0]

                    # 6. Sum totals by currency for that TalepNo
                    cursor.execute("""
                        SELECT ParaBirimi, SUM(UrunToplamFiyat)
                        FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
                        WHERE TalepNo = ?
                        GROUP BY ParaBirimi
                    """, (talep_no,))

                    from collections import defaultdict

                    currency_totals = defaultdict(float)
                    for currency, amount in cursor.fetchall():
                        currency = currency.strip().capitalize()
                        currency_totals[currency] += float(amount or 0)

                    final_total_json = json.dumps(currency_totals)

                    cursor.execute("""
                        UPDATE [Yuce_Portal].[dbo].[SatinAlmaTalep]
                        SET FinalTotal = ?
                        WHERE TalepNo = ?
                    """, (final_total_json, talep_no))

            conn.commit()

        except Exception as e:
            conn.rollback()
            flash(f"Bir hata oluştu: {e}", "danger")
        finally:
            cursor.close()
            conn.close()
    
    Write_Log_ToDB(session.get('username'), "POST", "/satin_alma_teklif_sec", 0, f"{kalem_id} için {selected_teklif_id} teklif seçti.")
    return redirect(url_for('SatinAlma_Sorumlusu_Talep_Degerlendirme'))

