@app.route('/satin_alma_finans_degerlendirme', methods=['GET'])
@login_required
def satin_alma_finans_degerlendirme():
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    form = SatinAlmaForm(request.form)

    try:
        cursor.execute("""
            SELECT ID, TalepNo, TalepDept, TalepTarihi, FinalTotal, created_by, created_by_nam_surn,
                   is_active, created_at, Talep_Asama, TalepEdenDepartman, Aciklama, onaylar, TL_aprox, dolar_aprox_ratio, euro_aprox_ratio
            FROM [Yuce_Portal].[dbo].[SatinAlmaTalep] ORDER BY ID DESC
        """)
        rows = cursor.fetchall()
        
        columns = [column[0] for column in cursor.description]

        filtered_taleps = []
        for row in rows:
            record = dict(zip(columns, row))
            record['FinalTotalFormatted'] = format_final_total(record.get('FinalTotal'))
            onaylar_raw = record.get("onaylar")
            try:
                onaylar = json.loads(onaylar_raw)

                if onaylar.get("satin_alma_finans_sorumlu") == 0:
                    prior_approvals = {k: v for k, v in onaylar.items() if k != "satin_alma_finans_sorumlu"}
                    if all(v == 1 for v in prior_approvals.values()):
                        filtered_taleps.append(record)

            except (json.JSONDecodeError, TypeError):
                continue

    finally:
        cursor.close()
        conn.close()
    
    print(filtered_taleps)

    Write_Log_ToDB(session.get('username'), "GET", "/satin_alma_finans_degerlendirme", 0)
    return render_template("satin_alma_finans_talep_degerlendirme.html", taleps=filtered_taleps, form=form)

@app.route("/satin_alma_talep_detay2/<int:talep_no>", methods=["GET"])
@login_required
def SatinAlma_TalepDetay2(talep_no):
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    try:
        cursor.execute("""
            SELECT 
                k.ID,
                k.TalepNo,
                k.TalepEdilenUrun,
                k.TalepEdilenMiktar,
                k.UrunBirimFiyat,
                k.ParaBirimi,
                k.UrunToplamFiyat,
                k.onay,
                k.butce_tipi, 
                (SELECT COUNT(*) 
                 FROM [Yuce_Portal].[dbo].[SatinAlmaTeklif] t 
                 WHERE t.KalemID = k.ID) AS teklif_sayisi,
                log.SecilenDurum
            FROM [Yuce_Portal].[dbo].[SatinAlmaKalem] k

            OUTER APPLY (
                SELECT TOP 1 l.SecilenDurum
                FROM [Yuce_Portal].[dbo].[SatinAlmaOnayLog] l
                WHERE l.TalepNo = k.TalepNo
                ORDER BY l.ID DESC  -- ✅ en son kaydı belirleyen kolon (ID / created_at)
            ) log

            WHERE k.TalepNo = ?
            ORDER BY k.ID DESC
        """, (talep_no,))

        columns = [col[0] for col in cursor.description]
        kalemler = [dict(zip(columns, row)) for row in cursor.fetchall()]
        return jsonify(kalemler)

    except Exception as e:
        return jsonify({'error': str(e)}), 500

    finally:
        cursor.close()
        conn.close()

@app.route('/satin_alma_talep_guncelle', methods=['POST'])
@login_required
def satin_alma_talep_guncelle():
    conn = None
    cursor = None

    try:
        data = request.get_json(silent=True) or {}

        talep_no = data.get('talepNo')
        aciklama = data.get('aciklama')
        onay_reddet = data.get('onayRed')
        kalem_budgets = data.get('kalemBudgets', {}) or {}
        finans_aciklama = data.get('finansAciklama')

        if not talep_no:
            return jsonify({'success': False, 'message': 'TalepNo eksik'}), 400

        conn = pyodbc.connect(YA_2El_AracSatis)
        cursor = conn.cursor()

        # 1) Mevcut onaylar
        cursor.execute("""
            SELECT onaylar
            FROM [Yuce_Portal].[dbo].[SatinAlmaTalep]
            WHERE TalepNo = ?
        """, talep_no)
        row = cursor.fetchone()
        if not row:
            return jsonify({'success': False, 'message': 'Talep bulunamadı'}), 404

        # onaylar null/bozuk gelirse sağlamlaştır
        raw_onaylar = row[0]
        if not raw_onaylar:
            onaylar_json = {}
        else:
            try:
                onaylar_json = json.loads(raw_onaylar)
                if not isinstance(onaylar_json, dict):
                    onaylar_json = {}
            except Exception:
                onaylar_json = {}

        # 2) Kalem bütçe tiplerini güncelle
        for kalem_id, butce_tipi in kalem_budgets.items():
            cursor.execute("""
                UPDATE [Yuce_Portal].[dbo].[SatinAlmaKalem]
                SET butce_tipi = ?
                WHERE ID = ?
            """, butce_tipi, kalem_id)

        talep_asama = ""

        if onay_reddet == "Onayla":
            # Finans sorumlusu onayı
            onaylar_json["satin_alma_finans_sorumlu"] = 1
            talep_asama = "Finans tarafından onaylandı"

            # 3) TL_aprox çek
            cursor.execute("""
                SELECT ISNULL(TL_aprox, 0)
                FROM [Yuce_Portal].[dbo].[SatinAlmaTalep]
                WHERE TalepNo = ?
            """, talep_no)
            tl_aprox = cursor.fetchone()[0] or 0

            # 4) Bütçe dışı kalem var mı?
            cursor.execute("""
                SELECT COUNT(*)
                FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
                WHERE TalepNo = ? AND butce_tipi = N'Bütçe Dışı'
            """, talep_no)
            butce_disi_kalem_var = (cursor.fetchone()[0] or 0) > 0

            # 5) Limitleri çek (en güncel)
            cursor.execute("""
                SELECT TOP 1
                    SatinAlmaBirimMudur_Onay_Limiti,
                    CFO_Onay_Limiti,
                    CEO_Onay_Limiti
                FROM [Yuce_Portal].[dbo].[SatinAlmaKriterler]
                ORDER BY last_updated_at DESC
            """)
            kriter = cursor.fetchone()

            mudur_limit = kriter[0] if kriter else None
            cfo_limit   = kriter[1] if kriter else None
            ceo_limit   = kriter[2] if kriter else None

            # 6) Onaycı ekleme kuralı
            #    - Eğer herhangi bir kalem Bütçe Dışı ise: TUTARDAN BAĞIMSIZ burtayk + ulaso + zaferb onaya düşer
            #    - Değilse: limitlere göre düşer
            if butce_disi_kalem_var:
                onaylar_json.setdefault("burtayk", 0)  # Satın Alma Müdürü
                onaylar_json.setdefault("ulaso", 0)    # CFO
                onaylar_json.setdefault("zaferb", 0)   # CEO
            else:
                # Limitler yoksa sadece bildirim akışı finance sonrası devam eder (istersen burada hata da döndürebiliriz)
                if mudur_limit is not None and tl_aprox > mudur_limit:
                    onaylar_json.setdefault("burtayk", 0)

                if cfo_limit is not None and tl_aprox > cfo_limit:
                    onaylar_json.setdefault("ulaso", 0)

                if ceo_limit is not None and tl_aprox > ceo_limit:
                    onaylar_json.setdefault("zaferb", 0)

            updated_onaylar = json.dumps(onaylar_json, ensure_ascii=False)

            # 7) Sıradaki onaycıya bildirim (finance hariç ilk pending=0 olan)
            try:
                for username, value in onaylar_json.items():
                    if username == "satin_alma_finans_sorumlu":
                        continue
                    if value == 0:
                        message = f"{talep_no} numaralı satın alma talebi onayınızı bekliyor. Lütfen kontrol ediniz."
                        a_tag = "/satin_alma_onay"
                        send_notification(username, message, a_tag)
                        break
            except Exception as notify_err:
                print(f"Bildirim gönderilemedi: {str(notify_err)}")

        elif onay_reddet == "Reddet":
            onaylar_json["satin_alma_finans_sorumlu"] = -1
            talep_asama = "Finans tarafından reddedildi"
            updated_onaylar = json.dumps(onaylar_json, ensure_ascii=False)
        else:
            return jsonify({'success': False, 'message': 'Geçersiz onay/red seçimi'}), 400

        # 8) Talep tablosunu güncelle
        cursor.execute("""
            UPDATE [Yuce_Portal].[dbo].[SatinAlmaTalep]
            SET Aciklama = ?,
                Finans_Aciklama = ?,
                onaylar = ?,
                Talep_Asama = ?
            WHERE TalepNo = ?
        """, aciklama, finans_aciklama, updated_onaylar, talep_asama, talep_no)

        conn.commit()
        Write_Log_ToDB(session.get('username'), "POST", "/satin_alma_talep_guncelle", 0)
        return jsonify({'success': True})

    except Exception as e:
        if conn:
            try:
                conn.rollback()
            except:
                pass
        print("Hata:", e)
        return jsonify({'success': False, 'message': 'Sunucu hatası'}), 500

    finally:
        try:
            if cursor: cursor.close()
            if conn: conn.close()
        except:
            pass

@app.route('/satin_alma_onaySureci_tamamlanmis_satinalmalar', methods=['GET', 'POST'])
@login_required
def satin_alma_surec_tamamlanmis_talepler():
    form = SatinAlma_TeklifForm(request.form)
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    try:
        cursor.execute("""
            SELECT 
                [ID],
                [TalepNo],
                [TalepDept],
                [TalepTarihi],
                [FinalTotal],
                [created_by],
                [created_by_nam_surn],
                [is_active],
                [created_at],
                [Talep_Asama],
                [TalepEdenDepartman],
                [Aciklama],
                [onaylar],
                [Finans_Aciklama],
                ISNULL([YansitmaFatura], 0) AS YansitmaFatura
            FROM [Yuce_Portal].[dbo].[SatinAlmaTalep]
            WHERE is_active = 1
            ORDER BY created_at DESC
        """)

        columns = [col[0] for col in cursor.description]
        talepler = [dict(zip(columns, row)) for row in cursor.fetchall()]

        for t in talepler:
            t['FinalTotalFormatted'] = format_final_total(t.get('FinalTotal'))

            try:
                t['onaylar_dict'] = json.loads(t.get('onaylar') or '{}')
            except json.JSONDecodeError:
                t['onaylar_dict'] = {}

            # güvenli boolean
            t['YansitmaFatura'] = 1 if str(t.get('YansitmaFatura', 0)) in ('1', 'True', 'true') else 0

    except Exception as e:
        flash(f'Hata oluştu: {str(e)}', 'danger')
        talepler = []
    finally:
        cursor.close()
        conn.close()

    Write_Log_ToDB(session.get('username'), "GET", "/satin_alma_onaySurec_tamamlanmis_talepler", 0)
    return render_template("satin_alma_onaySurec_tamamlanmis_talepler.html", talepler=talepler, form=form)

@app.route("/satin_alma_talepler_excel", methods=["GET"])
@login_required
def satin_alma_talepler_excel():
    from openpyxl import Workbook
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    try:
        cursor.execute("""
            SELECT 
                [ID],
                [TalepNo],
                [TalepDept],
                [TalepTarihi],
                [FinalTotal],
                [created_by],
                [created_by_nam_surn],
                [is_active],
                [created_at],
                [Talep_Asama],
                [TalepEdenDepartman],
                [Aciklama],
                [onaylar],
                [Finans_Aciklama],
                [TL_aprox],
                [YansitmaFatura] 
            FROM [Yuce_Portal].[dbo].[SatinAlmaTalep]
            ORDER BY created_at DESC
        """)

        columns = [col[0] for col in cursor.description]
        talepler = [dict(zip(columns, row)) for row in cursor.fetchall()]

    finally:
        cursor.close()
        conn.close()

    # --- Excel oluştur ---
    output = BytesIO()
    wb = Workbook()
    ws = wb.active
    ws.title = "Satın Alma Talepleri"

    # Başlıklar (Excel kolonları)
    headers = [
        "Talep No",
        "Talep Departmanı",
        "Talep Eden Departman",
        "Talep Eden",
        "Talep Tarihi",
        "Toplam Tutar (Yazılı)",
        "Toplam Tutar (TL Approx)",
        "Yansıtma", 
        "Açıklama",
        "Finans Açıklama",
        "Talep Aşama"
    ]
    ws.append(headers)

    # Satırları doldur
    for t in talepler:
        final_total_str = format_final_total(t.get("FinalTotal"))
        talep_tarihi = t.get("TalepTarihi")
        if isinstance(talep_tarihi, (datetime.date, datetime.datetime)):
            talep_tarihi_str = talep_tarihi.strftime("%d.%m.%Y")
        else:
            talep_tarihi_str = str(talep_tarihi) if talep_tarihi is not None else ""

        yansitma_val = t.get("YansitmaFatura")
        yansitma_str = "Evet" if str(yansitma_val) in ("1", "True", "true") else "Hayır"

        ws.append([
            t.get("TalepNo"),
            t.get("TalepDept"),
            t.get("TalepEdenDepartman"),
            t.get("created_by_nam_surn"),
            talep_tarihi_str,
            final_total_str,
            t.get("TL_aprox"),
            yansitma_str,
            t.get("Aciklama"),
            t.get("Finans_Aciklama"),
            t.get("Talep_Asama"),
        ])

    wb.save(output)
    output.seek(0)

    filename = f"satinalma_talepleri_{datetime.datetime.now().strftime('%Y%m%d_%H%M')}.xlsx"

    # Log yaz (istersen)
    Write_Log_ToDB(session.get('username'), "GET", "/satin_alma_talepler_excel", 0)

    return send_file(output, as_attachment=True, download_name=filename, mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")

@app.route('/satin_alma_kriter_tanimlama', methods=['GET', 'POST'])
@login_required
def satin_alma_kriter_tanimlama():
    form = SatinAlmaKriterForm(request.form)
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    if request.method == "GET":
        query = """
        SELECT [ID],
               [SatinAlmaBirimMudur_Onay_Limiti],
               [CFO_Onay_Limiti],
               [CEO_Onay_Limiti],
               [updated_by],
               [last_updated_at]
        FROM [Yuce_Portal].[dbo].[SatinAlmaKriterler]
        ORDER BY ID DESC
        """
        cursor.execute(query)
        result = cursor.fetchone()

        Write_Log_ToDB(session.get('username'), "GET", "/satin_alma_kriter_tanimlama", 0)
        return render_template("satin_alma_kriter_tanimlama.html", form=form, result=result)

    elif request.method == "POST":
        try:
            satin_alma_muduru_limit = request.form.get('satin_alma_muduru_limit', '0').replace('.', '')
            cfo_limit = request.form.get('cfo_limit', '0').replace('.', '')
            ceo_limit = request.form.get('ceo_limit', '0').replace('.', '')

            satin_alma_muduru_limit = int(satin_alma_muduru_limit) if satin_alma_muduru_limit.isdigit() else 0
            cfo_limit = int(cfo_limit) if cfo_limit.isdigit() else 0
            ceo_limit = int(ceo_limit) if ceo_limit.isdigit() else 0

            insert_query = """
            INSERT INTO [Yuce_Portal].[dbo].[SatinAlmaKriterler]
            ([SatinAlmaBirimMudur_Onay_Limiti], [CFO_Onay_Limiti], [CEO_Onay_Limiti], [updated_by], [last_updated_at])
            VALUES (?, ?, ?, ?, GETDATE())
            """
            updated_by = session.get("username")
            cursor.execute(insert_query, (satin_alma_muduru_limit, cfo_limit, ceo_limit, updated_by))
            conn.commit()

            cursor.execute("""
            SELECT [ID],
                   [SatinAlmaBirimMudur_Onay_Limiti],
                   [CFO_Onay_Limiti],
                   [CEO_Onay_Limiti],
                   [updated_by],
                   [last_updated_at]
            FROM [Yuce_Portal].[dbo].[SatinAlmaKriterler]
            ORDER BY ID DESC
            """)
            result = cursor.fetchone()

            flash("Kriterler başarıyla güncellendi!", "success")
            return redirect(url_for("satin_alma_kriter_tanimlama"))
        except Exception as e:
            print(e)
            flash("Bir hata oluştu.", "danger")
            conn.rollback()

    cursor.close()
    conn.close()

    return render_template("satin_alma_kriter_tanimlama.html", form=form, result=result)

@app.route('/upload_sozlesme/<int:kalem_id>', methods=['POST'])
def upload_sozlesme(kalem_id):
    file = request.files.get('file')
    if not file:
        return jsonify(success=False, error="Dosya yok.")

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    # Fetch product name or any extra info (optional)
    cursor.execute("""
        SELECT TalepEdilenUrun FROM [Yuce_Portal].[dbo].[SatinAlmaKalem]
        WHERE ID = ?
    """, kalem_id)
    row = cursor.fetchone()
    urun_adi = row[0] if row else "urun"

    # Secure and generate filename
    filename = secure_filename(file.filename)
    ext = os.path.splitext(filename)[1]
    custom_filename = f"kalem_{kalem_id}_{urun_adi[:20].replace(' ', '_')}{ext}"
    
    # Save to disk
    folder = r"C:\Users\yuceappadmin\Documents\GitHub\RPA-Projects\static\satin_alma_sozlesmeler"
    os.makedirs(folder, exist_ok=True)
    file_path = os.path.join(folder, custom_filename)
    file.save(file_path)

    # Save relative path to DB
    relative_path = '/static/satin_alma_sozlesmeler/' + custom_filename
    cursor.execute("""
        UPDATE [Yuce_Portal].[dbo].[SatinAlmaKalem]
        SET sozlesme_path = ?
        WHERE ID = ?
    """, (relative_path, kalem_id))
    conn.commit()

    return jsonify(success=True)

