@app.route("/fikir&oneri_module", methods=["GET"])
@login_required
def fikir_oneri_module():
    form = YeniFikirForm(request.form)

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    query = """
        SELECT 
            FikirID,
            Baslik,
            Aciklama,
            Kategori,
            IlgiliDepartman,
            BeklenenFayda,
            GerekliKaynaklar,
            Durum,
            CASE 
                WHEN Durum = 'evaluating' THEN 'Değerlendiriliyor'
                WHEN Durum = 'pilot'      THEN 'Pilot Uygulama'
                WHEN Durum = 'approved'   THEN 'Onaylandı'
                WHEN Durum = 'rejected'   THEN 'Reddedildi'
                ELSE Durum
            END AS DurumText,
            DegerlendirmeNotu,
            CreatedByUsername,
            CreatedByFullName,
            FORMAT(CreatedAt, 'dd.MM.yyyy') AS CreatedDate
        FROM [Yuce_Portal].[dbo].[CalisanFikirleri]
        ORDER BY CreatedAt DESC;
    """

    cursor.execute(query)
    rows = cursor.fetchall()

    ideas = []
    for r in rows:
        ideas.append({
            "id":                r.FikirID,
            "baslik":            r.Baslik,
            "aciklama":          r.Aciklama,
            "kategori":          r.Kategori,
            # DB'de birden fazla departman varsa virgülle saklıyoruz, biz string olarak döneriz
            "departman":         r.IlgiliDepartman,
            "fayda":             r.BeklenenFayda,
            "kaynaklar":         r.GerekliKaynaklar,
            "durum":             r.Durum,
            "durum_text":        r.DurumText,
            "puan":              float(r.DegerlendirmeNotu) if r.DegerlendirmeNotu is not None else None,
            "sahibi":            r.CreatedByUsername if r.CreatedByUsername else r.CreatedByFullName,
            "sahibi_fullname":   r.CreatedByFullName,
            "tarih":             r.CreatedDate,
        })

    cursor.close()
    conn.close()

    idea_count = len(ideas)

    return render_template(
        "fikir_oneri_module.html",
        form=form,
        ideas=ideas,
        idea_count=idea_count
    )

@app.route("/yeni_fikir_olustur", methods=["POST"])
@login_required
def yeni_fikir_olustur():
    form = YeniFikirForm(request.form)
    form.ilgili_departman.data = request.form.getlist("ilgili_departman[]")

    uploaded_file = request.files.get("ek_dosya")

    if not form.validate():
        return jsonify({
            "ok": False,
            "errors": form.errors
        }), 400

    # departmanlar -> "Satış, Bilgi Teknolojileri" gibi tek string
    dept_list_raw = form.ilgili_departman.data or []
    dept_list_clean = [d.strip() for d in dept_list_raw if d and d.strip()]
    ilgili_departman_str = ", ".join(dept_list_clean) if dept_list_clean else None

    # Session bilgileri
    username_from_session = session.get("username")
    name_part = session.get("name") or ""
    surname_part = session.get("surname") or ""
    full_name_from_session = (name_part + " " + surname_part).strip() or username_from_session or "Unknown User"

    created_by_username = username_from_session or "unknown.user"
    created_by_fullname = full_name_from_session

    # Dosya kaydet
    saved_path_for_db = None
    if uploaded_file and uploaded_file.filename:
        ext = os.path.splitext(uploaded_file.filename)[1]  # ".pdf", ".pptx", ".xlsx" vs.
        new_name = f"{uuid.uuid4().hex}{ext}"

        upload_root = os.path.join("uploads", "fikirler")
        os.makedirs(upload_root, exist_ok=True)

        full_fs_path = os.path.join(upload_root, new_name)
        uploaded_file.save(full_fs_path)

        saved_path_for_db = full_fs_path

    # DB insert
    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    insert_sql = """
        INSERT INTO [Yuce_Portal].[dbo].[CalisanFikirleri] (
            Baslik,
            Aciklama,
            Kategori,
            IlgiliDepartman,
            BeklenenFayda,
            GerekliKaynaklar,
            EkDosyaYolu,
            Durum,
            YoneticiYorumu,
            FaydaPuani,
            FizibilitePuani,
            InovasyonPuani,
            DegerlendirmeNotu,
            CreatedByUsername,
            CreatedByFullName,
            CreatedAt,
            LastStatusChangeAt,
            LastUpdatedAt
        )
        OUTPUT INSERTED.FikirID,
               INSERTED.CreatedAt
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
    """

    now_utc = datetime.datetime.utcnow()

    params = (
        (form.baslik.data or "").strip() if form.baslik.data else None,
        (form.aciklama.data or "").strip() if form.aciklama.data else None,
        (form.kategori.data or "").strip() if form.kategori.data else None,
        ilgili_departman_str,
        (form.beklenen_fayda.data.strip() if form.beklenen_fayda.data else None),
        (form.gerekli_kaynaklar.data.strip() if form.gerekli_kaynaklar.data else None),
        saved_path_for_db,
        "evaluating",          # Durum
        None,                  # YoneticiYorumu
        None,                  # FaydaPuani
        None,                  # FizibilitePuani
        None,                  # InovasyonPuani
        None,                  # DegerlendirmeNotu
        created_by_username,   # CreatedByUsername
        created_by_fullname,   # CreatedByFullName
        now_utc,               # CreatedAt
        now_utc,               # LastStatusChangeAt
        now_utc                # LastUpdatedAt
    )

    cursor.execute(insert_sql, params)
    row = cursor.fetchone()

    yeni_id = row[0]
    created_at_dt = row[1]

    conn.commit()
    cursor.close()
    conn.close()

    tarih_str = created_at_dt.strftime("%d.%m.%Y")

    # Frontend'e geri dönecek payload
    new_idea_payload = {
        "id": yeni_id,
        "baslik": (form.baslik.data or "").strip(),
        "aciklama": (form.aciklama.data or "").strip(),
        "kategori": ((form.kategori.data or "").strip() or "-"),
        "departman": (ilgili_departman_str or "-"),
        "fayda": ((form.beklenen_fayda.data or "").strip() or "-"),
        "kaynaklar": ((form.gerekli_kaynaklar.data or "").strip() or ""),
        "durum": "evaluating",
        "durum_text": "Değerlendiriliyor",
        "puan": None,
        "sahibi": created_by_username,
        "sahibi_fullname": created_by_fullname,
        "tarih": tarih_str
    }

    return jsonify({
        "ok": True,
        "idea": new_idea_payload
    }), 200

