@app.route("/mobil_rapor_data", methods=["GET"])
@login_required
def mobil_rapor_data():
    from datetime import date, timedelta

    def get_cnx():
        return pyodbc.connect(YA_2El_AracSatis)  # kendi connection string’in

    # gün filtresi
    try:
        days = int(request.args.get("days") or 30)
    except ValueError:
        days = 30
    days = max(1, min(days, 365))

    today = date.today()
    start_day = today - timedelta(days=days - 1)
    mobile_filter = "RequestLink LIKE '%/IOS/%'"

    with get_cnx() as cnx:
        cur = cnx.cursor()

        # Top 5 link (tüm zaman)
        cur.execute(f"""
            SELECT TOP 5 RequestLink, COUNT(*) AS cnt
            FROM Yuce_Portal.dbo.YP_users_log WITH (NOLOCK)
            WHERE {mobile_filter}
            GROUP BY RequestLink
            ORDER BY cnt DESC
        """)
        top_links = [{"link": r.RequestLink, "count": int(r.cnt)} for r in cur.fetchall()]

        # Bugün tekil kullanıcı sayısı
        cur.execute(f"""
            SELECT COUNT(DISTINCT Username) AS ucount
            FROM Yuce_Portal.dbo.YP_users_log WITH (NOLOCK)
            WHERE {mobile_filter}
              AND Username IS NOT NULL AND LTRIM(RTRIM(Username)) <> ''
              AND CAST(RequestedDateTime AS DATE) = CAST(GETDATE() AS DATE)
        """)
        row_today = cur.fetchone()
        today_unique_users = int(row_today.ucount or 0)

        # Bugün kullanan kullanıcıların listesi (username + adet)
        cur.execute(f"""
            SELECT Username, COUNT(*) AS cnt
            FROM Yuce_Portal.dbo.YP_users_log WITH (NOLOCK)
            WHERE {mobile_filter}
              AND Username IS NOT NULL AND LTRIM(RTRIM(Username)) <> ''
              AND CAST(RequestedDateTime AS DATE) = CAST(GETDATE() AS DATE)
            GROUP BY Username
            ORDER BY cnt DESC, Username ASC
        """)
        today_users = [{"username": r.Username, "count": int(r.cnt)} for r in cur.fetchall()]

        # Son N gün günlük istatistik
        cur.execute(f"""
            SELECT CAST(RequestedDateTime AS DATE) AS d,
                   COUNT(*) AS request_count,
                   COUNT(DISTINCT Username) AS user_count
            FROM Yuce_Portal.dbo.YP_users_log WITH (NOLOCK)
            WHERE {mobile_filter}
              AND RequestedDateTime >= DATEADD(DAY, -?, CAST(GETDATE() AS DATE))
            GROUP BY CAST(RequestedDateTime AS DATE)
            ORDER BY d ASC
        """, (days - 1,))
        rows = cur.fetchall()
        by_day = {r.d: (int(r.request_count), int(r.user_count)) for r in rows}

        daily = []
        cur_day = start_day
        while cur_day <= today:
            rc, uc = by_day.get(cur_day, (0, 0))
            daily.append({"date": cur_day.isoformat(), "requests": rc, "users": uc})
            cur_day += timedelta(days=1)

        # Son N gün toplam
        cur.execute(f"""
            SELECT COUNT(*) AS total_requests,
                   COUNT(DISTINCT Username) AS distinct_users
            FROM Yuce_Portal.dbo.YP_users_log WITH (NOLOCK)
            WHERE {mobile_filter}
              AND RequestedDateTime >= DATEADD(DAY, -?, CAST(GETDATE() AS DATE))
              AND Username IS NOT NULL AND LTRIM(RTRIM(Username)) <> ''
        """, (days - 1,))
        r = cur.fetchone()
        totals = {
            "total_requests": int(r.total_requests or 0),
            "distinct_users": int(r.distinct_users or 0),
        }

    return jsonify({
        "days": days,
        "top_links": top_links,
        "today_unique_users": today_unique_users,
        "today_users": today_users,  # ✨ yeni
        "daily": daily,
        "totals": totals
    })

