@app.route("/import_urunrpa_year/<int:year>/<path:excelpath>", methods=["GET"])
@login_required
def import_urunrpa_year(year, excelpath):
    import re
    from datetime import date

    EXCEL_PATH = r"Y:\YUCE AUTO GENEL\Urun_fiyat_excel\Prev_Years\ç".replace("ç","") + excelpath
    TR_MONTHS = {
        "ocak": 1, "şubat": 2, "subat": 2, "mart": 3, "nisan": 4,
        "mayıs": 5, "mayis": 5, "haziran": 6, "temmuz": 7,
        "ağustos": 8, "agustos": 8, "eylül": 9, "eylul": 9,
        "ekim": 10, "kasım": 11, "kasim": 11,
        "aralık": 12, "aralik": 12
    }

    if not os.path.exists(EXCEL_PATH):
        return f"❌ Excel bulunamadı: {EXCEL_PATH}", 404

    # 1️⃣ Excel oku
    xl = pd.ExcelFile(EXCEL_PATH)
    rows = []

    for sheet in xl.sheet_names:
        df = pd.read_excel(EXCEL_PATH, sheet_name=sheet)
        if df.empty:
            continue

        marka = str(sheet).strip()
        model_col = df.columns[0]

        # tarih kolonlarını yakala
        date_cols = []
        for c in df.columns[1:]:
            if not isinstance(c, str):
                continue

            m = re.match(r"^(\d{1,2})\s+([A-Za-zÇĞİÖŞÜçğıöşü]+)\s+(\d{4})$", c.strip())
            if not m:
                continue

            d = int(m.group(1))
            mon = m.group(2).lower().replace("i̇", "i")
            y = int(m.group(3))

            if y != year or mon not in TR_MONTHS:
                continue

            date_cols.append((c, date(y, TR_MONTHS[mon], d)))

        if not date_cols:
            continue

        for _, r in df.iterrows():
            model = r.get(model_col)
            if not isinstance(model, str) or not model.strip():
                continue

            model = model.strip()
            if model.lower().startswith("ortalama"):
                continue

            for col, dt in date_cols:
                v = r.get(col)
                if v is None or (isinstance(v, float) and pd.isna(v)):
                    continue

                s = str(v).strip()
                if s in ("", "-", "nan"):
                    continue

                s = s.replace(".", "").replace(",", ".")
                try:
                    price = float(s)
                except:
                    continue

                rows.append((year, marka, model, dt, price))

    if not rows:
        return f"❌ {year} için aktarılacak veri bulunamadı", 400

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    cur.fast_executemany = True

    try:
        cur.execute("DELETE FROM [Yuce_Portal].[dbo].[UrunRPA_PricePoints] WHERE Yil = ?", year)

        cur.executemany(
            """
            INSERT INTO [Yuce_Portal].[dbo].[UrunRPA_PricePoints]
            (Yil, Marka, Model, FiyatTarihi, Fiyat)
            VALUES (?, ?, ?, ?, ?)
            """, rows)

        conn.commit()
        return f"✅ {year} için {len(rows)} satır başarıyla içeri aktarıldı"

    except Exception as e:
        conn.rollback()
        return f"❌ Hata: {str(e)}", 500
    finally:
        cur.close()
        conn.close()

