@app.route("/api/urunrpa/models", methods=["POST"])
@login_required
def api_urunrpa_models():
    payload = request.get_json(silent=True) or {}
    year = int(payload.get("year"))
    brands = payload.get("brands") or []

    if not brands:
        return jsonify([])

    # IN (...) parametreli kurulum
    placeholders = ",".join(["?"] * len(brands))
    params = [year] + brands + [year]

    sql = f"""
    ;WITH X AS (
        SELECT
            Yil, Marka, Model, FiyatTarihi, CAST(Fiyat AS FLOAT) AS Fiyat
        FROM [Yuce_Portal].[dbo].[UrunRPA_PricePoints]
        WHERE Yil = ? AND Marka IN ({placeholders}) AND Fiyat IS NOT NULL
    ),
    R AS (
        SELECT
            Marka, Model, FiyatTarihi, Fiyat,
            ROW_NUMBER() OVER (PARTITION BY Marka, Model ORDER BY FiyatTarihi ASC)  AS rn_asc,
            ROW_NUMBER() OVER (PARTITION BY Marka, Model ORDER BY FiyatTarihi DESC) AS rn_desc
        FROM X
    )
    SELECT
        ? AS year,
        a.Marka AS brand,
        a.Model AS model,
        a.Fiyat AS first_price,
        b.Fiyat AS last_price,
        (b.Fiyat - a.Fiyat) AS diff
    FROM (SELECT Marka, Model, Fiyat FROM R WHERE rn_asc  = 1) a
    JOIN (SELECT Marka, Model, Fiyat FROM R WHERE rn_desc = 1) b
      ON a.Marka = b.Marka AND a.Model = b.Model
    ORDER BY a.Marka, a.Model
    """

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    try:
        cur.execute(sql, params)
        rows = cur.fetchall()

        data = []
        for r in rows:
            data.append({
                "year": int(r.year),
                "brand": r.brand,
                "model": r.model,
                "first_price": None if r.first_price is None else float(r.first_price),
                "last_price": None if r.last_price is None else float(r.last_price),
                "diff": None if r.diff is None else float(r.diff),
            })

        return jsonify(data)
    finally:
        cur.close()
        conn.close()

@app.route("/api/urunrpa/series", methods=["POST"])
@login_required
def api_urunrpa_series():
    payload = request.get_json(silent=True) or {}
    year = int(payload.get("year"))
    items = payload.get("items") or []

    # basit validasyon
    clean = []
    for it in items:
        b = (it.get("brand") or "").strip()
        m = (it.get("model") or "").strip()
        if b and m:
            clean.append((b, m))

    if not clean:
        return jsonify({"labels": [], "series": []})

    # (Marka,Model) OR listesi
    # (Marka=? AND Model=?) OR (Marka=? AND Model=?)
    or_clauses = " OR ".join(["(Marka=? AND Model=?)"] * len(clean))
    params = [year]
    for b, m in clean:
        params.extend([b, m])

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    try:
        # 1) labels (tarih listesi) - yıl içindeki tüm tarihler
        cur.execute("""
            SELECT DISTINCT FiyatTarihi
            FROM [Yuce_Portal].[dbo].[UrunRPA_PricePoints]
            WHERE Yil = ? AND FiyatTarihi IS NOT NULL
            ORDER BY FiyatTarihi
        """, year)
        dates = [row[0] for row in cur.fetchall()]
        labels = [d.strftime("%Y-%m-%d") for d in dates]  # frontend bunu direkt kullanır

        if not labels:
            return jsonify({"labels": [], "series": []})

        # date -> index map
        idx_map = {d: i for i, d in enumerate(dates)}

        # 2) tüm seçili seriler için fiyatları tek query ile çek
        sql = f"""
            SELECT Marka, Model, FiyatTarihi, CAST(Fiyat AS FLOAT) AS Fiyat
            FROM [Yuce_Portal].[dbo].[UrunRPA_PricePoints]
            WHERE Yil = ? AND Fiyat IS NOT NULL AND ({or_clauses})
            ORDER BY Marka, Model, FiyatTarihi
        """
        cur.execute(sql, params)
        fetched = cur.fetchall()

        # her seri için null array
        series_map = {}
        for b, m in clean:
            series_map[(b, m)] = [None] * len(labels)

        for r in fetched:
            key = (r.Marka, r.Model)
            if key not in series_map:
                continue
            i = idx_map.get(r.FiyatTarihi)
            if i is None:
                continue
            series_map[key][i] = None if r.Fiyat is None else float(r.Fiyat)

        series = []
        for (b, m), arr in series_map.items():
            series.append({"brand": b, "model": m, "data": arr})

        return jsonify({"labels": labels, "series": series})

    finally:
        cur.close()
        conn.close()        

