# GRID (POST)  -> Excel gibi tablo + grafik aynı data ile
# request:  { "year": 2025, "brands": ["Skoda","Audi"] }
# response: { "labels": ["08.01.2025", ...], "rows": [{"brand":"Skoda","model":"Octavia","prices":[...]}] }
@app.route("/api/urunrpa/grid", methods=["POST"])
@login_required
def api_urunrpa_grid():
    payload = request.get_json(silent=True) or {}
    year = int(payload.get("year") or 0)
    brands = payload.get("brands") or []

    # temizlik
    brands = [b.strip() for b in brands if isinstance(b, str) and b.strip()]
    if year <= 0 or not brands:
        return jsonify({"labels": [], "rows": []})

    placeholders = ",".join(["?"] * len(brands))

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    try:
        # 1) LABELS (tarih kolonları) -> seçili markalarda bulunan tarihler
        sql_dates = f"""
            SELECT DISTINCT FiyatTarihi
            FROM [Yuce_Portal].[dbo].[UrunRPA_PricePoints]
            WHERE Yil = ?
              AND Marka IN ({placeholders})
              AND FiyatTarihi IS NOT NULL
              AND Fiyat IS NOT NULL
            ORDER BY FiyatTarihi
        """
        cur.execute(sql_dates, [year] + brands)
        date_rows = cur.fetchall()
        dates = [r[0] for r in date_rows]  # python date
        if not dates:
            return jsonify({"labels": [], "rows": []})

        # frontend label formatı: "dd.MM.yyyy" (Excel gibi)
        labels = [d.strftime("%d.%m.%Y") for d in dates]
        idx_map = {d: i for i, d in enumerate(dates)}

        # 2) DATA (marka-model-tarih-fiyat)
        # Not: aynı gün aynı model için birden fazla kayıt varsa MAX alıyoruz.
        sql_data = f"""
            SELECT
                Marka,
                Model,
                FiyatTarihi,
                MAX(CAST(Fiyat AS FLOAT)) AS Fiyat
            FROM [Yuce_Portal].[dbo].[UrunRPA_PricePoints]
            WHERE Yil = ?
              AND Marka IN ({placeholders})
              AND FiyatTarihi IS NOT NULL
              AND Fiyat IS NOT NULL
            GROUP BY Marka, Model, FiyatTarihi
            ORDER BY Marka, Model, FiyatTarihi
        """
        cur.execute(sql_data, [year] + brands)
        rows = cur.fetchall()

        # 3) Pivot (Excel grid)
        series_map = {}  # (marka, model) -> prices[]
        for r in rows:
            marka = r[0]
            model = r[1]
            dt = r[2]
            fiyat = r[3]

            key = (marka, model)
            if key not in series_map:
                series_map[key] = [None] * len(labels)

            j = idx_map.get(dt)
            if j is None:
                continue
            series_map[key][j] = None if fiyat is None else float(fiyat)

        # 4) JSON rows
        out_rows = []
        for (marka, model), prices in series_map.items():
            out_rows.append({
                "brand": marka,
                "model": model,
                "prices": prices
            })

        return jsonify({"labels": labels, "rows": out_rows})

    finally:
        cur.close()
        conn.close()

