@app.route("/eshop_admin_orders", methods=["GET"])
@login_required
@department_check("Bilgi Teknolojileri", "SSH")
def eshop_admin_orders():
    try:
        conn = pyodbc.connect(YA_2El_AracSatis)
        cur = conn.cursor()
        cur.execute("""
            SELECT 
                order_id,
                username,
                user_namesurname,
                total_amount,
                order_status,
                created_at,
                order_status_updated_at,
                admin_cancel_note, 
                is_active,
                delivery_location
            FROM [Yuce_Portal].[eshop].[orders]
            WHERE is_active = 1
            ORDER BY created_at DESC
        """)
        rows = cur.fetchall()

        orders = [{
            "order_id": r.order_id,
            "username": r.username,
            "fullname": r.user_namesurname,
            "total_amount": float(r.total_amount),
            "order_status": r.order_status,
            "created_at": r.created_at,
            "status_updated_at": r.order_status_updated_at,
            "admin_cancel_note": r.admin_cancel_note,
            "is_active": r.is_active,
            "teslim_noktasi": r.delivery_location
        } for r in rows]

        return render_template("eshop_admin_orders.html", orders=orders)

    except Exception as e:
        print(f"Admin sipariş listesi hatası: {str(e)}")
        import traceback
        traceback.print_exc()
        return render_template("eshop_admin_orders.html", orders=[])

    finally:
        if conn: conn.close()

@app.route("/eshop_admin_orders/<int:order_id>/update", methods=["POST"])
@login_required
def eshop_admin_orders_update(order_id):
    if session.get("departman") != "SSH":
        return jsonify({"error": "Yetkiniz yok"}), 403

    data = request.get_json() or {}
    new_status = data.get("order_status")
    admin_cancel_note = (data.get("cancel_note") or "").strip()

    if new_status not in ["Beklemede", "Tamamlandı", "İptal"]:
        return jsonify({"error": "Geçersiz durum"}), 400

    # ✅ İptalde açıklama zorunlu
    if new_status == "İptal" and len(admin_cancel_note) < 3:
        return jsonify({"error": "İptal açıklaması zorunludur"}), 400

    conn = None

    try:
        conn = pyodbc.connect(YA_2El_AracSatis)
        conn.autocommit = False
        cur = conn.cursor()

        # Siparişi kontrol et
        cur.execute("""
            SELECT username, user_namesurname, total_amount, delivery_location, is_active, order_status
            FROM [Yuce_Portal].[eshop].[orders]
            WHERE order_id = ?
        """, (order_id,))
        result = cur.fetchone()

        if not result:
            conn.rollback()
            return jsonify({"error": "Sipariş bulunamadı"}), 404
        
        if result.order_status == 'İptal':
            conn.rollback()
            return jsonify({"error": "İptal edilmiş bir sipariş üzerinde tekrar işlem yapılamaz."}), 400

        delivery_location = (result.delivery_location or "").strip() or None

        if result.is_active != 1:
            conn.rollback()
            return jsonify({"error": "Sipariş aktif değil"}), 400

        # ✅ Durumu güncelle (NOT: artık admin_cancel_note'u iptal değilse NULL yapmıyoruz!)
        cur.execute("""
            UPDATE [Yuce_Portal].[eshop].[orders]
            SET order_status = ?,
                order_status_updated_at = GETDATE()
            WHERE order_id = ?
        """, (new_status, order_id))

        # ✅ Sadece iptal ise notu yaz
        if new_status == "İptal":
            cur.execute("""
                UPDATE [Yuce_Portal].[eshop].[orders]
                SET admin_cancel_note = ?
                WHERE order_id = ?
            """, (admin_cancel_note, order_id))

        # -----------------------------
        # ⭐⭐⭐ İPTALDE STOĞU GERİ ARTIR ⭐⭐⭐
        # -----------------------------
        if new_status == "İptal":

            cur.execute("""
                SELECT product_id, product_size, quantity
                FROM [Yuce_Portal].[eshop].[order_products]
                WHERE order_id = ?
            """, (order_id,))
            items = cur.fetchall()

            for item in items:
                pid = item.product_id
                size = item.product_size
                qty = item.quantity

                if not pid:
                    continue

                cur.execute("""
                    SELECT stock, sizes_json
                    FROM [Yuce_Portal].[eshop].[eshop_product]
                    WHERE product_id = ?
                """, (pid,))
                p = cur.fetchone()
                if not p:
                    continue

                total_stock = p.stock or 0

                # Normalize sizes_json
                try:
                    raw_sizes = json.loads(p.sizes_json or "[]")
                except:
                    raw_sizes = []

                if isinstance(raw_sizes, dict):
                    sizes = [{"name": k, "stock": int(v)} for k, v in raw_sizes.items()]
                elif isinstance(raw_sizes, list):
                    sizes = raw_sizes
                else:
                    sizes = []

                # Bedensiz ürün → stok > 0 ise artır
                if not size:
                        total_stock += qty
                # Bedenli ürün → her zaman artır
                else:
                    for s in sizes:
                        if s.get("name", "").lower() == (size or "").lower():
                            old_stock = int(s.get("stock", 0))
                            s["stock"] = old_stock + qty
                            total_stock += qty
                            break

                # Güncelle
                cur.execute("""
                    UPDATE [Yuce_Portal].[eshop].[eshop_product]
                    SET sizes_json = ?, stock = ?, updated_at = SYSDATETIME()
                    WHERE product_id = ?
                """, (json.dumps(sizes, ensure_ascii=False), total_stock, pid))

            # Ürün bağını kopar
            cur.execute("""
                UPDATE [Yuce_Portal].[eshop].[order_products]
                SET product_id = NULL
                WHERE order_id = ?
            """, (order_id,))

        # -----------------------------
        # Mail gönderimi
        # -----------------------------
        if new_status in ["Tamamlandı", "İptal"]:

            receiver_email = result.username
            user_fullname  = result.user_namesurname
            total_amount   = result.total_amount
            delivery_location_html = ""
            if new_status == "Tamamlandı":
                delivery_location_html = f"<b>Bırakılacak Yer:</b> {delivery_location}<br>"
                    

            if new_status == "Tamamlandı":
                mail_title = "✔ Siparişiniz Tamamlandı"
                mail_msg = "Siparişiniz başarıyla tamamlanmıştır."
                status_color = "#0E3A2F"
                cancel_note_html = ""
            else:
                mail_title = "❌ Siparişiniz İptal Edildi"
                mail_msg = "Siparişiniz iptal edilmiştir."
                status_color = "#f15252"

                cancel_note_html = f"""
                <div style="background:#fff7ed; padding:14px 16px; border-radius:10px; margin:16px 0;
                            border:1px solid #fed7aa;">
                    <p style="margin:0; font-size:14px; line-height:1.6; color:#7c2d12;">
                        <b>İptal Açıklaması (Admin):</b><br>
                        {admin_cancel_note if admin_cancel_note else "-"}
                    </p>
                </div>
                """

            email_body = f"""
            <div style="font-family: Arial, sans-serif; background:#f4f4f4; padding:24px;">
            <div style="max-width:600px; margin:auto; background:white; padding:30px; border-radius:16px;
                        border-top:6px solid {status_color}; box-shadow:0 4px 14px rgba(0,0,0,0.08);">

                <h2 style="color:{status_color}; text-align:center; margin-bottom:16px;">
                    {mail_title}
                </h2>

                <p style="font-size:15px; color:#333;">
                    Sayın <b>{user_fullname}</b>,<br>{mail_msg}
                </p>

                <div style="background:#f8f8f8; padding:16px; border-radius:10px; margin:20px 0;
                            border:1px solid #e6e6e6;">
                    <p style="margin:0; font-size:15px; line-height:1.6;">
                        <b>Sipariş No:</b> #{order_id}<br>
                        <b>Tutar:</b> {total_amount:,} ₺<br>
                        <b>Durum:</b> <span style="color:{status_color}; font-weight:bold;">{new_status}</span><br>
                        {delivery_location_html}
                    </p>
                </div>

                {cancel_note_html}

                <div style="text-align:center; margin-top:30px;">
                    <a href="https://yuceportal.skoda.com.tr/eshop_orders"
                        style="
                            display:inline-block;
                            background:{status_color};
                            color:white;
                            padding:12px 24px;
                            font-size:16px;
                            border-radius:8px;
                            text-decoration:none;
                            font-weight:bold;
                            box-shadow:0 3px 10px rgba(0,0,0,0.15);
                        ">
                        🔗 Siparişlerimi Görüntüle
                    </a>
                </div>

                <p style="font-size:13px; color:#888; text-align:center; margin-top:28px;">
                    Bu e-posta otomatik olarak gönderilmiştir. Yanıtlamanıza gerek yoktur.
                </p>

            </div>
            </div>
            """

            send_email(
                content=email_body,
                subject=mail_title,
                receiver_email=receiver_email,
                sender_email="yuceportal@skoda.com.tr",
                login=None
            )

        conn.commit()

        # ✅ Frontend isterse kullanabilsin diye notu da döndürüyoruz
        return jsonify({
            "success": True,
            "order_status": new_status,
            "admin_cancel_note": admin_cancel_note if new_status == "İptal" else None
        })

    except Exception as e:
        if conn:
            conn.rollback()
        return jsonify({"error": str(e)}), 500

    finally:
        if conn:
            conn.close()

@app.route("/eshop_orders/detail/<int:order_id>")
@login_required
def eshop_order_detail(order_id):
    user_email = session.get("email")
    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    cur.execute("""
        SELECT order_id, total_amount, order_status, created_at
        FROM [Yuce_Portal].[eshop].[orders]
        WHERE order_id = ? AND username = ? AND is_active = 1
    """, (order_id, user_email))
    order = cur.fetchone()
    if not order:
        conn.close()
        return "<p>Sipariş bulunamadı.</p>"
    cur.execute("""
        SELECT 
            p.product_name, p.photo1,
            op.product_size, op.quantity, op.price, op.total_price
        FROM [Yuce_Portal].[eshop].[order_products] op
        JOIN [Yuce_Portal].[eshop].[eshop_product] p
            ON op.product_id = p.product_id
        WHERE op.order_id = ?
    """, (order_id,))
    items = cur.fetchall()
    conn.close()
    html = f"""
    <h5>Sipariş #{order.order_id}</h5>
    <p><strong>Tarih:</strong> {order.created_at}</p>
    <p><strong>Durum:</strong> {order.order_status}</p>
    <p><strong>Toplam Tutar:</strong> {order.total_amount} ₺</p>
    <hr>
    <h6>Ürünler</h6>
    <table class="table table-bordered">
        <thead>
            <tr>
                <th>Ürün</th><th>Beden</th><th>Adet</th><th>Birim Fiyat</th><th>Toplam</th>
            </tr>
        </thead>
        <tbody>
    """
    for i in items:
        photo = i.photo1 or ""
        html += f"""
            <tr>
                <td><img src="{photo}" width="40" style="border-radius:6px;margin-right:8px;"> {i.product_name}</td>
                <td>{i.product_size or '-'}</td>
                <td>{i.quantity}</td>
                <td>{i.price} ₺</td>
                <td>{i.total_price} ₺</td>
            </tr>
        """
    html += "</tbody></table>"
    return html

