@app.post("/eshop_products/reorder")
@login_required
def eshop_products_reorder():
    data = request.get_json() or {}
    order = data.get("order", [])

    if not isinstance(order, list) or not order:
        return jsonify({"error": "order listesi boş"}), 400

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    try:
        for idx, pid in enumerate(order, start=1):
            cur.execute("""
                UPDATE [Yuce_Portal].[eshop].[eshop_product]
                SET sort_order = ?, updated_at = SYSDATETIME()
                WHERE product_id = ?
            """, (idx * 100, int(pid)))

        conn.commit()
        return jsonify({"success": True})
    except Exception as e:
        conn.rollback()
        return jsonify({"error": str(e)}), 500
    finally:
        conn.close()

@app.route("/bayiler", methods=["GET"])
@login_required
@kunye_yetki
def bayiler():
    # ---------- ORACLE CONNECTION ----------
    username = "USR_YUCE_DOGANO"
    userpwd = "qxBhjm0rUA"
    host = "10.113.197.4"
    port = 1521
    service_name = "DOTODWHDBP1"

    dsn = f"{username}/{userpwd}@{host}:{port}/{service_name}"
    oracle_conn = oracledb.connect(dsn)
    oracle_cur = oracle_conn.cursor()

    oracle_query = """
    SELECT
        YS.FK_EDUCATION_FIRM_ID AS FIRM_ID,
        YS.FIRM_CODE,
        MAX(CASE WHEN DR.REGION_TYPE = 'S' THEN DRC.REGION_CHIEF_FULL_NAME END) AS "Satış Bölge Yöneticisi",
        MAX(CASE WHEN DR.REGION_TYPE = 'L' THEN DRC.REGION_CHIEF_FULL_NAME END) AS "SSH Bölge Yöneticisi",
        CC.CITY_NAME  CITY
    FROM
        YUCE_DM.TBL_DW_GEN_DIM_DEALER YS
        INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION DR
            ON YS.DEALER_ID = DR.FK_DEALER_ID
           AND DR.REGION_TYPE IN ('S','L')
        INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION_CHIEF DRC
            ON DRC.FK_REGION_DEALER_ID = DR.REGION_DEALER_ID
        INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM GEN_FIRM
            ON GEN_FIRM.EDUCATION_FIRM_ID = YS.FK_EDUCATION_FIRM_ID
        LEFT JOIN YUCE_DM.TBL_DW_GEN_DIM_CITY_COUNTY CC
            ON CC.CODE = YS.FK_CITY_CODE
    WHERE
        YS.STATUS_EXPLANATION = 'Yürürlükte'
        AND YS.FIRM_CODE NOT IN ('YÜCE AUTO')
    GROUP BY
        YS.FK_EDUCATION_FIRM_ID, YS.FIRM_CODE, CC.CITY_NAME
    ORDER BY
        YS.FIRM_CODE ASC
    """
    oracle_cur.execute(oracle_query)
    results = oracle_cur.fetchall()  # (FIRM_ID, FIRM_CODE, SatisBolge, SSHBolge, CITY)

    # ---------- BAYİ ÖZELLİKLERİ (2S / 3S / City Store) ----------
    conn_ba = pyodbc.connect(YA_2El_AracSatis)
    cursor_ba = conn_ba.cursor()
    query_ba = """
        SELECT [ys_code],
               [S2],
               [S3],
               [City_Store]
        FROM [YucePortal_Bolgesel].[dbo].[BayiBilgileri]
    """
    cursor_ba.execute(query_ba)
    bayi_rows = cursor_ba.fetchall()

    # Map: FIRM_ID (= ys_code) -> flag'ler
    bayi_map = {}
    for row in bayi_rows:
        firm_id_str = str(row[0]).strip()  # ys_code = FIRM_ID
        bayi_map[firm_id_str] = {
            "S2": bool(row[1]),
            "S3": bool(row[2]),
            "City_Store": bool(row[3]),
        }

    # ---------- MSSQL ODD MARKET SHARE ----------
    mssql_conn = pyodbc.connect(YuceDB)
    cursor_mssql = mssql_conn.cursor()
    query_odd = """
      SELECT Year, City, Quantity, MarketShare
      FROM [Raporlar].[dbo].[ODD]
      WHERE CreatedDate = (SELECT MAX(CreatedDate) FROM [Raporlar].[dbo].[ODD])
        AND Brand = 'Skoda'
        AND Quantity <> 0
    """
    cursor_mssql.execute(query_odd)
    market_shares = cursor_mssql.fetchall()

    city_market = {}
    total_market_share = 0.0
    bayi_count = 0

    for row in market_shares:
        city = row[1]
        share = row[3]
        try:
            share_f = float(share)
        except (TypeError, ValueError):
            continue

        city_market[city] = share_f
        total_market_share += share_f
        bayi_count += 1

    avg = total_market_share / bayi_count if bayi_count else 0.0
    avg_str = f"{avg:.2f}"

    # ---------- ORACLE SONUÇLARINI 2S/3S/CITY_STORE İLE ZENGİNLEŞTİR ----------
    enriched_results = []
    for row in results:
        firm_id = row[0]                      # FK_EDUCATION_FIRM_ID
        firm_id_str = str(firm_id).strip()    # bayi_map key'i
        firm_code = str(row[1]).strip()
        satis_bolge = row[2]
        ssh_bolge = row[3]
        city = row[4]

        # FIRM_ID üzerinden eşleştirme
        flags = bayi_map.get(
            firm_id_str,
            {"S2": False, "S3": False, "City_Store": False}
        )

        enriched_results.append({
            "FIRM_ID": firm_id,
            "FIRM_CODE": firm_code,
            "SatisBolgeYonetici": satis_bolge,
            "SSHBolgeYonetici": ssh_bolge,
            "CITY": city,
            "S2": flags["S2"],
            "S3": flags["S3"],
            "City_Store": flags["City_Store"],
        })

    Write_Log_ToDB(session.get('username'), "GET", "/bayiler", 0, "Page viewed.")

    return render_template("bayiler.html", results=enriched_results, market_shares=market_shares, city_market=city_market, avg=avg, avg_str=avg_str)

@app.route("/api/aksiyonlar", methods=["GET"])
@login_required
def api_aksiyonlar():
    cn = pyodbc.connect(YA_2El_AracSatis)
    cur = cn.cursor()

    q = """
    SELECT 
      a.ID,
      a.Bayi_kodu,
      a.Aciklama,
      a.Baslangic_Tarihi,
      a.Termin_Tarihi,
      a.YA_Sorumlu2,
      a.YS_Sorumlu,
      a.Kritik,
      a.Degerlendirme_Alani,
      a.created_by,
      a.created_at,
      b.dealerName_Turkuaz
    FROM [YucePortal_Bolgesel].[dbo].[Satis_Genel_Aksiyonlar] a
    LEFT JOIN [YA_2El_AracSatis].[dbo].[Bayiiler] b ON a.Bayi_kodu=b.YS_code
    ORDER BY CASE WHEN a.Termin_Tarihi IS NULL THEN 1 ELSE 0 END, a.Termin_Tarihi
    """
    cur.execute(q)
    cols = [c[0] for c in cur.description]
    rows = []
    for r in cur.fetchall():
        d = dict(zip(cols, r))
        for k in ("Baslangic_Tarihi", "Termin_Tarihi", "created_at"):
            v = d.get(k)
            if hasattr(v, "isoformat"):
                d[k] = v.isoformat()
        rows.append(d)

    q2 = """
    SELECT 
        a.[ID],
        a.[kategori],
        a.[etki_alani],
        a.[baslik],
        a.[anlik_hedef],
        a.[anlik_gerceklesen],
        a.[baslangic_tarihi],
        a.[termin_tarihi],
        a.[YA_sorumlu],
        a.[YS_sorumlu],
        a.[kritik],
        a.[Bayi_kodu],
        a.[created_by],
        a.[created_at],
        b.[dealerName_Turkuaz] AS dealername_turkuaz
    FROM [YucePortal_Bolgesel].[dbo].[Satis_Checklist_Aksiyonlar] AS a
    LEFT JOIN [YA_2El_AracSatis].[dbo].[Bayiiler] AS b
        ON a.[Bayi_kodu] = b.[YS_code]
    """
    cur.execute(q2)
    cols2 = [c[0] for c in cur.description]
    rows_checklist = []
    for r in cur.fetchall():
        d = dict(zip(cols2, r))
        for k in ("baslangic_tarihi", "termin_tarihi", "created_at"):
            v = d.get(k)
            if hasattr(v, "isoformat"):
                d[k] = v.isoformat()
        rows_checklist.append(d)

    cur.close()
    cn.close()

    return jsonify({
        "rows": rows,
        "rows_checklist": rows_checklist
    })

@app.route("/api/ziyaret_konumlari", methods=["GET"])
@login_required
def api_ziyaret_konumlari():
    cn = pyodbc.connect(YA_2El_AracSatis)
    cur = cn.cursor()

    # ---- Query 1: Owners (Bayi_Ziyaret_Form) ----
    sql_owners = """
    DECLARE @today date = CONVERT(date, GETDATE());

    SELECT
        f.ID                          AS FormID,
        f.YS_code                     AS DealerCode,
        f.YS_name                     AS DealerName,
        f.Ziyaret_Tipi                AS ZiyaretTipi,
        f.Ziyaret_Sahibi              AS FullName,
        f.Ziyaret_Sahibi_username     AS Username,
        f.Ziyaret_Baslangic_tarihi    AS StartTime,
        f.Ziyaret_Bitis_Tarihi        AS EndTime,
        f.Ziyaret_Tarihindeki_SATIS_Bolge_Y AS SatisBolgeY,
        f.Ziyaret_Tarihindeki_SSH_Bolge_Y   AS SSHBolgeY,
        f.Report_Stage
    FROM [YucePortal_Bolgesel].[dbo].[Bayi_Ziyaret_Form] AS f
    WHERE
        f.Report_Stage IN (0,1,2)
        AND CONVERT(date, f.Ziyaret_Baslangic_tarihi) <= @today
        AND CONVERT(date, COALESCE(f.Ziyaret_Bitis_Tarihi, GETDATE())) >= @today
    ORDER BY f.YS_name, f.Ziyaret_Sahibi;
    """
    cur.execute(sql_owners)
    owners_cols = [c[0] for c in cur.description]
    owners_rows = [dict(zip(owners_cols, row)) for row in cur.fetchall()]

    sql_participants = """
    DECLARE @today date = CONVERT(date, GETDATE());

    SELECT
        k.FormID,
        f.YS_code                  AS DealerCode,
        f.YS_name                  AS DealerName,
        k.Katilimci_AdSoyad        AS FullName,
        k.Katilimci_Username       AS Username,
        k.Kismi                    AS RoleKismi,
        k.Baslangic_Tarihi         AS StartTime,
        k.Bitis_Tarihi             AS EndTime,
        f.Ziyaret_Tarihindeki_SATIS_Bolge_Y AS SatisBolgeY,
        f.Ziyaret_Tarihindeki_SSH_Bolge_Y   AS SSHBolgeY,
        f.Report_Stage
    FROM [YucePortal_Bolgesel].[dbo].[Bayi_Ziyaret_Form_Katilimcilar] AS k
    JOIN [YucePortal_Bolgesel].[dbo].[Bayi_Ziyaret_Form] AS f
      ON f.ID = k.FormID
    WHERE
        f.Report_Stage IN (0,1,2)
        AND CONVERT(date, k.Baslangic_Tarihi) <= @today
        AND CONVERT(date, COALESCE(k.Bitis_Tarihi, GETDATE())) >= @today
    ORDER BY f.YS_name, k.Katilimci_AdSoyad;
    """
    cur.execute(sql_participants)
    parts_cols = [c[0] for c in cur.description]
    parts_rows = [dict(zip(parts_cols, row)) for row in cur.fetchall()]

    # Optional: ISO-format datetime fields for JSON-friendliness
    def isoify(rec, keys=("StartTime", "EndTime")):
        for k in keys:
            v = rec.get(k)
            if hasattr(v, "isoformat"):
                rec[k] = v.isoformat()
        return rec

    owners_rows = [isoify(r) for r in owners_rows]
    parts_rows  = [isoify(r) for r in parts_rows]

    return jsonify({
        "owners": owners_rows,
        "participants": parts_rows
    })

def _load_kisiler():
        mc = mysql.connection.cursor()
        mc.execute("""
            SELECT ID, username, name, surname, departman
            FROM users1
            WHERE is_active = 1
              AND departman != 'Yönetim Kurulu'
              AND departman != 'Yeni İş Modelleri'
            ORDER BY departman ASC, name ASC
        """)
        results = mc.fetchall()
        mc.close()

        kisiler = [(int(row['ID']), f"{row['name']} {row['surname']} ({row['departman']})") for row in results]
