@app.route("/bayiler/<int:ys_code>/genel-aksiyon", methods=["POST"])
@login_required
def genel_aksiyon_ekle_bayi_sayfasi(ys_code):
    # Not: Rapor_ID bilinmiyor -> NULL
    from datetime import datetime
    conn = pyodbc.connect(YA_2El_AracSatis)
    cur  = conn.cursor()

    # ---- dosya kaydetme helper ----
    def _save_single_upload(file, subdir, base_name, allowed_exts):
        if not file or not getattr(file, "filename", ""): return None
        filename = secure_filename(file.filename)
        _, ext   = os.path.splitext(filename.lower())
        if ext not in allowed_exts: return None

        dest_dir = os.path.join(current_app.root_path, "static", subdir)
        os.makedirs(dest_dir, exist_ok=True)

        final = f"{base_name}{ext}"
        abs_path = os.path.join(dest_dir, final)
        k = 1
        while os.path.exists(abs_path):
            final = f"{base_name}_{k}{ext}"
            abs_path = os.path.join(dest_dir, final)
            k += 1

        file.save(abs_path)
        return f"/static/{subdir}/{final}"

    try:
        aciklama = (request.form.get("aciklama") or "").strip()
        bas_tarih = request.form.get("baslangic_tarihi") or None
        ter_tarih = request.form.get("termin_tarihi") or None
        ya_sorumlu = request.form.get("YA_Sorumlu") or None
        ys_sorumlu = request.form.get("YS_Sorumlu") or None
        kritik = 1 if (request.form.get("Kritik") in ("1","on","true","True")) else 0
        deger_alani = request.form.get("Degerlendirme_Alani") or None

        ts = datetime.now().strftime("%Y%m%d%H%M%S")
        base_prefix = f"{ys_code}_NULL_{ts}"

        ek_url = _save_single_upload(request.files.get("ek_dosya"), "Genel_Aksiyonlar", f"{base_prefix}_ek",
                                     {'.pdf','.doc','.docx','.xls','.xlsx','.png','.jpg','.jpeg','.webp'})
        f1_url = _save_single_upload(request.files.get("foto_1"), "Genel_Aksiyonlar", f"{base_prefix}_f1",
                                     {'.jpg','.jpeg','.png','.gif','.webp','.bmp'})
        f2_url = _save_single_upload(request.files.get("foto_2"), "Genel_Aksiyonlar", f"{base_prefix}_f2",
                                     {'.jpg','.jpeg','.png','.gif','.webp','.bmp'})

        mc = mysql.connection.cursor()
        mc.execute(f"SELECT name, surname, username FROM `users1` where ID={ya_sorumlu};")
        nam_surnam_usernam = mc.fetchone()
        name = nam_surnam_usernam["name"]
        surname = nam_surnam_usernam["surname"]
        username = nam_surnam_usernam["username"]
        nam_surnam = name + " " + surname

        cur.execute("""
            INSERT INTO [YucePortal_Bolgesel].[dbo].[Satis_Genel_Aksiyonlar]
            (Rapor_ID, Bayi_kodu,
             Aciklama, Baslangic_Tarihi, Termin_Tarihi,
             YA_Sorumlu, YS_Sorumlu, Kritik,
             Degerlendirme_Alani,
             Ek_Dosya_Path, Foto_1_Path, Foto_2_Path,
             created_by, created_at, YA_Sorumlu2, YA_Sorumlu3)
            VALUES (NULL, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, GETDATE(); ?, ?)
        """, (ys_code, aciklama, bas_tarih, ter_tarih, ya_sorumlu, ys_sorumlu, kritik, deger_alani,
              ek_url, f1_url, f2_url, session.get("username"), username, nam_surnam))
        conn.commit()

        # Kullanıcı adını -> ad soyad
        created_full = None
        try:
            mc = mysql.connection.cursor()
            mc.execute("SELECT CONCAT(name,' ',surname) AS full_name FROM users1 WHERE username=%s", (session.get("username"),))
            rr = mc.fetchone()
            if rr and rr.get("full_name"): created_full = rr["full_name"]
            mc.close()
        except Exception:
            pass

        # Frontend’e kart çizmek için pratik JSON dön
        def _fmt(d): 
            try:
                return datetime.strptime(str(d), "%Y-%m-%d").strftime("%d.%m.%Y")
            except: return None

        return jsonify({
            "ID": int(cur.execute("SELECT SCOPE_IDENTITY()").fetchval() or 0),
            "Rapor_ID": None,
            "Bayi_kodu": ys_code,
            "aciklama": aciklama,
            "baslik": (aciklama[:79] + "…") if aciklama and len(aciklama) > 80 else aciklama,
            "baslangic_tarihi": bas_tarih,
            "baslangic_tarihi_fmt": _fmt(bas_tarih) if bas_tarih else None,
            "termin_tarihi": ter_tarih,
            "termin_tarihi_fmt": _fmt(ter_tarih) if ter_tarih else None,
            "YA_sorumlu": ya_sorumlu,
            "YS_sorumlu": ys_sorumlu,
            "kritik": bool(kritik),
            "Degerlendirme_Alani": deger_alani,
            "created_by": session.get("username"),
            "created_by_full": created_full,
            "created_at_fmt": datetime.now().strftime("%d.%m.%Y"),
            "ek": ek_url,
            "foto1": f1_url,
            "foto2": f2_url,
            "images": [p for p in [f1_url, f2_url] if p],
            "has_files": bool(ek_url or f1_url or f2_url)
        })

    except Exception as e:
        conn.rollback()
        return (str(e), 400)
    finally:
        conn.close()

