@app.get("/api/bayiler/<int:ys_code>/info")
@login_required
def api_bayi_info(ys_code):
    # ===== ORACLE QUERY =====
    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"

    dsn = f"{username}/{userpwd}@{host}:{port}/{service}"
    connection = oracledb.connect(dsn)
    cursor = connection.cursor()

    query = f"""
    SELECT
        YS.FK_EDUCATION_FIRM_ID                                  AS FIRM_ID,
        YS.FIRM_CODE                                              AS FIRM_NAME,
        MAX(CASE WHEN DR.REGION_TYPE = 'S' THEN DRC.REGION_CHIEF_FULL_NAME END) AS SALES_REGION_CHIEF,
        MAX(CASE WHEN DR.REGION_TYPE = 'L' THEN DRC.REGION_CHIEF_FULL_NAME END) AS SSH_REGION_CHIEF,
        CC.CITY_NAME                                              AS CITY
    FROM YUCE_DM.TBL_DW_GEN_DIM_DEALER YS
    INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION DR
        ON YS.DEALER_ID = DR.FK_DEALER_ID AND DR.REGION_TYPE IN ('S','L')
    INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION_CHIEF DRC
        ON DRC.FK_REGION_DEALER_ID = DR.REGION_DEALER_ID
    INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM GEN_FIRM
        ON GEN_FIRM.EDUCATION_FIRM_ID = YS.FK_EDUCATION_FIRM_ID
    LEFT JOIN  YUCE_DM.TBL_DW_GEN_DIM_CITY_COUNTY CC
        ON CC.CODE = YS.FK_CITY_CODE
    WHERE
        YS.STATUS_EXPLANATION = 'Yürürlükte'
        AND YS.FIRM_CODE NOT IN ('YÜCE AUTO')
        AND GEN_FIRM.EDUCATION_FIRM_ID = {ys_code}
    GROUP BY
        YS.FK_EDUCATION_FIRM_ID, YS.FIRM_CODE, CC.CITY_NAME
    """

    cursor.execute(query)
    row = cursor.fetchone()
    cursor.close()
    connection.close()

    if not row:
        return jsonify({"error": "Dealer not found"}), 404

    firm_id, firm_name, sales_chief, ssh_chief, city = row

    # ===== SQL SERVER QUERY - BayiBilgileri tablosundan ek bilgileri çek =====
    cn = pyodbc.connect(YA_2El_AracSatis)
    cur = cn.cursor()

    cur.execute("""
        SELECT 
            telefon,
            email,
            ticaret_sicil,
            vergi_dairesi,
            kep_mail,
            kvps_kodu,
            instagram,
            linkedin,
            web,
            maps_link,
            adres_long
        FROM [YucePortal_Bolgesel].[dbo].[BayiBilgileri]
        WHERE ys_code = ?
    """, (ys_code,))
    
    bayi_row = cur.fetchone()
    cur.close()
    cn.close()

    # Varsayılan değerler (eğer kayıt yoksa)
    telefon = None
    email = None
    ticaret_sicil = None
    vergi_dairesi = None
    kep_mail = None
    kvps_kodu = None
    instagram = None
    linkedin = None
    web = None
    maps_link = None
    address = None

    # Eğer BayiBilgileri'nde kayıt varsa değerleri al
    if bayi_row:
        (telefon, email, ticaret_sicil, vergi_dairesi, 
         kep_mail, kvps_kodu, instagram, linkedin, web, maps_link, address) = bayi_row

    # ===== COMBINED RESPONSE =====
