@app.get("/api/bayiler/<int:ys_code>/photos")
@login_required
def api_bayi_photos(ys_code):
    from datetime import date, datetime
    make_absolute = bool(request.args.get("absolute"))

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
    cur.execute("""
        SELECT file_path, photo_desc, uploaded_at
        FROM [YucePortal_Bolgesel].[dbo].[BayiResimleri]
        WHERE ys_code = ?
        ORDER BY sort_order, uploaded_at
    """, ys_code)

    photos = []
    for row in cur.fetchall():
        if not row.file_path:
            continue

        if isinstance(row.uploaded_at, (datetime, date)):
            created_at = row.uploaded_at.strftime("%d.%m.%Y")
        else:
            created_at = None

        photos.append({"url": url_for("static", filename=row.file_path, _external=make_absolute), "caption": (row.photo_desc or "").strip(), "created_at": created_at})

    cur.close()
    conn.close()
    return jsonify(photos)

# API: Raporlar =========
@app.get("/api/bayiler/<int:ys_code>/reports")
@login_required
def api_bayi_reports(ys_code):
    import datetime as _dt
    from flask import jsonify, url_for
    import pyodbc

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()

    # 1) Raporları çek (Satış / Satis ve stage=2)
    cur.execute("""
        SELECT
            ID,
            YS_code,
            Ziyaret_Tipi,
            Ziyaret_Sebebi,
            Ziyaret_Baslangic_tarihi,
            Ziyaret_Bitis_Tarihi,
            Ziyaret_Sahibi,
            Report_Stage
        FROM [YucePortal_Bolgesel].[dbo].[Bayi_Ziyaret_Form]
        WHERE YS_code = ?
          AND Ziyaret_Tipi IN ('Satış','Satis')
          AND Report_Stage = 2
        ORDER BY Ziyaret_Baslangic_tarihi DESC, ID DESC
    """, (ys_code,))
    rows = cur.fetchall()

    stage_map = {0: "Planlandı", 1: "Rapor Hazırlanıyor", 2: "Onaylandı"}

    def _to_date_str(v):
        if not v:
            return ""
        if isinstance(v, (_dt.date, _dt.datetime)):
            return v.strftime("%Y-%m-%d")
        try:
            return _dt.datetime.fromisoformat(str(v)).date().strftime("%Y-%m-%d")
        except Exception:
            return str(v)

    # Eğer rapor yoksa direkt dön
    if not rows:
        cur.close()
        conn.close()
        return jsonify([])

    report_ids = [int(r.ID) for r in rows]

    # pyodbc için IN (?, ?, ?) placeholder üret
    placeholders = ",".join("?" for _ in report_ids)

    # 2) Checklist aksiyon adetleri (Satis_Checklist_Aksiyonlar.RaporID)
    cur.execute(f"""
        SELECT
            RaporID AS report_id,
            COUNT(1) AS cnt
        FROM [YucePortal_Bolgesel].[dbo].[Satis_Checklist_Aksiyonlar]
        WHERE RaporID IN ({placeholders})
        GROUP BY RaporID
    """, report_ids)
    checklist_counts = {int(r.report_id): int(r.cnt) for r in cur.fetchall()}

    # 3) Genel aksiyon adetleri (Satis_Genel_Aksiyonlar.Rapor_ID)
    cur.execute(f"""
        SELECT
            Rapor_ID AS report_id,
            COUNT(1) AS cnt
        FROM [YucePortal_Bolgesel].[dbo].[Satis_Genel_Aksiyonlar]
        WHERE Rapor_ID IN ({placeholders})
        GROUP BY Rapor_ID
    """, report_ids)
    general_counts = {int(r.report_id): int(r.cnt) for r in cur.fetchall()}

    cur.close()
    conn.close()

    # 4) JSON'a dön
    reports = []
    for r in rows:
        rid = int(r.ID)
        c = checklist_counts.get(rid, 0)
        g = general_counts.get(rid, 0)

        reports.append({
            "id": rid,
            "reason": (r.Ziyaret_Sebebi or "Bayi Ziyaret Raporu").strip(),
            "start_date": _to_date_str(r.Ziyaret_Baslangic_tarihi),
            "end_date": _to_date_str(r.Ziyaret_Bitis_Tarihi),
            "owner": (r.Ziyaret_Sahibi or "").strip(),
            "status": stage_map.get(int(r.Report_Stage or 0), "Bekliyor"),
            "actions_checklist": c,
            "actions_general": g,
            "actions_total": c + g,
            "report_url": url_for("bayi_ziyareti_olustur2", ys_code=ys_code, rapor_id=rid),
        })

    return jsonify(reports)

@app.get("/api/bayiler/employees")
@login_required
def api_bayiler_employees():
    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"
    dsn = f"{host}:{port}/{service}"

    ys_name = (request.args.get("ys_name") or "").strip()
    if not ys_name:
        return jsonify({"error": "ys_name is required"}), 400

    _paren_re = re.compile(r"\s*\([^)]*\)")
    def normalize_title(title: str) -> str:
        if not title:
            return ""
        t = _paren_re.sub("", title)
        t = re.sub(r"\s+", " ", t).strip().upper()
        return t

    TITLE_TO_ROLE = {
        "SATIŞ MÜDÜRÜ": "satis_muduru",
        "SERVİS MÜDÜRÜ": "servis_muduru",
        "SSH MÜDÜRÜ": "servis_muduru",
        "YEDEK PARÇA MÜDÜRÜ": "yedek_parca_muduru",
        "GENEL MÜDÜR": "genel_mudur",
        "GENEL MÜDÜR YARDIMCISI": "genel_mudur_yardimcisi",
    }

    def role_key_for(job_name: str) -> str | None:
        if not job_name:
            return None
        t = normalize_title(job_name)
        if t in TITLE_TO_ROLE:
            return TITLE_TO_ROLE[t]
        if "GENEL MÜDÜR YARDIMCISI" in t:
            return "genel_mudur_yardimcisi"
        if "GENEL MÜDÜR" in t:
            return "genel_mudur"
        if "YEDEK PARÇA" in t and "MÜDÜR" in t:
            return "yedek_parca_muduru"
        if ("SERVİS" in t or "SSH" in t) and "MÜDÜR" in t:
            return "servis_muduru"
        if "SATIŞ" in t and "MÜDÜR" in t:
            return "satis_muduru"
        return None

    sql = f"""
        SELECT DISTINCT  
        GEN_FIRM.EDUCATION_FIRM_ID, 
        YS.FIRM_CODE, 
        PERSONNEL.FIRST_NAME, 
        PERSONNEL.SURNAME, 
        PERSONNEL.JOB_NAME 
        FROM YUCE_DM.TBL_DW_GEN_DIM_PERSONNEL PERSONNEL 
        INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER YS ON (YS.FK_EDUCATION_FIRM_ID= PERSONNEL.FK_FIRM_ID) 
        INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER_REGION DR ON YS.DEALER_ID = DR.FK_DEALER_ID AND DR.REGION_TYPE IN ('S','L')
        INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM GEN_FIRM ON (GEN_FIRM.EDUCATION_FIRM_ID = YS.FK_EDUCATION_FIRM_ID ) 
        WHERE      YS.STATUS_EXPLANATION = 'Yürürlükte' 
                AND YS.FIRM_CODE NOT IN ('YÜCE AUTO') 
                AND PERSONNEL.JOB_NAME IN ('BÖLGE DİREKTÖRÜ','DİREKTÖR','FİLO SATIŞ YETKİLİSİ','GENEL MÜDÜR','GENEL MÜDÜR YARDIMCISI','MÜDÜR','MÜDÜR YARDIMCISI','SATIŞ MÜDÜRÜ', 
            'SATIŞ MÜDÜRÜ (AUDİ)','SATIŞ MÜDÜRÜ (VW BİNEK)','SATIŞ YETKİLİSİ','SATIŞ YETKİLİSİ (SKODA)','SATIŞ ŞEFİ','SATIŞ ŞEFİ (SKODA)', 
            'SERVİS MÜDÜRÜ','SERVİS YETKİLİSİ','SERVİS ŞEFİ','SSH MÜDÜRÜ','YEDEK PARÇA MÜDÜRÜ','YEDEK PARÇA YETKİLİSİ','YÖNETİM KURULU BAŞKANI','YÖNETİM KURULU ÜYESİ') 
            AND YS.FIRM_CODE = '{ys_name}'
        AND EXTRACT (YEAR FROM PERSONNEL.LEAVE_DATE )= 1900 
    """

    conn = oracledb.connect(user=username, password=userpwd, dsn=dsn)
    cur = conn.cursor()
    cur.execute(sql)
    rows = cur.fetchall()

    employees = []
    # >>>> DÜZELTİLEN KISIM: 5 kolon döndüğü için 5 değişkene açıyoruz
    for edu_firm_id, firm_code, first_name, surname, job_name in rows:
        first_name = (first_name or "").strip()
        surname    = (surname or "").strip()
        job_name   = (job_name or "").strip()
        full_name  = (" ".join([first_name, surname])).strip()
        rk = role_key_for(job_name)

        employees.append({
            "education_firm_id": edu_firm_id,
            "firm_code": firm_code,
            "firm_name": None,  # sorgu firm_name döndürmediği için None
            "first_name": first_name,
            "surname": surname,
            "full_name": full_name or None,
            "job_name": job_name,
            "role_key": rk
        })

    role_priority = {
        "genel_mudur": 1,
        "genel_mudur_yardimcisi": 2,
        "satis_muduru": 3,
        "servis_muduru": 4,
        "yedek_parca_muduru": 5,
        None: 99
    }
    employees.sort(key=lambda e: (role_priority.get(e["role_key"], 99), (e["full_name"] or "")))

    cur.close()
    conn.close()
    return jsonify(employees), 200

