@app.get("/api/bayiler/<int:ys_code>/kpi/monthly_sales")
@login_required
def api_kpi_monthly_sales(ys_code):
    from datetime import datetime

    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"
    dsn = f"{username}/{userpwd}@{host}:{port}/{service}"

    now = datetime.now()
    current_month = now.month
    m = request.args.get("month", "").strip()
    try:
        month_no = int(m) if m.isdigit() else current_month
    except Exception:
        month_no = current_month
    month_no = max(1, min(current_month, month_no))

    sql = f"""
    SELECT COUNT(DISTINCT VEH.VEHICLE_ID) AS SALES_COUNT
      FROM YUCE_DM.TBL_DW_VEH_RPT_STOCK_ACTIVITY_MAX RETURN_MAX_ACTIVITY
      RIGHT OUTER JOIN YUCE_DM.TBL_DW_VEH_VEHICLE VEH
        ON VEH.VEHICLE_ID = RETURN_MAX_ACTIVITY.VEHICLE_ID
       AND RETURN_MAX_ACTIVITY.ACTIVITY_TYPE = 9
      INNER JOIN YUCE_DM.TBL_DW_VEH_MODEL_CATALOG MODEL_CATALOG
        ON MODEL_CATALOG.COUNTRYMODEL_ID = VEH.FK_COUNTRYMODEL_ID
      INNER JOIN YUCE_DM.TBL_DW_VEH_STOCK_ACTIVITY STOCK_ACTIVITY
        ON STOCK_ACTIVITY.VEHICLE_ID = VEH.VEHICLE_ID
      INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER DEALER
        ON DEALER.DEALER_ID = STOCK_ACTIVITY.FK_DEALER_ID_SOURCE
      INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM GEN_FIRM
        ON GEN_FIRM.EDUCATION_FIRM_ID = DEALER.FK_EDUCATION_FIRM_ID
     WHERE EXTRACT(YEAR FROM STOCK_ACTIVITY."DATE") = EXTRACT(YEAR FROM SYSDATE)
       AND EXTRACT(MONTH FROM STOCK_ACTIVITY."DATE") = {month_no}
       AND STOCK_ACTIVITY.ACTIVITY_TYPE = 8
       AND STOCK_ACTIVITY.ACTIVITY_ID > NVL(RETURN_MAX_ACTIVITY.MAX_ACTIVITY_ID, 0)
       AND GEN_FIRM.EDUCATION_FIRM_ID = {ys_code}
    """.format(month_no=int(month_no), ys_code=int(ys_code))

    try:
        connection = oracledb.connect(dsn)
        cursor = connection.cursor()
        cursor.execute(sql)
        row = cursor.fetchone()
        value = int(row[0]) if row and row[0] is not None else 0
        cursor.close()
        connection.close()
        return jsonify({"value": value, "month": month_no})
    except Exception as e:
        return jsonify({"error": "Oracle sorgu hatası", "detail": str(e)}), 502

