@login_required
def api_kpi_sales_points(ys_code):
    from datetime import datetime

    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"
    dsn = f"{username}/{userpwd}@{host}:{port}/{service}"

    scope   = (request.args.get("scope", "month") or "month").lower()
    ys_name = (request.args.get("ys_name") or "").strip()
    if not ys_name:
        return jsonify({"error": "ys_name is required"}), 400

    ys_name_sql = ys_name.replace("'", "''")

    now = datetime.now()
    current_month = now.month
    try:
        month_no = int(request.args.get("month") or current_month)
    except Exception:
        month_no = current_month
    month_no = max(1, min(12, month_no))

    month_filter = "" if scope == "year" else f"AND T.PERIOD_MONTH = {month_no}"

    sql = f"""
    WITH T AS (
      SELECT
        CASE
          WHEN csa.FIRM_NAME = 'AYKAN KARTAL'                   THEN 'AYKAN KARTAL SKODA'
          WHEN csa.FIRM_NAME = 'AVEK İZMİR'                     THEN 'AVEK KARŞIYAKA'
          WHEN csa.FIRM_NAME = 'NEVA'                           THEN 'NEVA OTOMOTİV'
          WHEN csa.FIRM_NAME = 'DOĞUŞ OTO MASLAK OTOMOTION'     THEN 'DOĞUŞ OTO MASLAK'
          WHEN csa.FIRM_NAME = 'AYKAN SKODA'                    THEN 'AYKAN ADANA SKODA'
          WHEN csa.FIRM_NAME = 'LENA AYDIN'                     THEN 'LENA AYDIN SKODA'
          WHEN csa.FIRM_NAME = 'ERZ'                            THEN 'ERZ OTOMOTİV'
          WHEN csa.FIRM_NAME = 'DEMOTO MANİSA'                  THEN 'DEMOTO Manisa'
          WHEN csa.FIRM_NAME = 'Vimsa Gaziantep'                THEN 'VİMSA GAZİANTEP'
          ELSE csa.FIRM_NAME
        END AS FIRM_NAME_STD,
        csa.YEAR_  AS PERIOD_YEAR,
        csa.MONTH_ AS PERIOD_MONTH,
        csa.GENERAL_POINT,
        csa.BASE
      FROM YUCE_DM.TBL_DW_CUS_YUCE_IPSOS_VEHICLE_SALES csa
      WHERE csa.YEAR_ = EXTRACT(YEAR FROM SYSDATE-1)
    )
    SELECT
      ROUND( SUM(T.GENERAL_POINT * T.BASE) / NULLIF(SUM(T.BASE), 0), 2 ) AS VAL
    FROM T
    WHERE T.FIRM_NAME_STD = '{ys_name_sql}'
      {month_filter}
    """

    try:
        conn = oracledb.connect(dsn)
        cur  = conn.cursor()
        cur.execute(sql)
        row = cur.fetchone()
        cur.close()
        conn.close()

        value = float(row[0]) if row and row[0] is not None else 0.0
        if value == 0.0:
            return jsonify({"text": "-" , "scope": scope, "month": month_no, "ys_name": ys_name})
        return jsonify({"value": value, "scope": scope, "month": month_no, "ys_name": ys_name})
    except Exception as e:
        return jsonify({"error": "Oracle sorgu hatası", "detail": str(e)}), 502

