@app.get("/api/bayiler/<int:ys_code>/kpi/service/workorders")
@login_required
def api_kpi_service_workorders(ys_code):
    import oracledb
    import pyodbc
    from flask import request, jsonify

    # ---------- ORACLE (actual count) ----------
    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"
    dsn = "{}/{}@{}:{}/{}".format(username, userpwd, host, port, service)

    ys_name_param = (request.args.get("ys_name") or "").strip()

    ora_sql = """
    SELECT
      COUNT(DISTINCT wo.CODE) AS WORKORDER_COUNT,
      MIN(YS.FIRM_CODE)       AS FIRM_CODE
    FROM YUCE_DM.TBL_DW_ASX_WORK_ORDER       wo
    JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER       YS  ON YS.FIRM_CODE         = wo.FIRM_CODE
    JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM         GF  ON GF.EDUCATION_FIRM_ID = YS.FK_EDUCATION_FIRM_ID
    WHERE NVL(wo.PDI_STATUS_EXPLANATION,'') <> 'VAR'
      AND TRUNC(wo.CREATE_DATE) BETWEEN TRUNC(SYSDATE,'YEAR') AND TRUNC(SYSDATE)
      AND GF.EDUCATION_FIRM_ID = {ys_code}
    """.format(ys_code=int(ys_code))

    ora_conn = None
    ora_cur = None
    count_val = 0
    ys_name_db = ""

    try:
        ora_conn = oracledb.connect(dsn)
        ora_cur = ora_conn.cursor()
        ora_cur.execute(ora_sql)
        row = ora_cur.fetchone()
        if row:
            try:
                count_val = int(row[0] or 0)
            except Exception:
                count_val = 0
            ys_name_db = (row[1] or "").strip()
    except Exception as e:
        return jsonify({"error": "Oracle sorgu hatası", "detail": str(e)}), 502
    finally:
        try:
            ora_cur and ora_cur.close()
        except Exception:
            pass
        try:
            ora_conn and ora_conn.close()
        except Exception:
            pass

    # ---------- SQL SERVER (monthly target from YuceDB) ----------
    target_val = None
    mconn = None
    mcur = None
    try:
        # exactly as requested:
        mconn = pyodbc.connect(YuceDB)
        mcur = mconn.cursor()
        mssql_sql = """
            SELECT TOP 1 CAST(ROUND([Değer], 0) AS INT) AS TARGET
            FROM [YuceDashboard].[dbo].[WORK_ORDER_GOALS_SSH]
            WHERE [Bayi Adı] = ?
              AND YEAR([Tarih]) = YEAR(GETDATE())
              AND MONTH([Tarih]) = MONTH(GETDATE())
            ORDER BY [Tarih] DESC
        """
        # prefer FE name; fall back to Oracle firm_code if FE didn't send it
        dealer_name = (ys_name_param or ys_name_db)
        mcur.execute(mssql_sql, (dealer_name,))
        r = mcur.fetchone()
        if r and r[0] is not None:
            target_val = int(r[0])
    except Exception:
        # swallow MSSQL errors; response will just omit target
        target_val = None
    finally:
        try:
            mcur and mcur.close()
        except Exception:
            pass
        try:
            mconn and mconn.close()
        except Exception:
            pass

    # ---------- Response ----------
    resp = {
        "value": count_val,                       # actual workorder count (Oracle)
        "ys_name": ys_name_db or ys_name_param,   # resolved dealer name
    }
    if target_val is not None:
        resp["target"] = target_val              # rounded monthly target (SQL Server)
        resp["text"] = "{}/{}".format(count_val, target_val)

    return jsonify(resp)

