@app.get("/api/bayiler/<int:ys_code>/kpi/service/revenue")
@login_required
def api_kpi_service_revenue(ys_code):
    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"
    dsn = f"{username}/{userpwd}@{host}:{port}/{service}"

    # Yıl başından bugüne (YTD) ciro
    sql = f"""
    WITH WOD AS (
      SELECT 
        FK_WORK_ORDER_ID, 
        SUM(NET_AMOUNT) AS NET_AMOUNT
      FROM YUCE_DM.TBL_DW_ASX_WORK_ORDER_DETAIL
      GROUP BY FK_WORK_ORDER_ID
    )
    SELECT
      NVL(SUM(NVL(WOD.NET_AMOUNT, 0)), 0) AS TOTAL_NET_AMOUNT
    FROM YUCE_DM.TBL_DW_ASX_WORK_ORDER       wo
    JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER       YS  ON YS.FIRM_CODE         = wo.FIRM_CODE
    JOIN YUCE_DM.TBL_DW_GEN_DIM_FIRM         GF  ON GF.EDUCATION_FIRM_ID = YS.FK_EDUCATION_FIRM_ID
    LEFT JOIN WOD                                 ON WOD.FK_WORK_ORDER_ID = wo.WORK_ORDER_ID
    WHERE NVL(wo.PDI_STATUS_EXPLANATION,'') <> 'VAR'
      AND TRUNC(wo.CREATE_DATE) BETWEEN TRUNC(SYSDATE,'YEAR') AND TRUNC(SYSDATE)
      AND GF.EDUCATION_FIRM_ID = {ys_code}
    """.format(ys_code=int(ys_code))

    try:
        connection = oracledb.connect(dsn)
        cursor = connection.cursor()
        cursor.execute(sql)
        row = cursor.fetchone()
        total_net = row[0] if row and row[0] is not None else 0
        try:
            total_net = round(float(total_net))
        except Exception:
            total_net = 0.0
        return jsonify({"value": (total_net)})
    except Exception as e:
        return jsonify({"error": "Oracle sorgu hatası", "detail": str(e)}), 502
    finally:
        try:
            cursor.close()
        except Exception:
            pass
        try:
            connection.close()
        except Exception:
            pass

