@app.get("/api/bayiler/<int:ys_code>/kpi/service/cem_monthly")
@login_required
def api_kpi_service_cem_monthly(ys_code):
    from datetime import datetime

    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"
    dsn = f"{username}/{userpwd}@{host}:{port}/{service}"

    scope   = (request.args.get("scope", "month") or "month").lower()  # 'month' or 'year'
    ys_name = (request.args.get("ys_name") or "").strip()


    ys_name_sql = ys_name.replace("'", "''") 

    now = datetime.now()
    current_month = now.month
    try:
        month_no = int(request.args.get("month") or current_month)
    except Exception:
        month_no = current_month
    month_no = max(1, min(12, month_no))

    month_filter = "" if scope == "year" else f"AND T.PERIOD_MONTH = {month_no}"

    sql = f"""
    WITH ser_fix AS (
    SELECT
        ser.FIRM_CODE,
        ser.YEAR_,
        ser.MONTH_,
        ser.BASE,                    -- anket sayısı
        ser.SSH_GENERAL_POINT,       -- puan
        CASE
        WHEN ser.FIRM_NAME = 'AYKAN KARTAL'               THEN 'AYKAN KARTAL SKODA'
        WHEN ser.FIRM_NAME = 'AVEK İZMİR'                 THEN 'AVEK KARŞIYAKA'
        WHEN ser.FIRM_NAME = 'NEVA'                       THEN 'NEVA OTOMOTİV'
        WHEN ser.FIRM_NAME = 'DOĞUŞ OTO MASLAK OTOMOTION' THEN 'DOĞUŞ OTO MASLAK'
        WHEN ser.FIRM_NAME = 'AYKAN SKODA'                THEN 'AYKAN ADANA SKODA'
        WHEN ser.FIRM_NAME = 'LENA AYDIN'                 THEN 'LENA AYDIN SKODA'
        WHEN ser.FIRM_NAME = 'ERZ'                        THEN 'ERZ OTOMOTİV'
        WHEN ser.FIRM_NAME = 'DEMOTO MANİSA'              THEN 'DEMOTO Manisa'
        WHEN ser.FIRM_NAME = 'Vimsa Gaziantep'            THEN 'VİMSA GAZİANTEP'
        ELSE ser.FIRM_NAME
        END AS firm_name2
    FROM YUCE_DM.TBL_DW_CUS_YUCE_IPSOS_SERVICE ser
    WHERE ser.YEAR_ = EXTRACT(YEAR FROM SYSDATE - 1)
    )
    SELECT
    s.firm_name2,
    s.FIRM_CODE,
    wo.FK_FIRM_ID,
    s.YEAR_,
    s.MONTH_,
    SUM(s.BASE) AS BASE,  -- anket sayıları
    SUM(s.SSH_GENERAL_POINT * s.BASE) / NULLIF(SUM(s.BASE), 0) AS SSH_GENERAL_POINT
    FROM ser_fix s
    LEFT JOIN YUCE_DM.TBL_DW_ASX_WORK_ORDER wo
    ON UPPER(TRIM(wo.FIRM_CODE)) = UPPER(TRIM(s.firm_name2))  -- isimle JOIN
    
    WHERE 
    wo.FK_FIRM_ID = {ys_code}
    AND 
    MONTH_ = {month_no}
    AND 
    YEAR_ = 2025
    GROUP BY
    s.firm_name2,
    s.FIRM_CODE,
    wo.FK_FIRM_ID,
    s.YEAR_,
    s.MONTH_

    ORDER BY
    s.MONTH_ ASC
    """

    conn = oracledb.connect(dsn)
    cur  = conn.cursor()
    cur.execute(sql)
    row = cur.fetchone()
    cur.close()
    conn.close()

    value = float(row[6]) if row and row[6] is not None else 0.0
    if value == 0.0:
        return jsonify({"text": "-", "scope": scope, "month": month_no, "ys_name": ys_name})
    return jsonify({"value": value, "scope": scope, "month": month_no, "ys_name": ys_name})

