@app.get("/api/bayiler/<int:ys_code>/kpi/market_share")
@login_required
def api_kpi_active_customers(ys_code):
    ys_name = request.args.get("ys_name")

    username = "USR_YUCE_DOGANO"
    userpwd  = "qxBhjm0rUA"
    host     = "10.113.197.4"
    port     = 1521
    service  = "DOTODWHDBP1"

    dsn = f"{username}/{userpwd}@{host}:{port}/{service}"

    sql = F"""
    WITH base AS ( 
    SELECT DISTINCT 
            d.firm_code, 
            v.vehicle_id, 
            CASE 
            WHEN v.reserver_code = 'FİLO Rezervli' THEN 1   -- Filo 
            ELSE 0                                         -- Perakende (NULL dahil) 
            END AS is_fleet 
    FROM YUCE_DM.TBL_DW_VEH_RPT_STOCK_ACTIVITY_MAX RETURN_MAX_ACTIVITY 
    RIGHT OUTER JOIN YUCE_DM.TBL_DW_VEH_VEHICLE v  
        ON v.vehicle_id = RETURN_MAX_ACTIVITY.vehicle_id  
    AND RETURN_MAX_ACTIVITY.activity_type = 9 
    INNER JOIN YUCE_DM.TBL_DW_VEH_MODEL_CATALOG MODEL_CATALOG  
        ON MODEL_CATALOG.countrymodel_id = v.fk_countrymodel_id 
    INNER JOIN YUCE_DM.TBL_DW_VEH_STOCK_ACTIVITY sa  
        ON sa.vehicle_id = v.vehicle_id 
    INNER JOIN YUCE_DM.TBL_DW_GEN_DIM_DEALER d  
        ON d.dealer_id = sa.fk_dealer_id_source 
    WHERE TRUNC(sa."DATE") BETWEEN TRUNC(SYSDATE, 'YEAR') AND TRUNC(SYSDATE) 
        AND sa.activity_type = 8 
        AND sa.activity_id > NVL(RETURN_MAX_ACTIVITY.max_activity_id, 0) 
    ), 
    agg AS ( 
    SELECT 
        firm_code, 
        COUNT(*) AS sales_count_total, 
        SUM(CASE WHEN is_fleet = 1 THEN 1 ELSE 0 END) AS sales_count_fleet, 
        SUM(CASE WHEN is_fleet = 0 THEN 1 ELSE 0 END) AS sales_count_retail 
    FROM base 
    GROUP BY firm_code 
    ) 
    SELECT 
    a.firm_code, 
    a.sales_count_total, 
    a.sales_count_fleet, 
    a.sales_count_retail, 
    ROUND( 
        a.sales_count_fleet 
        / NULLIF(SUM(a.sales_count_fleet) OVER (), 0) * 100 
    , 2) AS fleet_pp_pct, 
    ROUND( 
        a.sales_count_retail 
        / NULLIF(SUM(a.sales_count_retail) OVER (), 0) * 100 
    , 2) AS retail_pp_pct 
    FROM agg a 
    ORDER BY a.firm_code 
    """

    conn = oracledb.connect(dsn)
    cur = conn.cursor()
    cur.execute(sql)
    rows = cur.fetchall()
    res = None
    for row in rows:
        if row[0] == ys_name:
            res = row[5]
        break
    return jsonify({"value": res})

