# NOT: Blueprint kullanıyorsanız @app.route yerine @pm_bp.route yazın.
@app.route('/pm/projects', methods=['POST'])
def create_project():
    data = request.get_json(silent=True) or {}
    name = (data.get('Name') or '').strip()
    key_raw = (data.get('ProjectKey') or '').strip()
    desc = (data.get('Description') or None)

    # ProjectKey normalize: boşlukları '-' yap, UPPER
    key = re.sub(r'\s+', '-', key_raw).upper()

    # Validasyon
    if not name or not key:
        return jsonify(error="Proje adı ve proje kodu zorunludur."), 400
    if not re.match(r'^[A-Z0-9\-_.]{2,20}$', key):
        return jsonify(error="Proje kodu 2-20 uzunlukta, A-Z/0-9/-/_/. karakterlerinden oluşmalıdır."), 400


    cn = pyodbc.connect(YA_2El_AracSatis)
    cn.autocommit = False
    cur = cn.cursor()

    cur.execute("""
        SELECT 1
        FROM [Yuce_Portal].[pm].[Projects]
        WHERE UPPER(ProjectKey) = ?
    """, (key,))
    if cur.fetchone():
        cn.rollback()
        return jsonify(error="Bu proje kodu zaten kayıtlı."), 409

    cur.execute("""
        SET NOCOUNT ON;
        INSERT INTO [Yuce_Portal].[pm].[Projects]
            (ProjectKey, [Name], [Description], IsActive, CreatedAt)
        OUTPUT INSERTED.ProjectId
        VALUES (?, ?, ?, 1, GETDATE());
    """, (key, name, desc))
    new_id = int(cur.fetchone()[0])

    # Kaydı geri oku (opsiyonel ama güzel)
    cur.execute("""
        SELECT ProjectId, ProjectKey, [Name], [Description], IsActive, CreatedAt, UpdatedAt
        FROM [Yuce_Portal].[pm].[Projects]
        WHERE ProjectId = ?
    """, (new_id,))
    row = cur.fetchone()
    cn.commit()

    to_str = lambda d: d.isoformat(sep=' ') if d else None
    return jsonify(
        ProjectId=row[0],
        ProjectKey=row[1],
        Name=row[2],
        Description=row[3],
        IsActive=bool(row[4]),
        CreatedAt=to_str(row[5]),
        UpdatedAt=to_str(row[6]),
    ), 201

