@app.route("/pm/lookups", methods=["GET"])
@login_required
def pm_lookups():
    def mssql_conn():
        return pyodbc.connect(YA_2El_AracSatis)

    username = session.get("username") or "system"
    conn = None; cursor = None
    mcur = None
    try:
        # MSSQL lookuplar (projeler, öncelikler, statüler)
        conn = mssql_conn(); cursor = conn.cursor()

        cursor.execute("SELECT ProjectId, ProjectKey, Name FROM [Yuce_Portal].[pm].Projects WHERE IsActive=1 ORDER BY Name")
        projects = [{"ProjectId": r[0], "ProjectKey": r[1], "Name": r[2]} for r in cursor.fetchall()]

        cursor.execute("SELECT PriorityId, Name, Rank FROM [Yuce_Portal].[pm].Priorities WHERE IsActive=1 ORDER BY Rank")
        priorities = [{"PriorityId": r[0], "Name": r[1], "Rank": r[2]} for r in cursor.fetchall()]

        cursor.execute("SELECT StatusId, Name, ColumnOrder, IsClosed FROM [Yuce_Portal].[pm].Statuses ORDER BY ColumnOrder")
        statuses = [{"StatusId": r[0], "Name": r[1], "ColumnOrder": r[2], "IsClosed": bool(r[3])} for r in cursor.fetchall()]

        # --- PEOPLE: MySQL users1'dan “isim soyisim (departman)” ---
        people = []
        try:
            mcur = mysql.connection.cursor()  # dict cursor olduğunu söylemiştin
            mcur.execute("""
                SELECT username, name, surname, departman
                FROM users1
                WHERE is_active = 1
                AND departman != 'Yönetim' AND departman != 'Yönetim Kurulu' AND departman != 'Yeni İş Modelleri'
                ORDER BY departman ASC, name ASC, surname ASC
            """)
            rows = mcur.fetchall()  # dict döner (username/name/surname/departman)
            for r in rows:
                uname = (r.get("username") or "").strip()
                fname = (r.get("name") or "").strip()
                sname = (r.get("surname") or "").strip()
                dept  = (r.get("departman") or "").strip()
                disp  = f"{fname} {sname}".strip()
                if dept:
                    disp = f"{disp} ({dept})"
                people.append({
                    "Username": uname,
                    "DisplayName": disp,
                    "Department": dept,   # FE'de data attribute olarak kullanacağız
                })
        except Exception as _e:
            # MySQL erişiminde sorun olursa sessizce MSSQL fallback (eski yöntem)
            try:
                cursor.execute("""
                    SELECT DISTINCT AssigneeUsername, AssigneeDisplayName
                      FROM [Yuce_Portal].[pm].Tickets
                     WHERE AssigneeUsername IS NOT NULL AND DeletedAt IS NULL
                    UNION
                    SELECT DISTINCT RequestedByUsername, RequestedByDisplayName
                      FROM [Yuce_Portal].[pm].Tickets
                     WHERE RequestedByUsername IS NOT NULL AND DeletedAt IS NULL
                """)
                people = [{"Username": r[0], "DisplayName": r[1], "Department": ""} for r in cursor.fetchall()]
            except Exception:
                people = []

        # success log (best-effort)
        try:
            cursor2 = conn.cursor()
            cursor2.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YP_Users_Log]
                    ([Username],[Method],[Path],[IsError],[Message],[CreatedAt])
                VALUES (?,?,?,?,?,GETDATE())
            """, (username, "GET", "/pm/lookups", 0, "ok"))
            conn.commit()
            cursor2.close()
        except Exception:
            pass

        return jsonify({"projects": projects, "priorities": priorities, "statuses": statuses, "people": people})

    except Exception as e:
        # error log (best-effort)
        try:
            msg = str(e)[:4000]
            conn2 = mssql_conn(); cur2 = conn2.cursor()
            cur2.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YP_Users_Log]
                    ([Username],[Method],[Path],[IsError],[Message],[CreatedAt])
                VALUES (?,?,?,?,?,GETDATE())
            """, (username, "GET", "/pm/lookups", 1, msg))
            conn2.commit(); cur2.close(); conn2.close()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            if mcur: mcur.close()
        except Exception:
            pass
        try:
            if cursor: cursor.close()
        finally:
            if conn: conn.close()

