@app.route("/pm/board", methods=["GET"])
@login_required
def pm_board():
    def db_conn():
        return pyodbc.connect(YA_2El_AracSatis)

    username = session.get("username") or "system"
    conn = None
    cursor = None
    try:
        conn = db_conn()
        cursor = conn.cursor()

        # v_TicketsBoard'da DeletedAt yok; filtreyi Tickets'tan yapıyoruz.
        # EstimatedEndDate'i YYYY-MM-DD string olarak ekliyoruz ki FE direkt kullansın.
        cursor.execute("""
            SELECT
              v.*,
              CONVERT(varchar(10), t.EstimatedEndDate, 23) AS EstimatedEndDate
            FROM [Yuce_Portal].[pm].v_TicketsBoard AS v
            INNER JOIN [Yuce_Portal].[pm].Tickets AS t
                    ON t.TicketId = v.TicketId
            WHERE t.DeletedAt IS NULL
            ORDER BY v.ColumnOrder, v.RankInStatus
        """)

        cols = [c[0] for c in cursor.description]
        data = [dict(zip(cols, row)) for row in cursor.fetchall()]

        # (best-effort) log
        try:
            cursor2 = conn.cursor()
            cursor2.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YP_Users_Log]
                    ([Username],[Method],[Path],[IsError],[Message],[CreatedAt])
                VALUES (?,?,?,?,?,GETDATE())
            """, (username, "GET", "/pm/board", 0, "ok"))
            conn.commit()
            cursor2.close()
        except Exception:
            pass

        return jsonify(data)

    except Exception as e:
        # (best-effort) error log
        try:
            msg = str(e)[:4000]
            conn2 = db_conn()
            cur2 = conn2.cursor()
            cur2.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YP_Users_Log]
                    ([Username],[Method],[Path],[IsError],[Message],[CreatedAt])
                VALUES (?,?,?,?,?,GETDATE())
            """, (username, "GET", "/pm/board", 1, msg))
            conn2.commit()
            cur2.close()
            conn2.close()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500

    finally:
        try:
            if cursor:
                cursor.close()
        finally:
            if conn:
                conn.close()

