@app.route("/pm/tickets", methods=["POST"])
@login_required
def pm_ticket_create():
    def db_conn():
        return pyodbc.connect(YA_2El_AracSatis)

    body = request.get_json(silent=True) or {}
    username = session.get("username") or "system"
    display  = (f"{session.get('name') or ''} {session.get('surname') or ''}").strip() or "system"

    required = ["ProjectId","Title","StatusId","PriorityId","EffortHours"]
    missing = [k for k in required if body.get(k) in (None, "")]
    if missing:
        return jsonify({"ok": False, "error": f"Eksik alan: {', '.join(missing)}"}), 400

    # opsiyoneller
    est_end  = body.get("EstimatedEndDate") or None         # 'YYYY-MM-DD' veya None
    asg_dept = body.get("AssigneeDepartment") or None       # departman adı (opsiyonel)

    conn = None; cursor = None
    try:
        conn = db_conn(); cursor = conn.cursor()
        sql = """
        DECLARE @tid BIGINT;
        EXEC [Yuce_Portal].[pm].sp_Ticket_Create
          @ProjectId=?, @Title=?, @Description=?, @StatusId=?,
          @AssigneeUsername=?, @AssigneeDisplayName=?, @AssigneeDepartment=?,
          @RequestedByUsername=?, @RequestedByDisplayName=?,
          @OwnerUsername=?, @OwnerDisplayName=?,
          @PriorityId=?, @EffortHours=?, @EstimatedEndDate=?,
          @CreatedByUsername=?, @CreatedByDisplayName=?,
          @TicketId=@tid OUTPUT;
        SELECT @tid;
        """
        cursor.execute(sql, (
            int(body.get("ProjectId")),
            body.get("Title"),
            body.get("Description"),
            int(body.get("StatusId")),
            body.get("AssigneeUsername"),
            body.get("AssigneeDisplayName"),
            asg_dept,                                        # <-- yeni
            body.get("RequestedByUsername"),
            body.get("RequestedByDisplayName"),
            username, display,                               # owner = oluşturan
            int(body.get("PriorityId")),
            int(body.get("EffortHours") or 0),
            est_end,                                         # <-- yeni
            username, display
        ))
        new_id = cursor.fetchone()[0]
        conn.commit()
        return jsonify({"ok": True, "TicketId": int(new_id)}), 201
    except Exception as e:
        if conn:
            try: conn.rollback()
            except Exception: pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            if cursor: cursor.close()
        finally:
            if conn: conn.close()

# --- TICKET DETAY + YORUMLAR + DUE HISTORY ---
@app.route("/pm/tickets/<int:ticket_id>", methods=["GET"])
@login_required
def pm_ticket_get(ticket_id):
    def db_conn():
        return pyodbc.connect(YA_2El_AracSatis)

    conn = None; cursor = None
    try:
        conn = db_conn(); cursor = conn.cursor()

        # Detay: EstimatedEndDate'i YYYY-MM-DD string olarak getir.
        cursor.execute("""
            SELECT
              v.*,
              CONVERT(varchar(10), t.EstimatedEndDate, 23) AS EstimatedEndDate
            FROM [Yuce_Portal].[pm].v_TicketsBoard AS v
            LEFT JOIN [Yuce_Portal].[pm].Tickets AS t
                   ON t.TicketId = v.TicketId
            WHERE v.TicketId = ?
        """, (ticket_id,))
        row = cursor.fetchone()
        if not row:
            return jsonify({"ok": False, "error": "Bulunamadı"}), 404
        cols = [c[0] for c in cursor.description]
        ticket = dict(zip(cols, row))

        # Yorumlar
        cursor.execute("""
            SELECT CommentId, TicketId, Body, AuthorUsername, AuthorDisplayName, CreatedAt
            FROM [Yuce_Portal].[pm].TicketComments
            WHERE TicketId=? AND DeletedAt IS NULL
            ORDER BY CreatedAt
        """, (ticket_id,))
        ccols = [c[0] for c in cursor.description]
        ticket["comments"] = [dict(zip(ccols, r)) for r in cursor.fetchall()]

        # Tahmini bitiş geçmişi: FE kolay parse etsin diye CONVERT ile string formatlar
        cursor.execute("""
            SELECT
              DueHistoryId,
              CONVERT(varchar(10), OldEstimatedEndDate, 23) AS OldEstimatedEndDate,  -- YYYY-MM-DD
              CONVERT(varchar(10), NewEstimatedEndDate, 23) AS NewEstimatedEndDate,  -- YYYY-MM-DD
              ChangedByUsername,
              ChangedByDisplayName,
              CONVERT(varchar(19), ChangedAt, 126)          AS ChangedAt             -- YYYY-MM-DDTHH:MM:SS
            FROM [Yuce_Portal].[pm].TicketDueDateHistory
            WHERE TicketId = ?
            ORDER BY ChangedAt DESC
        """, (ticket_id,))
        hcols = [c[0] for c in cursor.description]
        ticket["dueHistory"] = [dict(zip(hcols, r)) for r in cursor.fetchall()]

        print(ticket["dueHistory"])

        return jsonify(ticket)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            if cursor: cursor.close()
        finally:
            if conn: conn.close()

# --- TEK ALAN GÜNCELLE (owner only) ---
@app.route("/pm/tickets/<int:ticket_id>/field", methods=["POST"])
@login_required
def pm_ticket_update_field(ticket_id):
    def db_conn():
        return pyodbc.connect(YA_2El_AracSatis)

    payload = request.get_json(silent=True) or {}
    field   = payload.get("FieldName")
    value   = payload.get("NewValue")
    if not field:
        return jsonify({"ok": False, "error": "FieldName gerekli"}), 400

    username = session.get("username") or "system"
    display  = (f"{session.get('name') or ''} {session.get('surname') or ''}").strip() or "system"

    allowed = {
        "Title","Description","EffortHours","PriorityId","ProjectId",
        "AssigneeUsername","AssigneeDisplayName","AssigneeDepartment",  # <-- yeni
        "RequestedByUsername","RequestedByDisplayName",
        "EstimatedEndDate"                                             # <-- yeni
    }
    if field not in allowed:
        return jsonify({"ok": False, "error": "İzin verilmeyen alan"}), 400

    conn = None; cursor = None
    try:
        conn = db_conn(); cursor = conn.cursor()

        # owner kontrolü
        cursor.execute(
            "SELECT OwnerUsername FROM [Yuce_Portal].[pm].Tickets WHERE TicketId=? AND DeletedAt IS NULL",
            (ticket_id,)
        )
        r = cursor.fetchone()
        if not r:
            return jsonify({"ok": False, "error": "Bulunamadı"}), 404
        if (r[0] or "").strip().lower() != (username or "").strip().lower():
            return jsonify({"ok": False, "error": "Yetki yok (owner)"}), 403

        cursor.execute(
            "EXEC [Yuce_Portal].[pm].sp_Ticket_UpdateField @TicketId=?, @FieldName=?, @NewValue=?, @Username=?, @DisplayName=?",
            (ticket_id, field, "" if value is None else str(value), username, display)
        )
        conn.commit()
        return jsonify({"ok": True})
    except Exception as e:
        if conn:
            try: conn.rollback()
            except Exception: pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            if cursor: cursor.close()
        finally:
            if conn: conn.close()

# --- TAŞI / SIRALA ---
@app.route("/pm/tickets/<int:ticket_id>/move", methods=["POST"])
@login_required
def pm_ticket_move(ticket_id):
    def db_conn():
        return pyodbc.connect(YA_2El_AracSatis)

    payload = request.get_json(silent=True) or {}
    target_status_id = payload.get("TargetStatusId")
    place = (payload.get("Place") or "top").lower()
    ref_id = payload.get("RefTicketId")
    try:
        ref_id = int(ref_id) if ref_id is not None else None
    except Exception:
        ref_id = None

    if not target_status_id:
        return jsonify({"ok": False, "error": "TargetStatusId gerekli"}), 400

    username = session.get("username") or "system"
    display  = (f"{session.get('name') or ''} {session.get('surname') or ''}").strip() or "system"

    conn = None; cursor = None
    try:
        conn = db_conn(); cursor = conn.cursor()
        cursor.execute(
            "EXEC [Yuce_Portal].[pm].sp_Ticket_Move @TicketId=?, @TargetStatusId=?, @Place=?, @RefTicketId=?, @Username=?, @DisplayName=?",
            (ticket_id, int(target_status_id), place, ref_id, username, display)
        )
        conn.commit()

        try:
            cursor.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YP_Users_Log]
                    ([Username],[Method],[Path],[IsError],[Message],[CreatedAt])
                VALUES (?,?,?,?,?,GETDATE())
            """, (username, "POST", f"/pm/tickets/{ticket_id}/move", 0, f"{place}->{target_status_id}"))
            conn.commit()
        except Exception:
            pass

        return jsonify({"ok": True})
    except Exception as e:
        if conn:
            try: conn.rollback()
            except Exception: pass
        try:
            msg = str(e)[:4000]
            conn2 = db_conn(); cur2 = conn2.cursor()
            cur2.execute("""
                INSERT INTO [Yuce_Portal].[dbo].[YP_Users_Log]
                    ([Username],[Method],[Path],[IsError],[Message],[CreatedAt])
                VALUES (?,?,?,?,?,GETDATE())
            """, (username, "POST", f"/pm/tickets/{ticket_id}/move", 1, msg))
            conn2.commit(); cur2.close(); conn2.close()
        except Exception:
            pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            if cursor: cursor.close()
        finally:
            if conn: conn.close()

