# --- SİL (soft delete, owner only, idempotent) ---
@app.route("/pm/tickets/<int:ticket_id>/delete", methods=["POST"])
@login_required
def pm_ticket_delete(ticket_id):
    def db_conn():
        return pyodbc.connect(YA_2El_AracSatis)

    username = session.get("username") or "system"
    display  = (f"{session.get('name') or ''} {session.get('surname') or ''}").strip() or "system"

    conn = None; cursor = None
    try:
        conn = db_conn(); cursor = conn.cursor()

        cursor.execute("""
            SELECT OwnerUsername, DeletedAt
            FROM [Yuce_Portal].[pm].Tickets
            WHERE TicketId = ?
        """, (int(ticket_id),))  # tuple ÖNEMLİ
        row = cursor.fetchone()

        # kayıt yoksa bile FE sade olsun diye success dönüyoruz
        if not row:
            return jsonify({"ok": True, "message": "already deleted"}), 200

        owner_username, deleted_at = row

        # zaten silinmişse success dön
        if deleted_at is not None:
            return jsonify({"ok": True, "message": "already deleted"}), 200

        # owner kontrolü
        if (owner_username or "").strip().lower() != (username or "").strip().lower():
            return jsonify({"ok": False, "error": "Yetki yok (owner)"}), 403

        # soft delete
        cursor.execute(
            "EXEC [Yuce_Portal].[pm].sp_Ticket_SoftDelete @TicketId=?, @Username=?, @DisplayName=?",
            (int(ticket_id), username, display)
        )
        conn.commit()
        return jsonify({"ok": True}), 200

    except Exception as e:
        if conn:
            try: conn.rollback()
            except Exception: pass
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        try:
            if cursor: cursor.close()
        finally:
            if conn: conn.close()

