# === Rapor API: /pm/report?from=YYYY-MM-DD&to=YYYY-MM-DD&projects=1,2&assignees=u1,u2 ===
@app.route('/pm/report', methods=['GET'])
def pm_report():

    s_from = (request.args.get('from') or '').strip()  # 'YYYY-MM-DD'
    s_to   = (request.args.get('to') or '').strip()
    projects = [p for p in (request.args.get('projects') or '').split(',') if p.strip()]
    assignees= [u for u in (request.args.get('assignees') or '').split(',') if u.strip()]

    def status_key(name: str) -> str:
        n = (name or '').lower()
        if 'cancel' in n or 'iptal' in n: return 'cancel'
        if 'done' in n or 'tamam' in n or 'bitti' in n: return 'done'
        if 'test' in n: return 'test'
        if 'progress' in n or 'devam' in n: return 'inprogress'
        if 'todo' in n or 'yap' in n or 'backlog' in n: return 'todo'
        return 'other'

    try:
        cn = pyodbc.connect(YA_2El_AracSatis)
        cur = cn.cursor()

        where = ["1=1"]
        params = []

        if s_from:
            where.append("t.CreatedAt >= ?")
            params.append(s_from + " 00:00:00")

        if s_to:
            # bitiş dahil olacak şekilde ertesi gün < koşulu
            where.append("t.CreatedAt < DATEADD(day, 1, ?)")
            params.append(s_to + " 00:00:00")

        if projects:
            ph = ",".join("?"*len(projects))
            where.append(f"t.ProjectId IN ({ph})")
            params.extend([int(x) for x in projects])

        if assignees:
            ph = ",".join("?"*len(assignees))
            where.append(f"t.AssigneeUsername IN ({ph})")
            params.extend(assignees)

        sql = f"""
            SELECT
                t.TicketId, t.Title, t.EffortHours, t.CreatedAt,
                t.AssigneeUsername, t.AssigneeDisplayName,
                p.ProjectId, p.ProjectKey, p.Name AS ProjectName,
                s.StatusId, s.Name AS StatusName
            FROM [Yuce_Portal].[pm].[Tickets] t
            LEFT JOIN [Yuce_Portal].[pm].[Projects] p ON p.ProjectId = t.ProjectId
            LEFT JOIN [Yuce_Portal].[pm].[Statuses] s ON s.StatusId = t.StatusId
            WHERE {' AND '.join(where)}
            ORDER BY t.CreatedAt DESC
        """
        cur.execute(sql, params)
        rows = cur.fetchall()

        tickets = []
        for r in rows:
            skey = status_key(r.StatusName)
            tickets.append({
                "TicketId": r.TicketId,
                "Title": r.Title,
                "EffortHours": int(r.EffortHours or 0),
                "CreatedAt": r.CreatedAt.isoformat(sep=' ') if r.CreatedAt else None,
                "AssigneeUsername": r.AssigneeUsername,
                "AssigneeDisplayName": r.AssigneeDisplayName,
                "ProjectId": r.ProjectId,
                "ProjectKey": r.ProjectKey,
                "ProjectName": r.ProjectName,
                "StatusId": r.StatusId,
                "StatusName": r.StatusName,
                "StatusKey": skey,
            })

        total = len(tickets)
        done = sum(1 for t in tickets if t["StatusKey"] == "done")
        cancel = sum(1 for t in tickets if t["StatusKey"] == "cancel")
        open_cnt = sum(1 for t in tickets if t["StatusKey"] in ("todo","inprogress","test","other"))

        totals = {
            "total": total,
            "done": done,
            "cancel": cancel,
            "open": open_cnt,
        }

        proj_map = {}
        for t in tickets:
            k = t["ProjectId"]
            if k is None:  # güvenlik
                continue
            d = proj_map.setdefault(k, {
                "ProjectId": k, "ProjectKey": t["ProjectKey"], "ProjectName": t["ProjectName"],
                "total": 0, "done": 0, "cancel": 0
            })
            d["total"] += 1
            if t["StatusKey"] == "done": d["done"] += 1
            if t["StatusKey"] == "cancel": d["cancel"] += 1

        projectsSummary = []
        for d in proj_map.values():
            denom = max(1, d["total"] - d["cancel"])  # iptaller hariç ilerleme
            d["percentDone"] = 100.0 * d["done"] / denom
            projectsSummary.append(d)
        # azalan tamamlanma yüzdesine göre
        projectsSummary.sort(key=lambda x: (x["percentDone"], x["done"]), reverse=True)

        user_map = {}
        for t in tickets:
            u = t["AssigneeUsername"] or "(yok)"
            d = user_map.setdefault(u, {
                "Username": u,
                "DisplayName": t["AssigneeDisplayName"] or t["AssigneeUsername"] or "(yok)",
                "total": 0, "done": 0, "cancel": 0, "open": 0, "effortDone": 0
            })
            d["total"] += 1
            if t["StatusKey"] == "done":
                d["done"] += 1
                d["effortDone"] += int(t["EffortHours"] or 0)
            elif t["StatusKey"] == "cancel":
                d["cancel"] += 1
            else:
                d["open"] += 1

        assigneesSummary = []
        for d in user_map.values():
            denom = max(1, d["total"] - d["cancel"])
            d["percentDone"] = 100.0 * d["done"] / denom
            assigneesSummary.append(d)
        assigneesSummary.sort(key=lambda x: (x["done"], -x["cancel"]), reverse=True)

        return jsonify(
            tickets=tickets,
            projectsSummary=projectsSummary,
            assigneesSummary=assigneesSummary,
            totals=totals
        )
    except Exception as e:
        return jsonify(error=str(e)), 500
    finally:
        try:
            if cn: cn.close()
        except Exception:
            pass

@app.route("/haftanin_enleri", methods=["GET"])
def haftanin_enleri():
    query = "SELECT * FROM users1 WHERE is_active = 1"
    cursor = mysql.connection.cursor()
    cursor.execute(query)
    results = cursor.fetchall()

    today = datetime.date.today()
    window_end = today + timedelta(days=6)  # bugün dahil 7 gün

    anniversaries = []
    birthdays = []

    def safe_date(year: int, month: int, day: int) -> datetime.date:
        """
        Geçersiz günlerde (örn. 29 Şubat ve yıl artık değilse) 28 Şubat'a düşürür.
        İstersen 1 Mart'a taşıyacak şekilde değiştirebilirsin.
        """
        try:
            return datetime.date(year, month, day)
        except ValueError:
            if month == 2 and day == 29:
                return datetime.date(year, 2, 28)
            raise

    for result in results:
        name = result.get("name")
        surname = result.get("surname")

        # --- Work Anniversary (Kıdem) ---
        kidem_dt = result.get("Kidem_Tarihi")
        if kidem_dt:
            start_date = kidem_dt.date() if hasattr(kidem_dt, "date") else kidem_dt  # datetime/date toleransı
            anniv_this_year = safe_date(today.year, start_date.month, start_date.day)

            # Eğer bu seneki yıldönümü geçtiyse, yaklaşan yıldönümü gelecek yıl
            anniv_date = anniv_this_year if anniv_this_year >= today else safe_date(today.year + 1, start_date.month, start_date.day)

            if today <= anniv_date <= window_end:
                years = anniv_date.year - start_date.year  # kritik düzeltme
                if years >= 1:
                    anniversaries.append({
                        "name": name,
                        "surname": surname,
                        "date": anniv_date.strftime("%m-%d"),
                        "years": years,
                    })

        # --- Birthdays ---
        dogum_gun = result.get("dogum_gun")
        dogum_ay = result.get("dogum_ay")
        if dogum_gun and dogum_ay:
            birth_day = int(dogum_gun)
            birth_month = int(dogum_ay)

            bday_this_year = safe_date(today.year, birth_month, birth_day)
            bday_date = bday_this_year if bday_this_year >= today else safe_date(today.year + 1, birth_month, birth_day)

            if today <= bday_date <= window_end:
                birthdays.append({
                    "name": name,
                    "surname": surname,
                    "day": str(birth_day),
                    "month": month_number_to_name(birth_month),
                    "date": bday_date.strftime("%m-%d"),
                    "sort_date": bday_date
                })

    # Sıralamalar
    anniversaries.sort(key=lambda x: x["name"] or "")
    anniversaries.sort(key=lambda x: x["years"], reverse=True)

    birthdays.sort(key=lambda x: x["name"] or "")
    birthdays.sort(key=lambda x: x["sort_date"])

    return render_template("haftanin_enleri.html", anniversaries=anniversaries, birthdays=birthdays)

