@app.route("/chatbot", methods=["POST"])
def chatbot():
    conn = None
    cur = None
    try:
        if BrainAIYugii is None:
            return jsonify({"reply": "Yugii AI özelliği şu anda kullanılamıyor."})
        data = request.get_json(silent=True) or {}
        user_message = (data.get("message") or "").strip()
        username = session.get("username", "unknown")
 
        if not user_message:
            return jsonify({"reply": "Boş bir mesaj aldım, tekrar dener misin? 🙂"})
 
        # 1️⃣ Kullanıcı mesajını logla
        try:
            if _has_mssql_conn_str(YA_2El_AracSatis):
                conn = pyodbc.connect(YA_2El_AracSatis)
                cur = conn.cursor()
                cur.execute("""
                    INSERT INTO [Yuce_Portal].[dbo].[yugii_chat_log]
                        (username, sender, message_text, timestamp)
                    VALUES (?, 'user', ?, GETDATE())
                """, (username, user_message))
                conn.commit()
        except Exception as e:
            print("DB user log hata:", e)
        
        brain = BrainAIYugii.get_instance()
        reply = brain.process_message(user_message)
        
        bot_msg_id = None
        try:
            if cur is not None and conn is not None:
                cur.execute("""
                    INSERT INTO [Yuce_Portal].[dbo].[yugii_chat_log]
                        (username, sender, message_text, timestamp)
                    VALUES (?, 'bot', ?, GETDATE())
                """, (username, reply))
                conn.commit()

                # Son inserted ID
                cur.execute("SELECT @@IDENTITY AS id")
                row = cur.fetchone()
                bot_msg_id = int(row.id) if row else None
        except Exception as e:
            print("DB bot log hata:", e)
 
        return jsonify({
            "reply": reply,
            "id": bot_msg_id
        })
 
    except Exception as e:
        print("Chatbot hata:", e)
        return jsonify({"reply": "Bir hata oluştu, lütfen tekrar dener misin? 🙏"})
    finally:
        try:
            if cur is not None:
                cur.close()
        except Exception:
            pass
        try:
            if conn is not None:
                conn.close()
        except Exception:
            pass

