@app.route("/api/yugii/chatlog", methods=["GET", "POST"])
@login_required
def api_yugii_chatlog():
    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()
 
    if request.method == "POST":
        data = request.get_json()
        log_id = data.get("id")
        is_fixed = data.get("is_fixed")
 
        if log_id is None:
            return jsonify({"success": False}), 400
 
        conn = pyodbc.connect(YA_2El_AracSatis)
        cur = conn.cursor()
        cur.execute("""
            UPDATE Yuce_Portal.dbo.yugii_chat_log
            SET is_fixed = ?
            WHERE id = ?
        """, (int(is_fixed), int(log_id)))
 
        conn.commit()
        conn.close()
 
        return jsonify({"success": True})
    filter_type = request.args.get("filter")
 
    #  DISLIKE MODU
    if filter_type == "dislike":
        cur.execute("""
            SELECT 
                id, username, sender, message_text, timestamp, customer_answer, comment, is_fixed
            FROM Yuce_Portal.dbo.yugii_chat_log
            WHERE customer_answer = 2
            AND sender = 'bot'
            ORDER BY timestamp DESC
        """)
        bot_rows = cur.fetchall()
 
        data = []
        for bot in bot_rows:
            cur.execute("""
                SELECT TOP 1
                    id, username, sender, message_text, timestamp, customer_answer, comment
                FROM Yuce_Portal.dbo.yugii_chat_log
                WHERE id < ? AND sender = 'user'
                ORDER BY id DESC
            """, (bot.id,))
            user_row = cur.fetchone()
 
            data.append({
                "id": bot.id,
                "username": bot.username,
                "question": user_row.message_text if user_row else "",
                "answer": bot.message_text,
                "customer_answer": 2,
                "comment": bot.comment,
                "timestamp": str(bot.timestamp),
                "is_fixed": bot.is_fixed 
            })
 
        conn.close()
        return jsonify(data)
 
    #  LIKE MODU
    if filter_type == "like":
        cur.execute("""
            SELECT 
                id, username, sender, message_text, timestamp, customer_answer, comment,is_fixed
            FROM Yuce_Portal.dbo.yugii_chat_log
            WHERE customer_answer = 1
            AND sender = 'bot'
            ORDER BY timestamp DESC
        """)
        bot_rows = cur.fetchall()
 
        data = []
        for bot in bot_rows:
            cur.execute("""
                SELECT TOP 1
                    id, username, sender, message_text, timestamp, customer_answer, comment
                FROM Yuce_Portal.dbo.yugii_chat_log
                WHERE id < ? AND sender = 'user'
                ORDER BY id DESC
            """, (bot.id,))
            user_row = cur.fetchone()
 
            data.append({
                "id": bot.id,
                "username": bot.username,
                "question": user_row.message_text if user_row else "",
                "answer": bot.message_text,
                "customer_answer": 1,
                "comment": bot.comment,
                "timestamp": str(bot.timestamp),
                "is_fixed": bot.is_fixed
            })
 
        conn.close()
        return jsonify(data)
 
    #  NORMAL MOD
    cur.execute("""
    SELECT 
        id, username, sender, message_text, timestamp, customer_answer, comment,is_fixed
    FROM Yuce_Portal.dbo.yugii_chat_log
    ORDER BY id ASC
    """)
    rows = cur.fetchall()
 
    data = []
    last_user = None
 
    # NORMAL MOD
    for r in rows:
        if r.sender.lower() == "user":
            last_user = {
                "id": None,
                "username": r.username,
                "question": r.message_text,
                "answer": "",
                "customer_answer": 0,
                "comment": "",
                "timestamp": "",
                "is_fixed": 0,
            }
        else:
            if last_user:
                last_user["id"] = r.id
                last_user["answer"] = r.message_text
                last_user["timestamp"] = str(r.timestamp)
 
                # 🔑 FEEDBACK SADECE BOT'TAN
                last_user["customer_answer"] = r.customer_answer
                last_user["comment"] = r.comment or ""
                last_user["is_fixed"] = r.is_fixed if r.is_fixed is not None else 0
 
                data.append(last_user)
                last_user = None
    data.reverse()
    conn.close()
    return jsonify(data)

@app.route("/api/feedback", methods=["POST"])
@login_required
def api_yugii_feedback():
    data = request.get_json() or {}

    log_id = data.get("id")
    liked = data.get("liked")
    comment = (data.get("comment") or "").strip()

    if not log_id:
        return jsonify({"success": False, "error": "id missing"}), 400

    # liked -> customer_answer
    if liked is True:
        customer_answer = 1
    elif liked is False:
        customer_answer = 2
    else:
        customer_answer = 0  # null -> reset

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()

    cur.execute("""
        UPDATE Yuce_Portal.dbo.yugii_chat_log
        SET customer_answer = ?, comment = ?
        WHERE id = ? AND sender = 'bot'
    """, (customer_answer, comment, int(log_id)))

    conn.commit()
    conn.close()

    return jsonify({"success": True})

