def Add_Barcode_to_Depot_Entry(barcode):
    cursor, conn = Connectdb_N_Return_cursorNconn(Garanti_imha_DB)
    try:
        is_Active_status = 1
        insert_query_ = f"""
            INSERT INTO [Garanti_Imha].[dbo].[Depot_Entry] 
                ([Bayi_id], [Barcode_id], [Barcode_Scanned_datetime], [User_email], [is_Active])
            SELECT {session['garantiimha_bayiisi_id']}, '{barcode}', GETDATE(), '{session['email']}', {is_Active_status}
            WHERE NOT EXISTS (
                SELECT 1 
                FROM [Garanti_Imha].[dbo].[Depot_Entry]
                WHERE [Barcode_id] = '{barcode}'
            );
        """
        cursor.execute(insert_query_)
        affected_rows = cursor.rowcount
        
        # if it equals to 0, means it already exists in the table
        if affected_rows == 0:
            already_exists = True
        if affected_rows == 1:
            already_exists = False

        cursor.commit()
        conn.commit()
        conn.close()
        return jsonify({'status': 'success', 'already_exists': already_exists})
    except:
        pass

