from math import ceil
from urllib.parse import urlencode

@app.route("/YuceAutoUser/DepoGirisi_BarkodListe")
@login_required
def YuceAuto_Depot_Entry_BarcodeList():
    cursor, conn = Connectdb_N_Return_cursorNconn(Garanti_imha_DB)

    page = max(int(request.args.get('page', 1) or 1), 1)
    per_page = int(request.args.get('per_page', 100) or 100)
    if per_page <= 0: per_page = 100

    selected_bayi = request.args.getlist('bayi')
    barcode_q = (request.args.get('barcode') or '').strip()

    base_sql = """
    FROM [Garanti_Imha].[dbo].[Depot_Entry] AS d
    JOIN [Garanti_Imha].[dbo].[Dealers]     AS dl ON d.Bayi_id = dl.ID
    """
    where_clauses, params = [], []

    if selected_bayi:
        placeholders = ",".join(["?"] * len(selected_bayi))
        where_clauses.append(f"dl.dealerName IN ({placeholders})")
        params.extend(selected_bayi)

    if barcode_q:
        where_clauses.append("CAST(d.Barcode_id AS NVARCHAR(255)) LIKE ?")
        params.append(f"%{barcode_q}%")

    where_sql = ("WHERE " + " AND ".join(where_clauses)) if where_clauses else ""

    count_sql = "SELECT COUNT(*) " + base_sql + " " + where_sql
    total_count_row = cursor.execute(count_sql, params).fetchone()
    total_count = total_count_row[0] if total_count_row else 0
    total_pages = max(ceil(total_count / per_page), 1)

    if page > total_pages:
        page = total_pages

    data_sql = f"""
    SELECT d.*, dl.dealerName
    {base_sql}
    {where_sql}
    ORDER BY d.Barcode_Scanned_datetime DESC
    OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
    """
    offset = (page - 1) * per_page
    data_params = params + [offset, per_page]
    rows = cursor.execute(data_sql, data_params).fetchall()

    # dealer list for filters
    dealers_sql = """
    SELECT DISTINCT dl.dealerName
    FROM [Garanti_Imha].[dbo].[Depot_Entry] AS d
    JOIN [Garanti_Imha].[dbo].[Dealers]     AS dl ON d.Bayi_id = dl.ID
    ORDER BY dl.dealerName
    """
    all_bayi = [r[0] for r in cursor.execute(dealers_sql).fetchall()]
    cursor.close()

    for r in rows:
        try:
            if r[3]:
                r[3] = r[3].strftime("%d.%m.%Y")
        except Exception:
            pass

    persist_params = []
    for b in selected_bayi:
        persist_params.append(('bayi', b))
    if barcode_q:
        persist_params.append(('barcode', barcode_q))
    persist_params.append(('per_page', per_page))
    base_qs = urlencode(persist_params)

    return render_template("garanti_imha_YuceAutoUser_Depo_ParcaListesi.html", results=rows, bayii_isimleri=all_bayi, page=page, total_pages=total_pages, per_page=per_page,
        total_count=total_count, selected_bayi=selected_bayi, barcode_q=barcode_q, base_qs=base_qs)

