@app.route("/CRS", methods=['GET'])
@login_required
def crs():
    import re
    import matplotlib.pyplot as plt
    from matplotlib.figure import Figure
    try:
        from html import escape as h
    except Exception:
        def h(x):
            return "" if x is None else str(x)

    conn = pyodbc.connect(SkodabotDB)
    cursor = conn.cursor()

    # --- Model listesi ---
    cursor.execute("""
        SELECT DISTINCT ModelCode
        FROM [SkodaBot].[dbo].[Models]
        WHERE IsActive = 1
        ORDER BY ModelCode
    """)
    models = [r.ModelCode for r in cursor.fetchall()]

    model_filter = request.args.get('model')
    category_filter = request.args.get('category')
    start_date = request.args.get('start')  # yyyy-mm-dd
    end_date = request.args.get('end')

    # Görüşmeler (başlık popover’ları) için tabloda kullanılacak ek filtreler
    conv_category = request.args.get('conv_category')
    score_min = request.args.get('score_min')
    score_max = request.args.get('score_max')
    conv_start = request.args.get('start_date')
    conv_end = request.args.get('end_date')

    # --- conversation_metrics'i tekilleştirip join eden ortak parça ---
    METRICS_JOIN = """
    LEFT JOIN (
        SELECT
            conversation_id,
            AVG(CAST(success_score AS FLOAT)) AS success_score,
            MAX(category) AS category
        FROM [SkodaBot].[dbo].[conversation_metrics]
        GROUP BY conversation_id
    ) AS m
        ON m.conversation_id = c.id
    """

    def apply_common_filters(sql, params):
        # WHERE ifadesi varsa kontrol et
        if "WHERE" not in sql.upper():
            sql += " WHERE 1=1"
        else:
            sql = sql.strip().rstrip(";")

        # Model filtresi
        if model_filter and model_filter != "Tümü":
            sql += " AND EXISTS (SELECT 1 FROM [SkodaBot].[dbo].[Models] AS mo "
            sql += "WHERE mo.IsActive = 1 AND mo.ModelCode = ? "
            sql += "AND (c.question LIKE '%' + mo.ModelName + '%' OR c.answer LIKE '%' + mo.ModelName + '%'))"
            params.append(model_filter)

        # Kategori filtresi
        if category_filter and category_filter != "Tümü":
            sql += " AND m.category = ?"
            params.append(category_filter)

        # Tarih aralığı
        if start_date:
            sql += " AND c.timestamp >= ?"
            params.append(start_date)
        if end_date:
            sql += " AND c.timestamp <= ?"
            params.append(end_date)

        return sql

    # === KPI ===
    query_kpi = """
    SELECT
        (SELECT COUNT(DISTINCT conversation_id)
         FROM [SkodaBot].[dbo].[conversation_metrics]) AS total_questions,
        SUM(CASE WHEN m.customer_answer = 1 THEN 1 ELSE 0 END) AS like_count,
        SUM(CASE WHEN m.customer_answer = 2 THEN 1 ELSE 0 END) AS dislike_count,
        CAST(
            SUM(CASE WHEN m.customer_answer = 1 THEN 1 ELSE 0 END) * 100.0 /
            NULLIF(SUM(CASE WHEN m.customer_answer IN (1,2) THEN 1 ELSE 0 END), 0)
            AS DECIMAL(5,2)
        ) AS like_ratio,
        CAST(
            SUM(CASE WHEN m.customer_answer = 2 THEN 1 ELSE 0 END) * 100.0 /
            NULLIF(SUM(CASE WHEN m.customer_answer IN (1,2) THEN 1 ELSE 0 END), 0)
            AS DECIMAL(5,2)
        ) AS dislike_ratio,
        AVG(CAST(m.success_score AS FLOAT)) AS avg_success
    FROM [SkodaBot].[dbo].[conversation_metrics] AS m
    INNER JOIN [SkodaBot].[dbo].[conversations] AS c
        ON c.id = m.conversation_id
    WHERE m.customer_answer IN (1,2)
    """

    params_kpi = []
    query_kpi = apply_common_filters(query_kpi, params_kpi)
    cursor.execute(query_kpi, params_kpi)
    kpi_row = cursor.fetchone()

    total_questions = kpi_row.total_questions or 0
    like_count = kpi_row.like_count or 0
    dislike_count = kpi_row.dislike_count or 0
    total_reactions = like_count + dislike_count
    like_ratio = round((like_count / total_reactions) * 100, 1) if total_reactions > 0 else 0
    dislike_ratio = round(100 - like_ratio, 1) if total_reactions > 0 else 0
    avg_success_score = round(kpi_row.avg_success or 0, 2)

    # === GÖRÜŞMELER ===
    query_conv = f"""
    SELECT TOP 1000
        m.conversation_id AS id,
        c.question,
        c.answer,
        c.customer_answer,
        c.timestamp,
        c.username,
        m.success_score,
        m.category,
        ss.suggestion_text
    FROM [SkodaBot].[dbo].[conversation_metrics] AS m
    INNER JOIN [SkodaBot].[dbo].[conversations] AS c
        ON m.conversation_id = c.id
    LEFT JOIN [SkodaBot].[dbo].[solution_suggestions] AS ss
        ON ss.conversation_id = c.id
    WHERE 1=1
    """

    params_conv = []
    query_conv = apply_common_filters(query_conv, params_conv)

    if conv_category and conv_category != "Tümü":
        query_conv += " AND m.category = ?"
        params_conv.append(conv_category)

    if score_min:
        query_conv += " AND m.success_score >= ?"
        params_conv.append(float(score_min))

    if score_max:
        query_conv += " AND m.success_score <= ?"
        params_conv.append(float(score_max))

    if conv_start:
        query_conv += " AND c.timestamp >= ?"
        params_conv.append(conv_start)

    if conv_end:
        query_conv += " AND c.timestamp <= ?"
        params_conv.append(conv_end)

    conv_user = request.args.get('conv_user')
    if conv_user and conv_user != "Tümü":
        query_conv += " AND c.username = ?"
        params_conv.append(conv_user)

    query_conv += " ORDER BY m.conversation_id DESC"
    cursor.execute(query_conv, params_conv)
    rows = cursor.fetchall()

    # === TABLO VE GRAFİK VERİLERİ ===
    table_conv = ""
    timestamps, scores, categories = [], [], []

    for row in rows:
        question = row.question or "-"
        answer = row.answer or "-"
        answer = re.sub(r"<[^>]+>", "", answer)
        username = row.username or "-"
        category = row.category or "-"
        score = round((row.success_score or 0), 2)
        timestamp = row.timestamp.strftime("%Y-%m-%d %H:%M") if row.timestamp else "-"
        suggest = getattr(row, "suggestion_text", None) or "-"

        if row.customer_answer == 1:
            like_html, dislike_html = "👍", "-"
        elif row.customer_answer == 2:
            like_html, dislike_html = "-", "👎"
        else:
            like_html, dislike_html = "-", "-"

        table_conv += f"""
        <tr>
            <td class="c-question">{h(question)}</td>
            <td class="c-answer" title="{h(answer)}">{h(answer)}</td>
            <td class="c-user"><span class="tag">{h(username)}</span></td>
            <td class="c-suggest" data-tip="{h(suggest)}">{h(suggest)}</td>
            <td class="c-like">{like_html}</td>
            <td class="c-dislike">{dislike_html}</td>
            <td class="c-category"><span class="tag">{h(category)}</span></td>
            <td class="c-score"><strong>{score}</strong></td>
            <td class="c-date">{timestamp}</td>
        </tr>
        """

        ts = row.timestamp.strftime("%Y-%m-%d") if row.timestamp else "-"
        timestamps.append(ts)
        scores.append(score)
        categories.append(category)

    # === TOP 5 SORULAR ===
    query_topq = """
    SELECT TOP 5
        c.id,
        c.question AS question,
        c.answer AS answer,
        COUNT(DISTINCT c.id) AS cnt,
        MAX(m.category) AS category,
        AVG(CAST(m.success_score AS FLOAT)) AS avg_success
    FROM [SkodaBot].[dbo].[conversation_metrics] AS m
    INNER JOIN [SkodaBot].[dbo].[conversations] AS c
        ON m.conversation_id = c.id
    WHERE c.question IS NOT NULL
    GROUP BY c.id, c.question, c.answer
    ORDER BY COUNT(DISTINCT c.id) DESC;
    """
    cursor.execute(query_topq)
    table_topq = "".join([
        f"<tr>"
        f"<td>{r.question} <button class='btn-show-answer' data-answer=\"{h(r.answer)}\">Cevabı Gör</button></td>"
        f"<td><span class='tag'>{(r.category or '-')}</span></td>"
        f"<td class='text-right'>{round((r.avg_success or 0), 2)}</td>"
        f"</tr>"
        for r in cursor.fetchall()
    ])

    # === TOP 5 LIKE ===
    query_toplike = """
    SELECT TOP 5
        c.id,
        c.question AS question,
        c.answer AS answer,
        COUNT(DISTINCT c.id) AS cnt,
        MAX(m.category) AS category,
        AVG(CAST(m.success_score AS FLOAT)) AS avg_success
    FROM [SkodaBot].[dbo].[conversation_metrics] AS m
    INNER JOIN [SkodaBot].[dbo].[conversations] AS c
        ON m.conversation_id = c.id
    WHERE c.question IS NOT NULL
      AND m.customer_answer = 1
    GROUP BY c.id, c.question, c.answer
    ORDER BY COUNT(DISTINCT c.id) DESC;
    """
    cursor.execute(query_toplike)
    table_toplike = "".join([
        f"<tr>"
        f"<td>{h(r.question)}<button class='btn-show-answer' data-answer=\"{h(r.answer)}\">Cevabı Gör</button></td>"
        f"<td><span class='tag'>{(r.category or '-')}</span></td>"
        f"<td class='text-right'>{round((r.avg_success or 0), 2)}</td>"
        f"</tr>"
        for r in cursor.fetchall()
    ])

    # === TOP 5 DISLIKE ===
    query_topdis = """
    SELECT TOP 5
        c.id,
        c.question AS question,
        c.answer AS answer,
        COUNT(DISTINCT c.id) AS cnt,
        MAX(m.category) AS category,
        AVG(CAST(m.success_score AS FLOAT)) AS avg_success
    FROM [SkodaBot].[dbo].[conversation_metrics] AS m
    INNER JOIN [SkodaBot].[dbo].[conversations] AS c
        ON m.conversation_id = c.id
    WHERE c.question IS NOT NULL
      AND m.customer_answer = 2
      AND m.success_score IS NOT NULL
    GROUP BY c.id, c.question, c.answer
    ORDER BY COUNT(DISTINCT c.id) DESC;
    """
    cursor.execute(query_topdis)
    table_topdis = "".join([
        f"<tr>"
        f"<td>{h(r.question)}<button class='btn-show-answer' data-answer=\"{h(r.answer)}\">Cevabı Gör</button></td>"
        f"<td><span class='tag'>{(r.category or '-')}</span></td>"
        f"<td class='text-right'>{round((r.avg_success or 0), 2)}</td>"
        f"</tr>"
        for r in cursor.fetchall()
    ])

    # === ZAMAN SERİSİ ===
    if len(timestamps) > 0:
        df = pd.DataFrame({"timestamp": timestamps, "score": scores})
        df_group = df.groupby("timestamp").mean().reset_index()

        time_series = {
            "labels": df_group["timestamp"].tolist(),
            "values": df_group["score"].tolist()
        }

        plt.rcParams.update({
            "font.size": 11, "axes.titlesize": 12, "axes.labelsize": 11,
            "xtick.labelsize": 10, "ytick.labelsize": 10,
            "axes.edgecolor": "#e5e7eb", "axes.linewidth": 1.0,
        })
        fig1 = Figure(figsize=(7, 4.2), dpi=180)
        ax1 = fig1.subplots()
        ax1.plot(df_group["timestamp"], df_group["score"],
                 color="#1b5e20", marker="o", markersize=5, linewidth=2.5)
        ax1.grid(True, linestyle="--", linewidth=0.7, alpha=0.4)
        ax1.set_facecolor("#fafafa")
        ax1.set_ylim(0, 100)
        ax1.tick_params(axis='x', rotation=60, labelsize=9, pad=6)
        ax1.spines['top'].set_visible(False)
        ax1.spines['right'].set_visible(False)
        buf1 = io.BytesIO()
        fig1.tight_layout(pad=1.8)
        fig1.savefig(buf1, format="png", dpi=200)
        buf1.seek(0)
        img1_base64 = base64.b64encode(buf1.read()).decode("utf-8")
        chart_ts = f'<img src="data:image/png;base64,{img1_base64}" alt="Zaman serisi grafik" style="width:100%;border-radius:10px;">'
    else:
        chart_ts = "<p class='muted'>Veri bulunamadı.</p>"

    # === KATEGORİ GRAFİĞİ ===
    if len(categories) > 0:
        df2 = pd.DataFrame({"category": categories, "score": scores})
        df2 = df2.groupby("category").mean().reset_index()

        category_series = {
            "labels": df2["category"].tolist(),
            "values": df2["score"].tolist()
        }

        plt.rcParams.update({
            "font.size": 13,
            "axes.titlesize": 14,
            "axes.labelsize": 13,
            "xtick.labelsize": 14,
            "ytick.labelsize": 12,
            "axes.edgecolor": "#e5e7eb",
            "axes.linewidth": 1.0,
        })

    cursor.close()
    conn.close()

    if request.args.get("ajax") == "1":
        return jsonify({
            "table_html": table_conv,
            "kpis": {
                "totalQuestions": total_questions,
                "likeRatio": (like_ratio / 100.0),
                "avgSuccessScore": avg_success_score
            }
        })

    # === Template render ===
    return render_template(
        "CRS.html",
        table_html=table_conv,
        table_topq=table_topq,
        table_toplike=table_toplike,
        table_topdis=table_topdis,
        chart_ts=chart_ts,
        total_questions=total_questions,
        like_ratio=like_ratio,
        dislike_ratio=dislike_ratio,
        avg_success_score=avg_success_score,
        models=models,
        time_series=time_series,
        category_series=category_series
    )

