def _format_ddmmyyyy(val: str) -> str:
    """Accept yyyy-mm-dd or dd.mm.yyyy; return dd.mm.yyyy."""
    if not val:
        return ""
    val = val.strip()
    if len(val) == 10 and val[4] == "-" and val[7] == "-":
        y, m, d = val.split("-")
        return f"{d}.{m}.{y}"
    return val

def _coerce_bool(v):
    return True if v is True else False

def b64_static(filename: str) -> str:
    path = Path(current_app.static_folder) / filename
    if not path.exists():
        return ""

    ext = path.suffix.lower()
    mime = {
        ".png": "image/png",
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".svg": "image/svg+xml",
        ".webp": "image/webp",
    }.get(ext, "application/octet-stream")

    b64 = base64.b64encode(path.read_bytes()).decode("utf-8")
    return f"data:{mime};base64,{b64}"

