@login_required
def teslimat_formu_pdf():
    if not TESLIMAT_FORM_ORA_AVAILABLE:
        abort(503, description="Teslimat formu özelliği projeden kaldırıldı")
    payload = request.get_json(silent=True) or {}

    chassis = (payload.get("sasi_no") or "").strip()
    if not chassis:
        abort(400, description="sasi_no missing")

    ys_name = session.get("dealerName_Turkuaz")
    if not ys_name:
        abort(403, description="Dealer session missing")

    rows = _get_teslimat_formu_data(chassis, ys_name)
    if not rows:
        abort(404, description="Kayıt bulunamadı")
    row = rows[0]

    data = {
        "sasi_no": chassis,
        "musteri_unvan": row[8] if len(row) > 8 else "",
        "arac":          row[1] if len(row) > 1 else "",
        "motor_tipi_no": row[4] if len(row) > 4 else "",
        "fatura_no":     row[5] if len(row) > 5 else "",
        "trim_tipi":     row[9] if len(row) > 9 else "",
        "renk":          row[10] if len(row) > 10 else "",
        "model_yili":    row[11] if len(row) > 11 else "",
        "fatura_tarihi": row[7].strftime("%d.%m.%Y") if (len(row) > 7 and row[7]) else "",
        # editable defaults
        "plaka_no": "",
        "siparis_no": row[15] if len(row) > 9 else "",
        "anahtar_no": "",
        "radyo_kodu": "",
        "teslim_tarihi": "",
        "imza": "",
        "genel_aciklamalar": "",
        "servis_adi": "",
        "servis_danismani": "",
        "teslim_eden": "",
    }

    editable_keys = ["teslim_tarihi", "imza", "genel_aciklamalar", "servis_adi", "teslim_eden", "plaka_no"]
    for k in editable_keys:
        if k in payload:
            data[k] = (payload.get(k) or "").strip()

    data["teslim_tarihi"] = _format_ddmmyyyy(data.get("teslim_tarihi", ""))

    posted_cbs = payload.get("checkboxes") or {}
    for key, val in posted_cbs.items():
        data[key] = _coerce_bool(val)

    ys_code = session.get("YS_code")
    form = bayi_arac_teslimatForm(ys_code=ys_code)

    labels = {}
    for key in posted_cbs.keys():
        field = getattr(form, key, None)
        labels[key] = field.label.text if field is not None else key

    teslim_eden = data.get("teslim_eden", "")
    teslim_alan = (payload.get("teslim_alan") or "").strip() or None
    teslim_adresi = (payload.get("teslim_adresi") or "").strip() or None
    teslim_tarihi_text = data.get("teslim_tarihi", "")
    siparis_no = data.get("siparis_no", "")

    logo_src = b64_static("trafik_hayattir_logo.png")
    qr_src   = b64_static("qr.png")

    html_str = render_template(
        "teslimat_formu_pdf.html",
        data=data,
        labels=labels,
        teslim_eden=teslim_eden,
        teslim_alan=teslim_alan,
        teslim_adresi=teslim_adresi,
        teslim_tarihi_text=teslim_tarihi_text,
        siparis_no=siparis_no,
        ys_code=ys_code,
        logo_src=logo_src,
        qr_src=qr_src,
    )

    pdf_dir = Path(current_app.static_folder) / "teslimat_formlari"
    pdf_dir.mkdir(parents=True, exist_ok=True)

    filename = f"{chassis}_{teslim_tarihi_text}.pdf"
    pdf_path = pdf_dir / filename

    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        page = browser.new_page()

        page.set_content(html_str, wait_until="load", timeout=60_000)

        page.evaluate("() => (document.fonts ? document.fonts.ready : Promise.resolve())")

        pdf_bytes = page.pdf(
            format="A4",
            print_background=True,
            prefer_css_page_size=True,
            margin={"top": "14mm", "right": "14mm", "bottom": "14mm", "left": "14mm"},
        )

        browser.close()

    pdf_path.write_bytes(pdf_bytes)

    def parse_ddmmyyyy(s: str):
        s = (s or "").strip()
        if not s:
            return None
        return datetime.datetime.strptime(s, "%d.%m.%Y").date()

    teslim_dt = parse_ddmmyyyy(teslim_tarihi_text)

    fatura_dt = None
    if row[7]:
        fatura_dt = row[7].date() if hasattr(row[7], "date") else row[7]

    inserted_at = datetime.datetime.now()

    conn = pyodbc.connect(YA_2El_AracSatis)
    cursor = conn.cursor()

    query = """
    INSERT INTO [Yuce_Portal].[dbo].[Teslimat_Form]
        ([SaseNo], [Bayi], [TeslimTarihi], [FaturaTarihi], [inserted_by], [inserted_at], [PdfPath])
    VALUES (?, ?, ?, ?, ?, ?, ?)
    """

    cursor.execute(
        query,
        data["sasi_no"],
        ys_name,
        teslim_dt,
        fatura_dt,
        teslim_eden,
        inserted_at,
        filename
    )
    conn.commit()
    cursor.close()
    conn.close()

    return send_file(
        pdf_path,
        as_attachment=True,
        download_name=filename,
        mimetype="application/pdf",
        max_age=0,
    )

