@app.route("/meetset/api/event/create", methods=["POST"])
@login_required
def meetset_api_event_create():
    try:
        data = request.get_json(force=True)

        title = (data.get("title") or "").strip()
        description = (data.get("description") or "").strip()
        date_from = (data.get("date_from") or "").strip()
        date_to = (data.get("date_to") or "").strip()
        duration_minutes = int(data.get("duration_minutes") or 30)
        timezone_id = (data.get("timezone_id") or "Europe/Istanbul").strip()

        if not title:
            return jsonify({"ok": False, "message": "Başlık boş olamaz."}), 400

        # Session snapshot
        organizer_users1_id = session.get("ID") or session.get("users1_id") or session.get("user_id")
        organizer_username = session.get("username")
        organizer_name_surname = session.get("name") + " " + session.get("surname")

        if not organizer_username:
            return jsonify({"ok": False, "message": "Session user bilgisi eksik."}), 401

        try:
            df = datetime.datetime.strptime(date_from, "%Y-%m-%d").date()
            dt = datetime.datetime.strptime(date_to, "%Y-%m-%d").date()
            if dt < df:
                return jsonify({"ok": False, "message": "Bitiş tarihi başlangıçtan küçük olamaz."}), 400
        except:
            return jsonify({"ok": False, "message": "Tarih formatı hatalı (YYYY-MM-DD)."}), 400

        if duration_minutes not in (15, 20, 30, 45, 60, 90, 120):
            return jsonify({"ok": False, "message": "Geçersiz görüşme süresi."}), 400

        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        cursor.execute("""
            INSERT INTO [Yuce_Portal].[meet].[MeetSetEvent]
            (Title, Description,
             OrganizerUsers1Id, OrganizerUsername, OrganizerNameSurname,
             DurationMinutes, DateFrom, DateTo, TimeZoneId,
             Status,
             CreatedByUsers1Id, CreatedByUsername, CreatedByNameSurname)
            OUTPUT INSERTED.EventId
            VALUES (?, ?,
                    ?, ?, ?,
                    ?, ?, ?, ?,
                    1,
                    ?, ?, ?)
        """, (
            title, description,
            int(organizer_users1_id), organizer_username, organizer_name_surname,
            int(duration_minutes), df, dt, timezone_id,
            int(organizer_users1_id), organizer_username, organizer_name_surname
        ))

        event_id = cursor.fetchone()[0]
        connection.commit()
        connection.close()

        Write_Log_ToDB(session.get("username"), "POST", "/meetset/api/event/create", 0, f"Event created. EventId={event_id}")
        return jsonify({"ok": True, "event_id": int(event_id)})

    except Exception as e:
        try:
            connection.rollback()
            connection.close()
        except:
            pass
        return jsonify({"ok": False, "message": f"Event create hata: {str(e)}"}), 500

def _meetset_user_can_access_event(cursor, event_id: int, username: str) -> bool:
    cursor.execute("""
        SELECT TOP 1 1
        FROM [Yuce_Portal].[meet].[MeetSetEvent] e
        LEFT JOIN [Yuce_Portal].[meet].[MeetSetInvitee] i
          ON i.EventId = e.EventId AND i.InviteeUsername = ?
        WHERE e.EventId = ?
          AND (e.OrganizerUsername = ? OR i.InviteeUsername IS NOT NULL)
    """, (username, event_id, username))
    return cursor.fetchone() is not None

def ensure_graph_access_token_for_users1_id(user_id: int):
    try:
        rt = load_refresh_token(user_id)
        if not rt:
            return None

        app_msal = build_msal_app()
        result = app_msal.acquire_token_by_refresh_token(rt, scopes=MS_SCOPES)

        if not result or "error" in result:
            # refresh token invalid -> clear it
            save_refresh_token(user_id, None)
            return None

        access_token = result.get("access_token")
        if not access_token:
            return None

        # refresh token rotated -> persist new one
        if "refresh_token" in result and result["refresh_token"]:
            save_refresh_token(user_id, result["refresh_token"])

        return access_token
    except Exception:
        return None

