@app.route("/meetset/api/event/<int:event_id>/slots/list", methods=["GET"])
@login_required
def meetset_api_slots_list(event_id):
    username = (session.get("username") or "").strip()
    if not username:
        return jsonify({"ok": False, "message": "Unauthorized"}), 401

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()

    try:
        if not _meetset_user_can_access_event(cur, event_id, username):
            return jsonify({"ok": False, "message": "Forbidden"}), 403

        # Event header
        cur.execute("""
            SELECT EventId, Title, DurationMinutes, TimeZoneId
            FROM [Yuce_Portal].[meet].[MeetSetEvent]
            WHERE EventId = ?
        """, (event_id,))
        erow = cur.fetchone()
        if not erow:
            return jsonify({"ok": False, "message": "Event not found"}), 404

        event = {
            "event_id": int(erow.EventId),
            "title": erow.Title,
            "duration_minutes": int(erow.DurationMinutes),
            "timezone_id": erow.TimeZoneId
        }

        # (Opsiyonel ama faydalı) Kullanıcının bu event'te daha önce seçtiği slot var mı?
        # Not: burada "SelectedByUsername" üzerinden gidiyoruz (en pratik).
        cur.execute("""
            SELECT TOP 1 s.SlotId
            FROM [Yuce_Portal].[meet].[MeetSetSlot] s
            WHERE s.EventId = ?
              AND s.SelectedByUsername = ?
            ORDER BY s.SelectedAt DESC
        """, (event_id, username))
        chosen_row = cur.fetchone()
        already_chosen_slot_id = int(chosen_row.SlotId) if chosen_row else None
        event["already_chosen_slot_id"] = already_chosen_slot_id  # front-end isterse kullanır

        # Slots
        cur.execute("""
            SELECT
                s.SlotId,
                s.StartDateTime,
                s.EndDateTime,
                s.IsActive,
                s.SelectedByUsers1Id,
                s.SelectedByUsername,
                s.SelectedByNameSurname,
                s.SelectedAt
            FROM [Yuce_Portal].[meet].[MeetSetSlot] s
            WHERE s.EventId = ?
            ORDER BY s.StartDateTime ASC
        """, (event_id,))

        slots = []
        for r in cur.fetchall():
            sel_username = (r.SelectedByUsername or "").strip() if r.SelectedByUsername is not None else ""
            is_selected_by_me = (sel_username.lower() == username.lower()) if sel_username else False

            slots.append({
                "slot_id": int(r.SlotId),
                "start": r.StartDateTime.isoformat(sep=" "),
                "end": r.EndDateTime.isoformat(sep=" "),
                "is_active": bool(r.IsActive),
                "selected_by_users1_id": r.SelectedByUsers1Id,
                "selected_by_username": r.SelectedByUsername,
                "selected_by_name_surname": r.SelectedByNameSurname,
                "selected_at": r.SelectedAt.isoformat(sep=" ") if r.SelectedAt else None,

                # ✅ NEW: front-end bununla "ben daha önce seçmiş miyim?"i kesin anlar
                "is_selected_by_me": is_selected_by_me
            })

        return jsonify({"ok": True, "event": event, "slots": slots})

    finally:
        conn.close()

@app.route("/meetset/api/event/<int:event_id>/slots/choose", methods=["POST"])
@login_required
def meetset_api_slots_choose(event_id):
    data = request.get_json(force=True) or {}
    slot_id = data.get("slot_id")

    invitee_username = (session.get("username") or "").strip()
    invitee_users1_id = session.get("ID") or session.get("users1_id") or session.get("user_id")
    invitee_name_surname = f"{session.get('name','') or ''} {session.get('surname','') or ''}".strip()

    print("\n" + "="*110)
    print("[MEETSET] /slots/choose START")
    print("event_id:", event_id)
    print("slot_id:", slot_id)
    print("invitee_username:", invitee_username)
    print("invitee_users1_id:", invitee_users1_id)
    print("invitee_name_surname:", invitee_name_surname)

    if not invitee_username or not invitee_users1_id:
        print("[MEETSET] ERROR: session user missing")
        return jsonify({"ok": False, "message": "Session user bilgisi eksik."}), 401
    if not slot_id:
        print("[MEETSET] ERROR: slot_id missing")
        return jsonify({"ok": False, "message": "slot_id eksik."}), 400

    conn = pyodbc.connect(YA_2El_AracSatis)
    cur = conn.cursor()

    organizer_token = None
    created_graph_event_id = None

    try:
        # Yetki kontrolü
        if not _meetset_user_can_access_event(cur, event_id, invitee_username):
            print("[MEETSET] ERROR: Forbidden access to event")
            return jsonify({"ok": False, "message": "Forbidden"}), 403

        # 0) Tek seçim kuralı
        cur.execute("""
            SELECT TOP 1 s.SlotId
            FROM [Yuce_Portal].[meet].[MeetSetSlot] s
            WHERE s.EventId = ?
              AND s.SelectedByUsername = ?
            ORDER BY s.SelectedAt DESC
        """, (event_id, invitee_username))
        prev = cur.fetchone()
        if prev:
            print("[MEETSET] USER ALREADY CHOSEN SLOT:", int(prev.SlotId))
            return jsonify({
                "ok": False,
                "message": "Bu event'te zaten bir slot seçtin. Tekrar seçim yapamazsın.",
                "already_chosen_slot_id": int(prev.SlotId)
            }), 409

        # 1) Event bilgileri
        cur.execute("""
            SELECT
                EventId, Title,
                OrganizerUsers1Id, OrganizerUsername, OrganizerNameSurname,
                TimeZoneId
            FROM [Yuce_Portal].[meet].[MeetSetEvent]
            WHERE EventId = ?
        """, (event_id,))
        erow = cur.fetchone()
        if not erow:
            print("[MEETSET] ERROR: Event not found")
            return jsonify({"ok": False, "message": "Event not found"}), 404

        event_title = (erow.Title or "").strip() or "MeetSet"
        organizer_users1_id = int(erow.OrganizerUsers1Id)
        organizer_username = (erow.OrganizerUsername or "").strip()
        organizer_name_surname = (erow.OrganizerNameSurname or organizer_username or "").strip()
        timezone_id = (erow.TimeZoneId or "Europe/Istanbul").strip()

        # 2) Slot bilgisi
        cur.execute("""
            SELECT
                SlotId, StartDateTime, EndDateTime, IsActive,
                SelectedByUsers1Id, SelectedByUsername, SelectedByNameSurname, SelectedAt
            FROM [Yuce_Portal].[meet].[MeetSetSlot]
            WHERE EventId = ? AND SlotId = ?
        """, (event_id, int(slot_id)))
        srow = cur.fetchone()
        if not srow:
            print("[MEETSET] ERROR: Slot not found")
            return jsonify({"ok": False, "message": "Slot bulunamadı."}), 404

        if not bool(srow.IsActive):
            print("[MEETSET] ERROR: Slot inactive")
            return jsonify({"ok": False, "message": "Slot aktif değil."}), 400

        if srow.SelectedByUsers1Id is not None:
            chosen_by = (srow.SelectedByNameSurname or srow.SelectedByUsername or "Başka biri")
            chosen_at = srow.SelectedAt.isoformat(sep=" ") if srow.SelectedAt else None
            print("[MEETSET] ERROR: Slot already taken by:", chosen_by, "at:", chosen_at)
            return jsonify({
                "ok": False,
                "message": f"Bu slot daha önce seçildi: {chosen_by}",
                "chosen_by": chosen_by,
                "chosen_at": chosen_at
            }), 409

        slot_start = srow.StartDateTime
        slot_end = srow.EndDateTime

        organizer_token = ensure_graph_access_token_for_users1_id(organizer_users1_id)

        if not organizer_token:
            print("[MEETSET] ERROR: organizer token could not be obtained")
            return jsonify({"ok": False, "message": "Organizer Teams bağlı değil / token alınamadı."}), 409

        # 4) Organizer + Invitee email (MySQL users1.email)
        organizer_email = None
        invitee_email = None
        mcur = None
        try:
            mcur = mysql.connection.cursor()

            mcur.execute("SELECT email FROM users1 WHERE ID=%s", (organizer_users1_id,))
            r1 = mcur.fetchone()
            organizer_email = (r1.get("email") if r1 else None)

            mcur.execute("SELECT email FROM users1 WHERE ID=%s", (invitee_users1_id,))
            r2 = mcur.fetchone()
            invitee_email = (r2.get("email") if r2 else None)

        finally:
            try:
                if mcur:
                    mcur.close()
            except:
                pass

        organizer_email = (organizer_email or "").strip()
        invitee_email = (invitee_email or "").strip()

        print("[MEETSET] organizer_email:", organizer_email)
        print("[MEETSET] invitee_email  :", invitee_email)

        if not organizer_email:
            print("[MEETSET] ERROR: organizer email missing in MySQL users1.email")
            return jsonify({"ok": False, "message": "Organizer email bulunamadı (users1.email)."}), 409

        if not invitee_email:
            print("[MEETSET] ERROR: invitee email missing in MySQL users1.email")
            return jsonify({"ok": False, "message": "Invitee email bulunamadı (users1.email)."}), 409

        attendees = [
            {
                "emailAddress": {"address": organizer_email, "name": organizer_name_surname or organizer_username},
                "type": "required"
            },
            {
                "emailAddress": {"address": invitee_email, "name": invitee_name_surname or invitee_username},
                "type": "required"
            }
        ]

        # 5) Önce meeting yarat (başarısızsa slot seçme yok)
        payload = {
            "subject": event_title,
            "body": {
                "contentType": "HTML",
                "content": (
                    f"<p><b>Organizer:</b> {organizer_name_surname or organizer_username}</p>"
                    f"<p><b>Seçen:</b> {invitee_name_surname or invitee_username}</p>"
                    f"<p><b>Slot:</b> {slot_start.strftime('%d.%m.%Y %H:%M')} - {slot_end.strftime('%H:%M')}</p>"
                )
            },
            "start": {"dateTime": slot_start.strftime("%Y-%m-%dT%H:%M:%S"), "timeZone": timezone_id},
            "end":   {"dateTime": slot_end.strftime("%Y-%m-%dT%H:%M:%S"),   "timeZone": timezone_id},
            "attendees": attendees,
            "isOnlineMeeting": True,
            "onlineMeetingProvider": "teamsForBusiness"
        }

        headers = {
            "Authorization": f"Bearer {organizer_token}",
            "Accept": "application/json",
            "Content-Type": "application/json",
            "Prefer": 'outlook.timezone="Europe/Istanbul"'
        }

        create_url = f"{GRAPH_BASE}/me/events"

        print("[MEETSET] GRAPH CREATE URL:", create_url)
        print("[MEETSET] PAYLOAD subject:", payload.get("subject"))
        print("[MEETSET] PAYLOAD start:", payload.get("start"))
        print("[MEETSET] PAYLOAD end  :", payload.get("end"))
        print("[MEETSET] PAYLOAD attendees:", attendees)

        resp = requests.post(create_url, headers=headers, json=payload, timeout=25)

        print("[MEETSET] GRAPH RESP status:", resp.status_code)
        print("[MEETSET] GRAPH RESP request-id:", resp.headers.get("request-id"))
        print("[MEETSET] GRAPH RESP client-request-id:", resp.headers.get("client-request-id"))
        print("[MEETSET] GRAPH RESP text:", resp.text)

        if not resp.ok:
            Write_Log_ToDB(
                invitee_username,
                "POST",
                f"/meetset/api/event/{event_id}/slots/choose",
                0,
                f"Teams meeting create failed; slot NOT selected. status={resp.status_code} resp={resp.text}"
            )
            return jsonify({
                "ok": False,
                "message": "Teams toplantısı oluşturulamadı. Slot seçilmedi.",
                "graph_status": resp.status_code,
                "graph_error": resp.text
            }), 500

        created = resp.json()
        created_graph_event_id = created.get("id")
        join_url = (created.get("onlineMeeting") or {}).get("joinUrl")

        print("[MEETSET] GRAPH CREATED event_id:", created_graph_event_id)
        print("[MEETSET] GRAPH joinUrl:", join_url)

        # 6) Meeting başarılı -> şimdi slot’u DB'de seç
        cur.execute("""
            UPDATE s
            SET
                s.SelectedByUsers1Id = ?,
                s.SelectedByUsername = ?,
                s.SelectedByNameSurname = ?,
                s.SelectedAt = GETDATE()
            FROM [Yuce_Portal].[meet].[MeetSetSlot] s
            WHERE
                s.EventId = ?
                AND s.SlotId = ?
                AND s.IsActive = 1
                AND s.SelectedByUsers1Id IS NULL
        """, (int(invitee_users1_id), invitee_username, invitee_name_surname, event_id, int(slot_id)))

        print("[MEETSET] DB UPDATE rowcount:", cur.rowcount)

        if cur.rowcount != 1:
            print("[MEETSET] WARNING: Slot update failed after meeting created -> deleting meeting best-effort")
            if created_graph_event_id:
                try:
                    del_url = f"{GRAPH_BASE}/me/events/{created_graph_event_id}"
                    print("[MEETSET] DELETE URL:", del_url)
                    requests.delete(del_url, headers=headers, timeout=20)
                except Exception as ex:
                    print("[MEETSET] DELETE failed:", str(ex))

            cur.execute("""
                SELECT SelectedByUsername, SelectedByNameSurname, SelectedAt
                FROM [Yuce_Portal].[meet].[MeetSetSlot]
                WHERE EventId = ? AND SlotId = ?
            """, (event_id, int(slot_id)))
            r = cur.fetchone()
            chosen_by = (r.SelectedByNameSurname or r.SelectedByUsername or "Başka biri") if r else "Başka biri"
            chosen_at = r.SelectedAt.isoformat(sep=" ") if (r and r.SelectedAt) else None
            print("[MEETSET] Slot already taken by:", chosen_by, chosen_at)

            return jsonify({
                "ok": False,
                "message": f"Bu slot daha önce seçildi: {chosen_by}",
                "chosen_by": chosen_by,
                "chosen_at": chosen_at
            }), 409

        conn.commit()
        print("[MEETSET] SUCCESS: Slot selected + Teams meeting created")
        return jsonify({"ok": True, "joinUrl": join_url})

    except Exception as e:
        print("[MEETSET] EXCEPTION:", str(e))
        try:
            conn.rollback()
        except:
            pass

        # DB fail oldu ama meeting oluştuysa: orphan kalmasın diye silmeyi dene
        if created_graph_event_id and organizer_token:
            try:
                headers2 = {"Authorization": f"Bearer {organizer_token}", "Accept": "application/json"}
                del_url = f"{GRAPH_BASE}/me/events/{created_graph_event_id}"
                print("[MEETSET] EXCEPTION CLEANUP DELETE:", del_url)
                requests.delete(del_url, headers=headers2, timeout=20)
            except Exception as ex:
                print("[MEETSET] CLEANUP DELETE failed:", str(ex))

        return jsonify({"ok": False, "message": f"Slot seçme hata: {str(e)}"}), 500

    finally:
        try:
            conn.close()
        except:
            pass
        print("[MEETSET] /slots/choose END")
        print("="*110 + "\n")

@app.route("/meetset/api/event/<int:event_id>/ranges/save", methods=["POST"])
@login_required
def meetset_api_ranges_save(event_id):
    try:
        organizer_users1_id = session.get("ID") or session.get("users1_id") or session.get("user_id")
        organizer_username = session.get("username")
        organizer_name_surname = session.get("name") + " " + session.get("surname")

        if not organizer_users1_id:
            return jsonify({"ok": False, "message": "Session ID yok."}), 401

        data = request.get_json(force=True)
        ranges = data.get("ranges") or []

        parsed = []
        for r in ranges:
            try:
                s = datetime.datetime.strptime(r["start"], "%Y-%m-%d %H:%M")
                e = datetime.datetime.strptime(r["end"], "%Y-%m-%d %H:%M")
                if e > s:
                    parsed.append((s, e))
            except:
                pass

        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        # Yetki kontrolü
        cursor.execute("SELECT OrganizerUsers1Id FROM [Yuce_Portal].[meet].[MeetSetEvent] WHERE EventId=?", (event_id,))
        row = cursor.fetchone()
        if not row:
            connection.close()
            return jsonify({"ok": False, "message": "Event bulunamadı."}), 404

        if int(row[0]) != int(organizer_users1_id):
            connection.close()
            return jsonify({"ok": False, "message": "Bu event üzerinde yetkin yok."}), 403

        # replace
        cursor.execute("DELETE FROM [Yuce_Portal].[meet].[MeetSetAvailabilityRange] WHERE EventId=?", (event_id,))

        if parsed:
            cursor.fast_executemany = True
            cursor.executemany("""
                INSERT INTO [Yuce_Portal].[meet].[MeetSetAvailabilityRange] (EventId, StartDateTime, EndDateTime, IsActive)
                VALUES (?, ?, ?, 1)
            """, [(event_id, s, e) for (s, e) in parsed])

        # activity log
        cursor.execute("""
            INSERT INTO [Yuce_Portal].[meet].[MeetSetActivityLog]
            (EventId, ActorUsers1Id, ActorUsername, ActorNameSurname, ActionType, ActionDetail)
            VALUES (?, ?, ?, ?, 'ADD_RANGE', ?)
        """, (event_id, int(organizer_users1_id), organizer_username, organizer_name_surname, f"{len(parsed)} range saved"))

        connection.commit()
        connection.close()

        Write_Log_ToDB(session.get("username"), "POST", f"/meetset/api/event/{event_id}/ranges/save", 0, f"Ranges saved: {len(parsed)}")
        return jsonify({"ok": True, "saved": len(parsed)})

    except Exception as e:
        try:
            connection.rollback()
            connection.close()
        except:
            pass
        return jsonify({"ok": False, "message": f"Range save hata: {str(e)}"}), 500

@app.route("/meetset/api/event/<int:event_id>/slots/generate", methods=["POST"])
@login_required
def meetset_api_slots_generate(event_id):
    try:
        organizer_users1_id = session.get("ID") or session.get("users1_id") or session.get("user_id")
        organizer_username = session.get("username")
        organizer_name_surname = session.get("name") + " " + session.get("surname")

        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        cursor.execute("""
            SELECT OrganizerUsers1Id, DurationMinutes
            FROM [Yuce_Portal].[meet].[MeetSetEvent]
            WHERE EventId=?
        """, (event_id,))
        row = cursor.fetchone()

        if not row:
            connection.close()
            return jsonify({"ok": False, "message": "Event bulunamadı."}), 404

        if int(row[0]) != int(organizer_users1_id):
            connection.close()
            return jsonify({"ok": False, "message": "Bu event üzerinde yetkin yok."}), 403

        duration = int(row[1])

        cursor.execute("""
            SELECT StartDateTime, EndDateTime
            FROM [Yuce_Portal].[meet].[MeetSetAvailabilityRange]
            WHERE EventId=? AND IsActive=1
            ORDER BY StartDateTime
        """, (event_id,))
        ranges = cursor.fetchall()

        # replace slots
        cursor.execute("DELETE FROM [Yuce_Portal].[meet].[MeetSetSlot] WHERE EventId=?", (event_id,))

        slots = []
        for (start_dt, end_dt) in ranges:
            s = start_dt
            while s + datetime.timedelta(minutes=duration) <= end_dt:
                e = s + datetime.timedelta(minutes=duration)
                slots.append((event_id, s, e))
                s = s + datetime.timedelta(minutes=duration)

        if slots:
            cursor.fast_executemany = True
            cursor.executemany("""
                INSERT INTO [Yuce_Portal].[meet].[MeetSetSlot] (EventId, StartDateTime, EndDateTime, IsActive)
                VALUES (?, ?, ?, 1)
            """, slots)

        cursor.execute("""
            INSERT INTO [Yuce_Portal].[meet].[MeetSetActivityLog]
            (EventId, ActorUsers1Id, ActorUsername, ActorNameSurname, ActionType, ActionDetail)
            VALUES (?, ?, ?, ?, 'GENERATE_SLOTS', ?)
        """, (event_id, int(organizer_users1_id), organizer_username, organizer_name_surname, f"{len(slots)} slots generated"))

        connection.commit()
        connection.close()

        Write_Log_ToDB(session.get("username"), "POST", f"/meetset/api/event/{event_id}/slots/generate", 0, f"Slots generated: {len(slots)}")
        return jsonify({"ok": True, "generated": len(slots)})

    except Exception as e:
        try:
            connection.rollback()
            connection.close()
        except:
            pass
        return jsonify({"ok": False, "message": f"Slot generate hata: {str(e)}"}), 500

@app.route("/meetset/api/users/search", methods=["GET"])
@login_required
def meetset_api_users_search():
    q = (request.args.get("q") or "").strip()
    if len(q) < 2:
        return jsonify({"ok": True, "items": []})

    cursor = None
    try:
        cursor = mysql.connection.cursor()  # already a cursor (DictCursor in your config)

        like = f"%{q}%"
        query = """
            SELECT
                u.ID        AS users1_id,
                u.username  AS username,
                TRIM(CONCAT(COALESCE(u.name,''), ' ', COALESCE(u.surname,''))) AS name_surname,
                u.departman AS departman
            FROM users1 u
            WHERE
                u.username LIKE %s OR
                u.name     LIKE %s OR
                u.surname  LIKE %s OR
                CONCAT(COALESCE(u.name,''), ' ', COALESCE(u.surname,'')) LIKE %s
            ORDER BY u.name, u.surname
            LIMIT 20;
        """

        cursor.execute(query, (like, like, like, like))

        rows = cursor.fetchall()          # rows are already dicts
        items = list(rows) 

        return jsonify({"ok": True, "items": items})

    except Exception as e:
        return jsonify({"ok": False, "message": f"User search hata: {str(e)}"}), 500

    finally:
        try:
            if cursor:
                cursor.close()
        except:
            pass
    
@app.route("/meetset/api/event/<int:event_id>/invitees/add", methods=["POST"])
@login_required
def meetset_api_invitees_add(event_id):
    try:
        organizer_users1_id = session.get("ID") or session.get("users1_id") or session.get("user_id")
        organizer_username = session.get("username")
        organizer_name_surname = session.get("name") + " " + session.get("surname")

        data = request.get_json(force=True)
        invitees = data.get("invitees") or []

        clean = []
        for p in invitees:
            try:
                uid = int(p["users1_id"])
                un = str(p["username"]).strip()
                ns = str(p["name_surname"]).strip()
                if uid and un and ns:
                    clean.append((uid, un, ns))
            except:
                pass

        if not clean:
            return jsonify({"ok": False, "message": "Eklenecek kişi yok."}), 400

        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        # Yetki kontrolü
        cursor.execute("SELECT OrganizerUsers1Id FROM [Yuce_Portal].[meet].[MeetSetEvent] WHERE EventId=?", (event_id,))
        row = cursor.fetchone()
        if not row:
            connection.close()
            return jsonify({"ok": False, "message": "Event bulunamadı."}), 404
        if int(row[0]) != int(organizer_users1_id):
            connection.close()
            return jsonify({"ok": False, "message": "Bu event üzerinde yetkin yok."}), 403

        added = 0
        for (uid, un, ns) in clean:
            try:
                cursor.execute("""
                    INSERT INTO [Yuce_Portal].[meet].[MeetSetInvitee]
                    (EventId, InviteeUsers1Id, InviteeUsername, InviteeNameSurname, Status)
                    VALUES (?, ?, ?, ?, 1)
                """, (event_id, uid, un, ns))
                added += 1
            except Exception:
                # büyük ihtimal unique ihlali (zaten ekli)
                pass

        cursor.execute("""
            INSERT INTO [Yuce_Portal].[meet].[MeetSetActivityLog]
            (EventId, ActorUsers1Id, ActorUsername, ActorNameSurname, ActionType, ActionDetail)
            VALUES (?, ?, ?, ?, 'INVITE', ?)
        """, (event_id, int(organizer_users1_id), organizer_username, organizer_name_surname, f"{added} invitees added"))

        connection.commit()
        connection.close()

        Write_Log_ToDB(session.get("username"), "POST", f"/meetset/api/event/{event_id}/invitees/add", 0, f"Invitees added: {added}")
        return jsonify({"ok": True, "added": added})

    except Exception as e:
        try:
            connection.rollback()
            connection.close()
        except:
            pass
        return jsonify({"ok": False, "message": f"Invitee add hata: {str(e)}"}), 500

