@app.route("/api/m365/meetings/range", methods=["GET"])
def api_m365_meetings_range():
    start = request.args.get("start")  # YYYY-MM-DD
    end   = request.args.get("end")    # YYYY-MM-DD
    if not start or not end:
        return jsonify({"status": "error", "message": "start/end required (YYYY-MM-DD)"}), 400

    try:
        sdate = dt.datetime.strptime(start, "%Y-%m-%d").date()
        edate = dt.datetime.strptime(end, "%Y-%m-%d").date()
        if edate < sdate:
            return jsonify({"status": "error", "message": "end < start"}), 400
    except:
        return jsonify({"status": "error", "message": "invalid date format"}), 400

    token = ensure_graph_access_token()
    if not token:
        return jsonify({"status": "not_connected"}), 200

    # Istanbul local window
    start_dt = f"{sdate.isoformat()}T00:00:00+03:00"
    end_dt   = f"{edate.isoformat()}T23:59:59+03:00"

    headers = {
        "Authorization": f"Bearer {token}",
        "Prefer": 'outlook.timezone="Europe/Istanbul"',
        "Accept": "application/json"
    }

    url = f"{GRAPH_BASE}/me/calendarView"
    params = {
        "startDateTime": start_dt,
        "endDateTime": end_dt,
        "$orderby": "start/dateTime",
        "$top": 200
    }

    meetings = []
    try:
        while True:
            resp = requests.get(url, headers=headers, params=params, timeout=20)
            if resp.status_code == 401:
                session.pop("ms_access_token", None)
                token = ensure_graph_access_token()
                if not token:
                    return jsonify({"status": "not_connected"}), 200
                headers["Authorization"] = f"Bearer {token}"
                resp = requests.get(url, headers=headers, params=params, timeout=20)

            if not resp.ok:
                return jsonify({"status": "error", "message": resp.text}), 500

            data = resp.json()
            for ev in data.get("value", []):
                # Cancelled filter (isteğe bağlı)
                if ev.get("isCancelled") is True:
                    continue

                online = ev.get("isOnlineMeeting") is True or bool(ev.get("onlineMeeting"))
                join_url = (ev.get("onlineMeeting") or {}).get("joinUrl")

                meetings.append({
                    "id": ev.get("id"),
                    "subject": ev.get("subject") or "(No title)",
                    "start": (ev.get("start") or {}).get("dateTime"),
                    "end": (ev.get("end") or {}).get("dateTime"),
                    "isOnlineMeeting": online,
                    "provider": ev.get("onlineMeetingProvider"),
                    "joinUrl": join_url,
                    "location": (ev.get("location") or {}).get("displayName", "") or ""
                })

            next_link = data.get("@odata.nextLink")
            if not next_link:
                break
            url = next_link
            params = None

        return jsonify({"status": "ok", "start": start, "end": end, "meetings": meetings})

    except requests.RequestException as e:
        return jsonify({"status": "error", "message": f"network error: {e}"}), 502
    except Exception as e:
        return jsonify({"status": "error", "message": f"server error: {e}"}), 500

