import pymysql
from pymysql.cursors import DictCursor

def get_yuceverse_conn():
    return pymysql.connect(
        host=_get_mysql_setting("host", "localhost"),
        user=_get_mysql_setting("user", "root"),
        password=_get_mysql_setting("password", master_password),
        database="yuceverse",
        charset="utf8mb4",
        cursorclass=DictCursor,
        autocommit=True
    )

@app.route("/ik_panel")
@login_required
def ik_panel():
    conn = get_yuceverse_conn()
    cur = conn.cursor()

    try:
        
        # Toplam zorunlu evrak
        cur.execute("""
            SELECT COUNT(*) AS total_required
            FROM onboarding_document_types
            WHERE is_required = 1
        """)
        row = cur.fetchone()
        total_required = int(row["total_required"] or 0)

        # Adayları çek
        cur.execute("""
            SELECT u.ID, u.name, u.surname, u.departman,
                   s.start_date
            FROM users2 u
            LEFT JOIN onboarding_survey s ON s.user_id = u.ID
            WHERE u.aday_yetki = 1
            ORDER BY u.ID DESC
        """)
        users = cur.fetchall() or []

        employees = []
        
        # --- İSTATİSTİK DEĞİŞKENLERİ (Dinamik Kartlar İçin) ---
        stats = {
            "total_candidates": len(users),
            "completed": 0,
            "partial": 0,    # Eksik var / İncelemede
            "missing": 0,    # Kritik
            "avg_completion": 0,
            "recent_uploads": 0,
            "new_this_month": 0
        }
        
        total_pct = 0

        for u in users:
            user_id = u["ID"]

            # Yüklenen zorunlu evrak sayısı
            cur.execute("""
                SELECT COUNT(*) AS uploaded_required
                FROM onboarding_documents d
                JOIN onboarding_document_types t ON t.id = d.doc_type_id
                WHERE d.user_id = %s
                  AND t.is_required = 1
                  AND d.file_path IS NOT NULL
                  AND d.status = 'uploaded'
            """, (user_id,))

            r = cur.fetchone()
            uploaded_required = int(r["uploaded_required"] or 0)

            # Yüzde hesapla
            pct = 0
            if total_required > 0:
                pct = int((uploaded_required / total_required) * 100)
            
            total_pct += pct

            # Durum Belirleme ve İstatistik Güncelleme
            if pct == 100:
                badge = "complete"
                stats["completed"] += 1
            elif pct >= 50:
                badge = "partial"
                stats["partial"] += 1
            else:
                badge = "missing"
                stats["missing"] += 1

            # İsim boş gelme ihtimaline karşı initials koruması
            isim = u['name'] or ""
            soyisim = u['surname'] or ""
            initials = f"{isim[:1]}{soyisim[:1]}".upper() if isim or soyisim else "U"

            employees.append({
                "id": user_id,
                "name": f"{isim} {soyisim}".strip(),
                "initials": initials,
                "dept": u["departman"] or "-",
                "start": str(u["start_date"]) if u.get("start_date") else "-",
                "pct": pct,
                "badge": badge,
                "uploaded": uploaded_required,
                "total_required": total_required
            })

        # Genel ortalama tamamlanma oranını hesapla
        if stats["total_candidates"] > 0:
            stats["avg_completion"] = int(total_pct / stats["total_candidates"])

        # EKSTRA: Son 24 Saatte Yüklenen Evrak Sayısı
        try:
            cur.execute("""
                SELECT COUNT(*) AS recent
                FROM onboarding_documents
                WHERE uploaded_at >= DATE_SUB(NOW(), INTERVAL 24 HOUR)
            """)
            rec = cur.fetchone()
            stats["recent_uploads"] = int(rec["recent"] or 0) if rec else 0
        except:
            pass # Eğer uploaded_at sütunu yoksa hata vermesin diye try-except eklendi

        return render_template("ik_panel.html", employees=employees, stats=stats)

    finally:
        cur.close()
        conn.close()

