@app.route("/tek_soru_anket", methods=["GET", "POST"])
@login_required
def teksoru_anket():
    username = (session.get("username") or "").strip()
    fullname = f"{(session.get('name') or '').strip()} {(session.get('surname') or '').strip()}".strip()

    if not username or not fullname:
        return render_template("tek_soru_anket.html", has_voted=False, voted_message=""), 200

    if request.method == "GET":
        try:
            connection = pyodbc.connect(YA_2El_AracSatis)
            cursor = connection.cursor()

            cursor.execute("""
                SELECT TOP 1 Cevap, CevapTarihi
                FROM [Yuce_Portal].[dbo].[TelefonKullanimAnketCevaplari] WITH (NOLOCK)
                WHERE Username = ?
                ORDER BY CevapTarihi DESC
            """, (username,))
            row = cursor.fetchone()

            cursor.close()
            connection.close()

            if row:
                cevap = row[0]
                dt = row[1]
                voted_message = f"Daha önce cevap verdiniz: {cevap}"
                return render_template("tek_soru_anket.html", has_voted=True, voted_message=voted_message), 200

            return render_template("tek_soru_anket.html", has_voted=False, voted_message=""), 200

        except Exception:
            return render_template("tek_soru_anket.html", has_voted=False, voted_message=""), 200

    # ---- POST ----
    try:
        payload = request.get_json(silent=True) or {}
        answer = (payload.get("answer") or request.form.get("answer") or "").strip()

        if not answer:
            return jsonify({"ok": False, "message": "Cevap boş olamaz."}), 400

        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        # tekrar kaydı engelle
        cursor.execute("""
            SELECT 1
            FROM [Yuce_Portal].[dbo].[TelefonKullanimAnketCevaplari] WITH (NOLOCK)
            WHERE Username = ?
        """, (username,))
        if cursor.fetchone():
            cursor.close()
            connection.close()
            return jsonify({"ok": False, "message": "Bu anket için daha önce cevap verdiniz."}), 409

        cursor.execute("""
            INSERT INTO [Yuce_Portal].[dbo].[TelefonKullanimAnketCevaplari] (Username, AdSoyad, Cevap)
            VALUES (?, ?, ?)
        """, (username, fullname, answer))

        connection.commit()
        cursor.close()
        connection.close()

        return jsonify({"ok": True, "message": "Cevabınız kaydedildi. Teşekkürler!"}), 200

    except pyodbc.Error as e:
        try:
            connection.rollback()
        except Exception:
            pass
        return jsonify({"ok": False, "message": f"DB hatası: {str(e)}"}), 500

    except Exception as e:
        return jsonify({"ok": False, "message": f"Hata: {str(e)}"}), 500


"""
YücePortal Talep Yönetimi Backend
- Tek bir "hub" fonksiyon: tlp_backend(action)
- Private talepler: sadece owner + admin görür
- Dosya: static/talepler/<TicketId>/ içine kaydeder, çoklu dosya, max 12MB (her dosya)
"""

TBL_TICKET = f"[Yuce_Portal].[tlp].[Ticket]"
TBL_PROJECT = f"[Yuce_Portal].[tlp].[Project]"
TBL_ATTACH = f"[Yuce_Portal].[tlp].[TicketAttachment]"
TBL_COMMENT = f"[Yuce_Portal].[tlp].[TicketComment]"
TBL_EVENT = f"[Yuce_Portal].[tlp].[TicketEventLog]"

@app.route("/talep_yonetim", methods=["GET"])
@login_required
def talep_yonetim():
    # Basit bir guard istersen:
    if session.get("YA_user") is not True:
        return "Yetkisiz", 403
    return render_template("talep_yonetim.html")

@app.route("/talepler_api", methods=["GET", "POST"])
@login_required
def tlp_backend():
    ADMIN_USERS = {"dogao", "sevvalo"}
    MAX_FILE_MB = 12
    MAX_FILE_BYTES = MAX_FILE_MB * 1024 * 1024

    import datetime as dt
    # Not: Blueprint burada gereksiz ama senin yapını bozmamak için bırakıyorum.
    tlp_bp = Blueprint("tlp", __name__)

    """
    action parametresiyle tüm işleri tek fonk içinde yapar.

    GET actions:
      - action=list_tickets
      - action=get_ticket
      - action=list_projects
      - action=download_attachment  (AttachmentId ile)
      - action=stats (basit metrikler)

    POST actions:
      - action=create_ticket
      - action=update_ticket (admin)
      - action=set_status (admin)
      - action=add_comment (admin)
      - action=add_project (admin)
      - action=toggle_project_active (admin)  (silmek yerine pasif)
    """

    # --- küçük iç yardımcılar (fonksiyon sayısını şişirmeden) ---
    def _now():
        return dt.datetime.now()

    def _is_admin():
        return str(session.get("username", "")).lower() in ADMIN_USERS

    def _require_ya_user():
        if session.get("YA_user") is not True:
            abort(403, description="Yetkisiz: YA_user değil.")
        if not session.get("username"):
            abort(401, description="Session username yok.")

    def _actor_payload():
        return {
            "username": session.get("username"),
            "fullname": (str(session.get("name") or "").strip() + " " + str(session.get("surname") or "").strip()).strip(),
            "departman": session.get("departman"),
        }

    def _save_event(cur, ticket_id: int, event_type: str, old_val=None, new_val=None):
        actor = _actor_payload()
        cur.execute(
            f"""
            INSERT INTO {TBL_EVENT}
            (TicketId, EventType, OldValue, NewValue, ActorUsername, ActorFullName, ActorDepartman, CreatedAt)
            VALUES (?, ?, ?, ?, ?, ?, ?, SYSDATETIME())
            """,
            ticket_id,
            event_type,
            None if old_val is None else (old_val if isinstance(old_val, str) else json.dumps(old_val, ensure_ascii=False)),
            None if new_val is None else (new_val if isinstance(new_val, str) else json.dumps(new_val, ensure_ascii=False)),
            actor["username"],
            actor["fullname"],
            actor["departman"],
        )

    def _get_users1_id_mysql(username: str) -> int:
        """
        MySQL users1 tablosundan ID çeker (username ile).
        mysql bağlantısı: conn = mysql.connection ; cur = conn.cursor()
        """
        if not username:
            return None

        my_conn = mysql.connection
        my_cur = my_conn.cursor()
        try:
            my_cur.execute("SELECT ID FROM users1 WHERE username = %s LIMIT 1", (username,))
            row = my_cur.fetchone()
            return int(row["ID"]) if row else None
        finally:
            try:
                my_cur.close()
            except Exception:
                pass

    def _get_apple_token_mysql(username: str):
        if not username:
            return None
        my_conn = mysql.connection
        my_cur = my_conn.cursor()
        try:
            my_cur.execute("SELECT apple_token FROM users1 WHERE username = %s LIMIT 1", (username,))
            row = my_cur.fetchone()
            return row["apple_token"] if row and row.get("apple_token") else None
        finally:
            try:
                my_cur.close()
            except Exception:
                pass

    def _notify_ticket_status_changed(mssql_cur, ticket_id: int, new_status: str):
        """
        Admin status değiştirince:
        - ticket owner'ı bul
        - MySQL users1'den owner'ın user_id'sini bul
        - notifications tablosunda aynı (user_id + TicketId + a_tag) varsa sil
        - yeni notification ekle
        """
        # Ticket owner + title
        mssql_cur.execute(
            f"SELECT CreatedByUsername, Title FROM {TBL_TICKET} WHERE TicketId = ?",
            ticket_id
        )
        tr = mssql_cur.fetchone()
        if not tr:
            return

        owner_username = str(tr.CreatedByUsername or "").strip()
        title = (tr.Title or "").strip()
        if not owner_username:
            return

        # MySQL users1 ID
        owner_user_id = _get_users1_id_mysql(owner_username)
        if owner_user_id is None:
            abort(500, description=f"MySQL users1 içinde user bulunamadı: {owner_username}")

        # aynı ticket için önce eski notif'i sil (sadece bu notif tipi için)
        a_tag = "talep_yonetim"
        mssql_cur.execute(
            """
            DELETE FROM [Yuce_Portal].[dbo].[notifications]
            WHERE user_id = ? AND TicketId = ? AND a_tag = ?
            """,
            owner_user_id, ticket_id, a_tag
        )

        msg = f"Talebinizin durumu güncellendi: {new_status} (#{ticket_id}) - {title}"

        # yeni notif ekle
        mssql_cur.execute(
            """
            INSERT INTO [Yuce_Portal].[dbo].[notifications]
            (user_id, user_username, message, a_tag, image_path, is_read, is_active, created_at, TicketId)
            VALUES (?, ?, ?, ?, ?, 0, 1, SYSDATETIME(), ?)
            """,
            owner_user_id,
            owner_username,
            msg,
            a_tag,
            None,      # image_path
            ticket_id
        )

        # push (varsa)
        token = _get_apple_token_mysql(owner_username)
        if token:
            send_push_notification(
                token=token,
                title=f"#{ticket_id} talebiniz {new_status}",
                message=f"Talebinizin durumu güncellendi: {new_status} (#{ticket_id}) - {title}"
            )

    def _notify_ticket_commented(mssql_cur, ticket_id: int, comment_text: str):
        """
        Admin yorum ekleyince:
        - ticket owner'ı bul
        - MySQL users1'den owner'ın user_id'sini bul
        - notifications tablosunda aynı (user_id + TicketId + a_tag) varsa sil
        - yeni notification ekle
        - apple_token varsa push at
        """
        mssql_cur.execute(
            f"SELECT CreatedByUsername, Title FROM {TBL_TICKET} WHERE TicketId = ?",
            ticket_id
        )
        tr = mssql_cur.fetchone()
        if not tr:
            return

        owner_username = str(tr.CreatedByUsername or "").strip()
        title = (tr.Title or "").strip()
        if not owner_username:
            return

        owner_user_id = _get_users1_id_mysql(owner_username)
        if owner_user_id is None:
            abort(500, description=f"MySQL users1 içinde user bulunamadı: {owner_username}")

        a_tag = "talep_yonetim"

        # aynı tipte eski notif'i sil (spama karşı tekil kalsın)
        mssql_cur.execute(
            """
            DELETE FROM [Yuce_Portal].[dbo].[notifications]
            WHERE user_id = ? AND TicketId = ? AND a_tag = ?
            """,
            owner_user_id, ticket_id, a_tag
        )

        # kısa preview
        preview = (comment_text or "").strip().replace("\n", " ")
        if len(preview) > 120:
            preview = preview[:117] + "..."

        msg = f"Talebinize yorum eklendi (#{ticket_id}) - {title}"
        if preview:
            msg = msg + f" | {preview}"

        mssql_cur.execute(
            """
            INSERT INTO [Yuce_Portal].[dbo].[notifications]
            (user_id, user_username, message, a_tag, image_path, is_read, is_active, created_at, TicketId)
            VALUES (?, ?, ?, ?, ?, 0, 1, SYSDATETIME(), ?)
            """,
            owner_user_id,
            owner_username,
            msg,
            a_tag,
            None,
            ticket_id
        )

        token = _get_apple_token_mysql(owner_username)
        if token:
            send_push_notification(
                token=token,
                title=f"#{ticket_id} talebinize yorum",
                message=msg
            )

    def _visibility_where_for_list(params_out: list):
        """
        Liste için görünürlük koşulu:
        - Public: herkes (YA_user True)
        - Private: sadece owner + admin
        """
        if _is_admin():
            return "1=1"
        params_out.append(session.get("username"))
        return "(t.IsPrivate = 0 OR (t.IsPrivate = 1 AND t.CreatedByUsername = ?))"

    def _check_ticket_visibility(cur, ticket_id: int):
        """
        Ticket'a erişebilir mi? owner/admin/public.
        Dönen row: ticket temel alanları
        """
        cur.execute(
            f"""
            SELECT
                t.TicketId, t.CreatedByUsername, t.IsPrivate
            FROM {TBL_TICKET} t
            WHERE t.TicketId = ?
            """,
            ticket_id,
        )
        row = cur.fetchone()
        if not row:
            abort(404, description="Ticket bulunamadı.")
        if _is_admin():
            return row
        if row.IsPrivate:
            if str(row.CreatedByUsername).lower() != str(session.get("username", "")).lower():
                abort(403, description="Bu private ticket'a erişim yok.")
        return row

    def _files_root():
        # static/talepler
        static_root = current_app.static_folder or os.path.join(current_app.root_path, "static")
        root = os.path.join(static_root, "talepler")
        os.makedirs(root, exist_ok=True)
        return root

    def _save_attachments(cur, ticket_id: int):
        """
        Çoklu dosya kaydeder: request.files.getlist("files")
        Her dosya max 12MB.
        DB'ye metadata yazar + event log.
        """
        files = request.files.getlist("files")
        if not files:
            return []

        actor = _actor_payload()
        saved = []

        ticket_dir = os.path.join(_files_root(), str(ticket_id))
        os.makedirs(ticket_dir, exist_ok=True)

        for f in files:
            if not f or not getattr(f, "filename", ""):
                continue

            # Boyut kontrolü (stream okurken güvenli)
            f.stream.seek(0, os.SEEK_END)
            size = f.stream.tell()
            f.stream.seek(0)

            if size > MAX_FILE_BYTES:
                abort(413, description=f"Dosya çok büyük (max {MAX_FILE_MB}MB): {f.filename}")

            original = f.filename
            safe_name = secure_filename(original) or "file"
            unique = f"{uuid.uuid4().hex}_{safe_name}"
            abs_path = os.path.join(ticket_dir, unique)
            f.save(abs_path)

            rel_path = os.path.join("talepler", str(ticket_id), unique).replace("\\", "/")

            cur.execute(
                f"""
                INSERT INTO {TBL_ATTACH}
                (TicketId, OriginalFileName, StoredFileName, StoredRelPath, FileSizeBytes, MimeType,
                 UploadedAt, UploadedByUsername, UploadedByFullName)
                VALUES (?, ?, ?, ?, ?, ?, SYSDATETIME(), ?, ?)
                """,
                ticket_id,
                original,
                unique,
                rel_path,
                int(size),
                getattr(f, "mimetype", None),
                actor["username"],
                actor["fullname"],
            )

            saved.append({"original": original, "stored": unique, "rel_path": rel_path, "size": int(size)})

        if saved:
            _save_event(cur, ticket_id, "ATTACHMENT_ADDED", None, {"count": len(saved), "files": [s["original"] for s in saved]})

        return saved

    # ---- giriş ve action ----
    _require_ya_user()
    action = (request.args.get("action") if request.method == "GET" else request.form.get("action")) or ""
    action = action.strip()

    # DB bağlantısı (kullanıcının istediği şekilde)
    conn = pyodbc.connect(YA_2El_AracSatis)
    conn.autocommit = False

    try:
        cur = conn.cursor()

        # =========================
        # GET: Projects
        # =========================
        if request.method == "GET" and action == "list_projects":
            cur.execute(
                f"""
                SELECT ProjectId, ProjectName, IsActive, CreatedAt, CreatedByUser, CreatedByName
                FROM {TBL_PROJECT}
                ORDER BY IsActive DESC, ProjectName ASC
                """
            )
            rows = cur.fetchall()
            return jsonify([
                {
                    "ProjectId": r.ProjectId,
                    "ProjectName": r.ProjectName,
                    "IsActive": bool(r.IsActive),
                    "CreatedAt": r.CreatedAt.isoformat() if r.CreatedAt else None,
                    "CreatedByUser": r.CreatedByUser,
                    "CreatedByName": r.CreatedByName,
                }
                for r in rows
            ])

        # =========================
        # GET: Ticket list
        # filters: status, category, project_id, urgent, mine, q
        # =========================
        if request.method == "GET" and action == "list_tickets":
            params = []
            where = [_visibility_where_for_list(params)]

            mine = request.args.get("mine", "").lower() in ("1", "true", "yes", "on")
            if mine:
                params.append(session.get("username"))
                where.append("t.CreatedByUsername = ?")

            status = request.args.get("status")
            if status:
                params.append(status)
                where.append("t.Status = ?")

            category = request.args.get("category")
            if category:
                params.append(category)
                where.append("t.Category = ?")

            project_id = request.args.get("project_id")
            if project_id:
                params.append(int(project_id))
                where.append("t.ProjectId = ?")

            urgent = request.args.get("urgent")
            if urgent in ("0", "1"):
                params.append(int(urgent))
                where.append("t.IsUrgent = ?")

            q = (request.args.get("q") or "").strip()
            if q:
                params.append(f"%{q}%")
                params.append(f"%{q}%")
                where.append("(t.Title LIKE ? OR t.Description LIKE ?)")

            # pagination
            page = int(request.args.get("page") or 1)
            page_size = int(request.args.get("page_size") or 30)
            if page < 1:
                page = 1
            if page_size < 1 or page_size > 200:
                page_size = 30
            offset = (page - 1) * page_size

            where_sql = " AND ".join(where) if where else "1=1"

            cur.execute(
                f"""
                SELECT
                    t.TicketId, t.CreatedByUsername, t.CreatedAt,
                    t.CreatedByFullName, t.CreatedByDepartman,
                    t.Title, t.Category, t.IsUrgent, t.IsPrivate, t.Status,
                    t.ProjectId, p.ProjectName,
                    t.SeenAt, t.InProgressAt, t.CompletedAt, t.CancelledAt,
                    t.UpdatedAt, t.UpdatedByFullName
                FROM {TBL_TICKET} t
                LEFT JOIN {TBL_PROJECT} p ON p.ProjectId = t.ProjectId
                WHERE {where_sql}
                ORDER BY t.CreatedAt DESC
                OFFSET ? ROWS FETCH NEXT ? ROWS ONLY
                """,
                *params, offset, page_size
            )
            rows = cur.fetchall()

            cur.execute(
                f"SELECT COUNT(1) AS Cnt FROM {TBL_TICKET} t WHERE {where_sql}",
                *params
            )
            total = int(cur.fetchone().Cnt)

            return jsonify({
                "page": page,
                "page_size": page_size,
                "total": total,
                "items": [
                    {
                        "TicketId": r.TicketId,
                        "CreatedAt": r.CreatedAt.isoformat() if r.CreatedAt else None,
                        "CreatedByUsername": r.CreatedByUsername,
                        "CreatedByFullName": r.CreatedByFullName,
                        "CreatedByDepartman": r.CreatedByDepartman,
                        "Title": r.Title,
                        "Category": r.Category,
                        "IsUrgent": bool(r.IsUrgent),
                        "IsPrivate": bool(r.IsPrivate),
                        "Status": r.Status,
                        "ProjectId": r.ProjectId,
                        "ProjectName": r.ProjectName,
                        "SeenAt": r.SeenAt.isoformat() if r.SeenAt else None,
                        "InProgressAt": r.InProgressAt.isoformat() if r.InProgressAt else None,
                        "CompletedAt": r.CompletedAt.isoformat() if r.CompletedAt else None,
                        "CancelledAt": r.CancelledAt.isoformat() if r.CancelledAt else None,
                        "UpdatedAt": r.UpdatedAt.isoformat() if r.UpdatedAt else None,
                        "UpdatedByFullName": r.UpdatedByFullName,
                    }
                    for r in rows
                ]
            })

        # =========================
        # GET: Ticket detail (with attachments + comments)
        # =========================
        if request.method == "GET" and action == "get_ticket":
            ticket_id = int(request.args.get("ticket_id") or 0)
            if ticket_id <= 0:
                abort(400, description="ticket_id gerekli.")
            _check_ticket_visibility(cur, ticket_id)

            cur.execute(
                f"""
                SELECT
                    t.TicketId, t.CreatedAt,
                    t.CreatedByUsername, t.CreatedByFullName, t.CreatedByDepartman,
                    t.Title, t.Description, t.Category, t.IsUrgent, t.IsPrivate, t.Status,
                    t.ProjectId, p.ProjectName,
                    t.SeenAt, t.InProgressAt, t.CompletedAt, t.CancelledAt,
                    t.UpdatedAt, t.UpdatedByUsername, t.UpdatedByFullName
                FROM {TBL_TICKET} t
                LEFT JOIN {TBL_PROJECT} p ON p.ProjectId = t.ProjectId
                WHERE t.TicketId = ?
                """,
                ticket_id
            )
            t = cur.fetchone()
            if not t:
                abort(404, description="Ticket bulunamadı.")

            cur.execute(
                f"""
                SELECT AttachmentId, OriginalFileName, StoredRelPath, FileSizeBytes, MimeType, UploadedAt, UploadedByFullName
                FROM {TBL_ATTACH}
                WHERE TicketId = ?
                ORDER BY UploadedAt DESC
                """,
                ticket_id
            )
            atts = cur.fetchall()

            cur.execute(
                f"""
                SELECT CommentId, CommentText, CreatedAt, CreatedByFullName, IsAdminComment
                FROM {TBL_COMMENT}
                WHERE TicketId = ?
                ORDER BY CreatedAt ASC
                """,
                ticket_id
            )
            comms = cur.fetchall()

            return jsonify({
                "Ticket": {
                    "TicketId": t.TicketId,
                    "CreatedAt": t.CreatedAt.isoformat() if t.CreatedAt else None,
                    "CreatedByUsername": t.CreatedByUsername if _is_admin() else None,
                    "CreatedByFullName": t.CreatedByFullName,
                    "CreatedByDepartman": t.CreatedByDepartman,
                    "Title": t.Title,
                    "Description": t.Description,
                    "Category": t.Category,
                    "IsUrgent": bool(t.IsUrgent),
                    "IsPrivate": bool(t.IsPrivate),
                    "Status": t.Status,
                    "ProjectId": t.ProjectId,
                    "ProjectName": t.ProjectName,
                    "SeenAt": t.SeenAt.isoformat() if t.SeenAt else None,
                    "InProgressAt": t.InProgressAt.isoformat() if t.InProgressAt else None,
                    "CompletedAt": t.CompletedAt.isoformat() if t.CompletedAt else None,
                    "CancelledAt": t.CancelledAt.isoformat() if t.CancelledAt else None,
                    "UpdatedAt": t.UpdatedAt.isoformat() if t.UpdatedAt else None,
                    "UpdatedByFullName": t.UpdatedByFullName,
                },
                "Attachments": [
                    {
                        "AttachmentId": a.AttachmentId,
                        "OriginalFileName": a.OriginalFileName,
                        "StoredRelPath": a.StoredRelPath,
                        "FileSizeBytes": a.FileSizeBytes,
                        "MimeType": a.MimeType,
                        "UploadedAt": a.UploadedAt.isoformat() if a.UploadedAt else None,
                        "UploadedByFullName": a.UploadedByFullName,
                        "DownloadUrl": f"/talepler_api?action=download_attachment&attachment_id={a.AttachmentId}",
                    }
                    for a in atts
                ],
                "Comments": [
                    {
                        "CommentId": c.CommentId,
                        "CommentText": c.CommentText,
                        "CreatedAt": c.CreatedAt.isoformat() if c.CreatedAt else None,
                        "CreatedByFullName": c.CreatedByFullName,
                        "IsAdminComment": bool(c.IsAdminComment),
                    }
                    for c in comms
                ],
                "IsAdmin": _is_admin()
            })

        # =========================
        # GET: Download attachment (visibility checked via ticket)
        # =========================
        if request.method == "GET" and action == "download_attachment":
            attachment_id = int(request.args.get("attachment_id") or 0)
            if attachment_id <= 0:
                abort(400, description="attachment_id gerekli.")

            cur.execute(
                f"""
                SELECT a.AttachmentId, a.TicketId, a.OriginalFileName, a.StoredRelPath
                FROM {TBL_ATTACH} a
                WHERE a.AttachmentId = ?
                """,
                attachment_id
            )
            a = cur.fetchone()
            if not a:
                abort(404, description="Attachment bulunamadı.")

            _check_ticket_visibility(cur, int(a.TicketId))

            rel_path = str(a.StoredRelPath).replace("\\", "/")
            static_root = current_app.static_folder or os.path.join(current_app.root_path, "static")
            abs_path = os.path.join(static_root, rel_path.replace("/", os.sep))

            if not os.path.isfile(abs_path):
                abort(404, description="Dosya disk üzerinde bulunamadı.")

            directory = os.path.dirname(abs_path)
            filename = os.path.basename(abs_path)
            return send_from_directory(directory, filename, as_attachment=True, download_name=a.OriginalFileName)

        # =========================
        # GET: Basic stats
        # =========================
        if request.method == "GET" and action == "stats":
            params = []
            where_sql = _visibility_where_for_list(params)

            # Status sayıları
            cur.execute(
                f"""
                SELECT t.Status, COUNT(1) AS Cnt
                FROM {TBL_TICKET} t
                WHERE {where_sql}
                GROUP BY t.Status
                """,
                *params
            )
            by_status = {r.Status: int(r.Cnt) for r in cur.fetchall()}

            # Genel ortalama çözüm süresi (Tamamlandı)
            cur.execute(
                f"""
                SELECT AVG(DATEDIFF(MINUTE, t.CreatedAt, t.CompletedAt)) AS AvgMin
                FROM {TBL_TICKET} t
                WHERE {where_sql}
                  AND t.Status = N'Tamamlandı'
                  AND t.CompletedAt IS NOT NULL
                """,
                *params
            )
            avg_min = cur.fetchone().AvgMin

            # ✅ Kategori bazlı ortalama çözüm süresi
            cur.execute(
                f"""
                SELECT
                    t.Category,
                    AVG(DATEDIFF(MINUTE, t.CreatedAt, t.CompletedAt)) AS AvgMin
                FROM {TBL_TICKET} t
                WHERE {where_sql}
                  AND t.Status = N'Tamamlandı'
                  AND t.CompletedAt IS NOT NULL
                  AND t.Category IS NOT NULL
                GROUP BY t.Category
                """,
                *params
            )
            by_cat = {}
            for r in cur.fetchall():
                cat = (r.Category or "").strip()
                by_cat[cat if cat else "-"] = int(r.AvgMin) if r.AvgMin is not None else None

            return jsonify({
                "ByStatus": by_status,
                "AvgResolutionMinutes": int(avg_min) if avg_min is not None else None,
                "AvgResolutionMinutesByCategory": by_cat
            })
        # =========================
        # POST: Create ticket (with attachments)
        # =========================
        if request.method == "POST" and action == "create_ticket":
            title = (request.form.get("title") or "").strip()
            description = (request.form.get("description") or "").strip()
            category = (request.form.get("category") or "").strip()
            is_urgent = 1 if (request.form.get("is_urgent") or "").lower() in ("1", "true", "yes", "on") else 0
            is_private = 1 if (request.form.get("is_private") or "").lower() in ("1", "true", "yes", "on") else 0
            project_id = request.form.get("project_id")
            project_id = int(project_id) if project_id not in (None, "", "null") else None

            if not title:
                abort(400, description="title boş olamaz.")
            if category not in ("-", "Minör Hata", "Majör Hata", "Ek Geliştirme", "Erişim Yetkisi", "Veri Değişikliği"):
                abort(400, description="category geçersiz.")

            actor = _actor_payload()
            if not actor["fullname"] or not actor["username"] or not actor["departman"]:
                abort(400, description="Session name/surname/username/departman eksik.")

            cur.execute(
                f"""
                INSERT INTO {TBL_TICKET}
                (CreatedByUsername, CreatedByFullName, CreatedByDepartman,
                 Title, Description, Category, IsUrgent, IsPrivate, ProjectId, Status,
                 CreatedAt)
                OUTPUT INSERTED.TicketId
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, N'Yeni', SYSDATETIME())
                """,
                actor["username"], actor["fullname"], actor["departman"],
                title, (description if description else None),
                category, is_urgent, is_private,
                project_id
            )
            ticket_id = int(cur.fetchone()[0])

            # Admin'lere push (varsa) - senin önceki davranışın
            try:
                my_conn = mysql.connection
                my_cur = my_conn.cursor()
                try:
                    my_cur.execute(
                        "SELECT apple_token FROM users1 WHERE username IN ('dogao','sevvalo') LIMIT 2"
                    )
                    rows = my_cur.fetchall()
                    for row in rows or []:
                        token = row.get("apple_token") if row else None
                        if token:
                            send_push_notification(
                                token=token,
                                title=f"YücePortal'da Talep #{ticket_id}",
                                message=f"{actor['username']} bir talep oluşturdu. -> {title}"
                            )
                finally:
                    try:
                        my_cur.close()
                    except Exception:
                        pass
            except Exception:
                pass

            _save_event(cur, ticket_id, "CREATED", None, {
                "Title": title,
                "Category": category,
                "IsUrgent": bool(is_urgent),
                "IsPrivate": bool(is_private),
                "ProjectId": project_id
            })

            saved_files = _save_attachments(cur, ticket_id)

            conn.commit()
            return jsonify({"ok": True, "TicketId": ticket_id, "SavedFiles": saved_files})

        # =========================
        # POST: Admin - Update ticket fields (dosya hariç)
        # =========================
        if request.method == "POST" and action == "update_ticket":
            if not _is_admin():
                abort(403, description="Admin gerekli.")

            ticket_id = int(request.form.get("ticket_id") or 0)
            if ticket_id <= 0:
                abort(400, description="ticket_id gerekli.")
            _check_ticket_visibility(cur, ticket_id)

            fields = {
                "title": "Title",
                "description": "Description",
                "category": "Category",
                "is_urgent": "IsUrgent",
                "is_private": "IsPrivate",
                "project_id": "ProjectId",
                "created_by_fullname": "CreatedByFullName",
                "created_by_departman": "CreatedByDepartman",
                "created_by_username": "CreatedByUsername",
            }

            updates = []
            params = []

            def _coerce_bool(v):
                return 1 if str(v).lower() in ("1", "true", "yes", "on") else 0

            cur.execute(
                f"""
                SELECT Title, Description, Category, IsUrgent, IsPrivate, ProjectId,
                       CreatedByUsername, CreatedByFullName, CreatedByDepartman
                FROM {TBL_TICKET}
                WHERE TicketId = ?
                """,
                ticket_id
            )
            old = cur.fetchone()
            if not old:
                abort(404, description="Ticket bulunamadı.")

            payload_old = {
                "Title": old.Title,
                "Description": old.Description,
                "Category": old.Category,
                "IsUrgent": bool(old.IsUrgent),
                "IsPrivate": bool(old.IsPrivate),
                "ProjectId": old.ProjectId,
                "CreatedByUsername": old.CreatedByUsername,
                "CreatedByFullName": old.CreatedByFullName,
                "CreatedByDepartman": old.CreatedByDepartman,
            }

            for form_key, col in fields.items():
                if form_key not in request.form:
                    continue
                v = request.form.get(form_key)

                if col in ("IsUrgent", "IsPrivate"):
                    v = _coerce_bool(v)
                elif col == "ProjectId":
                    v = int(v) if v not in (None, "", "null") else None
                elif col == "Category":
                    v = (v or "").strip()
                    if v not in ("-", "Minör Hata", "Majör Hata", "Ek Geliştirme", "Erişim Yetkisi", "Veri Değişikliği"):
                        abort(400, description="category geçersiz.")
                else:
                    v = (v or "").strip()
                    if col == "Title" and not v:
                        abort(400, description="title boş olamaz.")
                    v = v if v else None

                updates.append(f"{col} = ?")
                params.append(v)

            if not updates:
                abort(400, description="Güncellenecek alan yok.")

            actor = _actor_payload()
            updates.append("UpdatedAt = SYSDATETIME()")
            updates.append("UpdatedByUsername = ?")
            updates.append("UpdatedByFullName = ?")
            params.extend([actor["username"], actor["fullname"]])

            params.append(ticket_id)

            cur.execute(
                f"""
                UPDATE {TBL_TICKET}
                SET {", ".join(updates)}
                WHERE TicketId = ?
                """,
                *params
            )

            cur.execute(
                f"""
                SELECT Title, Description, Category, IsUrgent, IsPrivate, ProjectId,
                       CreatedByUsername, CreatedByFullName, CreatedByDepartman
                FROM {TBL_TICKET}
                WHERE TicketId = ?
                """,
                ticket_id
            )
            new = cur.fetchone()
            payload_new = {
                "Title": new.Title,
                "Description": new.Description,
                "Category": new.Category,
                "IsUrgent": bool(new.IsUrgent),
                "IsPrivate": bool(new.IsPrivate),
                "ProjectId": new.ProjectId,
                "CreatedByUsername": new.CreatedByUsername,
                "CreatedByFullName": new.CreatedByFullName,
                "CreatedByDepartman": new.CreatedByDepartman,
            }

            _save_event(cur, ticket_id, "EDITED", payload_old, payload_new)

            conn.commit()
            return jsonify({"ok": True, "TicketId": ticket_id})

        # =========================
        # POST: Admin - Set status
        # =========================
        if request.method == "POST" and action == "set_status":
            if not _is_admin():
                abort(403, description="Admin gerekli.")

            ticket_id = int(request.form.get("ticket_id") or 0)
            status = (request.form.get("status") or "").strip()

            if ticket_id <= 0:
                abort(400, description="ticket_id gerekli.")
            if status not in ("Görüldü", "İşlemde", "Tamamlandı", "İptal"):
                abort(400, description="status geçersiz.")

            cur.execute(f"SELECT Status FROM {TBL_TICKET} WHERE TicketId = ?", ticket_id)
            r = cur.fetchone()
            if not r:
                abort(404, description="Ticket bulunamadı.")
            old_status = r.Status

            ts_col = None
            if status == "Görüldü":
                ts_col = "SeenAt"
            elif status == "İşlemde":
                ts_col = "InProgressAt"
            elif status == "Tamamlandı":
                ts_col = "CompletedAt"
            elif status == "İptal":
                ts_col = "CancelledAt"

            actor = _actor_payload()

            cur.execute(
                f"""
                UPDATE {TBL_TICKET}
                SET Status = ?,
                    {ts_col} = COALESCE({ts_col}, SYSDATETIME()),
                    UpdatedAt = SYSDATETIME(),
                    UpdatedByUsername = ?,
                    UpdatedByFullName = ?
                WHERE TicketId = ?
                """,
                status, actor["username"], actor["fullname"], ticket_id
            )

            _save_event(cur, ticket_id, "STATUS_CHANGED", {"Status": old_status}, {"Status": status})
            _notify_ticket_status_changed(cur, ticket_id, status)

            conn.commit()
            return jsonify({"ok": True, "TicketId": ticket_id, "OldStatus": old_status, "NewStatus": status})

        # =========================
        # POST: Admin - Add comment (admin only)  ✅ artık owner'a notification + push var
        # =========================
        if request.method == "POST" and action == "add_comment":
            if not _is_admin():
                abort(403, description="Admin gerekli.")

            ticket_id = int(request.form.get("ticket_id") or 0)
            text = (request.form.get("comment_text") or "").strip()
            if ticket_id <= 0:
                abort(400, description="ticket_id gerekli.")
            if not text:
                abort(400, description="comment_text boş olamaz.")

            actor = _actor_payload()

            cur.execute(
                f"""
                INSERT INTO {TBL_COMMENT}
                (TicketId, CommentText, CreatedAt, CreatedByUsername, CreatedByFullName, IsAdminComment)
                VALUES (?, ?, SYSDATETIME(), ?, ?, 1)
                """,
                ticket_id, text, actor["username"], actor["fullname"]
            )

            _save_event(cur, ticket_id, "COMMENT_ADDED", None, {"len": len(text)})

            # ✅ yorum bildirimi
            _notify_ticket_commented(cur, ticket_id, text)

            conn.commit()
            return jsonify({"ok": True, "TicketId": ticket_id})

        # =========================
        # POST: Admin - Add project
        # =========================
        if request.method == "POST" and action == "add_project":
            if not _is_admin():
                abort(403, description="Admin gerekli.")

            name = (request.form.get("project_name") or "").strip()
            if not name:
                abort(400, description="project_name boş olamaz.")

            actor = _actor_payload()

            cur.execute(
                f"""
                INSERT INTO {TBL_PROJECT}
                (ProjectName, IsActive, CreatedAt, CreatedByUser, CreatedByName)
                OUTPUT INSERTED.ProjectId
                VALUES (?, 1, SYSDATETIME(), ?, ?)
                """,
                name, actor["username"], actor["fullname"]
            )
            pid = int(cur.fetchone()[0])

            conn.commit()
            return jsonify({"ok": True, "ProjectId": pid, "ProjectName": name})

        # =========================
        # POST: Admin - Toggle project active (silmek yerine)
        # =========================
        if request.method == "POST" and action == "toggle_project_active":
            if not _is_admin():
                abort(403, description="Admin gerekli.")

            project_id = int(request.form.get("project_id") or 0)
            is_active = 1 if (request.form.get("is_active") or "").lower() in ("1", "true", "yes", "on") else 0
            if project_id <= 0:
                abort(400, description="project_id gerekli.")

            cur.execute(
                f"""
                UPDATE {TBL_PROJECT}
                SET IsActive = ?
                WHERE ProjectId = ?
                """,
                is_active, project_id
            )

            conn.commit()
            return jsonify({"ok": True, "ProjectId": project_id, "IsActive": bool(is_active)})

        abort(400, description="Geçersiz action.")

    except pyodbc.Error as e:
        conn.rollback()
        abort(500, description=f"DB Error: {str(e)}")
    except Exception:
        conn.rollback()
        raise
    finally:
        try:
            conn.close()
        except Exception:
            pass

# CHAT

from pymysql.cursors import DictCursor
import pymysql

CHAT_UPLOAD_DIR = os.path.join(app.root_path, "static", "chat_uploads")
os.makedirs(CHAT_UPLOAD_DIR, exist_ok=True)

# 25 MB (istersen artır)
app.config["MAX_CONTENT_LENGTH"] = 25 * 1024 * 1024

ALLOWED_EXTS = {
    "png","jpg","jpeg","gif","webp",
    "pdf","doc","docx","xls","xlsx",
    "ppt","pptx","txt","csv","zip","rar"
}

CHAT_DB_NAME = (os.getenv("YUCEPORTAL_CHAT_DB") or "yuceportal_chat").strip() or "yuceportal_chat"
CHAT_SCHEMA_LOCK = Lock()
CHAT_SCHEMA_READY = False


def _chat_db_connect_kwargs(*, include_database=True, autocommit=False):
    kwargs = {
        "host": _get_mysql_setting("host", "localhost"),
        "user": _get_mysql_setting("user", "root"),
        "password": _get_mysql_setting("password", master_password),
        "charset": "utf8mb4",
        "cursorclass": DictCursor,
        "autocommit": autocommit,
    }
    if include_database:
        kwargs["database"] = CHAT_DB_NAME
    return kwargs


def ensure_chat_schema():
    global CHAT_SCHEMA_READY

    if CHAT_SCHEMA_READY:
        return

    with CHAT_SCHEMA_LOCK:
        if CHAT_SCHEMA_READY:
            return

        admin_conn = None
        cursor = None
        try:
            admin_conn = pymysql.connect(**_chat_db_connect_kwargs(include_database=False, autocommit=True))
            cursor = admin_conn.cursor()
            cursor.execute(
                f"CREATE DATABASE IF NOT EXISTS `{CHAT_DB_NAME}` "
                "CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci"
            )
            cursor.execute(f"USE `{CHAT_DB_NAME}`")

            schema_statements = [
                """
                CREATE TABLE IF NOT EXISTS chat_threads (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    thread_type VARCHAR(32) NOT NULL,
                    title VARCHAR(255) NULL,
                    context_type VARCHAR(128) NULL,
                    context_id VARCHAR(255) NULL,
                    created_by VARCHAR(255) NULL,
                    is_archived TINYINT(1) NOT NULL DEFAULT 0,
                    created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
                    PRIMARY KEY (id),
                    KEY idx_chat_threads_type_archived (thread_type, is_archived),
                    KEY idx_chat_threads_context (context_type, context_id),
                    KEY idx_chat_threads_created_by (created_by)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci
                """,
                """
                CREATE TABLE IF NOT EXISTS chat_participants (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    thread_id BIGINT UNSIGNED NOT NULL,
                    username VARCHAR(255) NOT NULL,
                    role VARCHAR(32) NOT NULL DEFAULT 'member',
                    joined_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
                    left_at DATETIME(3) NULL,
                    last_read_message_id BIGINT UNSIGNED NOT NULL DEFAULT 0,
                    last_read_at DATETIME(3) NULL,
                    PRIMARY KEY (id),
                    UNIQUE KEY uq_chat_participants_thread_user (thread_id, username),
                    KEY idx_chat_participants_user_left (username, left_at),
                    KEY idx_chat_participants_thread_left (thread_id, left_at)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci
                """,
                """
                CREATE TABLE IF NOT EXISTS chat_messages (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    thread_id BIGINT UNSIGNED NOT NULL,
                    sender_username VARCHAR(255) NOT NULL,
                    message_type VARCHAR(32) NOT NULL DEFAULT 'text',
                    body MEDIUMTEXT NULL,
                    attachment_id BIGINT UNSIGNED NULL,
                    reply_to_message_id BIGINT UNSIGNED NULL,
                    created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
                    deleted_at DATETIME(3) NULL,
                    PRIMARY KEY (id),
                    KEY idx_chat_messages_thread_id (thread_id, id),
                    KEY idx_chat_messages_thread_deleted (thread_id, deleted_at, id),
                    KEY idx_chat_messages_reply (reply_to_message_id)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci
                """,
                """
                CREATE TABLE IF NOT EXISTS chat_message_reactions (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    message_id BIGINT UNSIGNED NOT NULL,
                    thread_id BIGINT UNSIGNED NOT NULL,
                    username VARCHAR(255) NOT NULL,
                    emoji VARCHAR(32) NOT NULL,
                    created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
                    PRIMARY KEY (id),
                    UNIQUE KEY uq_chat_reactions_unique (message_id, username, emoji),
                    KEY idx_chat_reactions_thread_msg (thread_id, message_id),
                    KEY idx_chat_reactions_message (message_id)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci
                """,
                """
                CREATE TABLE IF NOT EXISTS chat_message_attachments (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    thread_id BIGINT UNSIGNED NOT NULL,
                    uploader_username VARCHAR(255) NOT NULL,
                    original_name VARCHAR(255) NOT NULL,
                    stored_name VARCHAR(255) NOT NULL,
                    mime_type VARCHAR(255) NOT NULL,
                    file_ext VARCHAR(32) NULL,
                    file_size BIGINT UNSIGNED NOT NULL DEFAULT 0,
                    created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
                    PRIMARY KEY (id),
                    UNIQUE KEY uq_chat_attachments_stored (stored_name),
                    KEY idx_chat_attachments_thread_id (thread_id, id)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci
                """,
                """
                CREATE TABLE IF NOT EXISTS chat_typing_status (
                    id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
                    thread_id BIGINT UNSIGNED NOT NULL,
                    username VARCHAR(255) NOT NULL,
                    is_typing TINYINT(1) NOT NULL DEFAULT 0,
                    updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
                    PRIMARY KEY (id),
                    UNIQUE KEY uq_chat_typing_thread_user (thread_id, username),
                    KEY idx_chat_typing_thread_updated (thread_id, updated_at)
                ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci
                """,
            ]

            for statement in schema_statements:
                cursor.execute(statement)

            CHAT_SCHEMA_READY = True
        finally:
            try:
                if cursor:
                    cursor.close()
            except Exception:
                pass
            try:
                if admin_conn:
                    admin_conn.close()
            except Exception:
                pass

def _fetch_active_users_map(usernames):
    """
    ya_rpa.users1 tablosundan aktif kullanıcıları çeker.
    return: {username: {"name":..., "surname":...}}
    """
    if not usernames:
        return {}

    # duplicate temizle
    uniq = list(dict.fromkeys([u.strip() for u in usernames if u and str(u).strip()]))

    conn = mysql.connection
    cur = conn.cursor()

    placeholders = ",".join(["%s"] * len(uniq))
    cur.execute(f"""
        SELECT username, name, surname
        FROM users1
        WHERE is_active=1 AND username IN ({placeholders})
    """, tuple(uniq))
    rows = cur.fetchall() or []
    cur.close()

    out = {}
    for r in rows:
        out[r["username"]] = {
            "name": (r.get("name") or "").strip(),
            "surname": (r.get("surname") or "").strip()
        }
    return out

def _is_participant(cursor, thread_id, username):
    cursor.execute("""
        SELECT role
        FROM chat_participants
        WHERE thread_id=%s AND username=%s AND left_at IS NULL
        LIMIT 1
    """, (thread_id, username))
    return cursor.fetchone()

def get_chat_conn():
    ensure_chat_schema()
    return pymysql.connect(**_chat_db_connect_kwargs(include_database=True, autocommit=False))

@app.route("/api/chat/threads", methods=["POST"])
@login_required
def api_chat_threads():
    username = session.get("username")
    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401

    try:
        chat_conn = get_chat_conn()
        chat_cur = chat_conn.cursor()
    except Exception as e:
        print("api_chat_threads connection error:", e)
        return jsonify({"status": "success", "data": []})

    users_conn = mysql.connection
    users_cur = users_conn.cursor()

    try:
        chat_cur.execute("""
            SELECT
                t.id,
                t.thread_type,
                t.title,
                t.context_type,
                t.context_id,
                t.created_by,
                t.created_at,
                p.last_read_message_id
            FROM chat_participants p
            JOIN chat_threads t ON t.id = p.thread_id
            WHERE p.username = %s
              AND p.left_at IS NULL
              AND t.is_archived = 0
            ORDER BY t.id DESC
        """, (username,))
        threads = chat_cur.fetchall() or []

        out = []
        for t in threads:
            thread_id = t["id"]
            last_read_id = t.get("last_read_message_id") or 0

            other_username = None
            other_fullname = None
            display_title = (t.get("title") or "").strip()

            if t.get("thread_type") == "self":
                display_title = display_title or "Notlarım"

            if t.get("thread_type") == "dm":
                chat_cur.execute("""
                    SELECT p.username
                    FROM chat_participants p
                    WHERE p.thread_id = %s
                    AND p.username <> %s
                    ORDER BY p.joined_at ASC
                    LIMIT 1
                """, (thread_id, username))
                ou = chat_cur.fetchone()
                other_username = ou["username"] if ou else None

                if other_username:
                    users_cur.execute("""
                        SELECT name, surname
                        FROM users1
                        WHERE username = %s
                        LIMIT 1
                    """, (other_username,))
                    urow = users_cur.fetchone()
                    if urow:
                        other_fullname = f"{(urow.get('name') or '').strip()} {(urow.get('surname') or '').strip()}".strip()

                if not display_title:
                    display_title = other_fullname or other_username or "DM"

            # ✅ Son mesaj (reply_to dahil)
            chat_cur.execute("""
                SELECT id, sender_username, body, created_at, reply_to_message_id
                FROM chat_messages
                WHERE thread_id = %s AND deleted_at IS NULL
                ORDER BY id DESC
                LIMIT 1
            """, (thread_id,))
            last_msg = chat_cur.fetchone()

            chat_cur.execute("""
                SELECT COUNT(*) AS c
                FROM chat_messages
                WHERE thread_id = %s
                  AND deleted_at IS NULL
                  AND id > %s
                  AND sender_username <> %s
            """, (thread_id, last_read_id, username))
            unread = chat_cur.fetchone()
            unread_count = int(unread["c"] if unread else 0)

            out.append({
                "id": int(thread_id),
                "thread_type": t["thread_type"],
                "title": t["title"],
                "display_title": display_title,
                "other_username": other_username,
                "other_fullname": other_fullname,
                "context_type": t["context_type"],
                "context_id": t["context_id"],
                "created_by": t["created_by"],
                "created_at": (
                    t["created_at"].strftime("%Y-%m-%d %H:%M:%S")
                    if hasattr(t["created_at"], "strftime") else str(t["created_at"])
                ),
                "last_read_message_id": int(last_read_id),
                "unread_count": unread_count,
                "last_message": (None if not last_msg else {
                    "id": int(last_msg["id"]),
                    "sender_username": last_msg["sender_username"],
                    "body": last_msg["body"],
                    "reply_to_message_id": (int(last_msg["reply_to_message_id"]) if last_msg.get("reply_to_message_id") else None),
                    "created_at": (
                        last_msg["created_at"].strftime("%Y-%m-%d %H:%M:%S")
                        if hasattr(last_msg["created_at"], "strftime") else str(last_msg["created_at"])
                    )
                })
            })

        chat_conn.commit()
        return jsonify({"status": "success", "data": out})

    except Exception as e:
        chat_conn.rollback()
        print("api_chat_threads error:", e)
        return jsonify({"status": "success", "data": []})

    finally:
        try:
            chat_cur.close()
            chat_conn.close()
        except:
            pass
        try:
            users_cur.close()
        except:
            pass

@app.route("/api/chat/context_thread", methods=["POST"])
@login_required
def api_chat_context_thread():
    data = request.json or {}
    username = session.get("username")

    context_type = (data.get("context_type") or "").strip()
    context_id = (data.get("context_id") or "").strip()
    title = (data.get("title") or "").strip() or None

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not context_type or not context_id:
        return jsonify({"status": "error", "message": "context_type and context_id are required"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Aynı context için thread var mı?
        cursor.execute("""
            SELECT id
            FROM chat_threads
            WHERE thread_type='context'
              AND context_type=%s
              AND context_id=%s
              AND is_archived=0
            LIMIT 1
        """, (context_type, context_id))
        row = cursor.fetchone()

        if row:
            thread_id = row["id"]
        else:
            # Oluştur
            cursor.execute("""
                INSERT INTO chat_threads (thread_type, title, context_type, context_id, created_by)
                VALUES ('context', %s, %s, %s, %s)
            """, (title, context_type, context_id, username))
            thread_id = cursor.lastrowid

        # Kullanıcı participant değilse ekle
        cursor.execute("""
            SELECT 1 FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        p = cursor.fetchone()
        if not p:
            cursor.execute("""
                INSERT INTO chat_participants (thread_id, username, role)
                VALUES (%s, %s, 'member')
            """, (thread_id, username))

        conn.commit()

        return jsonify({"status": "success", "data": {"thread_id": thread_id}})

    except Exception as e:
        conn.rollback()
        print("api_chat_context_thread error:", e)
        return jsonify({"status": "error", "message": "Failed to create/get context thread"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/messages", methods=["POST"])
@login_required
def api_chat_messages():
    data = request.json or {}
    username = session.get("username")

    thread_id = data.get("thread_id")
    limit = int(data.get("limit") or 50)
    before_id = data.get("before_id")
    after_id  = data.get("after_id")  # polling

    # ---- Ayarlar ----
    # Bot kullanıcı ad(lar)ı burada olsun (gerekirse ekle)
    BOT_USERNAMES = {"yugii"}  # örn: {"yugii", "assistant_bot"}
    # İlk yüklemede kaç "tur" (user mesajı) gösterilecek?
    INITIAL_TURNS = 10
    # İlk yükleme için DB'den alınacak güvenli buffer (turn başına 2-3 mesaj düşün)
    INITIAL_BUFFER = 80

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status": "error", "message": "thread_id is required"}), 400
    if limit < 1 or limit > 200:
        limit = 50

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki
        cursor.execute("""
            SELECT 1
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # Participants (okundu hesabı için)
        cursor.execute("""
            SELECT username, last_read_message_id, last_read_at
            FROM chat_participants
            WHERE thread_id=%s AND left_at IS NULL
        """, (thread_id,))
        participants = cursor.fetchall() or []

        read_map = {
            p["username"]: (int(p.get("last_read_message_id") or 0), p.get("last_read_at"))
            for p in participants
        }
        other_usernames = [p["username"] for p in participants if p["username"] != username]

        base_select = """
            SELECT
              id, thread_id, sender_username, message_type, body,
              attachment_id, reply_to_message_id, created_at
            FROM chat_messages
            WHERE thread_id=%s AND deleted_at IS NULL
        """

        rows = []

        # --------------------------
        # 1) Polling (after_id) aynen
        # --------------------------
        if after_id:
            cursor.execute(
                base_select + " AND id > %s ORDER BY id ASC LIMIT %s",
                (thread_id, int(after_id), limit)
            )
            rows = cursor.fetchall() or []

        # --------------------------------
        # 2) Older messages (before_id) aynen
        # --------------------------------
        elif before_id:
            cursor.execute(
                base_select + " AND id < %s ORDER BY id DESC LIMIT %s",
                (thread_id, int(before_id), limit)
            )
            rows = cursor.fetchall() or []
            rows.reverse()

        # --------------------------------
        # 3) İlk yükleme: sadece son 10 tur
        # --------------------------------
        else:
            # Önce sondan buffer çek
            cursor.execute(
                base_select + " ORDER BY id DESC LIMIT %s",
                (thread_id, INITIAL_BUFFER)
            )
            buf = cursor.fetchall() or []
            buf.reverse()  # kronolojik

            if not buf:
                return jsonify({"status": "success", "data": []})

            # Son 10 user mesajının başladığı cutoff id'yi bul
            turns_found = 0
            cutoff_id = None

            # sondan başa tarıyoruz
            for r in reversed(buf):
                sender = (r.get("sender_username") or "")
                # "tur" sayımı: user mesajı = bot olmayan ve benim olmayan? hayır, burası "yugii dışı" olan her mesaj
                # Eğer gruplu chat'te farklı user'lar varsa: bot olmayan her mesajı tur kabul eder.
                if sender not in BOT_USERNAMES:
                    turns_found += 1
                    if turns_found == INITIAL_TURNS:
                        cutoff_id = int(r["id"])
                        break

            # Eğer yeterli tur yoksa buffer'ın hepsini dön
            if cutoff_id is None:
                rows = buf
            else:
                # cutoff_id ve sonrasını tekrar DB'den çek (cevapları da garanti dahil etmek için)
                cursor.execute(
                    base_select + " AND id >= %s ORDER BY id ASC",
                    (thread_id, cutoff_id)
                )
                rows = cursor.fetchall() or []

        # ---- ✅ REACTIONS: bu sayfadaki mesajların reaction özetini tek seferde çek ----
        message_ids = [int(r["id"]) for r in rows] if rows else []
        reactions_map = {}  # {mid: {emoji: {count, i_reacted}}}

        if message_ids:
            placeholders = ",".join(["%s"] * len(message_ids))
            cursor.execute(f"""
                SELECT
                  message_id,
                  emoji,
                  COUNT(*) AS cnt,
                  SUM(username=%s) AS i_reacted
                FROM chat_message_reactions
                WHERE thread_id=%s
                  AND message_id IN ({placeholders})
                GROUP BY message_id, emoji
            """, tuple([username, int(thread_id)] + message_ids))

            rrows = cursor.fetchall() or []
            for rr in rrows:
                mid = int(rr["message_id"])
                emj = rr["emoji"]
                reactions_map.setdefault(mid, {})
                reactions_map[mid][emj] = {
                    "count": int(rr["cnt"] or 0),
                    "i_reacted": bool(rr["i_reacted"])
                }

        # Bu sayfadaki reply hedeflerini tek seferde çekmek için
        reply_ids = sorted({int(r["reply_to_message_id"]) for r in rows if r.get("reply_to_message_id")})
        reply_map = {}
        if reply_ids:
            placeholders = ",".join(["%s"] * len(reply_ids))
            cursor.execute(f"""
                SELECT id, thread_id, sender_username, message_type, body, attachment_id, created_at
                FROM chat_messages
                WHERE thread_id=%s
                  AND id IN ({placeholders})
                  AND deleted_at IS NULL
            """, tuple([int(thread_id)] + reply_ids))
            rep_rows = cursor.fetchall() or []
            for rr in rep_rows:
                reply_map[int(rr["id"])] = rr

        # attachment meta cache (hem normal mesaj hem reply preview için)
        att_ids = set()
        for r in rows:
            if r.get("attachment_id"):
                att_ids.add(int(r["attachment_id"]))
        for _, rr in reply_map.items():
            if rr.get("attachment_id"):
                att_ids.add(int(rr["attachment_id"]))

        att_map = {}
        if att_ids:
            placeholders = ",".join(["%s"] * len(att_ids))
            cursor.execute(f"""
                SELECT id, original_name, mime_type, file_size
                FROM chat_message_attachments
                WHERE id IN ({placeholders})
            """, tuple(att_ids))
            arows = cursor.fetchall() or []
            for a in arows:
                att_map[int(a["id"])] = a

        messages = []
        for r in rows:
            mid = int(r["id"])

            seen_by = []
            seen_by_all = False
            seen_count = 0
            seen_at_max = None
            delivery_status = "delivered"

            # sadece benim mesajlarım için okundu hesabı
            if r["sender_username"] == username and other_usernames:
                for ou in other_usernames:
                    ou_last_read_id, ou_last_read_at = read_map.get(ou, (0, None))
                    if int(ou_last_read_id) >= mid:
                        seen_by.append(ou)
                        if ou_last_read_at and (seen_at_max is None or ou_last_read_at > seen_at_max):
                            seen_at_max = ou_last_read_at

                seen_count = len(seen_by)
                seen_by_all = (seen_count == len(other_usernames))
                delivery_status = "read" if seen_by_all else "delivered"

            msg = {
                "id": mid,
                "thread_id": int(r["thread_id"]),
                "sender_username": r["sender_username"],
                "message_type": r["message_type"],
                "body": r["body"],
                "created_at": (
                    r["created_at"].strftime("%Y-%m-%d %H:%M:%S")
                    if hasattr(r["created_at"], "strftime") else str(r["created_at"])
                ),

                "reply_to_message_id": (int(r["reply_to_message_id"]) if r.get("reply_to_message_id") else None),

                "status": delivery_status,
                "is_read": (delivery_status == "read"),
                "seen_by_all": seen_by_all,
                "seen_by": seen_by,
                "seen_count": seen_count,
                "seen_at": (
                    seen_at_max.strftime("%Y-%m-%d %H:%M:%S.%f")[:-3]
                    if hasattr(seen_at_max, "strftime") else None
                ),

                "reactions": reactions_map.get(mid, {})
            }

            # attachment meta
            att_id = r.get("attachment_id")
            if att_id and int(att_id) in att_map:
                a = att_map[int(att_id)]
                msg["attachment"] = {
                    "attachment_id": int(a["id"]),
                    "original_name": a["original_name"],
                    "mime_type": a["mime_type"],
                    "file_size": int(a["file_size"]),
                    "download_url": f"/api/chat/file/{a['id']}"
                }

            # reply preview
            rid = msg["reply_to_message_id"]
            if rid and rid in reply_map:
                rr = reply_map[rid]
                rr_body = (rr.get("body") or "")
                rr_body_stripped = rr_body.strip()

                prev = {
                    "id": int(rr["id"]),
                    "sender_username": rr["sender_username"],
                    "message_type": rr["message_type"],
                    "body": rr_body,
                    "created_at": (
                        rr["created_at"].strftime("%Y-%m-%d %H:%M:%S")
                        if hasattr(rr["created_at"], "strftime") else str(rr["created_at"])
                    ),
                    "snippet": (
                        rr_body_stripped[:180]
                        if rr_body_stripped
                        else ("📎 Dosya" if rr.get("attachment_id") else "(mesaj)")
                    )
                }

                ratt = rr.get("attachment_id")
                if ratt and int(ratt) in att_map:
                    a = att_map[int(ratt)]
                    prev["attachment"] = {
                        "attachment_id": int(a["id"]),
                        "original_name": a["original_name"],
                        "mime_type": a["mime_type"],
                        "file_size": int(a["file_size"]),
                        "download_url": f"/api/chat/file/{a['id']}"
                    }
                    if not rr_body_stripped:
                        prev["snippet"] = f"📎 {a['original_name']}"

                msg["reply_preview"] = prev
            else:
                msg["reply_preview"] = None

            messages.append(msg)

        return jsonify({"status": "success", "data": messages})

    except Exception as e:
        print("api_chat_messages error:", e)
        return jsonify({"status": "error", "message": "Failed to fetch messages"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/send", methods=["POST"])
@login_required
def api_chat_send():
    data = request.json or {}
    username = session.get("username")

    thread_id = data.get("thread_id")
    body = (data.get("body") or "").strip()
    attachment_id = data.get("attachment_id")
    reply_to_message_id = data.get("reply_to_message_id")  # ✅ NEW

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status": "error", "message": "thread_id is required"}), 400

    if not body and not attachment_id:
        return jsonify({"status": "error", "message": "body or attachment_id is required"}), 400
    if body and len(body) > 5000:
        return jsonify({"status": "error", "message": "Message too long"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki
        cursor.execute("""
            SELECT 1 FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # reply_to doğrula (aynı thread + silinmemiş)
        reply_preview = None
        reply_to_id_int = None
        if reply_to_message_id:
            try:
                reply_to_id_int = int(reply_to_message_id)
            except:
                return jsonify({"status":"error","message":"reply_to_message_id invalid"}), 400

            reply_preview = _get_reply_preview(cursor, int(thread_id), reply_to_id_int)
            if not reply_preview:
                return jsonify({"status":"error","message":"Reply target not found in this thread"}), 400

        msg_type = "text"
        att = None

        # attachment doğrula
        if attachment_id:
            msg_type = "file"
            cursor.execute("""
                SELECT id, original_name, mime_type, file_size
                FROM chat_message_attachments
                WHERE id=%s AND thread_id=%s
                LIMIT 1
            """, (attachment_id, thread_id))
            att = cursor.fetchone()
            if not att:
                return jsonify({"status":"error","message":"Invalid attachment"}), 400

        # ✅ reply_to_message_id + attachment_id tek seferde insert (kolonlar DB'de olmalı)
        cursor.execute("""
            INSERT INTO chat_messages
              (thread_id, sender_username, message_type, body, attachment_id, reply_to_message_id)
            VALUES
              (%s, %s, %s, %s, %s, %s)
        """, (thread_id, username, msg_type, body, attachment_id if attachment_id else None, reply_to_id_int))

        message_id = cursor.lastrowid

        conn.commit()
        Write_Log_ToDB(username, "POST", "/api/chat/send", 0, f"Message sent thread_id={thread_id} message_id={message_id}")

        # created_at al
        cursor.execute("SELECT created_at FROM chat_messages WHERE id=%s LIMIT 1", (message_id,))
        r = cursor.fetchone()
        created_at = ""
        if r and r.get("created_at"):
            created_at = r["created_at"].strftime("%Y-%m-%d %H:%M:%S") if hasattr(r["created_at"], "strftime") else str(r["created_at"])

        payload = {
            "id": int(message_id),
            "thread_id": int(thread_id),
            "sender_username": username,
            "message_type": msg_type,
            "body": body,
            "created_at": created_at,
            "status": "delivered",

            "reply_to_message_id": reply_to_id_int,
            "reply_preview": reply_preview
        }

        if attachment_id and att:
            payload["attachment"] = {
                "attachment_id": int(att["id"]),
                "original_name": att["original_name"],
                "mime_type": att["mime_type"],
                "file_size": int(att["file_size"]),
                "download_url": f"/api/chat/file/{att['id']}"
            }

        # push
        cursor.execute(
            "SELECT DISTINCT username FROM chat_participants WHERE thread_id=%s AND username <> %s",
            (int(thread_id), username)
        )
        participants = cursor.fetchall() or []
        push_executor.submit(_send_push_to_participants, participants, username, body)

        return jsonify({"status":"success", "data": payload})

    except Exception as e:
        conn.rollback()
        print("api_chat_send error:", e)
        return jsonify({"status": "error", "message": "Failed to send message"}), 500
    finally:
        cursor.close()
        conn.close()

def _get_reply_preview(cursor, thread_id: int, reply_to_id: int):
    """
    reply_to_id'nin aynı thread içinde var olup olmadığını doğrular.
    Varsa küçük bir preview dict döndürür, yoksa None.

    UI'ın düzgün gösterebilmesi için:
      - snippet alanı eklenmiştir
      - (opsiyonel) attachment meta eklenir
    """
    if not reply_to_id:
        return None

    cursor.execute("""
        SELECT id, sender_username, message_type, body, attachment_id, created_at
        FROM chat_messages
        WHERE id=%s AND thread_id=%s AND deleted_at IS NULL
        LIMIT 1
    """, (int(reply_to_id), int(thread_id)))
    r = cursor.fetchone()
    if not r:
        return None

    body_text = (r.get("body") or "")
    body_text_stripped = body_text.strip()

    preview = {
        "id": int(r["id"]),
        "sender_username": r["sender_username"],
        "message_type": r["message_type"],
        "body": body_text,
        "created_at": (
            r["created_at"].strftime("%Y-%m-%d %H:%M:%S")
            if hasattr(r["created_at"], "strftime") else str(r["created_at"])
        ),

        # ✅ UI bunu bekliyor (front-end reply quote bununla çalışıyor)
        "snippet": (
            body_text_stripped[:180]
            if body_text_stripped
            else ("📎 Dosya" if r.get("attachment_id") else "(mesaj)")
        )
    }

    # reply edilen mesaj file ise attachment meta da ekleyelim (UI isterse gösterebilir)
    att_id = r.get("attachment_id")
    if att_id:
        cursor.execute("""
            SELECT id, original_name, mime_type, file_size
            FROM chat_message_attachments
            WHERE id=%s
            LIMIT 1
        """, (att_id,))
        a = cursor.fetchone()
        if a:
            preview["attachment"] = {
                "attachment_id": int(a["id"]),
                "original_name": a["original_name"],
                "mime_type": a["mime_type"],
                "file_size": int(a["file_size"]),
                "download_url": f"/api/chat/file/{a['id']}"
            }

            # ✅ file reply’larında snippet’i daha anlamlı yapalım
            # (body boşsa zaten "📎 Dosya" diyordu; burada isim de eklenir)
            if not body_text_stripped:
                preview["snippet"] = f"📎 {a['original_name']}"

    return preview

@app.route("/api/chat/mark_read", methods=["POST"])
@login_required
def api_chat_mark_read():
    data = request.json or {}
    username = session.get("username")

    thread_id = data.get("thread_id")
    last_read_message_id = data.get("last_read_message_id")  # optional artık

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status": "error", "message": "thread_id is required"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki
        cursor.execute("""
            SELECT 1
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # Eğer client son id göndermediyse: thread’in son mesaj id’sini bul
        if not last_read_message_id:
            cursor.execute("""
                SELECT MAX(id) AS mx
                FROM chat_messages
                WHERE thread_id=%s AND deleted_at IS NULL
            """, (thread_id,))
            row = cursor.fetchone()
            last_read_message_id = int(row["mx"] or 0)

        new_last = int(last_read_message_id or 0)
        if new_last <= 0:
            return jsonify({"status": "success", "data": {"thread_id": thread_id, "read_up_to_id": 0}})

        # last_read sadece ileri gitsin
        cursor.execute("""
            SELECT last_read_message_id
            FROM chat_participants
            WHERE thread_id=%s AND username=%s
            LIMIT 1
        """, (thread_id, username))
        currow = cursor.fetchone()
        current_last = int((currow["last_read_message_id"] or 0) if currow else 0)

        if new_last > current_last:
            cursor.execute("""
                UPDATE chat_participants
                SET last_read_message_id=%s, last_read_at=NOW(3)
                WHERE thread_id=%s AND username=%s
            """, (new_last, thread_id, username))

        conn.commit()

        return jsonify({
            "status": "success",
            "data": {
                "thread_id": thread_id,
                "read_up_to_id": max(current_last, new_last)
            }
        })

    except Exception as e:
        conn.rollback()
        print("api_chat_mark_read error:", e)
        return jsonify({"status": "error", "message": "Failed to mark read"}), 500
    finally:
        cursor.close()
        conn.close()
        
@app.route("/api/chat/reaction_toggle", methods=["POST"])
@login_required
def api_chat_reaction_toggle():
    data = request.json or {}
    username = session.get("username")

    message_id = data.get("message_id")
    emoji = (data.get("emoji") or "").strip()

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not message_id or not emoji:
        return jsonify({"status": "error", "message": "message_id and emoji are required"}), 400
    if len(emoji) > 16:
        return jsonify({"status": "error", "message": "emoji too long"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # message -> thread_id
        cursor.execute("""
            SELECT thread_id
            FROM chat_messages
            WHERE id=%s AND deleted_at IS NULL
            LIMIT 1
        """, (message_id,))
        msg = cursor.fetchone()
        if not msg:
            return jsonify({"status": "error", "message": "Message not found"}), 404
        thread_id = msg["thread_id"]

        # participant mi?
        cursor.execute("""
            SELECT 1 FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # var mı?
        cursor.execute("""
            SELECT id
            FROM chat_message_reactions
            WHERE message_id=%s AND username=%s AND emoji=%s
            LIMIT 1
        """, (message_id, username, emoji))
        existing = cursor.fetchone()

        if existing:
            cursor.execute("DELETE FROM chat_message_reactions WHERE id=%s", (existing["id"],))
            action = "removed"
        else:
            cursor.execute("""
                INSERT INTO chat_message_reactions (message_id, thread_id, username, emoji)
                VALUES (%s, %s, %s, %s)
            """, (message_id, thread_id, username, emoji))
            action = "added"

        conn.commit()
        Write_Log_ToDB(username, "POST", "/api/chat/reaction_toggle", 0, f"Reaction {action} msg={message_id} emoji={emoji}")

        return jsonify({"status": "success", "data": {"action": action, "message_id": message_id, "emoji": emoji}})

    except Exception as e:
        conn.rollback()
        print("api_chat_reaction_toggle error:", e)
        return jsonify({"status": "error", "message": "Failed to toggle reaction"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/reactions_summary", methods=["POST"])
@login_required
def api_chat_reactions_summary():
    data = request.json or {}
    username = session.get("username")

    thread_id = data.get("thread_id")
    message_ids = data.get("message_ids")  # liste

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not thread_id or not isinstance(message_ids, list) or len(message_ids) == 0:
        return jsonify({"status": "error", "message": "thread_id and message_ids(list) are required"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # yetki
        cursor.execute("""
            SELECT 1 FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # IN clause
        placeholders = ",".join(["%s"] * len(message_ids))

        cursor.execute(f"""
            SELECT
              message_id,
              emoji,
              COUNT(*) AS cnt,
              SUM(username=%s) AS i_reacted
            FROM chat_message_reactions
            WHERE thread_id=%s
              AND message_id IN ({placeholders})
            GROUP BY message_id, emoji
        """, tuple([username, thread_id] + message_ids))

        rows = cursor.fetchall() or []

        # message_id -> list of {emoji,cnt,i_reacted}
        out = {}
        for r in rows:
            mid = r["message_id"]
            out.setdefault(mid, [])
            out[mid].append({
                "emoji": r["emoji"],
                "count": int(r["cnt"]),
                "i_reacted": bool(r["i_reacted"]),
            })

        return jsonify({"status": "success", "data": out})

    except Exception as e:
        print("api_chat_reactions_summary error:", e)
        return jsonify({"status": "error", "message": "Failed to fetch reactions summary"}), 500
    finally:
        cursor.close()
        conn.close()

