@app.route("/api/chat/start_dm", methods=["POST"])
@login_required
def api_chat_start_dm():
    data = request.json or {}
    other_username = (data.get("username") or "").strip()
    me = session.get("username")

    if not me:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not other_username:
        return jsonify({"status": "error", "message": "username required"}), 400
    if other_username == me:
        return jsonify({"status": "error", "message": "cannot dm yourself"}), 400

    # ✅ önce ya_rpa.users1’den user doğrula + ad soyad al
    users_conn = mysql.connection
    users_cur = users_conn.cursor()
    users_cur.execute("""
        SELECT name, surname
        FROM users1
        WHERE is_active = 1
          AND username = %s
        LIMIT 1
    """, (other_username,))
    u = users_cur.fetchone()
    users_cur.close()

    if not u:
        return jsonify({"status": "error", "message": "user not found or inactive"}), 404

    other_fullname = f"{(u.get('name') or '').strip()} {(u.get('surname') or '').strip()}".strip()
    display_title = other_fullname or other_username

    # ✅ chat DB işlemleri
    conn = get_chat_conn()
    cursor = conn.cursor()

    try:
        # 1️⃣ Var mı kontrol et
        cursor.execute("""
            SELECT t.id
            FROM chat_threads t
            JOIN chat_participants p1 ON p1.thread_id = t.id AND p1.username = %s AND p1.left_at IS NULL
            JOIN chat_participants p2 ON p2.thread_id = t.id AND p2.username = %s AND p2.left_at IS NULL
            WHERE t.thread_type = 'dm'
              AND t.is_archived = 0
            ORDER BY t.id DESC
            LIMIT 1
        """, (me, other_username))

        row = cursor.fetchone()
        if row:
            conn.commit()
            return jsonify({
                "status": "success",
                "thread_id": row["id"],
                "other_username": other_username,
                "other_fullname": other_fullname,
                "display_title": display_title
            })

        # 2️⃣ Yoksa oluştur
        cursor.execute("""
            INSERT INTO chat_threads (thread_type, created_by)
            VALUES ('dm', %s)
        """, (me,))
        thread_id = cursor.lastrowid

        cursor.executemany("""
            INSERT INTO chat_participants (thread_id, username, role)
            VALUES (%s, %s, 'member')
        """, [
            (thread_id, me),
            (thread_id, other_username)
        ])

        conn.commit()
        return jsonify({
            "status": "success",
            "thread_id": thread_id,
            "other_username": other_username,
            "other_fullname": other_fullname,
            "display_title": display_title
        })

    except Exception as e:
        conn.rollback()
        print("start_dm error:", e)
        return jsonify({"status": "error", "message": "Failed to start dm"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/upload", methods=["POST"])
@login_required
def api_chat_upload():
    username = session.get("username")
    if not username:
        return jsonify({"status":"error","message":"Unauthorized"}), 401

    thread_id = request.form.get("thread_id", type=int)
    f = request.files.get("file")

    if not thread_id:
        return jsonify({"status":"error","message":"thread_id is required"}), 400
    if not f or not f.filename:
        return jsonify({"status":"error","message":"file is required"}), 400

    original_name = f.filename
    safe_name = secure_filename(original_name) or "file"
    ext = (safe_name.rsplit(".", 1)[-1].lower() if "." in safe_name else "")

    if ext and ext not in ALLOWED_EXTS:
        return jsonify({"status":"error","message":"File type not allowed"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki
        cursor.execute("""
            SELECT 1
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status":"error","message":"Forbidden"}), 403

        stored_name = f"{uuid.uuid4().hex}.{ext}" if ext else uuid.uuid4().hex
        full_path = os.path.join(CHAT_UPLOAD_DIR, stored_name)

        f.save(full_path)

        file_size = os.path.getsize(full_path)
        mime_type = f.mimetype or "application/octet-stream"

        cursor.execute("""
            INSERT INTO chat_message_attachments
              (thread_id, uploader_username, original_name, stored_name, mime_type, file_ext, file_size)
            VALUES
              (%s, %s, %s, %s, %s, %s, %s)
        """, (thread_id, username, original_name, stored_name, mime_type, ext, file_size))
        attachment_id = cursor.lastrowid

        conn.commit()
        Write_Log_ToDB(username, "POST", "/api/chat/upload", 0, f"File uploaded thread_id={thread_id} att_id={attachment_id}")

        return jsonify({
            "status":"success",
            "data":{
                "attachment_id": int(attachment_id),
                "original_name": original_name,
                "mime_type": mime_type,
                "file_size": int(file_size),
                "download_url": f"/api/chat/file/{attachment_id}"
            }
        })

    except Exception as e:
        conn.rollback()
        print("api_chat_upload error:", e)
        return jsonify({"status":"error","message":"Failed to upload"}), 500
    finally:
        cursor.close()
        conn.close()

