@app.route("/api/chat/thread/delete", methods=["POST"])
@login_required
def api_chat_thread_delete():
    data = request.json or {}
    username = session.get("username")
    thread_id = data.get("thread_id")
    delete_for = (data.get("delete_for") or "me").strip().lower()  # "me" | "all"

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status": "error", "message": "thread_id is required"}), 400
    if delete_for not in ("me", "all"):
        delete_for = "me"

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki: participant mi?
        cursor.execute("""
            SELECT role
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        me_p = cursor.fetchone()
        if not me_p:
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # Thread bilgisi
        cursor.execute("""
            SELECT thread_type
            FROM chat_threads
            WHERE id=%s
            LIMIT 1
        """, (thread_id,))
        t = cursor.fetchone()
        if not t:
            return jsonify({"status":"error","message":"Thread not found"}), 404

        thread_type = (t.get("thread_type") or "").strip().lower()

        if delete_for == "me":
            # ✅ mevcut davranış: sadece bu user için sil (left_at)
            cursor.execute("""
                UPDATE chat_participants
                SET left_at = NOW(3)
                WHERE thread_id=%s AND username=%s AND left_at IS NULL
            """, (thread_id, username))

            # Aktif participant kaldı mı?
            cursor.execute("""
                SELECT COUNT(*) AS c
                FROM chat_participants
                WHERE thread_id=%s AND left_at IS NULL
            """, (thread_id,))
            c = cursor.fetchone()
            active_count = int(c["c"] if c else 0)

            # Kimse kalmadıysa thread'i archive et
            if active_count == 0:
                cursor.execute("""
                    UPDATE chat_threads
                    SET is_archived=1
                    WHERE id=%s
                """, (thread_id,))

            conn.commit()
            Write_Log_ToDB(username, "POST", "/api/chat/thread/delete", 0, f"Thread deleted(me) thread_id={thread_id}")
            return jsonify({"status": "success", "data": {"thread_id": int(thread_id), "delete_for": "me"}})

        # delete_for == "all"
        # ✅ Grup için (opsiyonel ama tavsiye): sadece admin “herkesten sil” yapabilsin
        if thread_type == "group" and (me_p.get("role") or "").lower() != "admin":
            return jsonify({"status":"error","message":"Only admin can delete group for everyone"}), 403

        # 1) Mesajları herkes için sil (soft delete: deleted_at)
        cursor.execute("""
            UPDATE chat_messages
            SET deleted_at = NOW(3)
            WHERE thread_id=%s AND deleted_at IS NULL
        """, (thread_id,))

        # 2) Mesajlarda attachment referanslarını kopar (integrity için)
        cursor.execute("""
            UPDATE chat_messages
            SET attachment_id = NULL
            WHERE thread_id=%s
        """, (thread_id,))

        # 3) Attachment kayıtlarını sil + dosyaları diskten kaldır
        cursor.execute("""
            SELECT stored_name
            FROM chat_message_attachments
            WHERE thread_id=%s
        """, (thread_id,))
        files = cursor.fetchall() or []

        cursor.execute("""
            DELETE FROM chat_message_attachments
            WHERE thread_id=%s
        """, (thread_id,))

        for f in files:
            stored = f.get("stored_name")
            if stored:
                full_path = os.path.join(CHAT_UPLOAD_DIR, stored)
                try:
                    if os.path.exists(full_path):
                        os.remove(full_path)
                except:
                    pass

        # 4) Herkesi sohbetten çıkar + thread’i archive et
        cursor.execute("""
            UPDATE chat_participants
            SET left_at = NOW(3)
            WHERE thread_id=%s AND left_at IS NULL
        """, (thread_id,))

        cursor.execute("""
            UPDATE chat_threads
            SET is_archived=1
            WHERE id=%s
        """, (thread_id,))

        conn.commit()
        Write_Log_ToDB(username, "POST", "/api/chat/thread/delete", 0, f"Thread deleted(all) thread_id={thread_id}")

        return jsonify({"status":"success","data":{"thread_id": int(thread_id), "delete_for":"all"}})

    except Exception as e:
        conn.rollback()
        print("api_chat_thread_delete error:", e)
        return jsonify({"status": "error", "message": "Failed to delete thread"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/typing", methods=["POST"])
@login_required
def api_chat_typing():
    data = request.json or {}
