@app.route("/api/chat/typing_status", methods=["POST"])
@login_required
def api_chat_typing_status():
    data = request.json or {}
    username = session.get("username")
    thread_id = data.get("thread_id")

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status": "error", "message": "thread_id is required"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki: participant mi?
        cursor.execute("""
            SELECT 1
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # Başkası typing mi? (son 5 sn)
        cursor.execute("""
            SELECT username, updated_at
            FROM chat_typing_status
            WHERE thread_id=%s
              AND username <> %s
              AND is_typing=1
              AND updated_at >= (NOW(3) - INTERVAL 5 SECOND)
            ORDER BY updated_at DESC
            LIMIT 1
        """, (thread_id, username))
        row = cursor.fetchone()

        if row:
            return jsonify({"status": "success", "is_typing": True, "username": row["username"]})
        return jsonify({"status": "success", "is_typing": False, "username": None})

    except Exception as e:
        print("api_chat_typing_status error:", e)
        return jsonify({"status": "error", "message": "Failed to get typing status"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/shared_media", methods=["POST"])
@login_required
def api_chat_shared_media():
    data = request.json or {}
    username = session.get("username")
    thread_id = data.get("thread_id")
    limit = int(data.get("limit") or 30)
    if limit < 1 or limit > 200:
        limit = 30

    if not username:
        return jsonify({"status":"error","message":"Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status":"error","message":"thread_id is required"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki
        cursor.execute("""
            SELECT 1
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status":"error","message":"Forbidden"}), 403

        # Görseller: attachment mime image/*
        cursor.execute("""
            SELECT
              a.id AS attachment_id,
              a.original_name,
              a.mime_type,
              a.file_size,
              a.created_at
            FROM chat_message_attachments a
            WHERE a.thread_id=%s
              AND a.mime_type LIKE 'image/%%'
            ORDER BY a.id DESC
            LIMIT %s
        """, (thread_id, limit))
        rows = cursor.fetchall() or []

        out = []
        for r in rows:
            out.append({
                "attachment_id": int(r["attachment_id"]),
                "original_name": r["original_name"],
                "mime_type": r["mime_type"],
                "file_size": int(r["file_size"] or 0),
                "download_url": f"/api/chat/file/{int(r['attachment_id'])}",
                "created_at": r["created_at"].strftime("%Y-%m-%d %H:%M:%S") if hasattr(r["created_at"], "strftime") else str(r["created_at"]),
            })

        return jsonify({"status":"success","data": out})

    except Exception as e:
        print("api_chat_shared_media error:", e)
        return jsonify({"status":"error","message":"Failed to fetch shared media"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/create_group", methods=["POST"])
@login_required
def api_chat_create_group():
    data = request.json or {}
    me = session.get("username")

    title = (data.get("title") or "").strip()
    members = data.get("members") or []  # ["u1","u2",...]

    if not me:
        return jsonify({"status":"error","message":"Unauthorized"}), 401
    if not title or len(title) < 2:
        return jsonify({"status":"error","message":"Group title is required (min 2 chars)"}), 400
    if len(title) > 80:
        return jsonify({"status":"error","message":"Group title too long (max 80)"}), 400
    if not isinstance(members, list):
        return jsonify({"status":"error","message":"members must be a list"}), 400

    # me + members (me zorunlu dahil)
    raw_users = [me] + members
    raw_users = [str(x).strip() for x in raw_users if x and str(x).strip()]
    # duplicate temizle
    uniq_users = list(dict.fromkeys(raw_users))

    # limit (opsiyonel)
    if len(uniq_users) < 2:
        return jsonify({"status":"error","message":"At least 1 other member required"}), 400
    if len(uniq_users) > 50:
        return jsonify({"status":"error","message":"Too many members (max 50)"}), 400

    # ya_rpa.users1 doğrula (aktif mi)
    users_map = _fetch_active_users_map(uniq_users)
    missing = [u for u in uniq_users if u not in users_map]
    if missing:
        return jsonify({"status":"error","message":f"Inactive/not found users: {', '.join(missing)}"}), 404

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # thread oluştur
        cursor.execute("""
            INSERT INTO chat_threads (thread_type, title, created_by)
            VALUES ('group', %s, %s)
        """, (title, me))
        thread_id = cursor.lastrowid

        # participants ekle (me admin)
        rows = []
        for u in uniq_users:
            role = "admin" if u == me else "member"
            rows.append((thread_id, u, role))

        cursor.executemany("""
            INSERT INTO chat_participants (thread_id, username, role)
            VALUES (%s, %s, %s)
        """, rows)

        conn.commit()
        Write_Log_ToDB(me, "POST", "/api/chat/create_group", 0, f"Group created thread_id={thread_id} title={title}")

        # response: UI thread listesine eklenecek
        return jsonify({
            "status":"success",
            "data":{
                "thread_id": int(thread_id),
                "thread_type": "group",
                "title": title,
                "member_count": len(uniq_users)
            }
        })

    except Exception as e:
        conn.rollback()
        print("api_chat_create_group error:", e)
        return jsonify({"status":"error","message":"Failed to create group"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/group_members", methods=["POST"])
@login_required
def api_chat_group_members():
    data = request.json or {}
    me = session.get("username")
    thread_id = data.get("thread_id")

    if not me:
        return jsonify({"status":"error","message":"Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status":"error","message":"thread_id is required"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # thread type kontrol + participant kontrol
        cursor.execute("SELECT thread_type, title FROM chat_threads WHERE id=%s AND is_archived=0 LIMIT 1", (thread_id,))
        t = cursor.fetchone()
        if not t:
            return jsonify({"status":"error","message":"Thread not found"}), 404
        if t["thread_type"] != "group":
            return jsonify({"status":"error","message":"Not a group thread"}), 400

        me_p = _is_participant(cursor, thread_id, me)
        if not me_p:
            return jsonify({"status":"error","message":"Forbidden"}), 403

        cursor.execute("""
            SELECT username, role, joined_at
            FROM chat_participants
            WHERE thread_id=%s AND left_at IS NULL
            ORDER BY role='admin' DESC, joined_at ASC
        """, (thread_id,))
        parts = cursor.fetchall() or []

        usernames = [p["username"] for p in parts]
        users_map = _fetch_active_users_map(usernames)

        out = []
        for p in parts:
            u = p["username"]
            full = users_map.get(u, {})
            out.append({
                "username": u,
                "name": full.get("name",""),
                "surname": full.get("surname",""),
                "role": p["role"],
                "joined_at": p["joined_at"].strftime("%Y-%m-%d %H:%M:%S") if hasattr(p["joined_at"], "strftime") else str(p["joined_at"])
            })

        return jsonify({"status":"success","data":{
            "thread_id": int(thread_id),
            "title": t.get("title") or "",
            "members": out,
            "my_role": me_p.get("role")
        }})

    except Exception as e:
        print("api_chat_group_members error:", e)
        return jsonify({"status":"error","message":"Failed"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/chat/group_add_members", methods=["POST"])
@login_required
def api_chat_group_add_members():
    data = request.json or {}
    me = session.get("username")

    thread_id = data.get("thread_id")
    members = data.get("members") or []

    if not me:
        return jsonify({"status":"error","message":"Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status":"error","message":"thread_id is required"}), 400
    if not isinstance(members, list) or not members:
        return jsonify({"status":"error","message":"members(list) is required"}), 400

    members = [str(x).strip() for x in members if x and str(x).strip()]
    members = list(dict.fromkeys(members))
    members = [u for u in members if u != me]  # me eklenmeye çalışılırsa boşver

    if not members:
        return jsonify({"status":"error","message":"No valid members"}), 400

    # aktif user doğrula
    users_map = _fetch_active_users_map(members)
    missing = [u for u in members if u not in users_map]
    if missing:
        return jsonify({"status":"error","message":f"Inactive/not found users: {', '.join(missing)}"}), 404

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        cursor.execute("SELECT thread_type, title FROM chat_threads WHERE id=%s AND is_archived=0 LIMIT 1", (thread_id,))
        t = cursor.fetchone()
        if not t:
            return jsonify({"status":"error","message":"Thread not found"}), 404
        if t["thread_type"] != "group":
            return jsonify({"status":"error","message":"Not a group thread"}), 400

        me_p = _is_participant(cursor, thread_id, me)
        if not me_p:
            return jsonify({"status":"error","message":"Forbidden"}), 403
        if me_p.get("role") != "admin":
            return jsonify({"status":"error","message":"Only admin can add members"}), 403

        added = []
        for u in members:
            # varsa left_at NULL değilse re-join
            cursor.execute("""
                SELECT left_at
                FROM chat_participants
                WHERE thread_id=%s AND username=%s
                LIMIT 1
            """, (thread_id, u))
            ex = cursor.fetchone()

            if ex and ex.get("left_at") is None:
                continue

            if ex and ex.get("left_at") is not None:
                cursor.execute("""
                    UPDATE chat_participants
                    SET left_at=NULL, role='member', joined_at=NOW(3)
                    WHERE thread_id=%s AND username=%s
                """, (thread_id, u))
            else:
                cursor.execute("""
                    INSERT INTO chat_participants (thread_id, username, role)
                    VALUES (%s, %s, 'member')
                """, (thread_id, u))

            added.append(u)

        conn.commit()
        Write_Log_ToDB(me, "POST", "/api/chat/group_add_members", 0, f"Group add members thread_id={thread_id} added={','.join(added)}")

        return jsonify({"status":"success","data":{"thread_id": int(thread_id), "added": added}})

    except Exception as e:
        conn.rollback()
        print("api_chat_group_add_members error:", e)
        return jsonify({"status":"error","message":"Failed"}), 500
    finally:
        cursor.close()
        conn.close()

