@app.route("/api/chat/group_leave", methods=["POST"])
@login_required
def api_chat_group_leave():
    data = request.json or {}
    me = session.get("username")
    thread_id = data.get("thread_id")

    if not me:
        return jsonify({"status":"error","message":"Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status":"error","message":"thread_id is required"}), 400

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        cursor.execute("SELECT thread_type FROM chat_threads WHERE id=%s AND is_archived=0 LIMIT 1", (thread_id,))
        t = cursor.fetchone()
        if not t:
            return jsonify({"status":"error","message":"Thread not found"}), 404
        if t["thread_type"] != "group":
            return jsonify({"status":"error","message":"Not a group thread"}), 400

        me_p = _is_participant(cursor, thread_id, me)
        if not me_p:
            return jsonify({"status":"error","message":"Forbidden"}), 403

        # Eğer admin ise ve başka admin yoksa: en eski member'ı admin yap (fallback)
        if me_p.get("role") == "admin":
            cursor.execute("""
                SELECT username
                FROM chat_participants
                WHERE thread_id=%s AND left_at IS NULL AND username<>%s
                ORDER BY (role='admin') DESC, joined_at ASC
                LIMIT 1
            """, (thread_id, me))
            candidate = cursor.fetchone()
            if candidate:
                # eğer candidate member ise admin yap
                cursor.execute("""
                    UPDATE chat_participants
                    SET role='admin'
                    WHERE thread_id=%s AND username=%s AND left_at IS NULL
                """, (thread_id, candidate["username"]))

        # çıkış
        cursor.execute("""
            UPDATE chat_participants
            SET left_at=NOW(3)
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
        """, (thread_id, me))

        # kimse kalmadıysa archive
        cursor.execute("""
            SELECT COUNT(*) AS c
            FROM chat_participants
            WHERE thread_id=%s AND left_at IS NULL
        """, (thread_id,))
        c = cursor.fetchone()
        if int(c["c"] if c else 0) == 0:
            cursor.execute("UPDATE chat_threads SET is_archived=1 WHERE id=%s", (thread_id,))

        conn.commit()
        Write_Log_ToDB(me, "POST", "/api/chat/group_leave", 0, f"Group leave thread_id={thread_id}")

        return jsonify({"status":"success","data":{"thread_id": int(thread_id)}})

    except Exception as e:
        conn.rollback()
        print("api_chat_group_leave error:", e)
        return jsonify({"status":"error","message":"Failed"}), 500
    finally:
        cursor.close()
        conn.close()

