@app.route("/api/chat/long_poll", methods=["POST"])
@login_required
def api_chat_long_poll():
    """
    Long-poll endpoint:
    - Client, thread_id + after_id gönderir.
    - Sunucu, yeni mesaj gelene kadar (timeout saniye) bekler.
    - Yeni mesaj gelince: window_after = after_id-60 bazlı küçük bir pencere döndürür
      (hem yeni mesajlar hem de read-status güncellemeleri için).
    """
    import time

    data = request.json or {}
    username = session.get("username")

    thread_id = data.get("thread_id")
    after_id = int(data.get("after_id") or 0)
    timeout = int(data.get("timeout") or 25)

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not thread_id:
        return jsonify({"status": "error", "message": "thread_id is required"}), 400

    # güvenlik: timeout sınırı
    if timeout < 5:
        timeout = 5
    if timeout > 30:
        timeout = 30

    # status güncellemeleri için küçük bir pencere döndürelim
    window_after = max(0, after_id - 60)
    limit = 80

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # Yetki: participant mi?
        cursor.execute("""
            SELECT 1
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        if not cursor.fetchone():
            return jsonify({"status": "error", "message": "Forbidden"}), 403

        # Participants (okundu hesabı için)
        cursor.execute("""
            SELECT username, last_read_message_id, last_read_at
            FROM chat_participants
            WHERE thread_id=%s AND left_at IS NULL
        """, (thread_id,))
        participants = cursor.fetchall() or []

        read_map = {
            p["username"]: (int(p.get("last_read_message_id") or 0), p.get("last_read_at"))
            for p in participants
        }
        other_usernames = [p["username"] for p in participants if p["username"] != username]

        def build_payload(rows):
            # reply_to hedeflerini tek seferde çekmek için:
            reply_ids = sorted({int(r["reply_to_message_id"]) for r in rows if r.get("reply_to_message_id")})
            reply_map = {}
            if reply_ids:
                placeholders = ",".join(["%s"] * len(reply_ids))
                cursor.execute(f"""
                    SELECT id, thread_id, sender_username, message_type, body, attachment_id, created_at
                    FROM chat_messages
                    WHERE thread_id=%s
                      AND id IN ({placeholders})
                      AND deleted_at IS NULL
                """, tuple([int(thread_id)] + reply_ids))
                rep_rows = cursor.fetchall() or []
                for rr in rep_rows:
                    reply_map[int(rr["id"])] = rr

            # attachment meta cache
            att_ids = set()
            for r in rows:
                if r.get("attachment_id"):
                    att_ids.add(int(r["attachment_id"]))
            for rid, rr in reply_map.items():
                if rr.get("attachment_id"):
                    att_ids.add(int(rr["attachment_id"]))

            att_map = {}
            if att_ids:
                placeholders = ",".join(["%s"] * len(att_ids))
                cursor.execute(f"""
                    SELECT id, original_name, mime_type, file_size
                    FROM chat_message_attachments
                    WHERE id IN ({placeholders})
                """, tuple(att_ids))
                arows = cursor.fetchall() or []
                for a in arows:
                    att_map[int(a["id"])] = a

            messages = []
            for r in rows:
                mid = int(r["id"])

                seen_by = []
                seen_by_all = False
                seen_count = 0
                seen_at_max = None
                delivery_status = "delivered"

                # sadece benim mesajlarım için okundu hesabı
                if r["sender_username"] == username and other_usernames:
                    for ou in other_usernames:
                        ou_last_read_id, ou_last_read_at = read_map.get(ou, (0, None))
                        if int(ou_last_read_id) >= mid:
                            seen_by.append(ou)
                            if ou_last_read_at and (seen_at_max is None or ou_last_read_at > seen_at_max):
                                seen_at_max = ou_last_read_at

                    seen_count = len(seen_by)
                    seen_by_all = (seen_count == len(other_usernames))
                    delivery_status = "read" if seen_by_all else "delivered"

                msg = {
                    "id": mid,
                    "thread_id": int(r["thread_id"]),
                    "sender_username": r["sender_username"],
                    "message_type": r["message_type"],
                    "body": r["body"],
                    "created_at": (
                        r["created_at"].strftime("%Y-%m-%d %H:%M:%S")
                        if hasattr(r["created_at"], "strftime") else str(r["created_at"])
                    ),
                    "reply_to_message_id": (int(r["reply_to_message_id"]) if r.get("reply_to_message_id") else None),

                    # UI status alanları
                    "status": delivery_status,
                    "is_read": (delivery_status == "read"),
                    "seen_by_all": seen_by_all,
                    "seen_by": seen_by,
                    "seen_count": seen_count,
                    "seen_at": (seen_at_max.strftime("%Y-%m-%d %H:%M:%S.%f")[:-3] if hasattr(seen_at_max, "strftime") else None),
                }

                # attachment meta
                att_id = r.get("attachment_id")
                if att_id and int(att_id) in att_map:
                    a = att_map[int(att_id)]
                    msg["attachment"] = {
                        "attachment_id": int(a["id"]),
                        "original_name": a["original_name"],
                        "mime_type": a["mime_type"],
                        "file_size": int(a["file_size"]),
                        "download_url": f"/api/chat/file/{a['id']}"
                    }

                # reply preview
                rid = msg["reply_to_message_id"]
                if rid and rid in reply_map:
                    rr = reply_map[rid]
                    rr_body = (rr.get("body") or "")
                    rr_body_stripped = rr_body.strip()

                    prev = {
                        "id": int(rr["id"]),
                        "sender_username": rr["sender_username"],
                        "message_type": rr["message_type"],
                        "body": rr_body,
                        "created_at": (
                            rr["created_at"].strftime("%Y-%m-%d %H:%M:%S")
                            if hasattr(rr["created_at"], "strftime") else str(rr["created_at"])
                        ),
                        "snippet": (
                            rr_body_stripped[:180]
                            if rr_body_stripped
                            else ("📎 Dosya" if rr.get("attachment_id") else "(mesaj)")
                        )
                    }

                    ratt = rr.get("attachment_id")
                    if ratt and int(ratt) in att_map:
                        a = att_map[int(ratt)]
                        prev["attachment"] = {
                            "attachment_id": int(a["id"]),
                            "original_name": a["original_name"],
                            "mime_type": a["mime_type"],
                            "file_size": int(a["file_size"]),
                            "download_url": f"/api/chat/file/{a['id']}"
                        }
                        if not rr_body_stripped:
                            prev["snippet"] = f"📎 {a['original_name']}"

                    msg["reply_preview"] = prev
                else:
                    msg["reply_preview"] = None

                messages.append(msg)

            return messages

        start = time.time()
        while True:
            # window_after sonrası mesajları çek
            cursor.execute("""
                SELECT
                  id, thread_id, sender_username, message_type, body,
                  attachment_id, reply_to_message_id, created_at
                FROM chat_messages
                WHERE thread_id=%s
                  AND deleted_at IS NULL
                  AND id > %s
                ORDER BY id ASC
                LIMIT %s
            """, (thread_id, int(window_after), int(limit)))
            rows = cursor.fetchall() or []

            # gerçekten after_id'den büyük yeni mesaj var mı?
            has_new = any(int(r["id"]) > after_id for r in rows)

            if rows and (has_new or window_after < after_id):
                # rows varsa (özellikle status update için), payload üret
                messages = build_payload(rows)
                return jsonify({"status": "success", "data": {"messages": messages}})

            # timeout kontrol
            if (time.time() - start) >= timeout:
                return jsonify({"status": "success", "data": {"messages": []}})

            time.sleep(0.5)

    except Exception as e:
        print("api_chat_long_poll error:", e)
        return jsonify({"status": "error", "message": "Failed"}), 500
    finally:
        try:
            cursor.close()
            conn.close()
        except:
            pass

@app.route("/api/chat/message/delete", methods=["POST"])
@login_required
def api_chat_message_delete():
    data = request.json or {}
    username = session.get("username")

    message_id = data.get("message_id")
    delete_for = (data.get("delete_for") or "me").strip().lower()  # "me" | "all"

    if not username:
        return jsonify({"status": "error", "message": "Unauthorized"}), 401
    if not message_id:
        return jsonify({"status": "error", "message": "message_id is required"}), 400
    if delete_for not in ("me", "all"):
        delete_for = "me"

    conn = get_chat_conn()
    cursor = conn.cursor()
    try:
        # mesajı bul (thread + sender + attachment)
        cursor.execute("""
            SELECT id, thread_id, sender_username, attachment_id
            FROM chat_messages
            WHERE id=%s AND deleted_at IS NULL
            LIMIT 1
        """, (int(message_id),))
        m = cursor.fetchone()
        if not m:
            return jsonify({"status":"error","message":"Message not found"}), 404

        thread_id = int(m["thread_id"])
        sender = m["sender_username"]
        attachment_id = m.get("attachment_id")

        # yetki: participant mi?
        cursor.execute("""
            SELECT role
            FROM chat_participants
            WHERE thread_id=%s AND username=%s AND left_at IS NULL
            LIMIT 1
        """, (thread_id, username))
        me_p = cursor.fetchone()
        if not me_p:
            return jsonify({"status":"error","message":"Forbidden"}), 403

        # thread_type al (group admin kontrolü için)
        cursor.execute("""
            SELECT thread_type
            FROM chat_threads
            WHERE id=%s AND is_archived=0
            LIMIT 1
        """, (thread_id,))
        t = cursor.fetchone()
        if not t:
            return jsonify({"status":"error","message":"Thread not found"}), 404
        thread_type = (t.get("thread_type") or "").strip().lower()

        # ---- Yetki kuralı ----
        # delete_for=me: sadece kendi mesajını silebilir (en güvenlisi)
        if delete_for == "me":
            if sender != username:
                return jsonify({"status":"error","message":"You can delete only your own messages"}), 403

        # delete_for=all:
        # - kendi mesajını herkesten silebilsin
        # - group thread ise sadece admin herkesten silebilsin
        if delete_for == "all":
            if thread_type == "group":
                if (me_p.get("role") or "").lower() != "admin":
                    return jsonify({"status":"error","message":"Only admin can delete for everyone in group"}), 403
            else:
                # dm/self/context: sadece mesaj sahibi herkesten silebilsin
                if sender != username:
                    return jsonify({"status":"error","message":"Only sender can delete for everyone"}), 403

        # 1) mesaj soft-delete
        cursor.execute("""
            UPDATE chat_messages
            SET deleted_at = NOW(3)
            WHERE id=%s AND deleted_at IS NULL
        """, (int(message_id),))

        # 2) reactions temizle (count’lar doğru kalsın)
        cursor.execute("""
            DELETE FROM chat_message_reactions
            WHERE message_id=%s
        """, (int(message_id),))

        # 3) attachment varsa: attachment kaydını sil + dosyayı kaldır (opsiyonel ama temiz)
        if attachment_id:
            cursor.execute("""
                SELECT stored_name
                FROM chat_message_attachments
                WHERE id=%s AND thread_id=%s
                LIMIT 1
            """, (int(attachment_id), int(thread_id)))
            a = cursor.fetchone()

            # mesajda referansı kopar (integrity)
            cursor.execute("""
                UPDATE chat_messages
                SET attachment_id=NULL
                WHERE id=%s
            """, (int(message_id),))

            # attachment kaydını sil
            cursor.execute("""
                DELETE FROM chat_message_attachments
                WHERE id=%s AND thread_id=%s
            """, (int(attachment_id), int(thread_id)))

            # diskten sil
            """
            if a and a.get("stored_name"):
                try:
                    full_path = os.path.join(CHAT_UPLOAD_DIR, a["stored_name"])
                    if os.path.exists(full_path):
                        os.remove(full_path)
                except:
                    pass
            """

        conn.commit()
        Write_Log_ToDB(username, "POST", "/api/chat/message/delete", 0, f"Message deleted message_id={message_id} thread_id={thread_id} delete_for={delete_for}")

        return jsonify({"status":"success","data":{
            "message_id": int(message_id),
            "thread_id": int(thread_id),
            "delete_for": delete_for
        }})

    except Exception as e:
        conn.rollback()
        print("api_chat_message_delete error:", e)
        return jsonify({"status":"error","message":"Failed to delete message"}), 500
    finally:
        cursor.close()
        conn.close()

@app.route("/api/users/last_seen", methods=["POST"])
@login_required
def api_users_last_seen():
    from datetime import datetime
    data = request.json or {}

    one = (data.get("username") or "").strip()
    many = data.get("usernames") or []

    usernames = []
    single_mode = False

    if one:
        usernames = [one]
        single_mode = True
    elif isinstance(many, list):
        usernames = [str(u).strip() for u in many if u and str(u).strip()]

    # unique (order-preserving)
    usernames = list(dict.fromkeys(usernames))

    if not usernames:
        return jsonify({"status": "error", "message": "username or usernames(list) is required"}), 400

    # güvenlik: çok büyük listeyi sınırlayalım
    if len(usernames) > 200:
        return jsonify({"status": "error", "message": "Too many usernames (max 200)"}), 400

    connection = None
    cursor = None

    try:
        connection = pyodbc.connect(YA_2El_AracSatis)
        cursor = connection.cursor()

        placeholders = ",".join(["?"] * len(usernames))

        q = f"""
            SELECT
                Username,
                MAX(RequestedDateTime) AS last_seen
            FROM Yuce_Portal.dbo.YP_users_log
            WHERE Username IN ({placeholders})
            GROUP BY Username
        """

        cursor.execute(q, tuple(usernames))
        rows = cursor.fetchall() or []

        out = {}
        now = datetime.now()

        for r in rows:
            u = str(r[0]).strip() if r[0] is not None else ""
            dt = r[1]  # datetime ya da None

            if not u:
                continue

            if not dt:
                out[u] = {
                    "username": u,
                    "last_seen": None,          # frontend'in aradığı alan
                    "last_seen_raw": None,
                    "last_seen_display": None
                }
                continue

            # display kuralı: bugünse HH:MM, değilse dd.MM.yyyy HH:MM
            if dt.date() == now.date():
                display = dt.strftime("%H:%M")
            else:
                display = dt.strftime("%d.%m.%Y %H:%M")

            dt_str = dt.strftime("%Y-%m-%d %H:%M:%S")

            out[u] = {
                "username": u,
                "last_seen": dt_str,          # frontend bunu okuyor
                "last_seen_raw": dt_str,      # geriye dönük uyumluluk
                "last_seen_display": display
            }

        # logda hiç yoksa da boş dönmesin, istenen kullanıcılar için null ekleyelim
        for u in usernames:
            if u not in out:
                out[u] = {
                    "username": u,
                    "last_seen": None,
                    "last_seen_raw": None,
                    "last_seen_display": None
                }

        # ✅ Frontend uyumu:
        # - Tek username gönderildiyse: data = obje
        # - usernames listesi gönderildiyse: data = map
        if single_mode:
            key = usernames[0]
            return jsonify({"status": "success", "data": out.get(key)})

        return jsonify({"status": "success", "data": out})

    except Exception as e:
        print("api_users_last_seen error:", e)
        return jsonify({"status": "error", "message": "Failed to fetch last seen"}), 500

    finally:
        try:
            if cursor:
                cursor.close()
            if connection:
                connection.close()
        except:
            pass

@app.route("/api/ofis_home_status/<string:username>", methods=["GET"])
@login_required
def api_ofis_home_status(username):
    """
    Frontend expects:
      { "status": "success", "username": "...", "ofis_status": "Home|Ofis|Bayi|Izin" }

    Notes:
    - We return today's status based on ofis_gunleri.selected_date = today
    - If no row exists -> Izin
    """

    try:
        cursor = mysql.connection.cursor()

        # 1) Find user ID
        cursor.execute("""
            SELECT ID
            FROM users1
            WHERE username = %s
            LIMIT 1
        """, (username,))
        u = cursor.fetchone()

        if not u:
            cursor.close()
            return jsonify({
                "status": "success",
                "username": username,
                "ofis_status": "Izin"
            }), 200

        user_id = u["ID"] if isinstance(u, dict) else u[0]

        # 2) Today's status (Ofis/Bayi/Home)
        cursor.execute("""
            SELECT ofis_bayi
            FROM ofis_gunleri
            WHERE users1_id = %s
              AND DATE(selected_date) = CURDATE()
            ORDER BY selected_date DESC
            LIMIT 1
        """, (user_id,))
        row = cursor.fetchone()
        cursor.close()

        ofis_status = None
        if row:
            ofis_status = row["ofis_bayi"] if isinstance(row, dict) else row[0]

        # Normalize output to what frontend expects
        # (Frontend badges: Home / Ofis / Bayi ; else => Izin)
        if ofis_status not in ("Home", "Ofis", "Bayi", "Izin"):
            ofis_status = "Izin"

        if ofis_status == "Ofis":
            ofis_status = "ofis"
        elif ofis_status == "Home":
            ofis_status = "home"
        elif ofis_status == "Bayi":
            ofis_status = "bayi"
        elif ofis_status == "Izin":
            ofis_status = "izin"
        else:
            ofis_status = "unknown"

        return jsonify({
            "status": "success",
            "username": username,
            "ofis_status": ofis_status
        }), 200

    except Exception as e:
        print("api_ofis_home_status error:", e)
        try:
            cursor.close()
        except:
            pass
        return jsonify({
            "status": "error",
            "message": "Failed to fetch ofis status"
        }), 500

