@app.route("/api/send_notif", methods=["POST"])
@login_required
@department_check("Bilgi Teknolojileri")
def send_custom_push_notification():
    users = request.form.getlist("user_picker")
    web_message = (request.form.get("web_notif_message") or "").strip()
    page_link = "/talep_yonetim"
    portal_check = request.form.get("web_notif_check")

    mobile_title = (request.form.get("tel_notif_title") or "").strip()
    mobile_message = (request.form.get("tel_notif_message") or "").strip()
    mobile_check = request.form.get("tel_notif_check")

    if not users:
        return jsonify({"status": "error", "message": "Kullanıcı seçilmedi."}), 400

    if portal_check and not web_message:
        return jsonify({"status": "error", "message": "Portal bildirimi için mesaj zorunlu."}), 400

    if mobile_check and (not mobile_title or not mobile_message):
        return jsonify({"status": "error", "message": "Mobil bildirim için başlık ve mesaj zorunlu."}), 400

    portal_sent = 0
    mobile_sent = 0
    portal_skipped = []
    mobile_skipped = []

    for username in users:
        username = (username or "").strip()
        if not username:
            continue

        if portal_check:
            mysql_cursor = mysql.connection.cursor()
            mysql_cursor.execute("SELECT ID FROM users1 WHERE username = %s", (username,))
            row = mysql_cursor.fetchone()
            mysql_cursor.close()

            if not row:
                portal_skipped.append({"user": username, "reason": "user_not_found"})
            else:
                user_id = row["ID"] if isinstance(row, dict) else row[0]

                conn = pyodbc.connect(YA_2El_AracSatis)
                cursor = conn.cursor()

                notif_insert_query = """
                    INSERT INTO [Yuce_Portal].[dbo].[notifications]
                    ([user_id],[user_username],[message],[a_tag],[image_path],[is_read],[is_active],[created_at])
                    VALUES( ?, ?, ?, ?, NULL, 0, 1, GETDATE());
                """
                cursor.execute(notif_insert_query, user_id, username, web_message, page_link)
                conn.commit()
                cursor.close()
                conn.close()
                portal_sent += 1

        if mobile_check:
            token = find_device_token(username)
            if not token:
                mobile_skipped.append({"user": username, "reason": "token_not_found"})
            else:
                send_push_notification(token=token, title=mobile_title, message=mobile_message)
                mobile_sent += 1

    return jsonify({
        "status": "success",
        "message": "İşlem tamamlandı.",
        "portal": {"sent": portal_sent, "skipped": portal_skipped},
        "mobile": {"sent": mobile_sent, "skipped": mobile_skipped},
        "selected_users": users
    }), 200

