BASE_PATH = r"C:\Users\yuceappadmin\Documents\GitHub\RPA-Projects\static"

@app.route("/internal/upload_file", methods=["POST"])
def internal_upload_file():
    # --- Required fields ---
    username = request.form.get("username", "").strip()
    target_folder = request.form.get("target_folder", "").strip()  # e.g. "users_card_photos"
    filename = request.form.get("filename", "").strip()            # e.g. "furkana.jpg"
    target_type = request.form.get("target_type", "file").lower()  # "image" | "file"
    file = request.files.get("file")

    if not all([target_folder, filename, file]):
        return jsonify({"status": "error", "message": "Missing fields"}), 400

    save_dir = os.path.join(BASE_PATH, target_folder)
    os.makedirs(save_dir, exist_ok=True)
    save_path = os.path.join(save_dir, filename)

    try:
        if target_type == "image":
            img = Image.open(file.stream).convert("RGB")
            img.thumbnail((2000, 2000))
            img.save(save_path, "JPEG", optimize=True, quality=85)
        else:
            file.save(save_path)
    except UnidentifiedImageError:
        return jsonify({"status": "error", "message": "Invalid image file"}), 400
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

    return jsonify({
        "status": "success",
        "saved_to": save_path.replace(BASE_PATH, "").lstrip("\\/"),
        "target_type": target_type,
        "username": username
    }), 200

@app.route("/internal/delete_file", methods=["POST"])
def internal_delete_file():
    data = request.form or request.get_json(silent=True) or {}

    username = (data.get("username") or "").strip()
    target_folder = (data.get("target_folder") or "").strip()
    filename = (data.get("filename") or "").strip()
    target_type = (data.get("target_type") or "file").lower().strip()

    if not all([target_folder, filename]):
        return jsonify({"status": "error", "message": "Missing fields"}), 400

    # Path traversal koruması
    safe_folder = secure_filename(target_folder)
    safe_filename = secure_filename(filename)

    # Upload ile aynı hedef: BASE_PATH/target_folder/filename
    save_dir = os.path.join(BASE_PATH, safe_folder)
    abs_path = os.path.join(save_dir, safe_filename)

    try:
        # Ek güvenlik: abs_path mutlaka BASE_PATH altında olmalı
        base_abs = os.path.abspath(BASE_PATH)
        file_abs = os.path.abspath(abs_path)
        if not file_abs.startswith(base_abs + os.sep) and file_abs != base_abs:
            return jsonify({"status": "error", "message": "Geçersiz dosya yolu"}), 400

        if not os.path.exists(file_abs):
            # idempotent: dosya yoksa da başarı dön
            return jsonify({
                "status": "success",
                "message": "Dosya zaten yok",
                "target_type": target_type,
                "username": username
            }), 200

        os.remove(file_abs)

        return jsonify({
            "status": "success",
            "message": "Dosya silindi",
            "deleted_from": file_abs.replace(BASE_PATH, "").lstrip("\\/"),
            "target_type": target_type,
            "username": username
        }), 200

    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

