import os
from PIL import Image, ImageOps

IMAGE_EXTS = (".png", ".jpg", ".jpeg", ".webp", ".gif")

TR_MONTHS = {
    1: "Ocak", 2: "Şubat", 3: "Mart", 4: "Nisan", 5: "Mayıs", 6: "Haziran",
    7: "Temmuz", 8: "Ağustos", 9: "Eylül", 10: "Ekim", 11: "Kasım", 12: "Aralık"
}

THUMB_DIRNAME = "_thumb"
THUMB_MAX_W = 640         # grid/kapak için ideal (480 da olur)
THUMB_QUALITY = 72        # 60-75 arası iyi
THUMB_FORMAT = "WEBP"     # en hızlı/ufak


# =========================
#  PATH HELPERS
# =========================

def _album_base_dir() -> str:
    return os.path.join(current_app.static_folder, "Albumler")

def _album_folder_path(album_slug: str) -> str:
    return os.path.join(_album_base_dir(), album_slug)

def _thumb_folder_path(album_slug: str) -> str:
    return os.path.join(_album_folder_path(album_slug), THUMB_DIRNAME)

def _thumb_filename_for(src_filename: str) -> str:
    stem, _ = os.path.splitext(src_filename)
    return f"{stem}.webp"

def _thumb_file_path(album_slug: str, src_filename: str) -> str:
    return os.path.join(_thumb_folder_path(album_slug), _thumb_filename_for(src_filename))


# =========================
#  THUMBNAIL GENERATION
# =========================

def _ensure_one_thumb(album_slug: str, src_filename: str, force: bool = False) -> bool:
    """
    Albüm içindeki bir görüntü için _thumb altında WEBP thumbnail üretir.
    True: üretildi
    False: zaten vardı / üretilemedi / kaynak yok
    """
    src_path = os.path.join(_album_folder_path(album_slug), src_filename)
    out_path = _thumb_file_path(album_slug, src_filename)

    if not os.path.isfile(src_path):
        return False

    if (not force) and os.path.isfile(out_path):
        return False

    os.makedirs(os.path.dirname(out_path), exist_ok=True)

    try:
        with Image.open(src_path) as im:
            # iPhone orientation fix
            try:
                im = ImageOps.exif_transpose(im)
            except Exception:
                pass

            if im.mode not in ("RGB", "RGBA"):
                im = im.convert("RGB")

            w, h = im.size
            if w > THUMB_MAX_W:
                new_h = int((THUMB_MAX_W / w) * h)
                im = im.resize((THUMB_MAX_W, new_h), Image.LANCZOS)

            im.save(out_path, THUMB_FORMAT, quality=THUMB_QUALITY, method=6)

        return True
    except Exception:
        return False


def ensure_album_thumbs(album_slug: str, filenames: list[str], force: bool = False) -> dict:
    """
    Albümdeki tüm görseller için thumb üretimini garanti eder.
    Return: {"generated": X, "skipped": Y}
    """
    generated = 0
    skipped = 0

    for fn in filenames:
        if not fn.lower().endswith(IMAGE_EXTS):
            continue

        ok = _ensure_one_thumb(album_slug, fn, force=force)
        if ok:
            generated += 1
        else:
            skipped += 1

    return {"generated": generated, "skipped": skipped}


def build_photo_obj(album_slug: str, filename: str) -> dict:
    stem, _ = os.path.splitext(filename)
    return {
        "full": f"/static/Albumler/{album_slug}/{filename}",
        "thumb": f"/static/Albumler/{album_slug}/{THUMB_DIRNAME}/{stem}.webp",
    }


