#  ROUTES
# =========================

@app.route("/albumler", methods=["GET"])
@login_required
def albumler():
    base = _album_base_dir()
    albums = []

    if os.path.isdir(base):
        for folder in os.listdir(base):
            full_dir = os.path.join(base, folder)
            if not os.path.isdir(full_dir):
                continue

            # Parse folder name like "Oktoberfest_20251023"
            m = re.match(r"(.+?)_(\d{8})$", folder)
            title = folder.replace("_", " ")
            date_display = ""
            dt_iso = None

            if m:
                name, datestr = m.groups()
                try:
                    d = dt.datetime.strptime(datestr, "%Y%m%d").date()
                    date_display = f"{d.day} {TR_MONTHS[d.month]} {d.year}"
                    title = f"{name.replace('_', ' ')} {d.year}"
                    dt_iso = d.isoformat()
                except ValueError:
                    pass

            try:
                files = [f for f in os.listdir(full_dir) if f.lower().endswith(IMAGE_EXTS)]
            except PermissionError:
                continue

            if not files:
                continue

            # İstersen mtime sort:
            # files.sort(key=lambda f: os.path.getmtime(os.path.join(full_dir, f)))
            files.sort()

            # 1) Thumb'ları garanti et (ilk çalıştırmada üretir, sonra cache)
            ensure_album_thumbs(folder, files, force=False)

            # 2) Payload: thumb + full
            photos = [build_photo_obj(folder, fn) for fn in files]

            albums.append({
                "slug": folder,
                "title": title,
                "date": date_display,
                "dt": dt_iso,
                "count": len(photos),
                "cover": photos[0]["thumb"],   # kapak artık thumb -> hızlı
                "photos": photos,              # artık list of objects
            })

    Write_Log_ToDB(session.get('username'), "GET", "/albumler", 0, "Page viewed.")

    albums.sort(key=lambda a: (a["dt"] is not None, a["dt"], a["title"]), reverse=True)
    return render_template("albumler.html", albums=albums)

from concurrent.futures import ThreadPoolExecutor
push_executor = ThreadPoolExecutor(max_workers=10)
def _send_push_to_participants(participants, title_username, body):
    for participant in participants:
        try:
            token = find_device_token(participant["username"])
            print(participant, token)
            if token:
                send_push_notification(token=token, title=title_username, message=body)
        except Exception:
            app.logger.exception("Push gönderimi başarısız")

@app.route("/albumler/IOSalbums", methods=["GET"])
def albumler_ios_albums():
    try:
        base = _album_base_dir()
        albums = []

        if os.path.isdir(base):
            for folder in os.listdir(base):
                full_dir = os.path.join(base, folder)
                if os.path.isdir(full_dir):
                    albums.append(folder)

        albums.sort()

        return jsonify({"success": True, "albums": albums}), 200

    except Exception as e:
        return jsonify({"success": False, "error": str(e), "albums": []}), 500

@app.route("/albumler/IOSfilenames", methods=["GET"])
def albumler_ios_filenames():
    """
    iOS client albüm seçince dosya adlarını döner.
    NOTE: secure_filename yerine whitelist kullanıyoruz (klasör adını bozmasın diye).
    """
    try:
        album = (request.args.get("album") or "").strip()
        if not album:
            return jsonify({"success": False, "error": "Albüm parametresi zorunludur.", "filenames": []}), 400

        base = _album_base_dir()
        folder_path = os.path.join(base, album)

        # whitelist: album mutlaka base içindeki bir klasör olmalı
        if not (os.path.isdir(folder_path) and os.path.dirname(folder_path) == base):
            return jsonify({"success": False, "error": "Albüm bulunamadı.", "filenames": []}), 404

        filenames = [
            f for f in os.listdir(folder_path)
            if os.path.isfile(os.path.join(folder_path, f)) and f.lower().endswith(IMAGE_EXTS)
        ]
        filenames.sort()

        return jsonify({"success": True, "filenames": filenames}), 200

    except Exception as e:
        return jsonify({"success": False, "error": str(e), "filenames": []}), 500
    
